--
-- Name: assert_entry_balanced("uuid"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."assert_entry_balanced"("p_entry_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_total_debit NUMERIC;
  v_total_credit NUMERIC;
  v_diff NUMERIC;
BEGIN
  SELECT 
    COALESCE(SUM(CASE WHEN debit_credit = 'DEBIT' THEN amount ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN debit_credit = 'CREDIT' THEN amount ELSE 0 END), 0)
  INTO v_total_debit, v_total_credit
  FROM accounting.journal_entry_lines
  WHERE journal_entry_id = p_entry_id;

  v_diff := ABS(v_total_debit - v_total_credit);

  IF v_diff > 0.01 THEN
    RAISE EXCEPTION 'Asiento % desequilibrado: Debe=% Haber=% Diferencia=%',
      p_entry_id, v_total_debit, v_total_credit, v_diff;
  END IF;
END;
$$;
ALTER FUNCTION "accounting"."assert_entry_balanced"("p_entry_id" "uuid") OWNER TO "postgres";
--
-- Name: assert_period_not_closed("date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."assert_period_not_closed"("p_date" "date") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_year int;
  v_month int;
  v_closed boolean;
BEGIN
  v_year := EXTRACT(YEAR FROM p_date)::int;
  v_month := EXTRACT(MONTH FROM p_date)::int;
  SELECT is_period_closed(v_year, v_month) INTO v_closed;
  IF v_closed THEN
    RAISE WARNING 'Per├¡odo %/% est├í cerrado', v_year, v_month;
  END IF;
  RETURN true;
END;
$$;
ALTER FUNCTION "accounting"."assert_period_not_closed"("p_date" "date") OWNER TO "postgres";
--
-- Name: auto_close_previous_month_if_tenth(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."auto_close_previous_month_if_tenth"() RETURNS TABLE("closed_year" integer, "closed_month" integer, "action" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting'
    AS $$
DECLARE
  v_day INTEGER;
  v_prev_year INTEGER;
  v_prev_month INTEGER;
  v_start DATE;
  v_end DATE;
BEGIN
  v_day := EXTRACT(DAY FROM CURRENT_DATE)::INTEGER;
  IF v_day <> 10 THEN
    RETURN QUERY SELECT NULL::INTEGER, NULL::INTEGER, 'skip_not_tenth'::TEXT;
    RETURN;
  END IF;

  v_prev_month := EXTRACT(MONTH FROM CURRENT_DATE)::INTEGER - 1;
  v_prev_year := EXTRACT(YEAR FROM CURRENT_DATE)::INTEGER;
  IF v_prev_month <= 0 THEN
    v_prev_month := v_prev_month + 12;
    v_prev_year := v_prev_year - 1;
  END IF;

  IF accounting.is_period_closed(v_prev_year, v_prev_month) THEN
    RETURN QUERY SELECT v_prev_year, v_prev_month, 'already_closed'::TEXT;
    RETURN;
  END IF;

  v_start := make_date(v_prev_year, v_prev_month, 1);
  v_end := (v_start + interval '1 month' - interval '1 day')::date;

  INSERT INTO accounting.period_closures (year, month, period_start, period_end, closed_by)
  VALUES (v_prev_year, v_prev_month, v_start, v_end, NULL)
  ON CONFLICT (year, month) DO UPDATE
  SET is_locked = true, closed_at = now();

  RETURN QUERY SELECT v_prev_year, v_prev_month, 'closed'::TEXT;
END;
$$;
ALTER FUNCTION "accounting"."auto_close_previous_month_if_tenth"() OWNER TO "postgres";
--
-- Name: auto_create_invoice_purchase_entry(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."auto_create_invoice_purchase_entry"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_entry_id UUID;
  v_entry_date DATE;
BEGIN
  IF NEW.status = 'APPROVED' AND (OLD.status IS NULL OR OLD.status != 'APPROVED') THEN
    SELECT id INTO v_entry_id
    FROM accounting.journal_entries
    WHERE reference_id = NEW.id AND reference_type = 'purchase_invoice' AND entry_type = 'INVOICE_PURCHASE';
    IF v_entry_id IS NULL THEN
      v_entry_date := COALESCE(NEW.issue_date, NEW.updated_at::date, CURRENT_DATE);
      PERFORM accounting.create_invoice_purchase_entry(p_purchase_invoice_id := NEW.id, p_entry_date := v_entry_date);
    END IF;
  END IF;
  RETURN NEW;
END;
$$;
