--
-- Name: auto_create_invoice_sale_entry(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."auto_create_invoice_sale_entry"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_existing_entry_id UUID;
BEGIN
  -- Solo actuar cuando el estado cambia a ISSUED
  IF NEW.status = 'ISSUED' AND (OLD.status IS NULL OR OLD.status != 'ISSUED') THEN
    -- Verificar que no exista ya un asiento para esta factura
    SELECT id INTO v_existing_entry_id
    FROM accounting.journal_entries
    WHERE reference_id = NEW.id
      AND reference_type = 'invoice'
      AND entry_type = 'INVOICE_SALE';
    
    -- Si no existe, crear el asiento
    IF v_existing_entry_id IS NULL THEN
      PERFORM accounting.create_invoice_sale_entry(
        p_invoice_id := NEW.id,
        p_entry_date := COALESCE(NEW.issue_date, CURRENT_DATE)
      );
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$;
