--
-- Name: auto_create_purchase_payment_entry(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."auto_create_purchase_payment_entry"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_entry_id UUID;
  v_entry_number TEXT;
  v_invoice RECORD;
  v_supplier_account_code TEXT;
  v_counterpart_code TEXT;
  v_description TEXT;
  v_fiscal_year INTEGER;
  v_third_party_id UUID;
  v_third_party_type accounting.third_party_type;
  v_internal_user_id UUID;
  v_abs_amount NUMERIC;
  v_is_refund BOOLEAN;
  v_partner RECORD;
BEGIN
  IF NEW.is_confirmed IS NOT NULL AND NEW.is_confirmed = false THEN
    RETURN NEW;
  END IF;

  v_is_refund := NEW.amount < 0;
  v_abs_amount := ABS(NEW.amount);

  SELECT 
    pi.id, pi.internal_purchase_number, pi.supplier_id, pi.technician_id, pi.project_id,
    COALESCE(s.company_name, t.company_name, 'Proveedor') as provider_name
  INTO v_invoice
  FROM sales.purchase_invoices pi
  LEFT JOIN internal.suppliers s ON pi.supplier_id = s.id
  LEFT JOIN internal.technicians t ON pi.technician_id = t.id
  WHERE pi.id = NEW.purchase_invoice_id;

  IF v_invoice IS NULL THEN
    RAISE EXCEPTION 'Invoice not found for payment';
  END IF;

  IF v_invoice.supplier_id IS NOT NULL THEN
    v_third_party_id := v_invoice.supplier_id;
    v_third_party_type := 'SUPPLIER';
    v_supplier_account_code := '400000';
  ELSIF v_invoice.technician_id IS NOT NULL THEN
    v_third_party_id := v_invoice.technician_id;
    v_third_party_type := 'TECHNICIAN';
    v_supplier_account_code := '410000';
  ELSE
    v_supplier_account_code := '410000';
  END IF;

  v_fiscal_year := EXTRACT(YEAR FROM NEW.payment_date);
  v_entry_number := accounting.get_next_entry_number(v_fiscal_year);
  v_internal_user_id := internal.get_authorized_user_id(auth.uid());

  IF NEW.payer_type = 'PERSONAL' THEN
    IF NEW.payer_person_id IS NULL THEN
      RAISE EXCEPTION 'payer_person_id is required for PERSONAL payments';
    END IF;

    SELECT id, full_name, account_code INTO v_partner
    FROM internal.partners WHERE id = NEW.payer_person_id;

    IF NOT FOUND THEN
      RAISE EXCEPTION 'Partner not found: %', NEW.payer_person_id;
    END IF;

    v_counterpart_code := COALESCE(
      REPLACE(v_partner.account_code, '465', '551'),
      '551000'
    );

    INSERT INTO accounting.chart_of_accounts (account_code, account_name, account_type, description)
    VALUES (v_counterpart_code, 'Cta. corriente ' || v_partner.full_name, 'LIABILITY', 'Deuda con socio por gastos personales')
    ON CONFLICT (account_code) DO NOTHING;

    v_description := 'Pago personal ' || v_partner.full_name || ' - ' || COALESCE(v_invoice.internal_purchase_number, 'N/A');

  ELSE
    -- Resolver banco usando la funci├│n robusta
    v_counterpart_code := accounting.resolve_bank_accounting_code(NEW.company_bank_account_id);

    IF v_is_refund THEN
      v_description := 'Reembolso ' || COALESCE(v_invoice.internal_purchase_number, 'N/A') || ' - ' || v_invoice.provider_name;
    ELSE
      v_description := 'Pago ' || COALESCE(v_invoice.internal_purchase_number, 'N/A') || ' - ' || v_invoice.provider_name;
    END IF;
  END IF;

  INSERT INTO accounting.journal_entries (
    entry_number, entry_date, entry_type, description,
    reference_id, reference_type, project_id, is_automatic, created_by
  ) VALUES (
    v_entry_number, NEW.payment_date, 'PAYMENT'::accounting.journal_entry_type,
    v_description, NEW.id, 'PURCHASE_PAYMENT', v_invoice.project_id, true, v_internal_user_id
  ) RETURNING id INTO v_entry_id;

  IF v_is_refund THEN
    INSERT INTO accounting.journal_entry_lines (
      journal_entry_id, account_code, debit_credit, amount, third_party_id, third_party_type, description, line_order
    ) VALUES 
      (v_entry_id, v_counterpart_code, 'DEBIT', v_abs_amount, NULL, NULL, v_description, 1),
      (v_entry_id, v_supplier_account_code, 'CREDIT', v_abs_amount, v_third_party_id, v_third_party_type, v_description, 2);
  ELSE
    INSERT INTO accounting.journal_entry_lines (
      journal_entry_id, account_code, debit_credit, amount, third_party_id, third_party_type, description, line_order
    ) VALUES 
      (v_entry_id, v_supplier_account_code, 'DEBIT', v_abs_amount, v_third_party_id, v_third_party_type, v_description, 1),
      (v_entry_id, v_counterpart_code, 'CREDIT', v_abs_amount, 
       CASE WHEN NEW.payer_type = 'PERSONAL' THEN NEW.payer_person_id ELSE NULL END,
       CASE WHEN NEW.payer_type = 'PERSONAL' THEN 'PARTNER'::accounting.third_party_type ELSE NULL END,
       v_description, 2);
  END IF;

  RETURN NEW;
END;
$$;
ALTER FUNCTION "accounting"."auto_create_purchase_payment_entry"() OWNER TO "postgres";
--
-- Name: auto_recalculate_corporate_tax(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."auto_recalculate_corporate_tax"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting'
    AS $$
DECLARE
  v_entry_date DATE;
  v_entry_type accounting.journal_entry_type;
  v_year_start DATE;
  v_year_end DATE;
BEGIN
  SELECT je.entry_date, je.entry_type INTO v_entry_date, v_entry_type
  FROM accounting.journal_entries je
  WHERE je.id = COALESCE(NEW.journal_entry_id, OLD.journal_entry_id);

  IF v_entry_date IS NULL THEN
    RETURN COALESCE(NEW, OLD);
  END IF;

  IF v_entry_type IN ('TAX_PROVISION', 'TAX_SETTLEMENT') THEN
    RETURN COALESCE(NEW, OLD);
  END IF;

  v_year_start := DATE_TRUNC('year', v_entry_date)::DATE;
  v_year_end := (DATE_TRUNC('year', v_entry_date) + INTERVAL '1 year' - INTERVAL '1 day')::DATE;

  PERFORM accounting.calculate_corporate_tax(
    p_period_start := v_year_start,
    p_period_end := v_year_end,
    p_force_recalculate := true
  );

  RETURN COALESCE(NEW, OLD);
END;
$$;
ALTER FUNCTION "accounting"."auto_recalculate_corporate_tax"() OWNER TO "postgres";
--
-- Name: FUNCTION "auto_recalculate_corporate_tax"(); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."auto_recalculate_corporate_tax"() IS 'Recalcula IS al cambiar ingresos/gastos. Excluye TAX_PROVISION y TAX_SETTLEMENT para evitar recursi├│n.';
--
-- Name: backfill_all_historical_data(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."backfill_all_historical_data"() RETURNS TABLE("process_name" "text", "records_processed" integer, "errors_count" integer, "status" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting'
    AS $$
DECLARE
  v_sales_count INTEGER := 0;
  v_purchase_count INTEGER := 0;
  v_purchase_payment_count INTEGER := 0;
  v_client_payment_count INTEGER := 0;
  v_sales_errors INTEGER := 0;
  v_purchase_errors INTEGER := 0;
  v_purchase_payment_errors INTEGER := 0;
  v_client_payment_errors INTEGER := 0;
  v_result RECORD;
BEGIN
  -- Backfill facturas de venta
  BEGIN
    SELECT COUNT(*) INTO v_sales_count
    FROM accounting.backfill_sales_invoices()
    WHERE status = 'SUCCESS';
    
    SELECT COUNT(*) INTO v_sales_errors
    FROM accounting.backfill_sales_invoices()
    WHERE status LIKE 'ERROR%';
    
    RETURN QUERY SELECT 
      'Facturas de Venta'::TEXT,
      v_sales_count,
      v_sales_errors,
      'SUCCESS'::TEXT;
  EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT 
      'Facturas de Venta'::TEXT,
      0,
      0,
      ('ERROR: ' || SQLERRM)::TEXT;
  END;
  
  -- Backfill facturas de compra
  BEGIN
    SELECT COUNT(*) INTO v_purchase_count
    FROM accounting.backfill_purchase_invoices()
    WHERE status = 'SUCCESS';
    
    SELECT COUNT(*) INTO v_purchase_errors
    FROM accounting.backfill_purchase_invoices()
    WHERE status LIKE 'ERROR%';
    
    RETURN QUERY SELECT 
      'Facturas de Compra'::TEXT,
      v_purchase_count,
      v_purchase_errors,
      'SUCCESS'::TEXT;
  EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT 
      'Facturas de Compra'::TEXT,
      0,
      0,
      ('ERROR: ' || SQLERRM)::TEXT;
  END;
  
  -- Backfill pagos de compra
  BEGIN
    SELECT COUNT(*) INTO v_purchase_payment_count
    FROM accounting.backfill_purchase_payments()
    WHERE status = 'SUCCESS';
    
    SELECT COUNT(*) INTO v_purchase_payment_errors
    FROM accounting.backfill_purchase_payments()
    WHERE status LIKE 'ERROR%';
    
    RETURN QUERY SELECT 
      'Pagos de Compra'::TEXT,
      v_purchase_payment_count,
      v_purchase_payment_errors,
      'SUCCESS'::TEXT;
  EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT 
      'Pagos de Compra'::TEXT,
      0,
      0,
      ('ERROR: ' || SQLERRM)::TEXT;
  END;
  
  -- Backfill pagos de clientes
  BEGIN
    SELECT COUNT(*) INTO v_client_payment_count
    FROM accounting.backfill_client_payments()
    WHERE status = 'SUCCESS';
    
    SELECT COUNT(*) INTO v_client_payment_errors
    FROM accounting.backfill_client_payments()
    WHERE status LIKE 'ERROR%';
    
    RETURN QUERY SELECT 
      'Pagos de Clientes'::TEXT,
      v_client_payment_count,
      v_client_payment_errors,
      'SUCCESS'::TEXT;
  EXCEPTION WHEN OTHERS THEN
    RETURN QUERY SELECT 
      'Pagos de Clientes'::TEXT,
      0,
      0,
      ('ERROR: ' || SQLERRM)::TEXT;
  END;
END;
$$;
ALTER FUNCTION "accounting"."backfill_all_historical_data"() OWNER TO "postgres";
--
-- Name: FUNCTION "backfill_all_historical_data"(); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."backfill_all_historical_data"() IS 'Ejecuta todo el proceso de contabilizaci├│n hist├│rica y devuelve un resumen';
--
-- Name: backfill_client_payments(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."backfill_client_payments"() RETURNS TABLE("payment_id" "uuid", "entry_id" "uuid", "entry_number" "text", "status" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_payment RECORD;
  v_entry_id UUID;
  v_count INTEGER := 0;
BEGIN
  -- Procesar todos los pagos de clientes que no tienen asiento contable
  -- SOLO desde el 01-01-2026 en adelante
  FOR v_payment IN
    SELECT 
      ip.id,
      ip.payment_date,
      ip.amount,
      i.invoice_number,
      i.client_id
    FROM sales.invoice_payments ip
    JOIN sales.invoices i ON ip.invoice_id = i.id
    WHERE ip.payment_date >= '2026-01-01'  -- SOLO DESDE 2026
      AND NOT EXISTS (
        SELECT 1 FROM accounting.journal_entries je
        WHERE je.reference_id = ip.id
          AND je.reference_type = 'payment_received'
      )
    ORDER BY ip.payment_date, ip.created_at
  LOOP
    BEGIN
      -- Deshabilitar temporalmente el trigger de rec├ílculo de IS para evitar loops
      ALTER TABLE accounting.journal_entry_lines DISABLE TRIGGER trigger_auto_recalculate_corporate_tax;
      
      -- Generar asiento contable
      v_entry_id := accounting.create_invoice_payment_entry(
        v_payment.id,
        v_payment.payment_date
      );
      
      -- Rehabilitar el trigger
      ALTER TABLE accounting.journal_entry_lines ENABLE TRIGGER trigger_auto_recalculate_corporate_tax;
      
      v_count := v_count + 1;
      
      RETURN QUERY SELECT 
        v_payment.id,
        v_entry_id,
        (SELECT je.entry_number FROM accounting.journal_entries je WHERE je.id = v_entry_id),
        'SUCCESS'::TEXT;
        
    EXCEPTION WHEN OTHERS THEN
      -- Asegurar que el trigger se rehabilite incluso si hay error
      ALTER TABLE accounting.journal_entry_lines ENABLE TRIGGER trigger_auto_recalculate_corporate_tax;
      
      RETURN QUERY SELECT 
        v_payment.id,
        NULL::UUID,
        NULL::TEXT,
        ('ERROR: ' || SQLERRM)::TEXT;
    END;
  END LOOP;
  
  RAISE NOTICE 'Procesados % pagos de clientes desde 2026', v_count;
END;
$$;
ALTER FUNCTION "accounting"."backfill_client_payments"() OWNER TO "postgres";
--
-- Name: FUNCTION "backfill_client_payments"(); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."backfill_client_payments"() IS 'Genera asientos contables para pagos de clientes hist├│ricos desde 2026-01-01 que a├║n no est├ín contabilizados.';
--
-- Name: backfill_purchase_invoices(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."backfill_purchase_invoices"() RETURNS TABLE("invoice_id" "uuid", "entry_id" "uuid", "entry_number" "text", "status" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_invoice RECORD;
  v_entry_id UUID;
  v_count INTEGER := 0;
BEGIN
  -- Procesar todas las facturas de compra que no tienen asiento contable
  -- SOLO desde el 01-01-2026 en adelante
  FOR v_invoice IN
    SELECT 
      pi.id,
      pi.invoice_number,
      pi.issue_date,
      pi.status,
      pi.total,
      pi.supplier_id,
      pi.technician_id,
      pi.document_type,
      pi.created_by
    FROM sales.purchase_invoices pi
    WHERE pi.status IN ('ISSUED', 'REGISTERED', 'PAID')
      AND pi.issue_date >= '2026-01-01'  -- SOLO DESDE 2026
      AND NOT EXISTS (
        SELECT 1 FROM accounting.journal_entries je
        WHERE je.reference_id = pi.id
          AND je.reference_type = 'purchase_invoice'
      )
    ORDER BY pi.issue_date, pi.created_at
  LOOP
    BEGIN
      -- Deshabilitar temporalmente el trigger de rec├ílculo de IS para evitar loops
      ALTER TABLE accounting.journal_entry_lines DISABLE TRIGGER trigger_auto_recalculate_corporate_tax;
      
      -- Generar asiento contable
      v_entry_id := accounting.create_invoice_purchase_entry(
        v_invoice.id,
        v_invoice.issue_date
      );
      
      -- Rehabilitar el trigger
      ALTER TABLE accounting.journal_entry_lines ENABLE TRIGGER trigger_auto_recalculate_corporate_tax;
      
      v_count := v_count + 1;
      
      RETURN QUERY SELECT 
        v_invoice.id,
        v_entry_id,
        (SELECT je.entry_number FROM accounting.journal_entries je WHERE je.id = v_entry_id),
        'SUCCESS'::TEXT;
        
    EXCEPTION WHEN OTHERS THEN
      -- Asegurar que el trigger se rehabilite incluso si hay error
      ALTER TABLE accounting.journal_entry_lines ENABLE TRIGGER trigger_auto_recalculate_corporate_tax;
      
      RETURN QUERY SELECT 
        v_invoice.id,
        NULL::UUID,
        NULL::TEXT,
        ('ERROR: ' || SQLERRM)::TEXT;
    END;
  END LOOP;
  
  RAISE NOTICE 'Procesadas % facturas de compra desde 2026', v_count;
END;
$$;
ALTER FUNCTION "accounting"."backfill_purchase_invoices"() OWNER TO "postgres";
--
-- Name: FUNCTION "backfill_purchase_invoices"(); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."backfill_purchase_invoices"() IS 'Genera asientos contables para facturas de compra hist├│ricas desde 2026-01-01 que a├║n no est├ín contabilizadas';
--
-- Name: backfill_purchase_payments(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."backfill_purchase_payments"() RETURNS TABLE("payment_id" "uuid", "entry_id" "uuid", "entry_number" "text", "status" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_payment RECORD;
  v_entry_id UUID;
  v_entry_number TEXT;
  v_account_pending TEXT;
  v_account_bank TEXT := '572000';
  v_count INTEGER := 0;
BEGIN
  FOR v_payment IN
    SELECT 
      pip.id,
      pip.purchase_invoice_id,
      pip.payment_date,
      pip.amount,
      pip.payment_method,
      pip.bank_reference,
      pi.invoice_number,
      pi.supplier_id,
      pi.technician_id,
      pi.document_type,
      pi.manual_beneficiary_name,
      pip.created_by
    FROM sales.purchase_invoice_payments pip
    JOIN sales.purchase_invoices pi ON pip.purchase_invoice_id = pi.id
    WHERE NOT EXISTS (
        SELECT 1 FROM accounting.journal_entries je
        WHERE je.reference_id = pip.id
          AND je.reference_type = 'purchase_payment'
      )
    ORDER BY pip.payment_date, pip.created_at
  LOOP
    BEGIN
      IF v_payment.supplier_id IS NOT NULL THEN
        v_account_pending := '400000';
      ELSIF v_payment.technician_id IS NOT NULL THEN
        v_account_pending := '410000';
      ELSIF v_payment.document_type = 'EXPENSE' AND (v_payment.manual_beneficiary_name IS NOT NULL AND trim(v_payment.manual_beneficiary_name) != '') THEN
        v_account_pending := '410000';
      ELSE
        CONTINUE;
      END IF;

      v_entry_number := accounting.get_next_entry_number();

      INSERT INTO accounting.journal_entries (
        entry_number,
        entry_date,
        entry_type,
        description,
        reference_id,
        reference_type,
        created_by
      ) VALUES (
        v_entry_number,
        v_payment.payment_date,
        'PAYMENT_MADE',
        'Pago factura compra: ' || v_payment.invoice_number,
        v_payment.id,
        'purchase_payment',
        v_payment.created_by
      ) RETURNING id INTO v_entry_id;

      INSERT INTO accounting.journal_entry_lines (
        journal_entry_id,
        account_code,
        debit_credit,
        amount,
        description,
        line_order
      ) VALUES (
        v_entry_id,
        v_account_pending,
        'DEBIT',
        v_payment.amount,
        'Pago ' || v_payment.invoice_number,
        1
      );

      INSERT INTO accounting.journal_entry_lines (
        journal_entry_id,
        account_code,
        debit_credit,
        amount,
        description,
        line_order
      ) VALUES (
        v_entry_id,
        v_account_bank,
        'CREDIT',
        v_payment.amount,
        'Pago factura ' || v_payment.invoice_number,
        2
      );

      v_count := v_count + 1;

      RETURN QUERY SELECT 
        v_payment.id,
        v_entry_id,
        v_entry_number,
        'SUCCESS'::TEXT;

    EXCEPTION WHEN OTHERS THEN
      RETURN QUERY SELECT 
        v_payment.id,
        NULL::UUID,
        NULL::TEXT,
        ('ERROR: ' || SQLERRM)::TEXT;
    END;
  END LOOP;

  RAISE NOTICE 'Procesados % pagos de compra', v_count;
END;
$$;
ALTER FUNCTION "accounting"."backfill_purchase_payments"() OWNER TO "postgres";
--
-- Name: FUNCTION "backfill_purchase_payments"(); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."backfill_purchase_payments"() IS 'Genera asientos contables para pagos de compra hist├│ricos desde 2026-01-01 que a├║n no est├ín contabilizados';
--
-- Name: backfill_sales_invoices(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."backfill_sales_invoices"() RETURNS TABLE("invoice_id" "uuid", "entry_id" "uuid", "entry_number" "text", "status" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_invoice RECORD;
  v_entry_id UUID;
  v_count INTEGER := 0;
BEGIN
  -- Procesar todas las facturas emitidas que no tienen asiento contable
  -- SOLO desde el 01-01-2026 en adelante
  FOR v_invoice IN
    SELECT 
      i.id,
      i.invoice_number,
      i.issue_date,
      i.status,
      i.total,
      i.tax_amount,
      i.subtotal,
      i.client_id,
      c.client_number,
      c.company_name,
      i.project_id,
      i.created_by
    FROM sales.invoices i
    JOIN crm.clients c ON i.client_id = c.id
    WHERE i.status IN ('ISSUED', 'PAID', 'SENT')
      AND i.issue_date >= '2026-01-01'  -- SOLO DESDE 2026
      AND NOT EXISTS (
        SELECT 1 FROM accounting.journal_entries je
        WHERE je.reference_id = i.id
          AND je.reference_type = 'invoice'
      )
    ORDER BY i.issue_date, i.created_at
  LOOP
    BEGIN
      -- Deshabilitar temporalmente el trigger de rec├ílculo de IS para evitar loops
      ALTER TABLE accounting.journal_entry_lines DISABLE TRIGGER trigger_auto_recalculate_corporate_tax;
      
      -- Generar asiento contable
      v_entry_id := accounting.create_invoice_sale_entry(
        v_invoice.id,
        v_invoice.issue_date
      );
      
      -- Rehabilitar el trigger
      ALTER TABLE accounting.journal_entry_lines ENABLE TRIGGER trigger_auto_recalculate_corporate_tax;
      
      v_count := v_count + 1;
      
      RETURN QUERY SELECT 
        v_invoice.id,
        v_entry_id,
        (SELECT je.entry_number FROM accounting.journal_entries je WHERE je.id = v_entry_id),
        'SUCCESS'::TEXT;
        
    EXCEPTION WHEN OTHERS THEN
      -- Asegurar que el trigger se rehabilite incluso si hay error
      ALTER TABLE accounting.journal_entry_lines ENABLE TRIGGER trigger_auto_recalculate_corporate_tax;
      
      RETURN QUERY SELECT 
        v_invoice.id,
        NULL::UUID,
        NULL::TEXT,
        ('ERROR: ' || SQLERRM)::TEXT;
    END;
  END LOOP;
  
  RAISE NOTICE 'Procesadas % facturas de venta desde 2026', v_count;
END;
$$;
ALTER FUNCTION "accounting"."backfill_sales_invoices"() OWNER TO "postgres";
