-- Name: FUNCTION "backfill_sales_invoices"(); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."backfill_sales_invoices"() IS 'Genera asientos contables para facturas de venta hist├│ricas desde 2026-01-01 que a├║n no est├ín contabilizadas';
--
-- Name: calculate_corporate_tax("date", "date", numeric, boolean); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."calculate_corporate_tax"("p_period_start" "date" DEFAULT NULL::"date", "p_period_end" "date" DEFAULT NULL::"date", "p_tax_rate" numeric DEFAULT 25.00, "p_force_recalculate" boolean DEFAULT false) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting'
    AS $$
DECLARE
  v_entry_id UUID;
  v_entry_number TEXT;
  v_profit_before_tax NUMERIC(12,2);
  v_tax_amount NUMERIC(12,2);
  v_existing_entry_id UUID;
  v_user_id UUID;
  v_period_description TEXT;
  v_fiscal_year INT;
BEGIN
  SELECT auth.uid() INTO v_user_id;
  SELECT profit_before_tax INTO v_profit_before_tax
  FROM accounting.calculate_profit_before_tax(p_period_start, p_period_end);
  
  IF v_profit_before_tax > 0 THEN
    v_tax_amount := ROUND(v_profit_before_tax * (p_tax_rate / 100), 2);
  ELSE
    v_tax_amount := 0;
  END IF;
  
  IF p_period_start IS NOT NULL AND p_period_end IS NOT NULL THEN
    v_period_description := 'Per├¡odo: ' || p_period_start::TEXT || ' a ' || p_period_end::TEXT;
    v_fiscal_year := EXTRACT(YEAR FROM p_period_start);
  ELSE
    v_period_description := 'Acumulado hasta ' || CURRENT_DATE::TEXT;
    v_fiscal_year := EXTRACT(YEAR FROM CURRENT_DATE);
  END IF;

  -- B├║squeda robusta: por a├▒o fiscal y tipo
  SELECT je.id INTO v_existing_entry_id
  FROM accounting.journal_entries je
  WHERE je.entry_type = 'TAX_PROVISION'
    AND je.reference_type = 'corporate_tax'
    AND je.is_locked = false
    AND EXTRACT(YEAR FROM je.entry_date) = v_fiscal_year
  ORDER BY je.created_at DESC
  LIMIT 1;

  IF v_existing_entry_id IS NOT NULL THEN
    DELETE FROM accounting.journal_entry_lines WHERE journal_entry_id = v_existing_entry_id;
    UPDATE accounting.journal_entries
    SET description = 'Provisi├│n IS ' || p_tax_rate || '% - ' || v_period_description || ' - BAI: ' || v_profit_before_tax || 'Ôé¼ - IS: ' || v_tax_amount || 'Ôé¼',
        period_start = p_period_start,
        period_end = p_period_end,
        updated_at = now()
    WHERE id = v_existing_entry_id;
    v_entry_id := v_existing_entry_id;
  ELSE
    v_entry_number := accounting.get_next_entry_number();
    INSERT INTO accounting.journal_entries (
      entry_number, entry_date, entry_type, description, reference_type, period_start, period_end, created_by
    ) VALUES (
      v_entry_number, COALESCE(p_period_end, CURRENT_DATE), 'TAX_PROVISION',
      'Provisi├│n IS ' || p_tax_rate || '% - ' || v_period_description || ' - BAI: ' || v_profit_before_tax || 'Ôé¼ - IS: ' || v_tax_amount || 'Ôé¼',
      'corporate_tax', p_period_start, p_period_end, v_user_id
    ) RETURNING id INTO v_entry_id;
  END IF;
  
  IF v_tax_amount > 0 THEN
    INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, debit_credit, amount, description, line_order)
    VALUES (v_entry_id, '630000', 'DEBIT', v_tax_amount, 'Provisi├│n IS ' || p_tax_rate || '% sobre BAI: ' || v_profit_before_tax || 'Ôé¼', 1);
    INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, debit_credit, amount, description, line_order)
    VALUES (v_entry_id, '475200', 'CREDIT', v_tax_amount, 'Provisi├│n IS a pagar', 2);
  END IF;
  
  RETURN v_entry_id;
END;
$$;
ALTER FUNCTION "accounting"."calculate_corporate_tax"("p_period_start" "date", "p_period_end" "date", "p_tax_rate" numeric, "p_force_recalculate" boolean) OWNER TO "postgres";
--
-- Name: FUNCTION "calculate_corporate_tax"("p_period_start" "date", "p_period_end" "date", "p_tax_rate" numeric, "p_force_recalculate" boolean); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."calculate_corporate_tax"("p_period_start" "date", "p_period_end" "date", "p_tax_rate" numeric, "p_force_recalculate" boolean) IS 'Provisi├│n IS. Idempotente por period_start/period_end (o descripci├│n legacy).';
--
-- Name: calculate_profit_before_tax("date", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."calculate_profit_before_tax"("p_period_start" "date" DEFAULT NULL::"date", "p_period_end" "date" DEFAULT NULL::"date") RETURNS TABLE("total_revenue" numeric, "total_expenses" numeric, "profit_before_tax" numeric)
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'accounting'
    AS $$
DECLARE
  v_period_filter TEXT;
  v_revenue NUMERIC(12,2) := 0;
  v_expenses NUMERIC(12,2) := 0;
BEGIN
  -- Construir filtro de per├¡odo
  IF p_period_start IS NOT NULL AND p_period_end IS NOT NULL THEN
    v_period_filter := ' AND je.entry_date BETWEEN ''' || p_period_start || ''' AND ''' || p_period_end || '''';
  ELSE
    v_period_filter := '';
  END IF;
  
  -- Calcular ingresos (cuentas 7xxxx - REVENUE)
  EXECUTE format('
    SELECT COALESCE(SUM(
      CASE WHEN jel.debit_credit = ''CREDIT'' THEN jel.amount ELSE -jel.amount END
    ), 0)
    FROM accounting.journal_entry_lines jel
    JOIN accounting.journal_entries je ON jel.journal_entry_id = je.id
    JOIN accounting.chart_of_accounts coa ON jel.account_code = coa.account_code
    WHERE coa.account_type = ''REVENUE''
      %s
  ', v_period_filter) INTO v_revenue;
  
  -- Calcular gastos (cuentas 6xxxx - EXPENSE, excluyendo 630000 IS)
  EXECUTE format('
    SELECT COALESCE(SUM(
      CASE WHEN jel.debit_credit = ''DEBIT'' THEN jel.amount ELSE -jel.amount END
    ), 0)
    FROM accounting.journal_entry_lines jel
    JOIN accounting.journal_entries je ON jel.journal_entry_id = je.id
    JOIN accounting.chart_of_accounts coa ON jel.account_code = coa.account_code
    WHERE coa.account_type = ''EXPENSE''
      AND coa.account_code != ''630000''
      %s
  ', v_period_filter) INTO v_expenses;
  
  RETURN QUERY SELECT 
    v_revenue,
    v_expenses,
    v_revenue - v_expenses;
END;
$$;
ALTER FUNCTION "accounting"."calculate_profit_before_tax"("p_period_start" "date", "p_period_end" "date") OWNER TO "postgres";
--
-- Name: FUNCTION "calculate_profit_before_tax"("p_period_start" "date", "p_period_end" "date"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."calculate_profit_before_tax"("p_period_start" "date", "p_period_end" "date") IS 'Calcula el resultado antes de impuestos (BAI) basado en ingresos y gastos contabilizados';
--
-- Name: check_journal_entry_period_not_closed(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."check_journal_entry_period_not_closed"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting'
    AS $$
BEGIN
  IF NEW.entry_date IS NOT NULL AND accounting.is_period_closed(EXTRACT(YEAR FROM NEW.entry_date)::INTEGER, EXTRACT(MONTH FROM NEW.entry_date)::INTEGER) THEN
    RAISE EXCEPTION 'Periodo cerrado: no se pueden crear ni modificar asientos con fecha % (a├▒o % mes %)', NEW.entry_date, EXTRACT(YEAR FROM NEW.entry_date), EXTRACT(MONTH FROM NEW.entry_date);
  END IF;
  RETURN NEW;
END;
$$;
