--
-- Name: check_month_closure_readiness(integer, integer); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."check_month_closure_readiness"("p_year" integer, "p_month" integer) RETURNS TABLE("check_name" "text", "passed" boolean, "message" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_start DATE;
  v_end DATE;
  v_sales_pending int;
  v_purchases_pending int;
  v_payroll_pending int;
BEGIN
  v_start := make_date(p_year, p_month, 1);
  v_end := (v_start + interval '1 month' - interval '1 day')::date;

  -- Ventas: no facturas en DRAFT/CANCELLED con issue_date en per├¡odo
  SELECT COUNT(*)::int INTO v_sales_pending
  FROM sales.invoices i
  WHERE i.issue_date >= v_start AND i.issue_date <= v_end
    AND i.status IN ('DRAFT', 'CANCELLED');
  RETURN QUERY SELECT 'ventas'::text, (v_sales_pending = 0), 
    format('Facturas venta pendientes: %s', v_sales_pending);

  -- Compras: no facturas en estados no contabilizados
  SELECT COUNT(*)::int INTO v_purchases_pending
  FROM sales.purchase_invoices pi
  WHERE pi.issue_date >= v_start AND pi.issue_date <= v_end
    AND pi.status IN ('DRAFT', 'PENDING_VALIDATION');
  RETURN QUERY SELECT 'compras'::text, (v_purchases_pending = 0),
    format('Facturas compra pendientes: %s', v_purchases_pending);

  -- N├│minas: no DRAFT
  SELECT COUNT(*)::int INTO v_payroll_pending
  FROM accounting.partner_compensation_runs pcr
  WHERE pcr.period_year = p_year AND pcr.period_month = p_month AND pcr.status = 'DRAFT';
  v_payroll_pending := v_payroll_pending + (SELECT COUNT(*)::int FROM accounting.payroll_runs pr 
    WHERE pr.period_year = p_year AND pr.period_month = p_month AND pr.status = 'DRAFT');
  RETURN QUERY SELECT 'nominas'::text, (v_payroll_pending = 0),
    format('N├│minas en DRAFT: %s', v_payroll_pending);
END;
$$;
ALTER FUNCTION "accounting"."check_month_closure_readiness"("p_year" integer, "p_month" integer) OWNER TO "postgres";
--
-- Name: close_period(integer, integer, "uuid"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."close_period"("p_year" integer, "p_month" integer, "p_closed_by" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_start DATE;
  v_end DATE;
  v_closure_id UUID;
  r RECORD;
BEGIN
  v_start := make_date(p_year, p_month, 1);
  v_end := (v_start + interval '1 month' - interval '1 day')::date;

  FOR r IN SELECT check_name, passed FROM accounting.check_month_closure_readiness(p_year, p_month)
  LOOP
    IF NOT r.passed THEN
      RAISE EXCEPTION 'Cierre no permitido: %', r.check_name;
    END IF;
  END LOOP;

  INSERT INTO accounting.period_closures (year, month, period_start, period_end, closed_by, is_locked)
  VALUES (p_year, p_month, v_start, v_end, p_closed_by, true)
  ON CONFLICT (year, month) DO UPDATE SET closed_at = now(), closed_by = p_closed_by, is_locked = true
  RETURNING id INTO v_closure_id;

  INSERT INTO accounting.monthly_reports (year, month, period_closure_id, status, locked_at)
  VALUES (p_year, p_month, v_closure_id, 'READY', now())
  ON CONFLICT (year, month) DO UPDATE SET
    period_closure_id = v_closure_id,
    status = 'READY',
    locked_at = now(),
    error_message = NULL,
    retry_count = 0,
    updated_at = now();

  RETURN v_closure_id;
END;
$$;
ALTER FUNCTION "accounting"."close_period"("p_year" integer, "p_month" integer, "p_closed_by" "uuid") OWNER TO "postgres";
--
-- Name: create_bank_balance_adjustment("text", "text", numeric, "date", "text"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_bank_balance_adjustment"("p_bank_account_id" "text", "p_bank_name" "text", "p_new_balance" numeric, "p_adjustment_date" "date" DEFAULT CURRENT_DATE, "p_notes" "text" DEFAULT NULL::"text") RETURNS TABLE("entry_id" "uuid", "entry_number" "text", "adjustment_amount" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_current_balance NUMERIC := 0;
  v_adjustment_amount NUMERIC;
  v_entry_id UUID;
  v_entry_number TEXT;
  v_authorized_user_id UUID;
  v_bank_account_code TEXT := '572000'; -- Cuenta gen├®rica de bancos
  v_adjustment_account_code TEXT := '129000'; -- Cuenta de resultados de ejercicios anteriores / ajustes
  v_line_order INT := 1;
BEGIN
  -- Obtener el ID del usuario autorizado
  v_authorized_user_id := internal.get_authorized_user_id(auth.uid());
  
  IF v_authorized_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;
  
  -- Calcular el saldo actual de la cuenta bancaria (todas las cuentas 572xxx)
  SELECT COALESCE(SUM(
    CASE WHEN jel.debit_credit = 'DEBIT' THEN jel.amount ELSE -jel.amount END
  ), 0)
  INTO v_current_balance
  FROM accounting.journal_entry_lines jel
  JOIN accounting.journal_entries je ON je.id = jel.journal_entry_id
  WHERE jel.account_code LIKE '572%'
    AND je.entry_date <= p_adjustment_date;
  
  -- Calcular el ajuste necesario
  v_adjustment_amount := p_new_balance - v_current_balance;
  
  -- Si no hay diferencia, no crear asiento
  IF v_adjustment_amount = 0 THEN
    RAISE EXCEPTION 'El saldo actual ya coincide con el saldo indicado (%.2f Ôé¼)', v_current_balance;
  END IF;
  
  -- Obtener el siguiente n├║mero de asiento
  v_entry_number := accounting.get_next_entry_number();
  
  -- Crear el asiento contable
  INSERT INTO accounting.journal_entries (
    entry_number,
    entry_date,
    entry_type,
    description,
    reference_type,
    is_automatic,
    is_locked,
    created_by
  ) VALUES (
    v_entry_number,
    p_adjustment_date,
    'ADJUSTMENT',
    COALESCE(p_notes, 'Ajuste de saldo bancario - ' || p_bank_name),
    'BANK_ADJUSTMENT',
    FALSE, -- No es autom├ítico, es manual
    FALSE,
    v_authorized_user_id
  )
  RETURNING id INTO v_entry_id;
  
  -- Si el ajuste es positivo (aumentar saldo): Debe Banco, Haber Ajuste
  -- Si el ajuste es negativo (reducir saldo): Debe Ajuste, Haber Banco
  
  IF v_adjustment_amount > 0 THEN
    -- Debe: Banco (aumentar activo)
    INSERT INTO accounting.journal_entry_lines (
      journal_entry_id,
      line_order,
      account_code,
      description,
      amount,
      debit_credit
    ) VALUES (
      v_entry_id,
      v_line_order,
      v_bank_account_code,
      'Ajuste saldo bancario - ' || p_bank_name,
      ABS(v_adjustment_amount),
      'DEBIT'
    );
    v_line_order := v_line_order + 1;
    
    -- Haber: Cuenta de ajuste
    INSERT INTO accounting.journal_entry_lines (
      journal_entry_id,
      line_order,
      account_code,
      description,
      amount,
      debit_credit
    ) VALUES (
      v_entry_id,
      v_line_order,
      v_adjustment_account_code,
      'Contrapartida ajuste saldo bancario',
      ABS(v_adjustment_amount),
      'CREDIT'
    );
  ELSE
    -- Debe: Cuenta de ajuste (reducir patrimonio)
    INSERT INTO accounting.journal_entry_lines (
      journal_entry_id,
      line_order,
      account_code,
      description,
      amount,
      debit_credit
    ) VALUES (
      v_entry_id,
      v_line_order,
      v_adjustment_account_code,
      'Contrapartida ajuste saldo bancario',
      ABS(v_adjustment_amount),
      'DEBIT'
    );
    v_line_order := v_line_order + 1;
    
    -- Haber: Banco (reducir activo)
    INSERT INTO accounting.journal_entry_lines (
      journal_entry_id,
      line_order,
      account_code,
      description,
      amount,
      debit_credit
    ) VALUES (
      v_entry_id,
      v_line_order,
      v_bank_account_code,
      'Ajuste saldo bancario - ' || p_bank_name,
      ABS(v_adjustment_amount),
      'CREDIT'
    );
  END IF;
  
  -- Devolver resultado
  RETURN QUERY SELECT v_entry_id, v_entry_number, v_adjustment_amount;
END;
$$;
ALTER FUNCTION "accounting"."create_bank_balance_adjustment"("p_bank_account_id" "text", "p_bank_name" "text", "p_new_balance" numeric, "p_adjustment_date" "date", "p_notes" "text") OWNER TO "postgres";
--
-- Name: FUNCTION "create_bank_balance_adjustment"("p_bank_account_id" "text", "p_bank_name" "text", "p_new_balance" numeric, "p_adjustment_date" "date", "p_notes" "text"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."create_bank_balance_adjustment"("p_bank_account_id" "text", "p_bank_name" "text", "p_new_balance" numeric, "p_adjustment_date" "date", "p_notes" "text") IS 'Crea un asiento de ajuste para establecer el saldo bancario actual. Genera un asiento balanceado con contrapartida en la cuenta 129000.';
--
-- Name: create_bank_balance_adjustment("uuid", "text", numeric, "date", "text"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_bank_balance_adjustment"("p_bank_account_id" "uuid", "p_bank_name" "text", "p_new_balance" numeric, "p_adjustment_date" "date" DEFAULT CURRENT_DATE, "p_notes" "text" DEFAULT NULL::"text") RETURNS TABLE("entry_id" "uuid", "entry_number" "text", "adjustment_amount" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_entry_id UUID;
  v_entry_number TEXT;
  v_bank_code TEXT;
  v_current_balance NUMERIC := 0;
  v_adjustment_amount NUMERIC;
  v_description TEXT;
  v_adjustment_account TEXT := '129000';
BEGIN
  -- Get the bank account code
  SELECT coa.account_code INTO v_bank_code
  FROM accounting.chart_of_accounts coa
  WHERE coa.description LIKE '%[ID:' || p_bank_account_id || ']%'
    AND coa.account_code LIKE '572%';
  
  IF v_bank_code IS NULL THEN
    RAISE EXCEPTION 'No se encontr├│ cuenta contable para este banco. Registre primero un asiento de apertura.';
  END IF;
  
  -- Calculate current balance from ledger (using correct column name: journal_entry_id)
  SELECT COALESCE(SUM(
    CASE WHEN jel.debit_credit = 'DEBIT' THEN jel.amount ELSE -jel.amount END
  ), 0) INTO v_current_balance
  FROM accounting.journal_entries je
  JOIN accounting.journal_entry_lines jel ON jel.journal_entry_id = je.id
  WHERE jel.account_code = v_bank_code
    AND je.entry_date <= p_adjustment_date;
  
  v_adjustment_amount := p_new_balance - v_current_balance;
  
  IF v_adjustment_amount = 0 THEN
    RETURN QUERY SELECT NULL::UUID, 'Sin ajuste necesario'::TEXT, 0::NUMERIC;
    RETURN;
  END IF;
  
  v_entry_number := accounting.get_next_entry_number();
  
  v_description := 'Ajuste saldo ' || p_bank_name || 
    ' (de ' || TO_CHAR(v_current_balance, 'FM999G999G990D00') || 
    ' a ' || TO_CHAR(p_new_balance, 'FM999G999G990D00') || ' Ôé¼)';
  
  IF p_notes IS NOT NULL AND p_notes != '' THEN
    v_description := v_description || ' - ' || p_notes;
  END IF;
  
  INSERT INTO accounting.journal_entries (
    entry_number, entry_date, entry_type, description, is_automatic, reference_type, created_by
  ) VALUES (
    v_entry_number, p_adjustment_date, 'ADJUSTMENT', v_description, false, 'BANK_ADJUSTMENT',
    internal.get_authorized_user_id(auth.uid())
  ) RETURNING id INTO v_entry_id;
  
  -- Use correct column name: journal_entry_id
  IF v_adjustment_amount > 0 THEN
    INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, debit_credit, amount, description, line_order)
    VALUES 
      (v_entry_id, v_bank_code, 'DEBIT', ABS(v_adjustment_amount), 'Ajuste positivo saldo bancario', 1),
      (v_entry_id, v_adjustment_account, 'CREDIT', ABS(v_adjustment_amount), 'Contrapartida ajuste bancario', 2);
  ELSE
    INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, debit_credit, amount, description, line_order)
    VALUES 
      (v_entry_id, v_bank_code, 'CREDIT', ABS(v_adjustment_amount), 'Ajuste negativo saldo bancario', 1),
      (v_entry_id, v_adjustment_account, 'DEBIT', ABS(v_adjustment_amount), 'Contrapartida ajuste bancario', 2);
  END IF;
  
  RETURN QUERY SELECT v_entry_id, v_entry_number, v_adjustment_amount;
END;
$$;
ALTER FUNCTION "accounting"."create_bank_balance_adjustment"("p_bank_account_id" "uuid", "p_bank_name" "text", "p_new_balance" numeric, "p_adjustment_date" "date", "p_notes" "text") OWNER TO "postgres";
--
-- Name: create_bank_opening_entry("jsonb", "date", "text"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_bank_opening_entry"("p_bank_balances" "jsonb", "p_entry_date" "date" DEFAULT CURRENT_DATE, "p_notes" "text" DEFAULT 'Asiento de apertura - Saldos iniciales de bancos'::"text") RETURNS TABLE("entry_id" "uuid", "entry_number" "text", "total_amount" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_entry_id UUID;
  v_entry_number TEXT;
  v_authorized_user_id UUID;
  v_total_amount NUMERIC := 0;
  v_line_order INT := 1;
  v_bank JSONB;
  v_bank_code TEXT;
  v_balance NUMERIC;
BEGIN
  -- Obtener usuario autorizado
  v_authorized_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_authorized_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;
  
  -- Calcular total
  SELECT COALESCE(SUM((b->>'balance')::NUMERIC), 0)
  INTO v_total_amount
  FROM jsonb_array_elements(p_bank_balances) b;
  
  IF v_total_amount = 0 THEN
    RAISE EXCEPTION 'No hay saldos para registrar';
  END IF;
  
  -- Crear asiento
  v_entry_number := accounting.get_next_entry_number();
  
  INSERT INTO accounting.journal_entries (
    entry_number,
    entry_date,
    entry_type,
    description,
    reference_type,
    is_automatic,
    is_locked,
    created_by
  ) VALUES (
    v_entry_number,
    p_entry_date,
    'OPENING',
    p_notes,
    'BANK_OPENING',
    FALSE,
    FALSE,
    v_authorized_user_id
  )
  RETURNING id INTO v_entry_id;
  
  -- Crear l├¡neas para cada banco (DEBE)
  FOR v_bank IN SELECT * FROM jsonb_array_elements(p_bank_balances)
  LOOP
    v_balance := (v_bank->>'balance')::NUMERIC;
    
    IF v_balance <> 0 THEN
      -- Registrar cuenta contable del banco si no existe
      v_bank_code := accounting.register_bank_account(
        v_bank->>'bank_account_id',
        v_bank->>'bank_name',
        v_bank->>'iban'
      );
      
      -- L├¡nea DEBE para el banco
      INSERT INTO accounting.journal_entry_lines (
        journal_entry_id,
        line_order,
        account_code,
        description,
        amount,
        debit_credit
      ) VALUES (
        v_entry_id,
        v_line_order,
        v_bank_code,
        'Saldo inicial - ' || (v_bank->>'bank_name'),
        ABS(v_balance),
        CASE WHEN v_balance > 0 THEN 'DEBIT' ELSE 'CREDIT' END
      );
      v_line_order := v_line_order + 1;
    END IF;
  END LOOP;
  
  -- L├¡nea HABER para contrapartida (Capital/Resultados anteriores)
  INSERT INTO accounting.journal_entry_lines (
    journal_entry_id,
    line_order,
    account_code,
    description,
    amount,
    debit_credit
  ) VALUES (
    v_entry_id,
    v_line_order,
    '129000',
    'Contrapartida apertura bancos',
    ABS(v_total_amount),
    CASE WHEN v_total_amount > 0 THEN 'CREDIT' ELSE 'DEBIT' END
  );
  
  RETURN QUERY SELECT v_entry_id, v_entry_number, v_total_amount;
END;
$$;
ALTER FUNCTION "accounting"."create_bank_opening_entry"("p_bank_balances" "jsonb", "p_entry_date" "date", "p_notes" "text") OWNER TO "postgres";
--
-- Name: FUNCTION "create_bank_opening_entry"("p_bank_balances" "jsonb", "p_entry_date" "date", "p_notes" "text"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."create_bank_opening_entry"("p_bank_balances" "jsonb", "p_entry_date" "date", "p_notes" "text") IS 'Crea asiento de apertura con saldos iniciales de m├║ltiples bancos';
--
-- Name: create_bank_transfer("text", "text", "text", "text", numeric, "date", "text"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_bank_transfer"("p_source_bank_id" "text", "p_source_bank_name" "text", "p_target_bank_id" "text", "p_target_bank_name" "text", "p_amount" numeric, "p_transfer_date" "date" DEFAULT CURRENT_DATE, "p_notes" "text" DEFAULT NULL::"text") RETURNS TABLE("entry_id" "uuid", "entry_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_entry_id UUID;
  v_entry_number TEXT;
  v_authorized_user_id UUID;
  v_source_code TEXT;
  v_target_code TEXT;
BEGIN
  IF p_amount <= 0 THEN
    RAISE EXCEPTION 'El importe debe ser positivo';
  END IF;
  
  IF p_source_bank_id = p_target_bank_id THEN
    RAISE EXCEPTION 'El banco origen y destino deben ser diferentes';
  END IF;
  
  v_authorized_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_authorized_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;
  
  -- Obtener c├│digos contables desde company_bank_accounts
  SELECT accounting_code INTO v_source_code
  FROM internal.company_bank_accounts
  WHERE id::text = p_source_bank_id AND is_active = TRUE;
  
  SELECT accounting_code INTO v_target_code
  FROM internal.company_bank_accounts
  WHERE id::text = p_target_bank_id AND is_active = TRUE;
  
  IF v_source_code IS NULL THEN
    v_source_code := accounting.get_bank_account_code(p_source_bank_id);
    IF v_source_code IS NULL THEN
      v_source_code := accounting.register_bank_account(p_source_bank_id, p_source_bank_name);
    END IF;
  END IF;
  
  IF v_target_code IS NULL THEN
    v_target_code := accounting.get_bank_account_code(p_target_bank_id);
    IF v_target_code IS NULL THEN
      v_target_code := accounting.register_bank_account(p_target_bank_id, p_target_bank_name);
    END IF;
  END IF;
  
  v_entry_number := accounting.get_next_entry_number();
  
  INSERT INTO accounting.journal_entries (
    entry_number, entry_date, entry_type, description,
    reference_type, is_automatic, is_locked, created_by
  ) VALUES (
    v_entry_number, p_transfer_date,
    'BANK_TRANSFER'::accounting.journal_entry_type,
    COALESCE(p_notes, 'Traspaso ' || p_source_bank_name || ' ÔåÆ ' || p_target_bank_name),
    'BANK_TRANSFER', FALSE, FALSE, v_authorized_user_id
  )
  RETURNING id INTO v_entry_id;
  
  INSERT INTO accounting.journal_entry_lines (
    journal_entry_id, line_order, account_code, description, amount, debit_credit
  ) VALUES (
    v_entry_id, 1, v_target_code,
    'Traspaso desde ' || p_source_bank_name, p_amount, 'DEBIT'
  );
  
  INSERT INTO accounting.journal_entry_lines (
    journal_entry_id, line_order, account_code, description, amount, debit_credit
  ) VALUES (
    v_entry_id, 2, v_source_code,
    'Traspaso a ' || p_target_bank_name, p_amount, 'CREDIT'
  );
  
  RETURN QUERY SELECT v_entry_id, v_entry_number;
END;
$$;
ALTER FUNCTION "accounting"."create_bank_transfer"("p_source_bank_id" "text", "p_source_bank_name" "text", "p_target_bank_id" "text", "p_target_bank_name" "text", "p_amount" numeric, "p_transfer_date" "date", "p_notes" "text") OWNER TO "postgres";
