COMMENT ON FUNCTION "accounting"."create_bank_transfer"("p_source_bank_id" "text", "p_source_bank_name" "text", "p_target_bank_id" "text", "p_target_bank_name" "text", "p_amount" numeric, "p_transfer_date" "date", "p_notes" "text") IS 'Registra un traspaso entre cuentas bancarias';
--
-- Name: create_invoice_payment_entry("uuid", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_invoice_payment_entry"("p_payment_id" "uuid", "p_entry_date" "date" DEFAULT NULL::"date") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_payment RECORD;
  v_entry_id UUID;
  v_entry_number TEXT;
  v_account_client TEXT := '430000';
  v_account_bank TEXT;
  v_max_retries INTEGER := 10;
  v_retry_count INTEGER := 0;
BEGIN
  SELECT 
    ip.id, ip.invoice_id, ip.payment_date, ip.amount, ip.payment_method,
    ip.bank_reference, ip.registered_by, ip.company_bank_account_id,
    i.invoice_number, i.client_id, c.client_number, c.company_name
  INTO v_payment
  FROM sales.invoice_payments ip
  JOIN sales.invoices i ON ip.invoice_id = i.id
  JOIN crm.clients c ON i.client_id = c.id
  WHERE ip.id = p_payment_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Pago no encontrado: %', p_payment_id;
  END IF;
  
  -- Resolver banco con la funci├│n robusta
  v_account_bank := accounting.resolve_bank_accounting_code(v_payment.company_bank_account_id);
  
  IF EXISTS (
    SELECT 1 FROM accounting.journal_entries je
    WHERE je.reference_id = p_payment_id AND je.reference_type = 'payment_received'
  ) THEN
    RAISE EXCEPTION 'Ya existe un asiento contable para este pago: %', p_payment_id;
  END IF;
  
  LOOP
    v_entry_number := accounting.get_next_entry_number();
    BEGIN
      INSERT INTO accounting.journal_entries (
        entry_number, entry_date, entry_type, description,
        reference_id, reference_type, project_id, created_by
      ) VALUES (
        v_entry_number,
        COALESCE(p_entry_date, v_payment.payment_date),
        'PAYMENT_RECEIVED',
        'Cobro factura: ' || v_payment.invoice_number,
        p_payment_id, 'payment_received', NULL, v_payment.registered_by
      ) RETURNING id INTO v_entry_id;
      EXIT;
    EXCEPTION WHEN unique_violation THEN
      v_retry_count := v_retry_count + 1;
      IF v_retry_count >= v_max_retries THEN
        RAISE EXCEPTION 'No se pudo generar n├║mero de asiento ├║nico despu├®s de % intentos', v_max_retries;
      END IF;
    END;
  END LOOP;
  
  INSERT INTO accounting.journal_entry_lines (
    journal_entry_id, account_code, debit_credit, amount, description, line_order
  ) VALUES (
    v_entry_id, v_account_bank, 'DEBIT', v_payment.amount,
    'Cobro ' || v_payment.invoice_number, 1
  );
  
  INSERT INTO accounting.journal_entry_lines (
    journal_entry_id, account_code, debit_credit, amount, description, line_order, third_party_id, third_party_type
  ) VALUES (
    v_entry_id, v_account_client, 'CREDIT', v_payment.amount,
    'Cobro factura ' || v_payment.invoice_number, 2,
    v_payment.client_id, 'CLIENT'::accounting.third_party_type
  );
  
  RETURN v_entry_id;
END;
$$;
ALTER FUNCTION "accounting"."create_invoice_payment_entry"("p_payment_id" "uuid", "p_entry_date" "date") OWNER TO "postgres";
--
-- Name: FUNCTION "create_invoice_payment_entry"("p_payment_id" "uuid", "p_entry_date" "date"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."create_invoice_payment_entry"("p_payment_id" "uuid", "p_entry_date" "date") IS 'Crea un asiento contable para un pago recibido de cliente (cobro). DEBE: Banco (572000), HABER: Clientes (430000) con third_party_id.';
--
-- Name: create_invoice_purchase_entry("uuid", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_invoice_purchase_entry"("p_purchase_invoice_id" "uuid", "p_entry_date" "date" DEFAULT CURRENT_DATE) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_entry_id UUID;
  v_entry_number TEXT;
  v_invoice RECORD;
  v_supplier RECORD;
  v_technician RECORD;
  v_account_supplier TEXT;
  v_account_technician TEXT := '410000';
  v_account_supplier_base TEXT := '400000';
  v_account_expense TEXT := '623000';
  v_account_expense_tickets TEXT := '627000';
  v_account_vat_supported TEXT := '472000';
  v_account_irpf TEXT := '475100';
  v_base_amount NUMERIC(12,2);
  v_vat_amount NUMERIC(12,2);
  v_irpf_amount NUMERIC(12,2);
  v_total_amount NUMERIC(12,2);
  v_third_party_id UUID;
  v_third_party_type accounting.third_party_type;
  v_third_party_name TEXT;
  v_is_ticket_without_provider BOOLEAN := false;
BEGIN
  SELECT 
    pi.id, pi.invoice_number, pi.document_type,
    pi.supplier_id, pi.technician_id, pi.manual_beneficiary_name,
    pi.subtotal, pi.tax_amount, pi.total,
    GREATEST(COALESCE(pi.retention_amount, 0), COALESCE(pi.withholding_amount, 0)) AS effective_retention,
    pi.project_id, pi.created_by
  INTO v_invoice
  FROM sales.purchase_invoices pi
  WHERE pi.id = p_purchase_invoice_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Factura de compra no encontrada: %', p_purchase_invoice_id;
  END IF;

  IF v_invoice.supplier_id IS NOT NULL THEN
    SELECT s.id, s.supplier_number, s.company_name INTO v_supplier
    FROM internal.suppliers s WHERE s.id = v_invoice.supplier_id;
    IF NOT FOUND THEN RAISE EXCEPTION 'Proveedor no encontrado: %', v_invoice.supplier_id; END IF;
    v_third_party_id := v_supplier.id;
    v_third_party_type := 'SUPPLIER';
    v_third_party_name := v_supplier.company_name;
    v_account_supplier := v_account_supplier_base;
  ELSIF v_invoice.technician_id IS NOT NULL THEN
    SELECT t.id, t.technician_number, t.company_name INTO v_technician
    FROM internal.technicians t WHERE t.id = v_invoice.technician_id;
    IF NOT FOUND THEN RAISE EXCEPTION 'T├®cnico no encontrado: %', v_invoice.technician_id; END IF;
    v_third_party_id := v_technician.id;
    v_third_party_type := 'TECHNICIAN';
    v_third_party_name := v_technician.company_name;
    v_account_supplier := v_account_technician;
  ELSIF v_invoice.document_type = 'EXPENSE' AND (v_invoice.manual_beneficiary_name IS NOT NULL AND trim(v_invoice.manual_beneficiary_name) != '') THEN
    v_is_ticket_without_provider := true;
    v_third_party_id := NULL;
    v_third_party_type := NULL;
    v_third_party_name := trim(v_invoice.manual_beneficiary_name);
    v_account_supplier := v_account_technician;
  ELSE
    RAISE EXCEPTION 'La factura de compra debe tener un proveedor, un t├®cnico o (si es ticket) un concepto manual.';
  END IF;
  
  v_base_amount := COALESCE(v_invoice.subtotal, 0);
  v_vat_amount := COALESCE(v_invoice.tax_amount, 0);
  v_irpf_amount := COALESCE(v_invoice.effective_retention, 0);
  v_total_amount := COALESCE(v_invoice.total, 0);
  v_entry_number := accounting.get_next_entry_number();
  
  INSERT INTO accounting.journal_entries (
    entry_number, entry_date, entry_type, description, reference_id, reference_type, project_id, created_by
  ) VALUES (
    v_entry_number, p_entry_date, 'INVOICE_PURCHASE',
    'Factura recibida: ' || v_invoice.invoice_number || ' - ' || v_third_party_name,
    v_invoice.id, 'purchase_invoice', v_invoice.project_id, v_invoice.created_by
  ) RETURNING id INTO v_entry_id;
  
  IF v_is_ticket_without_provider THEN
    INSERT INTO accounting.journal_entry_lines (
      journal_entry_id, account_code, debit_credit, amount, third_party_id, third_party_type, description, line_order
    ) VALUES (
      v_entry_id, v_account_expense_tickets, 'DEBIT', v_base_amount, NULL, NULL,
      'Tickets: ' || v_third_party_name || ' - ' || v_invoice.invoice_number, 1
    );
  ELSE
    INSERT INTO accounting.journal_entry_lines (
      journal_entry_id, account_code, debit_credit, amount, third_party_id, third_party_type, description, line_order
    ) VALUES (
      v_entry_id, v_account_expense, 'DEBIT', v_base_amount, v_third_party_id, v_third_party_type,
      'Base imponible factura ' || v_invoice.invoice_number, 1
    );
  END IF;
  
  IF v_vat_amount > 0 THEN
    INSERT INTO accounting.journal_entry_lines (
      journal_entry_id, account_code, debit_credit, amount, description, line_order
    ) VALUES (
      v_entry_id, v_account_vat_supported, 'DEBIT', v_vat_amount,
      'IVA soportado factura ' || v_invoice.invoice_number, 2
    );
  END IF;
  
  INSERT INTO accounting.journal_entry_lines (
    journal_entry_id, account_code, debit_credit, amount, third_party_id, third_party_type, description, line_order
  ) VALUES (
    v_entry_id, v_account_supplier, 'CREDIT', v_total_amount,
    v_third_party_id, v_third_party_type,
    CASE WHEN v_is_ticket_without_provider THEN 'Ticket ' || v_invoice.invoice_number || ' - ' || v_third_party_name ELSE 'Factura ' || v_invoice.invoice_number END,
    3
  );
  
  IF v_irpf_amount > 0 THEN
    INSERT INTO accounting.journal_entry_lines (
      journal_entry_id, account_code, debit_credit, amount, description, line_order
    ) VALUES (
      v_entry_id, v_account_irpf, 'CREDIT', v_irpf_amount,
      'Retenci├│n IRPF factura ' || v_invoice.invoice_number, 4
    );
  END IF;
  
  RETURN v_entry_id;
END;
$$;
ALTER FUNCTION "accounting"."create_invoice_purchase_entry"("p_purchase_invoice_id" "uuid", "p_entry_date" "date") OWNER TO "postgres";
--
-- Name: create_invoice_sale_entry("uuid", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_invoice_sale_entry"("p_invoice_id" "uuid", "p_entry_date" "date" DEFAULT CURRENT_DATE) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_entry_id UUID;
  v_entry_number TEXT;
  v_invoice RECORD;
  v_client RECORD;
  v_account_client TEXT := '430000';
  v_account_sales TEXT := '700000';
  v_account_vat TEXT := '477000';
  v_base_amount NUMERIC(12,2);
  v_vat_amount NUMERIC(12,2);
  v_total_amount NUMERIC(12,2);
  v_created_by UUID;
BEGIN
  -- Obtener datos de la factura PRIMERO
  SELECT 
    i.id,
    i.invoice_number,
    i.client_id,
    i.subtotal,
    i.tax_amount,
    i.total,
    i.project_id,
    i.created_by
  INTO v_invoice
  FROM sales.invoices i
  WHERE i.id = p_invoice_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Factura no encontrada: %', p_invoice_id;
  END IF;
  
  -- Validar que la factura tiene totales v├ílidos
  IF v_invoice.total IS NULL OR v_invoice.total <= 0 THEN
    RAISE EXCEPTION 'La factura no tiene un total v├ílido (total: %)', v_invoice.total;
  END IF;
  
  -- Obtener datos del cliente
  SELECT 
    c.id,
    c.client_number,
    c.company_name
  INTO v_client
  FROM crm.clients c
  WHERE c.id = v_invoice.client_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Cliente no encontrado: %', v_invoice.client_id;
  END IF;
  
  -- CORRECCI├ôN CR├ìTICA: Usar SIEMPRE el created_by de la factura (que ya es el internal ID)
  -- Si no existe, usar la funci├│n de mapeo para convertir auth.uid() -> internal ID
  v_created_by := v_invoice.created_by;
  
  IF v_created_by IS NULL THEN
    -- Fallback: mapear auth.uid() al internal ID
    v_created_by := internal.get_authorized_user_id(auth.uid());
  END IF;
  
  -- Log para debugging (se puede quitar despu├®s)
  RAISE NOTICE 'create_invoice_sale_entry: invoice=%, created_by from invoice=%, final v_created_by=%', 
    p_invoice_id, v_invoice.created_by, v_created_by;
  
  -- Calcular y validar importes
  v_base_amount := COALESCE(v_invoice.subtotal, 0);
  v_vat_amount := COALESCE(v_invoice.tax_amount, 0);
  v_total_amount := COALESCE(v_invoice.total, 0);
  
  -- Validar que los importes no sean negativos
  IF v_base_amount < 0 THEN
    RAISE EXCEPTION 'El subtotal de la factura no puede ser negativo: %', v_base_amount;
  END IF;
  
  IF v_vat_amount < 0 THEN
    RAISE EXCEPTION 'El importe de impuestos de la factura no puede ser negativo: %', v_vat_amount;
  END IF;
  
  IF v_total_amount < 0 THEN
    RAISE EXCEPTION 'El total de la factura no puede ser negativo: %', v_total_amount;
  END IF;
  
  -- Redondear a 2 decimales para asegurar precisi├│n
  v_base_amount := ROUND(v_base_amount, 2);
  v_vat_amount := ROUND(v_vat_amount, 2);
  v_total_amount := ROUND(v_total_amount, 2);
  
  -- Validar que el total sea igual a subtotal + impuestos (con tolerancia de 0.01 por redondeo)
  IF ABS(v_total_amount - (v_base_amount + v_vat_amount)) > 0.01 THEN
    RAISE EXCEPTION 'Los totales de la factura no coinciden: total=%, subtotal=%, impuestos=%', 
      v_total_amount, v_base_amount, v_vat_amount;
  END IF;
  
  -- Generar n├║mero de asiento
  v_entry_number := accounting.get_next_entry_number();
  
  -- Crear asiento (created_by ya es el internal ID correcto)
  INSERT INTO accounting.journal_entries (
    entry_number,
    entry_date,
    entry_type,
    description,
    reference_id,
    reference_type,
    project_id,
    created_by
  ) VALUES (
    v_entry_number,
    p_entry_date,
    'INVOICE_SALE',
    'Factura emitida: ' || COALESCE(v_invoice.invoice_number, 'SIN NUMERO') || ' - ' || v_client.company_name,
    v_invoice.id,
    'invoice',
    v_invoice.project_id,
    v_created_by
  ) RETURNING id INTO v_entry_id;
  
  -- DEBE: Clientes (430000) - Total de la factura
  INSERT INTO accounting.journal_entry_lines (
    journal_entry_id,
    account_code,
    debit_credit,
    amount,
    third_party_id,
    third_party_type,
    description,
    line_order
  ) VALUES (
    v_entry_id,
    v_account_client,
    'DEBIT',
    v_total_amount,
    v_client.id,
    'CLIENT',
    'Factura ' || COALESCE(v_invoice.invoice_number, 'SIN NUMERO'),
    1
  );
  
  -- HABER: Ventas (700000) - Base imponible (subtotal)
  INSERT INTO accounting.journal_entry_lines (
    journal_entry_id,
    account_code,
    debit_credit,
    amount,
    third_party_id,
    third_party_type,
    description,
    line_order
  ) VALUES (
    v_entry_id,
    v_account_sales,
    'CREDIT',
    v_base_amount,
    v_client.id,
    'CLIENT',
    'Venta - Factura ' || COALESCE(v_invoice.invoice_number, 'SIN NUMERO'),
    2
  );
  
  -- HABER: IVA Repercutido (477000) - Solo si hay IVA
  IF v_vat_amount > 0 THEN
    INSERT INTO accounting.journal_entry_lines (
      journal_entry_id,
      account_code,
      debit_credit,
      amount,
      third_party_id,
      third_party_type,
      description,
      line_order
    ) VALUES (
      v_entry_id,
      v_account_vat,
      'CREDIT',
      v_vat_amount,
      v_client.id,
      'CLIENT',
      'IVA Repercutido - Factura ' || COALESCE(v_invoice.invoice_number, 'SIN NUMERO'),
      3
    );
  END IF;
  
  -- Bloquear el asiento
  UPDATE accounting.journal_entries
  SET is_locked = true
  WHERE id = v_entry_id;
  
  RETURN v_entry_id;
END;
$$;
ALTER FUNCTION "accounting"."create_invoice_sale_entry"("p_invoice_id" "uuid", "p_entry_date" "date") OWNER TO "postgres";
--
-- Name: create_irpf_settlement_entry("date", "date", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_irpf_settlement_entry"("p_settlement_date" "date" DEFAULT CURRENT_DATE, "p_period_start" "date" DEFAULT NULL::"date", "p_period_end" "date" DEFAULT NULL::"date") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting'
    AS $$
DECLARE
  v_entry_id UUID;
  v_entry_number TEXT;
  v_irpf_accumulated NUMERIC(12,2) := 0;
  v_period_filter TEXT;
  v_user_id UUID;
BEGIN
  -- Obtener usuario actual
  SELECT auth.uid() INTO v_user_id;
  
  -- Construir filtro de per├¡odo
  IF p_period_start IS NOT NULL AND p_period_end IS NOT NULL THEN
    v_period_filter := ' AND je.entry_date BETWEEN ''' || p_period_start || ''' AND ''' || p_period_end || '''';
  ELSE
    v_period_filter := '';
  END IF;
  
  -- Calcular IRPF acumulado
  EXECUTE format('
    SELECT COALESCE(SUM(jel.amount), 0)
    FROM accounting.journal_entry_lines jel
    JOIN accounting.journal_entries je ON jel.journal_entry_id = je.id
    WHERE jel.account_code = ''475100''
      AND jel.debit_credit = ''CREDIT''
      %s
  ', v_period_filter) INTO v_irpf_accumulated;
  
  IF v_irpf_accumulated = 0 THEN
    RAISE EXCEPTION 'No hay retenciones IRPF acumuladas en el per├¡odo especificado';
  END IF;
  
  -- Generar n├║mero de asiento
  v_entry_number := accounting.get_next_entry_number();
  
  -- Crear asiento
  INSERT INTO accounting.journal_entries (
    entry_number,
    entry_date,
    entry_type,
    description,
    reference_type,
    created_by
  ) VALUES (
    v_entry_number,
    p_settlement_date,
    'TAX_SETTLEMENT',
    'Liquidaci├│n IRPF - Per├¡odo: ' || COALESCE(p_period_start::TEXT, 'Total') || ' a ' || COALESCE(p_period_end::TEXT, 'Actual'),
    'irpf_settlement',
    v_user_id
  ) RETURNING id INTO v_entry_id;
  
  -- DEBE: HP retenciones IRPF (475100)
  INSERT INTO accounting.journal_entry_lines (
    journal_entry_id,
    account_code,
    debit_credit,
    amount,
    description,
    line_order
  ) VALUES (
    v_entry_id,
    '475100',
    'DEBIT',
    v_irpf_accumulated,
    'Cierre retenciones IRPF',
    1
  );
  
  -- HABER: Banco (572000)
  INSERT INTO accounting.journal_entry_lines (
    journal_entry_id,
    account_code,
    debit_credit,
    amount,
    description,
    line_order
  ) VALUES (
    v_entry_id,
    '572000',
    'CREDIT',
    v_irpf_accumulated,
    'Pago retenciones IRPF',
    2
  );
  
  RETURN v_entry_id;
END;
$$;
ALTER FUNCTION "accounting"."create_irpf_settlement_entry"("p_settlement_date" "date", "p_period_start" "date", "p_period_end" "date") OWNER TO "postgres";
--
-- Name: create_manual_bank_movement("text", "text", numeric, "text", "text", "date", "text"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_manual_bank_movement"("p_bank_account_id" "text", "p_bank_name" "text", "p_amount" numeric, "p_movement_type" "text", "p_category" "text", "p_movement_date" "date" DEFAULT CURRENT_DATE, "p_description" "text" DEFAULT NULL::"text") RETURNS TABLE("entry_id" "uuid", "entry_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_entry_id UUID;
  v_entry_number TEXT;
  v_authorized_user_id UUID;
  v_bank_code TEXT;
BEGIN
  IF p_amount <= 0 THEN
    RAISE EXCEPTION 'El importe debe ser positivo';
  END IF;
  
  v_authorized_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_authorized_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;
  
  -- Obtener c├│digo banco
  v_bank_code := accounting.get_bank_account_code(p_bank_account_id);
  IF v_bank_code IS NULL THEN
    v_bank_code := accounting.register_bank_account(p_bank_account_id, p_bank_name);
  END IF;
  
  -- Crear asiento
  v_entry_number := accounting.get_next_entry_number();
  
  INSERT INTO accounting.journal_entries (
    entry_number,
    entry_date,
    entry_type,
    description,
    reference_type,
    is_automatic,
    is_locked,
    created_by
  ) VALUES (
    v_entry_number,
    p_movement_date,
    CASE WHEN UPPER(p_movement_type) = 'EXPENSE' THEN 'EXPENSE' ELSE 'INCOME' END,
    COALESCE(p_description, CASE WHEN UPPER(p_movement_type) = 'EXPENSE' THEN 'Gasto sin factura' ELSE 'Ingreso sin factura' END),
    'MANUAL_MOVEMENT',
    FALSE,
    FALSE,
    v_authorized_user_id
  )
  RETURNING id INTO v_entry_id;
  
  IF UPPER(p_movement_type) = 'EXPENSE' THEN
    -- Gasto: DEBE Gasto, HABER Banco
    INSERT INTO accounting.journal_entry_lines (
      journal_entry_id, line_order, account_code, description, amount, debit_credit
    ) VALUES (
      v_entry_id, 1, p_category,
      p_description,
      p_amount, 'DEBIT'
    );
    
    INSERT INTO accounting.journal_entry_lines (
      journal_entry_id, line_order, account_code, description, amount, debit_credit
    ) VALUES (
      v_entry_id, 2, v_bank_code,
      'Pago - ' || p_description,
      p_amount, 'CREDIT'
    );
  ELSE
    -- Ingreso: DEBE Banco, HABER Ingreso
    INSERT INTO accounting.journal_entry_lines (
      journal_entry_id, line_order, account_code, description, amount, debit_credit
    ) VALUES (
      v_entry_id, 1, v_bank_code,
      'Cobro - ' || p_description,
      p_amount, 'DEBIT'
    );
    
    INSERT INTO accounting.journal_entry_lines (
      journal_entry_id, line_order, account_code, description, amount, debit_credit
    ) VALUES (
      v_entry_id, 2, p_category,
      p_description,
      p_amount, 'CREDIT'
    );
  END IF;
  
  RETURN QUERY SELECT v_entry_id, v_entry_number;
END;
$$;
ALTER FUNCTION "accounting"."create_manual_bank_movement"("p_bank_account_id" "text", "p_bank_name" "text", "p_amount" numeric, "p_movement_type" "text", "p_category" "text", "p_movement_date" "date", "p_description" "text") OWNER TO "postgres";
