--
-- Name: create_partner_compensation_entry("uuid", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_partner_compensation_entry"("p_compensation_run_id" "uuid", "p_entry_date" "date" DEFAULT CURRENT_DATE) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_entry_id uuid;
  v_entry_number text;
  v_compensation record;
  v_partner record;
  v_account_salary text := '640000';
  v_account_pending text := '465000';
  v_account_irpf text := '475100';
  v_gross_amount numeric(12,2);
  v_irpf_amount numeric(12,2);
  v_net_amount numeric(12,2);
  v_user_id uuid;
BEGIN
  SELECT pcr.id, pcr.compensation_number, pcr.partner_id, pcr.gross_amount, pcr.irpf_amount, pcr.net_amount, pcr.created_by
  INTO v_compensation
  FROM accounting.partner_compensation_runs pcr
  WHERE pcr.id = p_compensation_run_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Retribuci├│n no encontrada: %', p_compensation_run_id;
  END IF;
  
  SELECT p.id, p.partner_number, p.full_name
  INTO v_partner
  FROM internal.partners p
  WHERE p.id = v_compensation.partner_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Socio no encontrado: %', v_compensation.partner_id;
  END IF;
  
  v_gross_amount := v_compensation.gross_amount;
  v_irpf_amount := v_compensation.irpf_amount;
  v_net_amount := v_compensation.net_amount;
  v_user_id := v_compensation.created_by;
  
  -- Usar expl├¡citamente la versi├│n sin par├ímetros (sequence-based)
  v_entry_number := (SELECT accounting.get_next_entry_number());
  
  INSERT INTO accounting.journal_entries (
    entry_number, entry_date, entry_type, description,
    reference_id, reference_type, created_by
  ) VALUES (
    v_entry_number, p_entry_date, 'PAYROLL_PARTNER'::accounting.journal_entry_type,
    'Retribuci├│n socio: ' || v_compensation.compensation_number || ' - ' || v_partner.full_name,
    v_compensation.id, 'partner_compensation', v_user_id
  ) RETURNING id INTO v_entry_id;
  
  INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, debit_credit, amount, description, line_order)
  VALUES (v_entry_id, v_account_salary, 'DEBIT', v_gross_amount, 'Retribuci├│n ' || v_compensation.compensation_number || ' - ' || v_partner.full_name, 1);
  
  INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, debit_credit, amount, description, line_order)
  VALUES (v_entry_id, v_account_pending, 'CREDIT', v_net_amount, 'Neto a pagar retribuci├│n ' || v_compensation.compensation_number, 2);
  
  IF v_irpf_amount > 0 THEN
    INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, debit_credit, amount, description, line_order)
    VALUES (v_entry_id, v_account_irpf, 'CREDIT', v_irpf_amount, 'Retenci├│n IRPF retribuci├│n ' || v_compensation.compensation_number, 3);
  END IF;
  
  UPDATE accounting.partner_compensation_runs
  SET journal_entry_id = v_entry_id, status = 'POSTED', updated_at = now()
  WHERE id = p_compensation_run_id;
  
  RETURN v_entry_id;
END;
$$;
ALTER FUNCTION "accounting"."create_partner_compensation_entry"("p_compensation_run_id" "uuid", "p_entry_date" "date") OWNER TO "postgres";
--
-- Name: FUNCTION "create_partner_compensation_entry"("p_compensation_run_id" "uuid", "p_entry_date" "date"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."create_partner_compensation_entry"("p_compensation_run_id" "uuid", "p_entry_date" "date") IS 'Genera autom├íticamente el asiento contable al postear una retribuci├│n de socio';
--
-- Name: create_partner_compensation_run("uuid", integer, integer, numeric, numeric, "text"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_partner_compensation_run"("p_partner_id" "uuid", "p_period_year" integer, "p_period_month" integer, "p_gross_amount" numeric, "p_irpf_rate" numeric DEFAULT 19.00, "p_notes" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_compensation_id UUID;
  v_compensation_number TEXT;
  v_irpf_amount NUMERIC(12,2);
  v_net_amount NUMERIC(12,2);
  v_user_id UUID;
BEGIN
  -- Verificar que el usuario es admin
  IF NOT internal.is_admin() THEN
    RAISE EXCEPTION 'Solo los administradores pueden crear retribuciones';
  END IF;
  
  -- Obtener usuario actual
  SELECT auth.uid() INTO v_user_id;
  
  -- Validar que no existe retribuci├│n para este per├¡odo y socio
  IF EXISTS (
    SELECT 1 FROM accounting.partner_compensation_runs
    WHERE partner_id = p_partner_id
      AND period_year = p_period_year
      AND period_month = p_period_month
      AND status != 'CANCELLED'
  ) THEN
    RAISE EXCEPTION 'Ya existe una retribuci├│n para este socio en el per├¡odo %/%', p_period_year, p_period_month;
  END IF;
  
  -- Calcular IRPF y neto
  v_irpf_amount := p_gross_amount * (p_irpf_rate / 100);
  v_net_amount := p_gross_amount - v_irpf_amount;
  
  -- Generar n├║mero de retribuci├│n
  v_compensation_number := accounting.get_next_compensation_number();
  
  -- Crear retribuci├│n
  INSERT INTO accounting.partner_compensation_runs (
    compensation_number,
    period_year,
    period_month,
    partner_id,
    gross_amount,
    irpf_rate,
    irpf_amount,
    net_amount,
    notes,
    created_by
  ) VALUES (
    v_compensation_number,
    p_period_year,
    p_period_month,
    p_partner_id,
    p_gross_amount,
    p_irpf_rate,
    v_irpf_amount,
    v_net_amount,
    p_notes,
    v_user_id
  ) RETURNING id INTO v_compensation_id;
  
  RETURN v_compensation_id;
END;
$$;
ALTER FUNCTION "accounting"."create_partner_compensation_run"("p_partner_id" "uuid", "p_period_year" integer, "p_period_month" integer, "p_gross_amount" numeric, "p_irpf_rate" numeric, "p_notes" "text") OWNER TO "postgres";
--
-- Name: FUNCTION "create_partner_compensation_run"("p_partner_id" "uuid", "p_period_year" integer, "p_period_month" integer, "p_gross_amount" numeric, "p_irpf_rate" numeric, "p_notes" "text"); Type: COMMENT; Schema: accounting; Owner: postgres
--

