--
-- Name: create_payroll_entry("uuid", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_payroll_entry"("p_payroll_run_id" "uuid", "p_entry_date" "date" DEFAULT CURRENT_DATE) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_entry_id uuid;
  v_entry_number text;
  v_payroll record;
  v_employee record;
  v_account_salary text := '640000';
  v_account_pending text := '465000';
  v_account_irpf text := '475100';
  v_gross_amount numeric(12,2);
  v_irpf_amount numeric(12,2);
  v_net_amount numeric(12,2);
  v_user_id uuid;
BEGIN
  SELECT pr.id, pr.payroll_number, pr.employee_id, pr.gross_amount, pr.irpf_amount, pr.net_amount, pr.created_by
  INTO v_payroll
  FROM accounting.payroll_runs pr
  WHERE pr.id = p_payroll_run_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'N├│mina no encontrada: %', p_payroll_run_id;
  END IF;
  
  SELECT e.id, e.employee_number, e.full_name
  INTO v_employee
  FROM internal.employees e
  WHERE e.id = v_payroll.employee_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Empleado no encontrado: %', v_payroll.employee_id;
  END IF;
  
  v_gross_amount := v_payroll.gross_amount;
  v_irpf_amount := v_payroll.irpf_amount;
  v_net_amount := v_payroll.net_amount;
  v_user_id := v_payroll.created_by;
  
  -- Usar expl├¡citamente la versi├│n sin par├ímetros (sequence-based)
  v_entry_number := (SELECT accounting.get_next_entry_number());
  
  INSERT INTO accounting.journal_entries (
    entry_number, entry_date, entry_type, description,
    reference_id, reference_type, created_by
  ) VALUES (
    v_entry_number, p_entry_date, 'PAYROLL_EMPLOYEE'::accounting.journal_entry_type,
    'N├│mina: ' || v_payroll.payroll_number || ' - ' || v_employee.full_name,
    v_payroll.id, 'payroll', v_user_id
  ) RETURNING id INTO v_entry_id;
  
  INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, debit_credit, amount, description, line_order)
  VALUES (v_entry_id, v_account_salary, 'DEBIT', v_gross_amount, 'N├│mina ' || v_payroll.payroll_number || ' - ' || v_employee.full_name, 1);
  
  INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, debit_credit, amount, description, line_order)
  VALUES (v_entry_id, v_account_pending, 'CREDIT', v_net_amount, 'Neto a pagar n├│mina ' || v_payroll.payroll_number, 2);
  
  IF v_irpf_amount > 0 THEN
    INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, debit_credit, amount, description, line_order)
    VALUES (v_entry_id, v_account_irpf, 'CREDIT', v_irpf_amount, 'Retenci├│n IRPF n├│mina ' || v_payroll.payroll_number, 3);
  END IF;
  
  UPDATE accounting.payroll_runs
  SET journal_entry_id = v_entry_id, status = 'POSTED', updated_at = now()
  WHERE id = p_payroll_run_id;
  
  RETURN v_entry_id;
END;
$$;
ALTER FUNCTION "accounting"."create_payroll_entry"("p_payroll_run_id" "uuid", "p_entry_date" "date") OWNER TO "postgres";
--
-- Name: FUNCTION "create_payroll_entry"("p_payroll_run_id" "uuid", "p_entry_date" "date"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."create_payroll_entry"("p_payroll_run_id" "uuid", "p_entry_date" "date") IS 'Genera autom├íticamente el asiento contable al postear una n├│mina de empleado';
--
-- Name: create_payroll_payment(numeric, "uuid", "uuid", "date", "text", "text", "text", "uuid"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_payroll_payment"("p_amount" numeric, "p_payroll_run_id" "uuid" DEFAULT NULL::"uuid", "p_partner_compensation_run_id" "uuid" DEFAULT NULL::"uuid", "p_payment_date" "date" DEFAULT CURRENT_DATE, "p_payment_method" "text" DEFAULT 'TRANSFER'::"text", "p_bank_reference" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text", "p_company_bank_account_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_payment_id UUID;
  v_payment_number TEXT;
  v_user_id UUID;
  v_year INTEGER;
  v_month INTEGER;
  v_day INTEGER;
  v_number INTEGER;
BEGIN
  -- Verificar que el usuario es admin
  IF NOT internal.is_admin() THEN
    RAISE EXCEPTION 'Solo los administradores pueden registrar pagos';
  END IF;
  
  -- Validar que se proporcione una fuente
  IF p_payroll_run_id IS NULL AND p_partner_compensation_run_id IS NULL THEN
    RAISE EXCEPTION 'Debe proporcionarse una n├│mina o retribuci├│n';
  END IF;
  
  -- Obtener usuario actual
  SELECT auth.uid() INTO v_user_id;
  
  -- Generar n├║mero de pago
  v_year := EXTRACT(YEAR FROM p_payment_date);
  v_month := EXTRACT(MONTH FROM p_payment_date);
  v_day := EXTRACT(DAY FROM p_payment_date);
  
  SELECT COALESCE(MAX(CAST(SUBSTRING(payment_number FROM 16 FOR 4) AS INTEGER)), 0) + 1
  INTO v_number
  FROM accounting.payroll_payments
  WHERE payment_number LIKE 'PAG-NOM-' || v_year || LPAD(v_month::TEXT, 2, '0') || LPAD(v_day::TEXT, 2, '0') || '-%';
  
  v_payment_number := 'PAG-NOM-' || v_year || LPAD(v_month::TEXT, 2, '0') || LPAD(v_day::TEXT, 2, '0') || '-' || LPAD(v_number::TEXT, 4, '0');
  
  -- Crear pago
  INSERT INTO accounting.payroll_payments (
    payment_number,
    payroll_run_id,
    partner_compensation_run_id,
    payment_date,
    amount,
    payment_method,
    bank_reference,
    notes,
    company_bank_account_id,
    created_by
  ) VALUES (
    v_payment_number,
    p_payroll_run_id,
    p_partner_compensation_run_id,
    p_payment_date,
    p_amount,
    p_payment_method,
    p_bank_reference,
    p_notes,
    p_company_bank_account_id,
    v_user_id
  ) RETURNING id INTO v_payment_id;
  
  -- Generar asiento autom├íticamente
  PERFORM accounting.create_payroll_payment_entry(v_payment_id, p_payment_date);
  
  RETURN v_payment_id;
END;
$$;
ALTER FUNCTION "accounting"."create_payroll_payment"("p_amount" numeric, "p_payroll_run_id" "uuid", "p_partner_compensation_run_id" "uuid", "p_payment_date" "date", "p_payment_method" "text", "p_bank_reference" "text", "p_notes" "text", "p_company_bank_account_id" "uuid") OWNER TO "postgres";
--
-- Name: create_payroll_payment_entry("uuid", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_payroll_payment_entry"("p_payment_id" "uuid", "p_entry_date" "date" DEFAULT CURRENT_DATE) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_entry_id UUID;
  v_entry_number TEXT;
  v_payment RECORD;
  v_payroll RECORD;
  v_compensation RECORD;
  v_account_pending TEXT := '465000';
  v_account_bank TEXT := '572000';
  v_bank_name TEXT;
  v_amount NUMERIC(12,2);
  v_user_id UUID;
  v_description TEXT;
BEGIN
  -- Obtener datos del pago
  SELECT 
    pp.id,
    pp.payment_number,
    pp.payroll_run_id,
    pp.partner_compensation_run_id,
    pp.amount,
    pp.payment_date,
    pp.company_bank_account_id,
    pp.created_by
  INTO v_payment
  FROM accounting.payroll_payments pp
  WHERE pp.id = p_payment_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Pago no encontrado: %', p_payment_id;
  END IF;
  
  v_amount := v_payment.amount;
  v_user_id := v_payment.created_by;
  
  -- Obtener cuenta bancaria espec├¡fica si se proporcion├│
  IF v_payment.company_bank_account_id IS NOT NULL THEN
    SELECT cba.accounting_code, cba.bank_name 
    INTO v_account_bank, v_bank_name
    FROM internal.company_bank_accounts cba
    WHERE cba.id = v_payment.company_bank_account_id
      AND cba.is_active = true;
    
    IF v_account_bank IS NULL THEN
      v_account_bank := '572000';
    END IF;
  END IF;
  
  -- Determinar si es n├│mina o retribuci├│n
  IF v_payment.payroll_run_id IS NOT NULL THEN
    SELECT payroll_number INTO v_payroll.payroll_number
    FROM accounting.payroll_runs
    WHERE id = v_payment.payroll_run_id;
    
    IF NOT FOUND THEN
      RAISE EXCEPTION 'N├│mina no encontrada: %', v_payment.payroll_run_id;
    END IF;
    
    v_description := 'Pago n├│mina: ' || v_payroll.payroll_number;
    
  ELSIF v_payment.partner_compensation_run_id IS NOT NULL THEN
    SELECT compensation_number INTO v_compensation.compensation_number
    FROM accounting.partner_compensation_runs
    WHERE id = v_payment.partner_compensation_run_id;
    
    IF NOT FOUND THEN
      RAISE EXCEPTION 'Retribuci├│n no encontrada: %', v_payment.partner_compensation_run_id;
    END IF;
    
    v_description := 'Pago retribuci├│n: ' || v_compensation.compensation_number;
  ELSE
    RAISE EXCEPTION 'El pago debe estar asociado a una n├│mina o retribuci├│n';
  END IF;
  
  -- A├▒adir nombre del banco a la descripci├│n
  IF v_bank_name IS NOT NULL THEN
    v_description := v_description || ' - ' || v_bank_name;
  END IF;
  
  -- Generar n├║mero de asiento
  v_entry_number := accounting.get_next_entry_number();
  
  -- Crear asiento
  INSERT INTO accounting.journal_entries (
    entry_number,
    entry_date,
    entry_type,
    description,
    reference_id,
    reference_type,
    created_by
  ) VALUES (
    v_entry_number,
    p_entry_date,
    'PAYMENT_MADE',
    v_description,
    v_payment.id,
    'payroll_payment',
    v_user_id
  ) RETURNING id INTO v_entry_id;
  
  -- DEBE: Remuneraciones pendientes (465000)
  INSERT INTO accounting.journal_entry_lines (
    journal_entry_id,
    account_code,
    debit_credit,
    amount,
    description,
    line_order
  ) VALUES (
    v_entry_id,
    v_account_pending,
    'DEBIT',
    v_amount,
    v_description,
    1
  );
  
  -- HABER: Banco espec├¡fico o 572000
  INSERT INTO accounting.journal_entry_lines (
    journal_entry_id,
    account_code,
    debit_credit,
    amount,
    description,
    line_order
  ) VALUES (
    v_entry_id,
    v_account_bank,
    'CREDIT',
    v_amount,
    'Pago ' || v_payment.payment_number || COALESCE(' - ' || v_bank_name, ''),
    2
  );
  
  -- Actualizar pago con el asiento generado
  UPDATE accounting.payroll_payments
  SET journal_entry_id = v_entry_id,
      updated_at = now()
  WHERE id = p_payment_id;
  
  -- Actualizar estado de n├│mina/retribuci├│n si est├í completamente pagada
  IF v_payment.payroll_run_id IS NOT NULL THEN
    UPDATE accounting.payroll_runs
    SET status = 'PAID',
        updated_at = now()
    WHERE id = v_payment.payroll_run_id
      AND (SELECT COALESCE(SUM(amount), 0) FROM accounting.payroll_payments WHERE payroll_run_id = v_payment.payroll_run_id) >= net_amount;
  END IF;
  
  IF v_payment.partner_compensation_run_id IS NOT NULL THEN
    UPDATE accounting.partner_compensation_runs
    SET status = 'PAID',
        updated_at = now()
    WHERE id = v_payment.partner_compensation_run_id
      AND (SELECT COALESCE(SUM(amount), 0) FROM accounting.payroll_payments WHERE partner_compensation_run_id = v_payment.partner_compensation_run_id) >= net_amount;
  END IF;
  
  RETURN v_entry_id;
END;
$$;
ALTER FUNCTION "accounting"."create_payroll_payment_entry"("p_payment_id" "uuid", "p_entry_date" "date") OWNER TO "postgres";
--
-- Name: FUNCTION "create_payroll_payment_entry"("p_payment_id" "uuid", "p_entry_date" "date"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."create_payroll_payment_entry"("p_payment_id" "uuid", "p_entry_date" "date") IS 'Genera autom├íticamente el asiento contable al registrar un pago de n├│mina/retribuci├│n';
--
-- Name: create_payroll_run("uuid", integer, integer, numeric, numeric, "text"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_payroll_run"("p_employee_id" "uuid", "p_period_year" integer, "p_period_month" integer, "p_gross_amount" numeric, "p_irpf_rate" numeric DEFAULT 19.00, "p_notes" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_payroll_id UUID;
  v_payroll_number TEXT;
  v_irpf_amount NUMERIC(12,2);
  v_net_amount NUMERIC(12,2);
  v_ss_employee NUMERIC(12,2);
  v_ss_company NUMERIC(12,2);
  v_ss_base NUMERIC(12,2);
  v_ss_employee_rate NUMERIC := 6.47;
  v_ss_employer_rate NUMERIC := 30.40;
  v_user_id UUID;
  v_employee RECORD;
BEGIN
  IF NOT internal.is_admin() THEN
    RAISE EXCEPTION 'Solo los administradores pueden crear n├│minas';
  END IF;
  
  SELECT auth.uid() INTO v_user_id;

  SELECT e.custom_ss_employee_rate, e.custom_ss_employer_rate
  INTO v_employee
  FROM internal.employees e WHERE e.id = p_employee_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Empleado no encontrado: %', p_employee_id;
  END IF;
  
  IF EXISTS (
    SELECT 1 FROM accounting.payroll_runs
    WHERE employee_id = p_employee_id
      AND period_year = p_period_year
      AND period_month = p_period_month
      AND status != 'CANCELLED'
  ) THEN
    RAISE EXCEPTION 'Ya existe una n├│mina para este empleado en el per├¡odo %/%', p_period_year, p_period_month;
  END IF;

  IF v_employee.custom_ss_employee_rate IS NOT NULL THEN
    v_ss_employee_rate := v_employee.custom_ss_employee_rate;
  END IF;
  IF v_employee.custom_ss_employer_rate IS NOT NULL THEN
    v_ss_employer_rate := v_employee.custom_ss_employer_rate;
  END IF;

  v_ss_base := p_gross_amount;
  v_ss_employee := ROUND(v_ss_base * (v_ss_employee_rate / 100.0), 2);
  v_ss_company := ROUND(v_ss_base * (v_ss_employer_rate / 100.0), 2);
  v_irpf_amount := ROUND(p_gross_amount * (p_irpf_rate / 100), 2);
  v_net_amount := p_gross_amount - v_ss_employee - v_irpf_amount;
  
  v_payroll_number := accounting.get_next_payroll_number();
  
  INSERT INTO accounting.payroll_runs (
    payroll_number, period_year, period_month, employee_id,
    gross_amount, irpf_rate, irpf_amount, net_amount,
    ss_employee, ss_company, ss_base,
    notes, created_by
  ) VALUES (
    v_payroll_number, p_period_year, p_period_month, p_employee_id,
    p_gross_amount, p_irpf_rate, v_irpf_amount, v_net_amount,
    v_ss_employee, v_ss_company, v_ss_base,
    p_notes, v_user_id
  ) RETURNING id INTO v_payroll_id;
  
  RETURN v_payroll_id;
END;
$$;
ALTER FUNCTION "accounting"."create_payroll_run"("p_employee_id" "uuid", "p_period_year" integer, "p_period_month" integer, "p_gross_amount" numeric, "p_irpf_rate" numeric, "p_notes" "text") OWNER TO "postgres";
--
-- Name: FUNCTION "create_payroll_run"("p_employee_id" "uuid", "p_period_year" integer, "p_period_month" integer, "p_gross_amount" numeric, "p_irpf_rate" numeric, "p_notes" "text"); Type: COMMENT; Schema: accounting; Owner: postgres
--

