--
-- Name: create_tax_payment("text", "text", "text", numeric, "date", "text", "text"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_tax_payment"("p_bank_account_id" "text", "p_bank_name" "text", "p_tax_type" "text", "p_amount" numeric, "p_payment_date" "date" DEFAULT CURRENT_DATE, "p_period" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text") RETURNS TABLE("entry_id" "uuid", "entry_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_entry_id UUID;
  v_entry_number TEXT;
  v_authorized_user_id UUID;
  v_bank_code TEXT;
  v_tax_account_code TEXT;
  v_description TEXT;
BEGIN
  IF p_amount <= 0 THEN
    RAISE EXCEPTION 'El importe debe ser positivo';
  END IF;
  
  v_authorized_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_authorized_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;
  
  -- Determinar cuenta de impuesto
  CASE UPPER(p_tax_type)
    WHEN 'IVA' THEN 
      v_tax_account_code := '475000'; -- HP IVA a pagar
      v_description := 'Pago IVA';
    WHEN 'IRPF' THEN 
      v_tax_account_code := '475100'; -- HP Retenciones IRPF
      v_description := 'Pago retenciones IRPF (Mod. 111)';
    WHEN 'IS' THEN 
      v_tax_account_code := '473000'; -- HP Impuesto Sociedades
      v_description := 'Pago Impuesto de Sociedades';
    ELSE
      RAISE EXCEPTION 'Tipo de impuesto no v├ílido: %', p_tax_type;
  END CASE;
  
  IF p_period IS NOT NULL THEN
    v_description := v_description || ' ' || p_period;
  END IF;
  
  -- Obtener c├│digo banco
  v_bank_code := accounting.get_bank_account_code(p_bank_account_id);
  IF v_bank_code IS NULL THEN
    v_bank_code := accounting.register_bank_account(p_bank_account_id, p_bank_name);
  END IF;
  
  -- Asegurar que existen las cuentas de impuestos
  INSERT INTO accounting.chart_of_accounts (account_code, account_name, account_type, is_active)
  VALUES 
    ('475000', 'HP IVA a pagar', 'LIABILITY', true),
    ('475100', 'HP Retenciones IRPF a ingresar', 'LIABILITY', true),
    ('473000', 'HP Impuesto sobre Sociedades', 'LIABILITY', true)
  ON CONFLICT (account_code) DO NOTHING;
  
  -- Crear asiento
  v_entry_number := accounting.get_next_entry_number();
  
  INSERT INTO accounting.journal_entries (
    entry_number,
    entry_date,
    entry_type,
    description,
    reference_type,
    is_automatic,
    is_locked,
    created_by
  ) VALUES (
    v_entry_number,
    p_payment_date,
    'TAX_PAYMENT',
    COALESCE(p_notes, v_description),
    'TAX_PAYMENT',
    FALSE,
    FALSE,
    v_authorized_user_id
  )
  RETURNING id INTO v_entry_id;
  
  -- DEBE: Cuenta de impuesto (reducimos deuda)
  INSERT INTO accounting.journal_entry_lines (
    journal_entry_id, line_order, account_code, description, amount, debit_credit
  ) VALUES (
    v_entry_id, 1, v_tax_account_code,
    v_description,
    p_amount, 'DEBIT'
  );
  
  -- HABER: Banco (sale dinero)
  INSERT INTO accounting.journal_entry_lines (
    journal_entry_id, line_order, account_code, description, amount, debit_credit
  ) VALUES (
    v_entry_id, 2, v_bank_code,
    'Pago ' || p_tax_type || ' desde ' || p_bank_name,
    p_amount, 'CREDIT'
  );
  
  RETURN QUERY SELECT v_entry_id, v_entry_number;
END;
$$;
ALTER FUNCTION "accounting"."create_tax_payment"("p_bank_account_id" "text", "p_bank_name" "text", "p_tax_type" "text", "p_amount" numeric, "p_payment_date" "date", "p_period" "text", "p_notes" "text") OWNER TO "postgres";
--
-- Name: FUNCTION "create_tax_payment"("p_bank_account_id" "text", "p_bank_name" "text", "p_tax_type" "text", "p_amount" numeric, "p_payment_date" "date", "p_period" "text", "p_notes" "text"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."create_tax_payment"("p_bank_account_id" "text", "p_bank_name" "text", "p_tax_type" "text", "p_amount" numeric, "p_payment_date" "date", "p_period" "text", "p_notes" "text") IS 'Registra pago de impuestos (IVA, IRPF, IS)';
--
-- Name: create_vat_settlement_entry("date", "date", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."create_vat_settlement_entry"("p_settlement_date" "date" DEFAULT CURRENT_DATE, "p_period_start" "date" DEFAULT NULL::"date", "p_period_end" "date" DEFAULT NULL::"date") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting'
    AS $$
DECLARE
  v_entry_id UUID;
  v_entry_number TEXT;
  v_vat_received NUMERIC(12,2) := 0;  -- IVA repercutido
  v_vat_paid NUMERIC(12,2) := 0;      -- IVA soportado
  v_vat_balance NUMERIC(12,2);        -- Diferencia
  v_period_filter TEXT;
  v_user_id UUID;
BEGIN
  -- Obtener usuario actual
  SELECT auth.uid() INTO v_user_id;
  
  -- Construir filtro de per├¡odo
  IF p_period_start IS NOT NULL AND p_period_end IS NOT NULL THEN
    v_period_filter := ' AND je.entry_date BETWEEN ''' || p_period_start || ''' AND ''' || p_period_end || '''';
  ELSE
    v_period_filter := '';
  END IF;
  
  -- Calcular IVA repercutido acumulado
  EXECUTE format('
    SELECT COALESCE(SUM(jel.amount), 0)
    FROM accounting.journal_entry_lines jel
    JOIN accounting.journal_entries je ON jel.journal_entry_id = je.id
    WHERE jel.account_code = ''477000''
      AND jel.debit_credit = ''CREDIT''
      %s
  ', v_period_filter) INTO v_vat_received;
  
  -- Calcular IVA soportado acumulado
  EXECUTE format('
    SELECT COALESCE(SUM(jel.amount), 0)
    FROM accounting.journal_entry_lines jel
    JOIN accounting.journal_entries je ON jel.journal_entry_id = je.id
    WHERE jel.account_code = ''472000''
      AND jel.debit_credit = ''DEBIT''
      %s
  ', v_period_filter) INTO v_vat_paid;
  
  v_vat_balance := v_vat_received - v_vat_paid;
  
  -- Generar n├║mero de asiento
  v_entry_number := accounting.get_next_entry_number();
  
  -- Crear asiento
  INSERT INTO accounting.journal_entries (
    entry_number,
    entry_date,
    entry_type,
    description,
    reference_type,
    created_by
  ) VALUES (
    v_entry_number,
    p_settlement_date,
    'TAX_SETTLEMENT',
    'Liquidaci├│n IVA - Per├¡odo: ' || COALESCE(p_period_start::TEXT, 'Total') || ' a ' || COALESCE(p_period_end::TEXT, 'Actual'),
    'vat_settlement',
    v_user_id
  ) RETURNING id INTO v_entry_id;
  
  -- DEBE: IVA repercutido (477000) - cerrar cuenta
  INSERT INTO accounting.journal_entry_lines (
    journal_entry_id,
    account_code,
    debit_credit,
    amount,
    description,
    line_order
  ) VALUES (
    v_entry_id,
    '477000',
    'DEBIT',
    v_vat_received,
    'Cierre IVA repercutido',
    1
  );
  
  -- HABER: IVA soportado (472000) - cerrar cuenta
  INSERT INTO accounting.journal_entry_lines (
    journal_entry_id,
    account_code,
    debit_credit,
    amount,
    description,
    line_order
  ) VALUES (
    v_entry_id,
    '472000',
    'CREDIT',
    v_vat_paid,
    'Cierre IVA soportado',
    2
  );
  
  -- Si hay diferencia, ir a Banco (572000)
  IF v_vat_balance != 0 THEN
    INSERT INTO accounting.journal_entry_lines (
      journal_entry_id,
      account_code,
      debit_credit,
      amount,
      description,
      line_order
    ) VALUES (
      v_entry_id,
      '572000',
      CASE WHEN v_vat_balance > 0 THEN 'DEBIT' ELSE 'CREDIT' END,
      ABS(v_vat_balance),
      CASE WHEN v_vat_balance > 0 THEN 'IVA a pagar' ELSE 'IVA a devolver' END,
      3
    );
  END IF;
  
  RETURN v_entry_id;
END;
$$;
ALTER FUNCTION "accounting"."create_vat_settlement_entry"("p_settlement_date" "date", "p_period_start" "date", "p_period_end" "date") OWNER TO "postgres";
--
-- Name: get_account_by_third_party_type("accounting"."third_party_type"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_account_by_third_party_type"("p_third_party_type" "accounting"."third_party_type") RETURNS "text"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'accounting', 'public'
    AS $$
BEGIN
  CASE p_third_party_type
    WHEN 'CLIENT' THEN
      RETURN '430000';
    WHEN 'SUPPLIER' THEN
      RETURN '400000';
    WHEN 'TECHNICIAN' THEN
      RETURN '410000';
    ELSE
      RETURN NULL;
  END CASE;
END;
$$;
ALTER FUNCTION "accounting"."get_account_by_third_party_type"("p_third_party_type" "accounting"."third_party_type") OWNER TO "postgres";
--
-- Name: get_balance_sheet("date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_balance_sheet"("p_as_of_date" "date" DEFAULT CURRENT_DATE) RETURNS TABLE("account_code" "text", "account_name" "text", "account_type" "text", "debit_balance" numeric, "credit_balance" numeric, "net_balance" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting'
    AS $$
  WITH entries AS (
    SELECT id
    FROM accounting.journal_entries
    WHERE entry_date <= p_as_of_date
  ),
  lines AS (
    SELECT jel.*
    FROM accounting.journal_entry_lines jel
    JOIN entries e ON e.id = jel.journal_entry_id
  )
  SELECT
    coa.account_code,
    coa.account_name,
    coa.account_type,
    COALESCE(SUM(CASE WHEN l.debit_credit = 'DEBIT' THEN l.amount ELSE 0 END), 0)::numeric(12,2) AS debit_balance,
    COALESCE(SUM(CASE WHEN l.debit_credit = 'CREDIT' THEN l.amount ELSE 0 END), 0)::numeric(12,2) AS credit_balance,
    CASE
      WHEN coa.account_type IN ('ASSET', 'EXPENSE') THEN
        COALESCE(SUM(CASE WHEN l.debit_credit = 'DEBIT' THEN l.amount ELSE -l.amount END), 0)
      ELSE
        COALESCE(SUM(CASE WHEN l.debit_credit = 'CREDIT' THEN l.amount ELSE -l.amount END), 0)
    END::numeric(12,2) AS net_balance
  FROM accounting.chart_of_accounts coa
  LEFT JOIN lines l ON l.account_code = coa.account_code
  WHERE coa.account_type IN ('ASSET', 'LIABILITY', 'EQUITY')
    AND coa.is_active = true
  GROUP BY coa.account_code, coa.account_name, coa.account_type
  ORDER BY coa.account_code;
$$;
ALTER FUNCTION "accounting"."get_balance_sheet"("p_as_of_date" "date") OWNER TO "postgres";
--
-- Name: FUNCTION "get_balance_sheet"("p_as_of_date" "date"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."get_balance_sheet"("p_as_of_date" "date") IS 'Balance de situaci├│n a fecha. Solo incluye asientos con entry_date <= p_as_of_date.';
--
-- Name: get_bank_account_code("text"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_bank_account_code"("p_bank_account_id" "text") RETURNS "text"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
BEGIN
  RETURN accounting.resolve_bank_accounting_code(p_bank_account_id);
END;
$$;
ALTER FUNCTION "accounting"."get_bank_account_code"("p_bank_account_id" "text") OWNER TO "postgres";
--
-- Name: get_bank_balance("text", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_bank_balance"("p_bank_account_id" "text", "p_as_of_date" "date" DEFAULT CURRENT_DATE) RETURNS numeric
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_bank_code TEXT;
  v_balance NUMERIC;
BEGIN
  v_bank_code := accounting.get_bank_account_code(p_bank_account_id);
  
  IF v_bank_code IS NULL THEN
    RETURN 0;
  END IF;
  
  SELECT COALESCE(SUM(
    CASE WHEN jel.debit_credit = 'DEBIT' THEN jel.amount ELSE -jel.amount END
  ), 0)
  INTO v_balance
  FROM accounting.journal_entry_lines jel
  JOIN accounting.journal_entries je ON je.id = jel.journal_entry_id
  WHERE jel.account_code = v_bank_code
    AND je.entry_date <= p_as_of_date;
  
  RETURN v_balance;
END;
$$;
ALTER FUNCTION "accounting"."get_bank_balance"("p_bank_account_id" "text", "p_as_of_date" "date") OWNER TO "postgres";
--
-- Name: FUNCTION "get_bank_balance"("p_bank_account_id" "text", "p_as_of_date" "date"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."get_bank_balance"("p_bank_account_id" "text", "p_as_of_date" "date") IS 'Obtiene saldo actual de un banco';
--
-- Name: get_bank_movements("text", "date", "date", integer); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_bank_movements"("p_bank_account_id" "text", "p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date", "p_limit" integer DEFAULT 100) RETURNS TABLE("entry_id" "uuid", "entry_number" "text", "entry_date" "date", "entry_type" "text", "description" "text", "amount" numeric, "movement_type" "text", "balance_after" numeric, "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_bank_code TEXT;
BEGIN
  v_bank_code := accounting.get_bank_account_code(p_bank_account_id);
  
  IF v_bank_code IS NULL THEN
    RETURN;
  END IF;
  
  RETURN QUERY
  WITH movements AS (
    SELECT 
      je.id AS entry_id,
      je.entry_number,
      je.entry_date,
      je.entry_type,
      je.description,
      jel.amount,
      jel.debit_credit,
      je.created_at
    FROM accounting.journal_entries je
    JOIN accounting.journal_entry_lines jel ON jel.journal_entry_id = je.id
    WHERE jel.account_code = v_bank_code
      AND (p_start_date IS NULL OR je.entry_date >= p_start_date)
      AND (p_end_date IS NULL OR je.entry_date <= p_end_date)
    ORDER BY je.entry_date ASC, je.created_at ASC
  ),
  with_balance AS (
    SELECT 
      m.*,
      CASE WHEN m.debit_credit = 'DEBIT' THEN 'IN' ELSE 'OUT' END AS mv_type,
      SUM(CASE WHEN m.debit_credit = 'DEBIT' THEN m.amount ELSE -m.amount END) 
        OVER (ORDER BY m.entry_date, m.created_at) AS running_balance
    FROM movements m
  )
  SELECT 
    wb.entry_id,
    wb.entry_number,
    wb.entry_date,
    wb.entry_type,
    wb.description,
    wb.amount,
    wb.mv_type,
    wb.running_balance,
    wb.created_at
  FROM with_balance wb
  ORDER BY wb.entry_date DESC, wb.created_at DESC
  LIMIT p_limit;
END;
$$;
ALTER FUNCTION "accounting"."get_bank_movements"("p_bank_account_id" "text", "p_start_date" "date", "p_end_date" "date", "p_limit" integer) OWNER TO "postgres";
--
-- Name: FUNCTION "get_bank_movements"("p_bank_account_id" "text", "p_start_date" "date", "p_end_date" "date", "p_limit" integer); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."get_bank_movements"("p_bank_account_id" "text", "p_start_date" "date", "p_end_date" "date", "p_limit" integer) IS 'Obtiene historial de movimientos de un banco';
--
-- Name: get_client_balances("date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_client_balances"("p_as_of_date" "date" DEFAULT CURRENT_DATE) RETURNS TABLE("client_id" "uuid", "client_number" "text", "client_name" "text", "debit_balance" numeric, "credit_balance" numeric, "net_balance" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
  WITH entries AS (
    SELECT id
    FROM accounting.journal_entries
    WHERE entry_date <= p_as_of_date
  ),
  lines AS (
    SELECT jel.*
    FROM accounting.journal_entry_lines jel
    JOIN entries e ON e.id = jel.journal_entry_id
  )
  SELECT
    c.id AS client_id,
    c.client_number,
    c.company_name AS client_name,
    COALESCE(SUM(CASE WHEN l.debit_credit = 'DEBIT' THEN l.amount ELSE 0 END), 0)::numeric(12,2) AS debit_balance,
    COALESCE(SUM(CASE WHEN l.debit_credit = 'CREDIT' THEN l.amount ELSE 0 END), 0)::numeric(12,2) AS credit_balance,
    COALESCE(SUM(CASE WHEN l.debit_credit = 'DEBIT' THEN l.amount ELSE -l.amount END), 0)::numeric(12,2) AS net_balance
  FROM crm.clients c
  LEFT JOIN lines l ON l.third_party_id = c.id
    AND l.third_party_type = 'CLIENT'
    AND l.account_code = '430000'
  WHERE c.deleted_at IS NULL
  GROUP BY c.id, c.client_number, c.company_name
  HAVING COALESCE(SUM(CASE WHEN l.debit_credit = 'DEBIT' THEN l.amount ELSE -l.amount END), 0) <> 0
  ORDER BY net_balance DESC;
$$;
ALTER FUNCTION "accounting"."get_client_balances"("p_as_of_date" "date") OWNER TO "postgres";
--
-- Name: FUNCTION "get_client_balances"("p_as_of_date" "date"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."get_client_balances"("p_as_of_date" "date") IS 'Saldos por cliente (430000) a fecha. Solo asientos con entry_date <= p_as_of_date.';
--
-- Name: get_corporate_tax_summary("date", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_corporate_tax_summary"("p_period_start" "date" DEFAULT NULL::"date", "p_period_end" "date" DEFAULT NULL::"date") RETURNS TABLE("profit_before_tax" numeric, "tax_rate" numeric, "tax_amount" numeric, "provision_entry_id" "uuid", "provision_entry_number" "text", "provision_date" "date")
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'accounting'
    AS $$
DECLARE
  v_tax_rate NUMERIC(5,2);
BEGIN
  -- Obtener tasa de IS configurada
  SELECT default_rate INTO v_tax_rate
  FROM accounting.tax_config
  WHERE tax_code = 'IS_25'
  LIMIT 1;
  
  IF v_tax_rate IS NULL THEN
    v_tax_rate := 25.00;
  END IF;
  
  -- Calcular BAI
  RETURN QUERY
  SELECT 
    pbt.profit_before_tax,
    v_tax_rate,
    CASE 
      WHEN pbt.profit_before_tax > 0 THEN pbt.profit_before_tax * (v_tax_rate / 100)
      ELSE 0
    END,
    je.id,
    je.entry_number,
    je.entry_date
  FROM accounting.calculate_profit_before_tax(p_period_start, p_period_end) pbt
  LEFT JOIN accounting.journal_entries je ON je.entry_type = 'TAX_PROVISION'
    AND (
      (p_period_start IS NULL AND p_period_end IS NULL) OR
      (je.entry_date BETWEEN p_period_start AND p_period_end)
    )
  ORDER BY je.created_at DESC
  LIMIT 1;
END;
$$;
ALTER FUNCTION "accounting"."get_corporate_tax_summary"("p_period_start" "date", "p_period_end" "date") OWNER TO "postgres";
--
-- Name: FUNCTION "get_corporate_tax_summary"("p_period_start" "date", "p_period_end" "date"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."get_corporate_tax_summary"("p_period_start" "date", "p_period_end" "date") IS 'Obtiene un resumen del c├ílculo de IS con la provisi├│n actual';
--
-- Name: get_irpf_by_period("date", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_irpf_by_period"("p_period_start" "date" DEFAULT NULL::"date", "p_period_end" "date" DEFAULT NULL::"date") RETURNS TABLE("period_year" integer, "period_month" integer, "total_irpf" numeric, "payroll_count" integer, "compensation_count" integer)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    pr.period_year,
    pr.period_month,
    COALESCE(SUM(pr.irpf_amount), 0) + COALESCE(SUM(pcr.irpf_amount), 0) as total_irpf,
    COUNT(DISTINCT pr.id)::INTEGER as payroll_count,
    COUNT(DISTINCT pcr.id)::INTEGER as compensation_count
  FROM accounting.payroll_runs pr
  FULL OUTER JOIN accounting.partner_compensation_runs pcr
    ON pr.period_year = pcr.period_year
    AND pr.period_month = pcr.period_month
  WHERE 
    (p_period_start IS NULL OR 
     (pr.period_year * 100 + pr.period_month >= EXTRACT(YEAR FROM p_period_start) * 100 + EXTRACT(MONTH FROM p_period_start)))
    AND (p_period_end IS NULL OR 
         (COALESCE(pr.period_year, pcr.period_year) * 100 + COALESCE(pr.period_month, pcr.period_month) <= EXTRACT(YEAR FROM p_period_end) * 100 + EXTRACT(MONTH FROM p_period_end)))
    AND (pr.status IN ('POSTED', 'PAID') OR pcr.status IN ('POSTED', 'PAID'))
  GROUP BY pr.period_year, pr.period_month, pcr.period_year, pcr.period_month
  ORDER BY COALESCE(pr.period_year, pcr.period_year) DESC, COALESCE(pr.period_month, pcr.period_month) DESC;
END;
$$;
ALTER FUNCTION "accounting"."get_irpf_by_period"("p_period_start" "date", "p_period_end" "date") OWNER TO "postgres";
--
-- Name: FUNCTION "get_irpf_by_period"("p_period_start" "date", "p_period_end" "date"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."get_irpf_by_period"("p_period_start" "date", "p_period_end" "date") IS 'Obtiene el IRPF retenido agrupado por per├¡odo (a├▒o/mes)';
--
-- Name: get_irpf_by_person("date", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_irpf_by_person"("p_period_start" "date" DEFAULT NULL::"date", "p_period_end" "date" DEFAULT NULL::"date") RETURNS TABLE("person_type" "text", "person_id" "uuid", "person_number" "text", "person_name" "text", "total_irpf" numeric, "total_gross" numeric, "total_net" numeric, "document_count" integer)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
BEGIN
  RETURN QUERY
  -- Empleados
  SELECT 
    'EMPLOYEE'::TEXT,
    e.id,
    e.employee_number,
    e.full_name,
    COALESCE(SUM(pr.irpf_amount), 0) as total_irpf,
    COALESCE(SUM(pr.gross_amount), 0) as total_gross,
    COALESCE(SUM(pr.net_amount), 0) as total_net,
    COUNT(pr.id)::INTEGER as document_count
  FROM internal.employees e
  LEFT JOIN accounting.payroll_runs pr ON pr.employee_id = e.id
    AND pr.status IN ('POSTED', 'PAID')
    AND (
      (p_period_start IS NULL AND p_period_end IS NULL) OR
      (pr.period_year * 100 + pr.period_month >= EXTRACT(YEAR FROM p_period_start) * 100 + EXTRACT(MONTH FROM p_period_start)
       AND pr.period_year * 100 + pr.period_month <= EXTRACT(YEAR FROM p_period_end) * 100 + EXTRACT(MONTH FROM p_period_end))
    )
  WHERE e.status = 'ACTIVE'
  GROUP BY e.id, e.employee_number, e.full_name
  HAVING COALESCE(SUM(pr.irpf_amount), 0) > 0
  
  UNION ALL
  
  -- Socios
  SELECT 
    'PARTNER'::TEXT,
    p.id,
    p.partner_number,
    p.full_name,
    COALESCE(SUM(pcr.irpf_amount), 0) as total_irpf,
    COALESCE(SUM(pcr.gross_amount), 0) as total_gross,
    COALESCE(SUM(pcr.net_amount), 0) as total_net,
    COUNT(pcr.id)::INTEGER as document_count
  FROM internal.partners p
  LEFT JOIN accounting.partner_compensation_runs pcr ON pcr.partner_id = p.id
    AND pcr.status IN ('POSTED', 'PAID')
    AND (
      (p_period_start IS NULL AND p_period_end IS NULL) OR
      (pcr.period_year * 100 + pcr.period_month >= EXTRACT(YEAR FROM p_period_start) * 100 + EXTRACT(MONTH FROM p_period_start)
       AND pcr.period_year * 100 + pcr.period_month <= EXTRACT(YEAR FROM p_period_end) * 100 + EXTRACT(MONTH FROM p_period_end))
    )
  WHERE p.status = 'ACTIVE'
  GROUP BY p.id, p.partner_number, p.full_name
  HAVING COALESCE(SUM(pcr.irpf_amount), 0) > 0
  
  ORDER BY total_irpf DESC;
END;
$$;
ALTER FUNCTION "accounting"."get_irpf_by_person"("p_period_start" "date", "p_period_end" "date") OWNER TO "postgres";
--
-- Name: FUNCTION "get_irpf_by_person"("p_period_start" "date", "p_period_end" "date"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."get_irpf_by_person"("p_period_start" "date", "p_period_end" "date") IS 'Obtiene el IRPF retenido agrupado por persona (empleado/socio)';
--
-- Name: get_irpf_model_111_summary("date", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_irpf_model_111_summary"("p_period_start" "date" DEFAULT NULL::"date", "p_period_end" "date" DEFAULT NULL::"date") RETURNS TABLE("total_irpf_accumulated" numeric, "total_payroll_irpf" numeric, "total_compensation_irpf" numeric, "total_documents" integer, "total_employees" integer, "total_partners" integer)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting'
    AS $$
DECLARE
  v_start_filter TEXT;
  v_end_filter TEXT;
BEGIN
  -- Construir filtros
  IF p_period_start IS NOT NULL AND p_period_end IS NOT NULL THEN
    v_start_filter := ' AND (pr.period_year * 100 + pr.period_month >= ' || 
                      EXTRACT(YEAR FROM p_period_start) * 100 + EXTRACT(MONTH FROM p_period_start) || ')';
    v_end_filter := ' AND (COALESCE(pr.period_year, pcr.period_year) * 100 + COALESCE(pr.period_month, pcr.period_month) <= ' ||
                    EXTRACT(YEAR FROM p_period_end) * 100 + EXTRACT(MONTH FROM p_period_end) || ')';
  ELSE
    v_start_filter := '';
    v_end_filter := '';
  END IF;
  
  RETURN QUERY
  EXECUTE format('
    SELECT 
      COALESCE(SUM(pr.irpf_amount), 0) + COALESCE(SUM(pcr.irpf_amount), 0) as total_irpf_accumulated,
      COALESCE(SUM(pr.irpf_amount), 0) as total_payroll_irpf,
      COALESCE(SUM(pcr.irpf_amount), 0) as total_compensation_irpf,
      (COUNT(DISTINCT pr.id) + COUNT(DISTINCT pcr.id))::INTEGER as total_documents,
      COUNT(DISTINCT pr.employee_id)::INTEGER as total_employees,
      COUNT(DISTINCT pcr.partner_id)::INTEGER as total_partners
    FROM accounting.payroll_runs pr
    FULL OUTER JOIN accounting.partner_compensation_runs pcr
      ON pr.period_year = pcr.period_year
      AND pr.period_month = pcr.period_month
    WHERE (pr.status IN (''POSTED'', ''PAID'') OR pcr.status IN (''POSTED'', ''PAID''))
      %s %s
  ', v_start_filter, v_end_filter);
END;
$$;
ALTER FUNCTION "accounting"."get_irpf_model_111_summary"("p_period_start" "date", "p_period_end" "date") OWNER TO "postgres";
--
-- Name: FUNCTION "get_irpf_model_111_summary"("p_period_start" "date", "p_period_end" "date"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."get_irpf_model_111_summary"("p_period_start" "date", "p_period_end" "date") IS 'Obtiene el resumen total de IRPF para el Modelo 111';
--
-- Name: get_irpf_summary("date", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_irpf_summary"("p_period_start" "date" DEFAULT NULL::"date", "p_period_end" "date" DEFAULT NULL::"date") RETURNS TABLE("irpf_accumulated" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting'
    AS $$
DECLARE
  v_period_filter TEXT;
  v_irpf NUMERIC(12,2) := 0;
BEGIN
  -- Construir filtro de per├¡odo
  IF p_period_start IS NOT NULL AND p_period_end IS NOT NULL THEN
    v_period_filter := ' AND je.entry_date BETWEEN ''' || p_period_start || ''' AND ''' || p_period_end || '''';
  ELSE
    v_period_filter := '';
  END IF;
  
  -- Calcular IRPF acumulado
  EXECUTE format('
    SELECT COALESCE(SUM(jel.amount), 0)
    FROM accounting.journal_entry_lines jel
    JOIN accounting.journal_entries je ON jel.journal_entry_id = je.id
    WHERE jel.account_code = ''475100''
      AND jel.debit_credit = ''CREDIT''
      %s
  ', v_period_filter) INTO v_irpf;
  
  RETURN QUERY SELECT v_irpf;
END;
$$;
ALTER FUNCTION "accounting"."get_irpf_summary"("p_period_start" "date", "p_period_end" "date") OWNER TO "postgres";
--
-- Name: FUNCTION "get_irpf_summary"("p_period_start" "date", "p_period_end" "date"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."get_irpf_summary"("p_period_start" "date", "p_period_end" "date") IS 'Obtiene el IRPF acumulado';
--
-- Name: get_monthly_closure_report_dataset(integer, integer); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_monthly_closure_report_dataset"("p_year" integer, "p_month" integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_start date;
  v_end date;
  v_closed boolean;
  v_result jsonb;
  v_profit_summary jsonb;
  v_profit_loss jsonb;
  v_balance_sheet jsonb;
  v_journal_entries jsonb;
  v_vat jsonb;
  v_irpf numeric;
  v_corporate_tax jsonb;
  v_clients jsonb;
  v_suppliers jsonb;
  v_payroll jsonb;
  v_compensations jsonb;
  v_cash_movements jsonb;
  v_company jsonb;
BEGIN
  v_start := make_date(p_year, p_month, 1);
  v_end := (v_start + interval '1 month' - interval '1 day')::date;

  SELECT accounting.is_period_closed(p_year, p_month) INTO v_closed;
  IF NOT v_closed THEN
    RAISE EXCEPTION 'El per├¡odo %/% no est├í cerrado o no est├í bloqueado', p_year, p_month;
  END IF;

  SELECT to_jsonb(r) INTO v_profit_summary
  FROM (SELECT * FROM accounting.get_period_profit_summary(v_start, v_end) LIMIT 1) r;

  SELECT jsonb_agg(to_jsonb(r)) INTO v_profit_loss
  FROM (SELECT * FROM public.get_profit_loss(v_start, v_end)) r;

  SELECT jsonb_agg(to_jsonb(r)) INTO v_balance_sheet
  FROM (SELECT * FROM public.get_balance_sheet(v_end)) r;

  SELECT jsonb_agg(entry_with_lines ORDER BY entry_date, entry_number) INTO v_journal_entries
  FROM (
    SELECT jsonb_build_object(
      'entry_number', je.entry_number,
      'entry_date', je.entry_date,
      'entry_type', je.entry_type,
      'description', je.description,
      'total_debit', je.total_debit,
      'total_credit', je.total_credit,
      'lines', COALESCE(lines_agg.lines, '[]'::jsonb)
    ) as entry_with_lines,
    je.entry_date,
    je.entry_number
    FROM (
      SELECT je2.id, je2.entry_number, je2.entry_date, je2.entry_type, je2.description,
        SUM(CASE WHEN jel.debit_credit = 'DEBIT' THEN jel.amount ELSE 0 END) as total_debit,
        SUM(CASE WHEN jel.debit_credit = 'CREDIT' THEN jel.amount ELSE 0 END) as total_credit
      FROM accounting.journal_entries je2
      LEFT JOIN accounting.journal_entry_lines jel ON jel.journal_entry_id = je2.id
      WHERE je2.entry_date BETWEEN v_start AND v_end
      GROUP BY je2.id, je2.entry_number, je2.entry_date, je2.entry_type, je2.description
    ) je
    LEFT JOIN LATERAL (
      SELECT jsonb_agg(jsonb_build_object(
        'account_code', jel.account_code,
        'account_name', ca.account_name,
        'debit_credit', jel.debit_credit,
        'amount', jel.amount,
        'description', jel.description
      ) ORDER BY jel.line_order) as lines
      FROM accounting.journal_entry_lines jel
      JOIN accounting.chart_of_accounts ca ON ca.account_code = jel.account_code
      WHERE jel.journal_entry_id = je.id
    ) lines_agg ON true
  ) sub;

  SELECT to_jsonb(r) INTO v_vat
  FROM (SELECT * FROM public.get_vat_summary(v_start, v_end) LIMIT 1) r;

  SELECT public.get_irpf_summary(v_start, v_end) INTO v_irpf;

  SELECT to_jsonb(r) INTO v_corporate_tax
  FROM (SELECT * FROM public.get_corporate_tax_summary(v_start, v_end) LIMIT 1) r;

  SELECT jsonb_agg(to_jsonb(r)) INTO v_clients
  FROM (SELECT * FROM public.get_client_balances(v_end)) r;

  SELECT jsonb_agg(to_jsonb(r)) INTO v_suppliers
  FROM (SELECT * FROM public.get_supplier_technician_balances(v_end)) r;

  SELECT jsonb_agg(to_jsonb(r)) INTO v_payroll
  FROM (SELECT * FROM public.list_payroll_runs(p_period_year => p_year, p_period_month => p_month)) r;

  SELECT jsonb_agg(to_jsonb(r)) INTO v_compensations
  FROM (SELECT * FROM public.list_partner_compensation_runs(p_period_year => p_year, p_period_month => p_month)) r;

  BEGIN
    SELECT jsonb_agg(to_jsonb(r)) INTO v_cash_movements
    FROM (SELECT * FROM public.list_cash_movements(v_start, v_end)) r;
  EXCEPTION WHEN undefined_function OR OTHERS THEN
    v_cash_movements := '[]'::jsonb;
  END;

  SELECT to_jsonb(r) INTO v_company
  FROM (SELECT legal_name, tax_id, commercial_name, fiscal_address, fiscal_city FROM internal.company_settings LIMIT 1) r;

  v_result := jsonb_build_object(
    'period', jsonb_build_object('year', p_year, 'month', p_month, 'start', v_start, 'end', v_end),
    'company', v_company,
    'profit_summary', v_profit_summary,
    'profit_loss', COALESCE(v_profit_loss, '[]'::jsonb),
    'balance_sheet', COALESCE(v_balance_sheet, '[]'::jsonb),
    'journal_entries', COALESCE(v_journal_entries, '[]'::jsonb),
    'vat_summary', v_vat,
    'irpf_summary', v_irpf,
    'corporate_tax_summary', v_corporate_tax,
    'client_balances', COALESCE(v_clients, '[]'::jsonb),
    'supplier_balances', COALESCE(v_suppliers, '[]'::jsonb),
    'payroll_runs', COALESCE(v_payroll, '[]'::jsonb),
    'partner_compensations', COALESCE(v_compensations, '[]'::jsonb),
    'cash_movements', COALESCE(v_cash_movements, '[]'::jsonb),
    'dataset_version', 'v1'
  );

  RETURN v_result;
END;
$$;
ALTER FUNCTION "accounting"."get_monthly_closure_report_dataset"("p_year" integer, "p_month" integer) OWNER TO "postgres";
--
-- Name: get_next_bank_account_code(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_next_bank_account_code"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_last_code TEXT;
  v_next_number INT;
BEGIN
  -- Buscar el ├║ltimo c├│digo 572.xxx usado
  SELECT account_code INTO v_last_code
  FROM accounting.chart_of_accounts
  WHERE account_code LIKE '572.%'
  ORDER BY account_code DESC
  LIMIT 1;
  
  IF v_last_code IS NULL THEN
    -- Primera cuenta bancaria
    RETURN '572.001';
  ELSE
    -- Extraer n├║mero y sumar 1
    v_next_number := CAST(SUBSTRING(v_last_code FROM 5) AS INT) + 1;
    RETURN '572.' || LPAD(v_next_number::TEXT, 3, '0');
  END IF;
END;
$$;
ALTER FUNCTION "accounting"."get_next_bank_account_code"() OWNER TO "postgres";
--
-- Name: get_next_compensation_number(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_next_compensation_number"() RETURNS "text"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'accounting'
    AS $$
DECLARE
  v_year INTEGER;
  v_month INTEGER;
  v_number INTEGER;
  v_compensation_number TEXT;
BEGIN
  v_year := EXTRACT(YEAR FROM CURRENT_DATE);
  v_month := EXTRACT(MONTH FROM CURRENT_DATE);
  
  SELECT COALESCE(MAX(CAST(SUBSTRING(pcr.compensation_number FROM 13 FOR 4) AS INTEGER)), 0) + 1
  INTO v_number
  FROM accounting.partner_compensation_runs pcr
  WHERE pcr.compensation_number LIKE 'RET-' || v_year || LPAD(v_month::TEXT, 2, '0') || '-%';
  
  v_compensation_number := 'RET-' || v_year || LPAD(v_month::TEXT, 2, '0') || '-' || LPAD(v_number::TEXT, 4, '0');
  
  RETURN v_compensation_number;
END;
$$;
ALTER FUNCTION "accounting"."get_next_compensation_number"() OWNER TO "postgres";
--
-- Name: get_next_entry_number(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_next_entry_number"() RETURNS "text"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'accounting'
    AS $_$
DECLARE
  v_year INTEGER;
  v_number INTEGER;
  v_entry_number TEXT;
BEGIN
  v_year := EXTRACT(YEAR FROM CURRENT_DATE);
  
  SELECT COALESCE(MAX(
    CAST(SUBSTRING(je.entry_number FROM '[0-9]+$') AS INTEGER)
  ), 0) + 1
  INTO v_number
  FROM accounting.journal_entries je
  WHERE je.entry_number ~ ('^AS-' || v_year || '-[0-9]+$');
  
  v_entry_number := 'AS-' || v_year || '-' || LPAD(v_number::TEXT, 4, '0');
  
  RETURN v_entry_number;
END;
$_$;
ALTER FUNCTION "accounting"."get_next_entry_number"() OWNER TO "postgres";
--
-- Name: FUNCTION "get_next_entry_number"(); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."get_next_entry_number"() IS 'Genera el siguiente n├║mero de asiento ├║nico usando secuencia de PostgreSQL';
--
-- Name: get_next_entry_number(integer); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_next_entry_number"("p_fiscal_year" integer) RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $_$
DECLARE
  v_next_number INTEGER;
  v_entry_number TEXT;
BEGIN
  -- Get the max entry number for the fiscal year
  SELECT COALESCE(MAX(
    CASE 
      WHEN entry_number ~ ('^A-' || p_fiscal_year || '-[0-9]+$') 
      THEN CAST(SUBSTRING(entry_number FROM '[0-9]+$') AS INTEGER)
      ELSE 0
    END
  ), 0) + 1
  INTO v_next_number
  FROM accounting.journal_entries
  WHERE EXTRACT(YEAR FROM entry_date) = p_fiscal_year;

  -- Format: A-YYYY-XXXX
  v_entry_number := 'A-' || p_fiscal_year || '-' || LPAD(v_next_number::TEXT, 4, '0');
  
  RETURN v_entry_number;
END;
$_$;
ALTER FUNCTION "accounting"."get_next_entry_number"("p_fiscal_year" integer) OWNER TO "postgres";
