-- Name: FUNCTION "get_supplier_technician_balances"("p_as_of_date" "date"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."get_supplier_technician_balances"("p_as_of_date" "date") IS 'Saldos proveedores/t├®cnicos (400000/410000) a fecha. Solo asientos con entry_date <= p_as_of_date.';
--
-- Name: get_vat_summary("date", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."get_vat_summary"("p_period_start" "date" DEFAULT NULL::"date", "p_period_end" "date" DEFAULT NULL::"date") RETURNS TABLE("vat_received" numeric, "vat_paid" numeric, "vat_balance" numeric, "vat_to_pay" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting'
    AS $$
DECLARE
  v_period_filter TEXT;
  v_vat_received NUMERIC(12,2) := 0;
  v_vat_paid NUMERIC(12,2) := 0;
BEGIN
  -- Construir filtro de per├¡odo
  IF p_period_start IS NOT NULL AND p_period_end IS NOT NULL THEN
    v_period_filter := ' AND je.entry_date BETWEEN ''' || p_period_start || ''' AND ''' || p_period_end || '''';
  ELSE
    v_period_filter := '';
  END IF;
  
  -- Calcular IVA repercutido
  EXECUTE format('
    SELECT COALESCE(SUM(jel.amount), 0)
    FROM accounting.journal_entry_lines jel
    JOIN accounting.journal_entries je ON jel.journal_entry_id = je.id
    WHERE jel.account_code = ''477000''
      AND jel.debit_credit = ''CREDIT''
      %s
  ', v_period_filter) INTO v_vat_received;
  
  -- Calcular IVA soportado
  EXECUTE format('
    SELECT COALESCE(SUM(jel.amount), 0)
    FROM accounting.journal_entry_lines jel
    JOIN accounting.journal_entries je ON jel.journal_entry_id = je.id
    WHERE jel.account_code = ''472000''
      AND jel.debit_credit = ''DEBIT''
      %s
  ', v_period_filter) INTO v_vat_paid;
  
  RETURN QUERY SELECT 
    v_vat_received,
    v_vat_paid,
    v_vat_received - v_vat_paid,
    CASE WHEN v_vat_received - v_vat_paid > 0 THEN v_vat_received - v_vat_paid ELSE 0 END;
END;
$$;
ALTER FUNCTION "accounting"."get_vat_summary"("p_period_start" "date", "p_period_end" "date") OWNER TO "postgres";
--
-- Name: FUNCTION "get_vat_summary"("p_period_start" "date", "p_period_end" "date"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."get_vat_summary"("p_period_start" "date", "p_period_end" "date") IS 'Obtiene resumen de IVA repercutido vs soportado';
