--
-- Name: list_bank_account_movements("text", "date", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."list_bank_account_movements"("p_account_code" "text", "p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date") RETURNS TABLE("id" "uuid", "entry_number" "text", "entry_date" "date", "entry_type" "text", "description" "text", "debit_amount" numeric, "credit_amount" numeric, "running_balance" numeric, "reference_id" "uuid", "reference_type" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
BEGIN
  RETURN QUERY
  WITH movements AS (
    SELECT 
      je.id,
      je.entry_number,
      je.entry_date,
      je.entry_type::TEXT as entry_type,
      je.description,
      CASE WHEN jel.debit_credit = 'DEBIT' THEN jel.amount ELSE 0 END as debit_amount,
      CASE WHEN jel.debit_credit = 'CREDIT' THEN jel.amount ELSE 0 END as credit_amount,
      je.reference_id,
      je.reference_type
    FROM accounting.journal_entries je
    JOIN accounting.journal_entry_lines jel ON jel.journal_entry_id = je.id
    WHERE jel.account_code = p_account_code
      AND (p_start_date IS NULL OR je.entry_date >= p_start_date)
      AND (p_end_date IS NULL OR je.entry_date <= p_end_date)
  )
  SELECT 
    m.id,
    m.entry_number,
    m.entry_date,
    m.entry_type,
    m.description,
    m.debit_amount,
    m.credit_amount,
    SUM(m.debit_amount - m.credit_amount) OVER (ORDER BY m.entry_date, m.entry_number) as running_balance,
    m.reference_id,
    m.reference_type
  FROM movements m
  ORDER BY m.entry_date, m.entry_number;
END;
$$;
ALTER FUNCTION "accounting"."list_bank_account_movements"("p_account_code" "text", "p_start_date" "date", "p_end_date" "date") OWNER TO "postgres";
--
-- Name: list_bank_accounts_with_balances("date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."list_bank_accounts_with_balances"("p_as_of_date" "date" DEFAULT CURRENT_DATE) RETURNS TABLE("bank_account_id" "text", "account_code" "text", "bank_name" "text", "balance" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    cba.id::text AS bank_account_id,
    cba.accounting_code AS account_code,
    cba.bank_name AS bank_name,
    COALESCE(SUM(
      CASE WHEN jel.debit_credit = 'DEBIT' THEN jel.amount ELSE -jel.amount END
    ), 0) AS balance
  FROM internal.company_bank_accounts cba
  LEFT JOIN accounting.journal_entry_lines jel ON jel.account_code = cba.accounting_code
  LEFT JOIN accounting.journal_entries je ON je.id = jel.journal_entry_id 
    AND je.entry_date <= p_as_of_date
  WHERE cba.is_active = true
  GROUP BY cba.id, cba.accounting_code, cba.bank_name
  ORDER BY cba.accounting_code;
END;
$$;
