--
-- Name: list_journal_entries("date", "date", "accounting"."journal_entry_type", "uuid", integer, integer); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."list_journal_entries"("p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date", "p_entry_type" "accounting"."journal_entry_type" DEFAULT NULL::"accounting"."journal_entry_type", "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_limit" integer DEFAULT 100, "p_offset" integer DEFAULT 0) RETURNS TABLE("id" "uuid", "entry_number" "text", "entry_date" "date", "entry_type" "text", "description" "text", "reference_id" "uuid", "reference_type" "text", "project_id" "uuid", "project_name" "text", "is_locked" boolean, "created_by_name" "text", "created_at" timestamp with time zone, "total_debit" numeric, "total_credit" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    je.id,
    je.entry_number,
    je.entry_date,
    je.entry_type::TEXT,
    je.description,
    je.reference_id,
    je.reference_type,
    je.project_id,
    p.title as project_name,
    je.is_locked,
    au.full_name as created_by_name,
    je.created_at,
    COALESCE(SUM(CASE WHEN jel.debit_credit = 'DEBIT' THEN jel.amount ELSE 0 END), 0) as total_debit,
    COALESCE(SUM(CASE WHEN jel.debit_credit = 'CREDIT' THEN jel.amount ELSE 0 END), 0) as total_credit
  FROM accounting.journal_entries je
  LEFT JOIN projects.projects p ON je.project_id = p.id
  LEFT JOIN internal.authorized_users au ON je.created_by = au.id
  LEFT JOIN accounting.journal_entry_lines jel ON jel.journal_entry_id = je.id
  WHERE 
    (p_start_date IS NULL OR je.entry_date >= p_start_date)
    AND (p_end_date IS NULL OR je.entry_date <= p_end_date)
    AND (p_entry_type IS NULL OR je.entry_type = p_entry_type)
    AND (p_project_id IS NULL OR je.project_id = p_project_id)
  GROUP BY je.id, je.entry_number, je.entry_date, je.entry_type, je.description, 
           je.reference_id, je.reference_type, je.project_id, p.title, 
           je.is_locked, au.full_name, je.created_at
  ORDER BY je.entry_date DESC, je.entry_number DESC
  LIMIT p_limit
  OFFSET p_offset;
END;
$$;
ALTER FUNCTION "accounting"."list_journal_entries"("p_start_date" "date", "p_end_date" "date", "p_entry_type" "accounting"."journal_entry_type", "p_project_id" "uuid", "p_limit" integer, "p_offset" integer) OWNER TO "postgres";
--
-- Name: FUNCTION "list_journal_entries"("p_start_date" "date", "p_end_date" "date", "p_entry_type" "accounting"."journal_entry_type", "p_project_id" "uuid", "p_limit" integer, "p_offset" integer); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."list_journal_entries"("p_start_date" "date", "p_end_date" "date", "p_entry_type" "accounting"."journal_entry_type", "p_project_id" "uuid", "p_limit" integer, "p_offset" integer) IS 'Lista asientos contables con filtros';
--
-- Name: list_journal_entry_lines_by_period("date", "date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."list_journal_entry_lines_by_period"("p_start_date" "date", "p_end_date" "date") RETURNS TABLE("entry_id" "uuid", "entry_number" "text", "entry_date" "date", "entry_type" "text", "description" "text", "is_locked" boolean, "source_type" "text", "source_id" "uuid", "line_id" "uuid", "account_code" "text", "account_name" "text", "line_description" "text", "debit" numeric, "credit" numeric)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting'
    AS $$
  SELECT
    je.id AS entry_id,
    je.entry_number,
    je.entry_date,
    je.entry_type::text,
    je.description,
    je.is_locked,
    je.reference_type AS source_type,
    je.reference_id AS source_id,
    jel.id AS line_id,
    jel.account_code,
    coa.account_name,
    jel.description AS line_description,
    CASE WHEN jel.debit_credit = 'DEBIT' THEN jel.amount ELSE 0 END AS debit,
    CASE WHEN jel.debit_credit = 'CREDIT' THEN jel.amount ELSE 0 END AS credit
  FROM accounting.journal_entries je
  JOIN accounting.journal_entry_lines jel ON jel.journal_entry_id = je.id
  LEFT JOIN accounting.chart_of_accounts coa ON coa.account_code = jel.account_code
  WHERE je.entry_date >= p_start_date AND je.entry_date <= p_end_date
  ORDER BY je.entry_date, je.entry_number, jel.id;
$$;
ALTER FUNCTION "accounting"."list_journal_entry_lines_by_period"("p_start_date" "date", "p_end_date" "date") OWNER TO "postgres";
--
-- Name: list_partner_compensation_runs(integer, integer, "uuid", "text", integer, integer); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."list_partner_compensation_runs"("p_period_year" integer DEFAULT NULL::integer, "p_period_month" integer DEFAULT NULL::integer, "p_partner_id" "uuid" DEFAULT NULL::"uuid", "p_status" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 100, "p_offset" integer DEFAULT 0) RETURNS TABLE("id" "uuid", "compensation_number" "text", "period_year" integer, "period_month" integer, "partner_id" "uuid", "partner_number" "text", "partner_name" "text", "gross_amount" numeric, "irpf_rate" numeric, "irpf_amount" numeric, "net_amount" numeric, "status" "text", "journal_entry_id" "uuid", "journal_entry_number" "text", "created_at" timestamp with time zone, "notes" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    pcr.id,
    pcr.compensation_number,
    pcr.period_year,
    pcr.period_month,
    pcr.partner_id,
    p.partner_number,
    p.full_name,
    pcr.gross_amount,
    pcr.irpf_rate,
    pcr.irpf_amount,
    pcr.net_amount,
    pcr.status,
    pcr.journal_entry_id,
    je.entry_number,
    pcr.created_at,
    pcr.notes
  FROM internal.partner_compensation_runs pcr
  JOIN internal.partners p ON pcr.partner_id = p.id
  LEFT JOIN accounting.journal_entries je ON pcr.journal_entry_id = je.id
  WHERE 
    (p_period_year IS NULL OR pcr.period_year = p_period_year)
    AND (p_period_month IS NULL OR pcr.period_month = p_period_month)
    AND (p_partner_id IS NULL OR pcr.partner_id = p_partner_id)
    AND (p_status IS NULL OR pcr.status = p_status)
  ORDER BY pcr.period_year DESC, pcr.period_month DESC, pcr.created_at DESC
  LIMIT p_limit OFFSET p_offset;
END;
$$;
ALTER FUNCTION "accounting"."list_partner_compensation_runs"("p_period_year" integer, "p_period_month" integer, "p_partner_id" "uuid", "p_status" "text", "p_limit" integer, "p_offset" integer) OWNER TO "postgres";
--
-- Name: list_payroll_payments("uuid", "uuid", "date", "date", integer, integer); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."list_payroll_payments"("p_payroll_run_id" "uuid" DEFAULT NULL::"uuid", "p_partner_compensation_run_id" "uuid" DEFAULT NULL::"uuid", "p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date", "p_limit" integer DEFAULT 100, "p_offset" integer DEFAULT 0) RETURNS TABLE("id" "uuid", "payment_number" "text", "payment_date" "date", "amount" numeric, "payment_method" "text", "bank_reference" "text", "payroll_run_id" "uuid", "payroll_number" "text", "partner_compensation_run_id" "uuid", "compensation_number" "text", "journal_entry_id" "uuid", "journal_entry_number" "text", "created_at" timestamp with time zone, "bank_name" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    pp.id,
    pp.payment_number,
    pp.payment_date,
    pp.amount,
    pp.payment_method,
    pp.bank_reference,
    pp.payroll_run_id,
    pr.payroll_number,
    pp.partner_compensation_run_id,
    COALESCE(internal_pcr.compensation_number, accounting_pcr.compensation_number) AS compensation_number,
    pp.journal_entry_id,
    je.entry_number,
    pp.created_at,
    (
      SELECT jel.description
      FROM accounting.journal_entry_lines jel
      WHERE jel.journal_entry_id = pp.journal_entry_id
        AND jel.account_code LIKE '572%'
        AND jel.debit_credit = 'CREDIT'
      LIMIT 1
    ) AS bank_name
  FROM accounting.payroll_payments pp
  LEFT JOIN accounting.payroll_runs pr ON pp.payroll_run_id = pr.id
  LEFT JOIN internal.partner_compensation_runs internal_pcr ON pp.partner_compensation_run_id = internal_pcr.id
  LEFT JOIN accounting.partner_compensation_runs accounting_pcr ON pp.partner_compensation_run_id = accounting_pcr.id
  LEFT JOIN accounting.journal_entries je ON pp.journal_entry_id = je.id
  WHERE 
    (p_payroll_run_id IS NULL OR pp.payroll_run_id = p_payroll_run_id)
    AND (p_partner_compensation_run_id IS NULL OR pp.partner_compensation_run_id = p_partner_compensation_run_id)
    AND (p_start_date IS NULL OR pp.payment_date >= p_start_date)
    AND (p_end_date IS NULL OR pp.payment_date <= p_end_date)
  ORDER BY pp.payment_date DESC, pp.created_at DESC
  LIMIT p_limit
  OFFSET p_offset;
END;
$$;
ALTER FUNCTION "accounting"."list_payroll_payments"("p_payroll_run_id" "uuid", "p_partner_compensation_run_id" "uuid", "p_start_date" "date", "p_end_date" "date", "p_limit" integer, "p_offset" integer) OWNER TO "postgres";
--
-- Name: list_payroll_runs(integer, integer, "uuid", "text", integer, integer); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."list_payroll_runs"("p_period_year" integer DEFAULT NULL::integer, "p_period_month" integer DEFAULT NULL::integer, "p_employee_id" "uuid" DEFAULT NULL::"uuid", "p_status" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 100, "p_offset" integer DEFAULT 0) RETURNS TABLE("id" "uuid", "payroll_number" "text", "period_year" integer, "period_month" integer, "employee_id" "uuid", "employee_number" "text", "employee_name" "text", "gross_amount" numeric, "irpf_rate" numeric, "irpf_amount" numeric, "net_amount" numeric, "status" "text", "journal_entry_id" "uuid", "journal_entry_number" "text", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    pr.id,
    pr.payroll_number,
    pr.period_year,
    pr.period_month,
    pr.employee_id,
    e.employee_number,
    e.full_name,
    pr.gross_amount,
    pr.irpf_rate,
    pr.irpf_amount,
    pr.net_amount,
    pr.status,
    pr.journal_entry_id,
    je.entry_number,  -- Calificado expl├¡citamente para evitar ambig├╝edad
    pr.created_at
  FROM accounting.payroll_runs pr
  JOIN internal.employees e ON pr.employee_id = e.id
  LEFT JOIN accounting.journal_entries je ON pr.journal_entry_id = je.id
  WHERE 
    (p_period_year IS NULL OR pr.period_year = p_period_year)
    AND (p_period_month IS NULL OR pr.period_month = p_period_month)
    AND (p_employee_id IS NULL OR pr.employee_id = p_employee_id)
    AND (p_status IS NULL OR pr.status = p_status)
  ORDER BY pr.period_year DESC, pr.period_month DESC, pr.created_at DESC
  LIMIT p_limit
  OFFSET p_offset;
END;
$$;
ALTER FUNCTION "accounting"."list_payroll_runs"("p_period_year" integer, "p_period_month" integer, "p_employee_id" "uuid", "p_status" "text", "p_limit" integer, "p_offset" integer) OWNER TO "postgres";
--
-- Name: list_periods_for_closure(integer); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."list_periods_for_closure"("p_months_back" integer DEFAULT 24) RETURNS TABLE("year" integer, "month" integer, "period_start" "date", "period_end" "date", "is_closed" boolean, "closed_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting'
    AS $$
  WITH current_year AS (
    SELECT EXTRACT(YEAR FROM CURRENT_DATE)::INTEGER AS y
  ),
  months AS (
    SELECT
      cy.y AS year,
      m.month,
      make_date(cy.y, m.month, 1) AS period_start,
      (make_date(cy.y, m.month, 1) + interval '1 month' - interval '1 day')::date AS period_end
    FROM current_year cy
    CROSS JOIN generate_series(1, 12) AS m(month)
  )
  SELECT
    m.year,
    m.month,
    m.period_start,
    m.period_end,
    (pc.id IS NOT NULL AND pc.is_locked = true) AS is_closed,
    pc.closed_at
  FROM months m
  LEFT JOIN accounting.period_closures pc ON pc.year = m.year AND pc.month = m.month
  ORDER BY m.month ASC;
$$;
ALTER FUNCTION "accounting"."list_periods_for_closure"("p_months_back" integer) OWNER TO "postgres";
--
-- Name: open_period(integer, integer); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."open_period"("p_year" integer, "p_month" integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_user_id UUID;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;

  UPDATE accounting.period_closures
  SET is_locked = false
  WHERE year = p_year AND month = p_month;
END;
$$;
ALTER FUNCTION "accounting"."open_period"("p_year" integer, "p_month" integer) OWNER TO "postgres";
--
-- Name: post_partner_compensation_run("uuid"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."post_partner_compensation_run"("p_compensation_run_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE v_entry_id UUID; v_status TEXT; v_user_id UUID; v_is_admin BOOLEAN;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    SELECT EXISTS (SELECT 1 FROM public.user_roles ur WHERE ur.user_id = auth.uid() AND ur.role = 'admin') INTO v_is_admin;
    IF NOT COALESCE(v_is_admin, false) THEN RAISE EXCEPTION 'Usuario no autorizado'; END IF;
  END IF;
  SELECT status INTO v_status FROM accounting.partner_compensation_runs WHERE id = p_compensation_run_id;
  IF v_status != 'DRAFT' THEN RAISE EXCEPTION 'Solo se pueden postear retribuciones en estado DRAFT. Estado actual: %', v_status; END IF;
  v_entry_id := accounting.create_partner_compensation_entry(p_compensation_run_id);
  RETURN v_entry_id;
END;
$$;
ALTER FUNCTION "accounting"."post_partner_compensation_run"("p_compensation_run_id" "uuid") OWNER TO "postgres";
--
-- Name: FUNCTION "post_partner_compensation_run"("p_compensation_run_id" "uuid"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."post_partner_compensation_run"("p_compensation_run_id" "uuid") IS 'Postea una retribuci├│n generando el asiento contable autom├íticamente';
--
-- Name: post_payroll_run("uuid"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."post_payroll_run"("p_payroll_run_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting'
    AS $$
DECLARE
  v_entry_id UUID;
  v_status TEXT;
BEGIN
  -- Verificar que el usuario es admin
  IF NOT internal.is_admin() THEN
    RAISE EXCEPTION 'Solo los administradores pueden postear n├│minas';
  END IF;
  
  -- Verificar estado
  SELECT status INTO v_status
  FROM accounting.payroll_runs
  WHERE id = p_payroll_run_id;
  
  IF v_status != 'DRAFT' THEN
    RAISE EXCEPTION 'Solo se pueden postear n├│minas en estado DRAFT. Estado actual: %', v_status;
  END IF;
  
  -- Generar asiento
  v_entry_id := accounting.create_payroll_entry(p_payroll_run_id);
  
  RETURN v_entry_id;
END;
$$;
ALTER FUNCTION "accounting"."post_payroll_run"("p_payroll_run_id" "uuid") OWNER TO "postgres";
--
-- Name: FUNCTION "post_payroll_run"("p_payroll_run_id" "uuid"); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."post_payroll_run"("p_payroll_run_id" "uuid") IS 'Postea una n├│mina generando el asiento contable autom├íticamente';
--
-- Name: prevent_locked_compensation_modification(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."prevent_locked_compensation_modification"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'accounting', 'public'
    AS $$
BEGIN
  IF OLD.is_locked = true OR OLD.status = 'PAID' THEN
    IF NEW.gross_amount IS DISTINCT FROM OLD.gross_amount 
       OR NEW.irpf_rate IS DISTINCT FROM OLD.irpf_rate 
       OR NEW.irpf_amount IS DISTINCT FROM OLD.irpf_amount
       OR NEW.net_amount IS DISTINCT FROM OLD.net_amount THEN
      RAISE EXCEPTION 'Cannot modify financial values of a locked/paid payroll. Document % is immutable.', OLD.compensation_number;
    END IF;
  END IF;
  
  IF NEW.status = 'PAID' AND OLD.status != 'PAID' THEN
    NEW.is_locked := true;
  END IF;
  
  RETURN NEW;
END;
$$;
ALTER FUNCTION "accounting"."prevent_locked_compensation_modification"() OWNER TO "postgres";
--
-- Name: raise_if_period_closed_for_date("date"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."raise_if_period_closed_for_date"("p_date" "date") RETURNS "void"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting'
    AS $$
BEGIN
  IF accounting.is_period_closed(EXTRACT(YEAR FROM p_date)::INTEGER, EXTRACT(MONTH FROM p_date)::INTEGER) THEN
    RAISE EXCEPTION 'Periodo cerrado: no se pueden registrar movimientos con fecha % (a├▒o % mes %)', p_date, EXTRACT(YEAR FROM p_date), EXTRACT(MONTH FROM p_date);
  END IF;
END;
$$;
ALTER FUNCTION "accounting"."raise_if_period_closed_for_date"("p_date" "date") OWNER TO "postgres";
