--
-- Name: recreate_corporate_tax_for_year(integer); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."recreate_corporate_tax_for_year"("p_year" integer) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_start DATE;
  v_end DATE;
  v_user_id UUID;
  v_pbt NUMERIC(12,2);
  v_tax NUMERIC(12,2);
  v_entry_id UUID;
  v_entry_number TEXT;
  v_count INT;
BEGIN
  v_start := make_date(p_year, 1, 1);
  v_end := (v_start + interval '1 year' - interval '1 day')::date;
  
  SELECT id INTO v_user_id FROM internal.authorized_users ORDER BY created_at LIMIT 1;
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'No hay usuarios autorizados para crear la provisi├│n';
  END IF;
  
  DELETE FROM accounting.journal_entries
  WHERE entry_type = 'TAX_PROVISION'
    AND entry_date BETWEEN v_start AND v_end;
  
  GET DIAGNOSTICS v_count = ROW_COUNT;
  
  SELECT profit_before_tax INTO v_pbt
  FROM accounting.calculate_profit_before_tax(v_start, v_end)
  LIMIT 1;
  
  v_tax := CASE WHEN v_pbt > 0 THEN v_pbt * 0.25 ELSE 0 END;
  
  IF v_tax > 0 THEN
    v_entry_number := accounting.get_next_entry_number();
    
    INSERT INTO accounting.journal_entries (
      entry_number, entry_date, entry_type, description,
      reference_type, created_by
    ) VALUES (
      v_entry_number, v_end, 'TAX_PROVISION',
      'Provisi├│n IS 25% - Per├¡odo: ' || v_start || ' a ' || v_end || ' - BAI: ' || v_pbt || 'Ôé¼ - IS: ' || v_tax || 'Ôé¼',
      'corporate_tax', v_user_id
    ) RETURNING id INTO v_entry_id;
    
    INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, debit_credit, amount, description, line_order)
    VALUES (v_entry_id, '630000', 'DEBIT', v_tax, 'Provisi├│n IS 25% sobre BAI: ' || v_pbt || 'Ôé¼', 1);
    
    INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, debit_credit, amount, description, line_order)
    VALUES (v_entry_id, '475200', 'CREDIT', v_tax, 'Provisi├│n IS a pagar', 2);
  END IF;
END;
$$;
ALTER FUNCTION "accounting"."recreate_corporate_tax_for_year"("p_year" integer) OWNER TO "postgres";
--
-- Name: register_bank_account("text", "text", "text"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."register_bank_account"("p_bank_account_id" "text", "p_bank_name" "text", "p_iban" "text" DEFAULT NULL::"text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_account_code TEXT;
  v_description TEXT;
BEGIN
  -- Verificar si ya existe una cuenta para este banco
  SELECT account_code INTO v_account_code
  FROM accounting.chart_of_accounts
  WHERE description LIKE '%[ID:' || p_bank_account_id || ']%'
  LIMIT 1;
  
  IF v_account_code IS NOT NULL THEN
    -- Ya existe, devolver el c├│digo existente
    RETURN v_account_code;
  END IF;
  
  -- Obtener siguiente c├│digo
  v_account_code := accounting.get_next_bank_account_code();
  
  -- Construir descripci├│n con ID del banco para referencia
  v_description := 'Cuenta bancaria ' || p_bank_name;
  IF p_iban IS NOT NULL AND LENGTH(p_iban) > 4 THEN
    v_description := v_description || ' - ' || SUBSTRING(p_iban FROM 1 FOR 4) || '****' || SUBSTRING(p_iban FROM LENGTH(p_iban) - 3);
  END IF;
  v_description := v_description || ' [ID:' || p_bank_account_id || ']';
  
  -- Crear la cuenta contable
  INSERT INTO accounting.chart_of_accounts (
    account_code,
    account_name,
    account_type,
    description,
    is_active
  ) VALUES (
    v_account_code,
    'Banco ' || p_bank_name,
    'ASSET',
    v_description,
    true
  );
  
  RETURN v_account_code;
END;
$$;
ALTER FUNCTION "accounting"."register_bank_account"("p_bank_account_id" "text", "p_bank_name" "text", "p_iban" "text") OWNER TO "postgres";
--
-- Name: resolve_bank_accounting_code("text"); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."resolve_bank_accounting_code"("p_bank_account_id" "text") RETURNS "text"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_code TEXT;
  v_bank_name TEXT;
BEGIN
  IF p_bank_account_id IS NULL THEN
    RETURN '572001'; -- Sabadell por defecto
  END IF;

  -- 1) Buscar directamente en company_bank_accounts por UUID
  BEGIN
    SELECT cba.accounting_code INTO v_code
    FROM internal.company_bank_accounts cba
    WHERE cba.id = p_bank_account_id::uuid AND cba.is_active = true
    LIMIT 1;
    IF v_code IS NOT NULL THEN RETURN v_code; END IF;
  EXCEPTION WHEN OTHERS THEN NULL;
  END;

  -- 2) Buscar en company_preferences.bank_accounts JSONB (IDs antiguos)
  SELECT bank_acc->>'bank' INTO v_bank_name
  FROM internal.company_preferences cp,
       jsonb_array_elements(cp.bank_accounts) AS bank_acc
  WHERE bank_acc->>'id' = p_bank_account_id
  LIMIT 1;

  IF v_bank_name IS NOT NULL THEN
    SELECT cba.accounting_code INTO v_code
    FROM internal.company_bank_accounts cba
    WHERE cba.bank_name ILIKE v_bank_name AND cba.is_active = true
    LIMIT 1;
    IF v_code IS NOT NULL THEN RETURN v_code; END IF;
  END IF;

  -- 3) Fallback: cuenta principal (Sabadell)
  RETURN '572001';
END;
$$;
ALTER FUNCTION "accounting"."resolve_bank_accounting_code"("p_bank_account_id" "text") OWNER TO "postgres";
