--
-- Name: validate_balanced_entry(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."validate_balanced_entry"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'accounting'
    AS $$
DECLARE
  v_total_debit NUMERIC(12,2) := 0;
  v_total_credit NUMERIC(12,2) := 0;
  v_entry_id UUID;
BEGIN
  -- The trigger is on journal_entries table, so use NEW.id (not NEW.journal_entry_id)
  IF TG_OP = 'DELETE' THEN
    v_entry_id := OLD.id;
  ELSE
    v_entry_id := NEW.id;
  END IF;
  
  -- Calcular totales
  SELECT 
    COALESCE(SUM(CASE WHEN debit_credit = 'DEBIT' THEN amount ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN debit_credit = 'CREDIT' THEN amount ELSE 0 END), 0)
  INTO v_total_debit, v_total_credit
  FROM accounting.journal_entry_lines
  WHERE journal_entry_id = v_entry_id;
  
  -- Verificar balance
  IF ABS(v_total_debit - v_total_credit) > 0.01 THEN
    RAISE EXCEPTION 'Asiento desbalanceado: DEBE (%) != HABER (%)', v_total_debit, v_total_credit;
  END IF;
  
  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  ELSE
    RETURN NEW;
  END IF;
END;
$$;
ALTER FUNCTION "accounting"."validate_balanced_entry"() OWNER TO "postgres";
--
-- Name: FUNCTION "validate_balanced_entry"(); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."validate_balanced_entry"() IS 'Valida que un asiento est├® balanceado (DEBE = HABER) antes de bloquearlo';
--
-- Name: validate_month_consistency(integer, integer, numeric); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."validate_month_consistency"("p_year" integer, "p_month" integer, "p_tolerance" numeric DEFAULT 0.01) RETURNS TABLE("check_code" "text", "check_name" "text", "passed" boolean, "severity" "text", "detail" "text", "meta" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE v_start DATE; v_end DATE;
BEGIN
  v_start := make_date(p_year, p_month, 1);
  v_end := (date_trunc('month', v_start::timestamp) + interval '1 month - 1 day')::date;
  RETURN QUERY
  WITH je AS (SELECT id, entry_number, entry_date, entry_type FROM accounting.journal_entries WHERE entry_date BETWEEN v_start AND v_end),
  sums AS (SELECT je.id, je.entry_number, COALESCE(SUM(CASE WHEN jel.debit_credit = 'DEBIT' THEN jel.amount ELSE 0 END), 0) AS total_debit, COALESCE(SUM(CASE WHEN jel.debit_credit = 'CREDIT' THEN jel.amount ELSE 0 END), 0) AS total_credit FROM je JOIN accounting.journal_entry_lines jel ON jel.journal_entry_id = je.id GROUP BY je.id, je.entry_number),
  agg AS (SELECT COUNT(*) FILTER (WHERE ABS(total_debit - total_credit) > p_tolerance) AS unbalanced_count, jsonb_agg(jsonb_build_object('entry_number', entry_number, 'diff', (total_debit - total_credit))) FILTER (WHERE ABS(total_debit - total_credit) > p_tolerance) AS examples FROM sums)
  SELECT 'JE_BALANCED'::text, 'Asientos balanceados (Debe=Haber)'::text, ((SELECT unbalanced_count FROM agg) = 0), 'BLOCKER'::text, CASE WHEN (SELECT unbalanced_count FROM agg) = 0 THEN 'OK' ELSE 'Hay asientos descuadrados en el per├¡odo' END, jsonb_build_object('unbalanced_count', (SELECT unbalanced_count FROM agg), 'examples', (SELECT examples FROM agg)) FROM agg;
  RETURN QUERY
  WITH pi AS (SELECT id, issue_date, updated_at FROM sales.purchase_invoices WHERE status = 'APPROVED' AND COALESCE(issue_date, updated_at::date) BETWEEN v_start AND v_end),
  missing AS (SELECT pi.id FROM pi LEFT JOIN accounting.journal_entries je ON je.reference_id = pi.id AND je.reference_type = 'purchase_invoice' AND je.entry_type = 'INVOICE_PURCHASE' WHERE je.id IS NULL),
  agg2 AS (SELECT COUNT(*) AS missing_count, (SELECT jsonb_agg(id) FROM (SELECT id FROM missing LIMIT 20) t) AS examples FROM missing)
  SELECT 'PURCHASE_APPROVED_HAS_ENTRY'::text, 'Compras APPROVED con asiento (mes por issue_date/updated_at)'::text, ((SELECT missing_count FROM agg2) = 0), 'BLOCKER'::text, CASE WHEN (SELECT missing_count FROM agg2) = 0 THEN 'OK' ELSE 'Hay facturas de compra APPROVED sin asiento INVOICE_PURCHASE' END, jsonb_build_object('missing_count', (SELECT missing_count FROM agg2), 'examples', (SELECT examples FROM agg2)) FROM agg2;
  RETURN QUERY
  WITH y AS (SELECT date_trunc('year', v_start::timestamp)::date AS y_start, (date_trunc('year', v_start::timestamp) + interval '1 year - 1 day')::date AS y_end),
  prov AS (SELECT je.id, je.entry_number, je.entry_date FROM accounting.journal_entries je, y WHERE je.entry_type = 'TAX_PROVISION' AND je.reference_type = 'corporate_tax' AND je.entry_date BETWEEN y.y_start AND y.y_end),
  agg3 AS (SELECT COUNT(*) AS prov_count, (SELECT jsonb_agg(jsonb_build_object('entry_number', entry_number, 'date', entry_date)) FROM prov) AS entries FROM prov)
  SELECT 'TAX_PROVISION_UNIQUE'::text, 'Provisi├│n IS sin duplicados (anual)'::text, ((SELECT prov_count FROM agg3) <= 1), 'BLOCKER'::text, CASE WHEN (SELECT prov_count FROM agg3) <= 1 THEN 'OK' ELSE 'Hay m├ís de una provisi├│n IS (TAX_PROVISION) en el a├▒o' END, jsonb_build_object('count', (SELECT prov_count FROM agg3), 'entries', (SELECT entries FROM agg3)) FROM agg3;
  RETURN QUERY
  WITH je AS (SELECT id, entry_number, entry_date FROM accounting.journal_entries WHERE entry_date BETWEEN v_start AND v_end),
  empty AS (SELECT je.id, je.entry_number FROM je LEFT JOIN accounting.journal_entry_lines jel ON jel.journal_entry_id = je.id GROUP BY je.id, je.entry_number HAVING COUNT(jel.id) = 0),
  agg4 AS (SELECT COUNT(*) AS empty_count, (SELECT jsonb_agg(jsonb_build_object('entry_number', entry_number)) FROM empty) AS examples FROM empty)
  SELECT 'JE_HAS_LINES'::text, 'Asientos con al menos una l├¡nea'::text, ((SELECT empty_count FROM agg4) = 0), 'BLOCKER'::text, CASE WHEN (SELECT empty_count FROM agg4) = 0 THEN 'OK' ELSE 'Hay asientos del mes sin l├¡neas' END, jsonb_build_object('empty_count', (SELECT empty_count FROM agg4), 'examples', (SELECT examples FROM agg4)) FROM agg4;
  RETURN QUERY
  WITH posted AS (SELECT net_amount FROM accounting.payroll_runs WHERE status = 'POSTED' AND make_date(period_year, period_month, 1) = v_start UNION ALL SELECT net_amount FROM accounting.partner_compensation_runs WHERE status = 'POSTED' AND make_date(period_year, period_month, 1) = v_start),
  pending_payroll AS (SELECT COALESCE(SUM(net_amount), 0)::numeric(12,2) AS total_pending FROM posted),
  acc465 AS (SELECT COALESCE(SUM(CASE WHEN jel.debit_credit = 'CREDIT' THEN jel.amount ELSE -jel.amount END), 0)::numeric(12,2) AS balance_465 FROM accounting.journal_entries je JOIN accounting.journal_entry_lines jel ON jel.journal_entry_id = je.id WHERE je.entry_date <= v_end AND jel.account_code = '465000')
  SELECT 'PAYROLL_465_COHERENCE'::text, 'Coherencia 465 vs n├│minas POSTED del mes'::text, (ABS((SELECT balance_465 FROM acc465) - (SELECT total_pending FROM pending_payroll)) <= 5.00), 'WARNING'::text, 'Comparaci├│n aproximada (465 acumulado vs neto pendiente del mes). Revisi├│n si difiere.', jsonb_build_object('balance_465', (SELECT balance_465 FROM acc465), 'pending_month_net', (SELECT total_pending FROM pending_payroll));
  RETURN QUERY
  WITH je AS (SELECT id, entry_number, entry_type FROM accounting.journal_entries WHERE entry_date BETWEEN v_start AND v_end AND entry_type IN ('PAYMENT_RECEIVED', 'PAYMENT_MADE')),
  bad_received AS (SELECT je.id, je.entry_number FROM je WHERE je.entry_type = 'PAYMENT_RECEIVED' AND (NOT EXISTS (SELECT 1 FROM accounting.journal_entry_lines l WHERE l.journal_entry_id = je.id AND l.account_code LIKE '572%') OR NOT EXISTS (SELECT 1 FROM accounting.journal_entry_lines l WHERE l.journal_entry_id = je.id AND l.account_code = '430000'))),
  bad_made AS (SELECT je.id, je.entry_number FROM je WHERE je.entry_type = 'PAYMENT_MADE' AND (NOT EXISTS (SELECT 1 FROM accounting.journal_entry_lines l WHERE l.journal_entry_id = je.id AND l.account_code LIKE '572%') OR NOT EXISTS (SELECT 1 FROM accounting.journal_entry_lines l WHERE l.journal_entry_id = je.id AND l.account_code IN ('400000', '410000', '465000')))),
  bad_cash AS (SELECT id, entry_number FROM bad_received UNION ALL SELECT id, entry_number FROM bad_made),
  agg6 AS (SELECT COUNT(*) AS bad_count, (SELECT jsonb_agg(jsonb_build_object('entry_number', entry_number)) FROM (SELECT entry_number FROM bad_cash LIMIT 20) t) AS examples FROM bad_cash)
  SELECT 'CASH_BOOK_COUNTERPART'::text, 'Cobros/pagos con 572 y contrapartida (430 o 400/410/465)'::text, ((SELECT bad_count FROM agg6) = 0), 'BLOCKER'::text, CASE WHEN (SELECT bad_count FROM agg6) = 0 THEN 'OK' ELSE 'Hay cobros/pagos sin l├¡nea 572 o sin contrapartida esperada' END, jsonb_build_object('bad_count', (SELECT bad_count FROM agg6), 'examples', (SELECT examples FROM agg6)) FROM agg6;
  RETURN QUERY
  WITH inv AS (SELECT i.id, i.invoice_number, i.issue_date FROM sales.invoices i WHERE i.status = 'ISSUED' AND i.issue_date BETWEEN v_start AND v_end),
  missing_sale AS (SELECT inv.id FROM inv LEFT JOIN accounting.journal_entries je ON je.reference_id = inv.id AND je.reference_type = 'invoice' AND je.entry_type = 'INVOICE_SALE' WHERE je.id IS NULL),
  agg7 AS (SELECT COUNT(*) AS missing_count, (SELECT jsonb_agg(id) FROM (SELECT id FROM missing_sale LIMIT 20) t) AS examples FROM missing_sale)
  SELECT 'SALES_ISSUED_HAS_ENTRY'::text, 'Ventas ISSUED con asiento contable'::text, ((SELECT missing_count FROM agg7) = 0), 'BLOCKER'::text, CASE WHEN (SELECT missing_count FROM agg7) = 0 THEN 'OK' ELSE 'Hay facturas de venta ISSUED sin asiento INVOICE_SALE' END, jsonb_build_object('missing_count', (SELECT missing_count FROM agg7), 'examples', (SELECT examples FROM agg7)) FROM agg7;
  RETURN;
END;
$$;
ALTER FUNCTION "accounting"."validate_month_consistency"("p_year" integer, "p_month" integer, "p_tolerance" numeric) OWNER TO "postgres";
--
-- Name: FUNCTION "validate_month_consistency"("p_year" integer, "p_month" integer, "p_tolerance" numeric); Type: COMMENT; Schema: accounting; Owner: postgres
--

COMMENT ON FUNCTION "accounting"."validate_month_consistency"("p_year" integer, "p_month" integer, "p_tolerance" numeric) IS 'Valida consistencia contable del mes (cierre). Incluye balance, compras/ventas con asiento, IS ├║nico, asientos con l├¡neas, contrapartidas caja.';
--
-- Name: validate_payroll_payment(); Type: FUNCTION; Schema: accounting; Owner: postgres
--

CREATE FUNCTION "accounting"."validate_payroll_payment"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_status TEXT;
BEGIN
  -- Validar estado de la n├│mina/retribuci├│n
  IF NEW.payroll_run_id IS NOT NULL THEN
    SELECT status INTO v_status
    FROM accounting.payroll_runs
    WHERE id = NEW.payroll_run_id;
    
    IF v_status != 'POSTED' THEN
      RAISE EXCEPTION 'No se puede pagar una n├│mina que no est├® en estado POSTED';
    END IF;
  END IF;
  
  IF NEW.partner_compensation_run_id IS NOT NULL THEN
    SELECT status INTO v_status
    FROM accounting.partner_compensation_runs
    WHERE id = NEW.partner_compensation_run_id;
    
    IF v_status != 'POSTED' THEN
      RAISE EXCEPTION 'No se puede pagar una retribuci├│n que no est├® en estado POSTED';
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$;
ALTER FUNCTION "accounting"."validate_payroll_payment"() OWNER TO "postgres";
--
-- Name: archive_old_records("text", "text", integer); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE FUNCTION "audit"."archive_old_records"("p_source_schema" "text", "p_source_table" "text", "p_batch_size" integer DEFAULT 1000) RETURNS TABLE("archived_count" integer, "deleted_count" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
DECLARE
  v_retention_days INTEGER;
  v_cutoff TIMESTAMPTZ;
  v_archived INTEGER := 0;
  v_deleted INTEGER := 0;
  v_enabled BOOLEAN;
BEGIN
  -- Get retention policy
  SELECT retention_days, archive_enabled
  INTO v_retention_days, v_enabled
  FROM audit.retention_policy
  WHERE source_schema = p_source_schema
    AND source_table = p_source_table;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'No retention policy found for %.%', p_source_schema, p_source_table;
  END IF;

  IF NOT v_enabled THEN
    RETURN QUERY SELECT 0::INTEGER, 0::INTEGER;
    RETURN;
  END IF;

  v_cutoff := now() - (v_retention_days || ' days')::INTERVAL;

  -- Archive records older than cutoff
  EXECUTE format(
    'INSERT INTO audit.archived_records (source_schema, source_table, original_id, record_data, original_created_at)
     SELECT %L, %L, id, to_jsonb(t.*), t.created_at
     FROM %I.%I t
     WHERE t.created_at < %L
     LIMIT %s',
    p_source_schema, p_source_table,
    p_source_schema, p_source_table,
    v_cutoff, p_batch_size
  );
  GET DIAGNOSTICS v_archived = ROW_COUNT;

  -- Delete archived records from source
  IF v_archived > 0 THEN
    EXECUTE format(
      'DELETE FROM %I.%I WHERE id IN (
         SELECT original_id FROM audit.archived_records
         WHERE source_schema = %L AND source_table = %L
         AND archived_at >= now() - INTERVAL ''1 minute''
       )',
      p_source_schema, p_source_table,
      p_source_schema, p_source_table
    );
    GET DIAGNOSTICS v_deleted = ROW_COUNT;
  END IF;

  -- Update last archived timestamp
  UPDATE audit.retention_policy
  SET last_archived_at = now(), updated_at = now()
  WHERE source_schema = p_source_schema
    AND source_table = p_source_table;

  RETURN QUERY SELECT v_archived, v_deleted;
END;
$$;
ALTER FUNCTION "audit"."archive_old_records"("p_source_schema" "text", "p_source_table" "text", "p_batch_size" integer) OWNER TO "postgres";
--
-- Name: cleanup_old_events(integer); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE FUNCTION "audit"."cleanup_old_events"("p_older_than_days" integer DEFAULT 90) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit'
    AS $$
DECLARE
  v_deleted_count INTEGER;
BEGIN
  DELETE FROM audit.events
  WHERE created_at < now() - (p_older_than_days || ' days')::INTERVAL
    AND severity NOT IN ('critical', 'error');
  
  GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
  
  RETURN v_deleted_count;
END;
$$;
ALTER FUNCTION "audit"."cleanup_old_events"("p_older_than_days" integer) OWNER TO "postgres";
--
-- Name: get_next_number("text", integer); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE FUNCTION "audit"."get_next_number"("p_prefix" "text", "p_year" integer DEFAULT (EXTRACT(year FROM "now"()))::integer) RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit'
    AS $$
DECLARE
  v_number INTEGER;
BEGIN
  INSERT INTO audit.sequence_counters (prefix, year, current_number, last_generated_at)
  VALUES (p_prefix, p_year, 1, now())
  ON CONFLICT (prefix, year) DO UPDATE
  SET current_number = audit.sequence_counters.current_number + 1,
      last_generated_at = now()
  RETURNING current_number INTO v_number;
  
  RETURN p_prefix || '-' || p_year || '-' || LPAD(v_number::TEXT, 6, '0');
END;
$$;
ALTER FUNCTION "audit"."get_next_number"("p_prefix" "text", "p_year" integer) OWNER TO "postgres";
--
-- Name: get_stats(integer); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE FUNCTION "audit"."get_stats"("p_days" integer DEFAULT 7) RETURNS TABLE("total_events" bigint, "events_by_category" "jsonb", "events_by_severity" "jsonb", "events_by_type" "jsonb", "top_users" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
BEGIN
  -- Verificar admin
  IF NOT internal.is_admin() THEN
    RAISE EXCEPTION 'Access denied: Admin role required';
  END IF;

  RETURN QUERY
  SELECT 
    (SELECT COUNT(*) FROM audit.events WHERE created_at >= now() - (p_days || ' days')::INTERVAL),
    (SELECT jsonb_object_agg(event_category, cnt) FROM (
      SELECT event_category, COUNT(*) as cnt 
      FROM audit.events 
      WHERE created_at >= now() - (p_days || ' days')::INTERVAL
      GROUP BY event_category
    ) t),
    (SELECT jsonb_object_agg(severity, cnt) FROM (
      SELECT severity, COUNT(*) as cnt 
      FROM audit.events 
      WHERE created_at >= now() - (p_days || ' days')::INTERVAL
      GROUP BY severity
    ) t),
    (SELECT jsonb_object_agg(event_type, cnt) FROM (
      SELECT event_type, COUNT(*) as cnt 
      FROM audit.events 
      WHERE created_at >= now() - (p_days || ' days')::INTERVAL
      GROUP BY event_type
      ORDER BY cnt DESC
      LIMIT 10
    ) t),
    (SELECT jsonb_agg(jsonb_build_object('email', user_email, 'count', cnt)) FROM (
      SELECT user_email, COUNT(*) as cnt 
      FROM audit.events 
      WHERE created_at >= now() - (p_days || ' days')::INTERVAL
        AND user_email IS NOT NULL
      GROUP BY user_email
      ORDER BY cnt DESC
      LIMIT 5
    ) t);
END;
$$;
ALTER FUNCTION "audit"."get_stats"("p_days" integer) OWNER TO "postgres";
--
-- Name: list_events(integer, integer, "text", "text", "uuid", "text", timestamp with time zone, timestamp with time zone, "text"); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE FUNCTION "audit"."list_events"("p_limit" integer DEFAULT 100, "p_offset" integer DEFAULT 0, "p_event_type" "text" DEFAULT NULL::"text", "p_event_category" "text" DEFAULT NULL::"text", "p_user_id" "uuid" DEFAULT NULL::"uuid", "p_severity" "text" DEFAULT NULL::"text", "p_from_date" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_to_date" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_search" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "event_type" "text", "event_category" "text", "severity" "text", "user_id" "uuid", "user_email" "text", "user_name" "text", "resource_type" "text", "resource_id" "text", "action" "text", "details" "jsonb", "ip_address" "inet", "user_agent" "text", "created_at" timestamp with time zone, "total_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
DECLARE
  v_total BIGINT;
BEGIN
  -- Verificar que el usuario es admin
  IF NOT internal.is_admin() THEN
    RAISE EXCEPTION 'Access denied: Admin role required';
  END IF;

  -- Contar total
  SELECT COUNT(*) INTO v_total
  FROM audit.events e
  WHERE (p_event_type IS NULL OR e.event_type = p_event_type)
    AND (p_event_category IS NULL OR e.event_category = p_event_category)
    AND (p_user_id IS NULL OR e.user_id = p_user_id)
    AND (p_severity IS NULL OR e.severity = p_severity)
    AND (p_from_date IS NULL OR e.created_at >= p_from_date)
    AND (p_to_date IS NULL OR e.created_at <= p_to_date)
    AND (p_search IS NULL OR 
         e.user_email ILIKE '%' || p_search || '%' OR
         e.user_name ILIKE '%' || p_search || '%' OR
         e.action ILIKE '%' || p_search || '%' OR
         e.resource_id ILIKE '%' || p_search || '%');

  RETURN QUERY
  SELECT 
    e.id,
    e.event_type,
    e.event_category,
    e.severity,
    e.user_id,
    e.user_email,
    e.user_name,
    e.resource_type,
    e.resource_id,
    e.action,
    e.details,
    e.ip_address,
    e.user_agent,
    e.created_at,
    v_total
  FROM audit.events e
  WHERE (p_event_type IS NULL OR e.event_type = p_event_type)
    AND (p_event_category IS NULL OR e.event_category = p_event_category)
    AND (p_user_id IS NULL OR e.user_id = p_user_id)
    AND (p_severity IS NULL OR e.severity = p_severity)
    AND (p_from_date IS NULL OR e.created_at >= p_from_date)
    AND (p_to_date IS NULL OR e.created_at <= p_to_date)
    AND (p_search IS NULL OR 
         e.user_email ILIKE '%' || p_search || '%' OR
         e.user_name ILIKE '%' || p_search || '%' OR
         e.action ILIKE '%' || p_search || '%' OR
         e.resource_id ILIKE '%' || p_search || '%')
  ORDER BY e.created_at DESC
  LIMIT p_limit
  OFFSET p_offset;
END;
$$;
ALTER FUNCTION "audit"."list_events"("p_limit" integer, "p_offset" integer, "p_event_type" "text", "p_event_category" "text", "p_user_id" "uuid", "p_severity" "text", "p_from_date" timestamp with time zone, "p_to_date" timestamp with time zone, "p_search" "text") OWNER TO "postgres";
--
-- Name: log_action("text", "text", "uuid", "uuid", "text", "inet", "text", "jsonb", "jsonb", "jsonb"); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE FUNCTION "audit"."log_action"("_action" "text", "_table_name" "text", "_record_id" "uuid" DEFAULT NULL::"uuid", "_user_id" "uuid" DEFAULT NULL::"uuid", "_user_email" "text" DEFAULT NULL::"text", "_ip_address" "inet" DEFAULT NULL::"inet", "_user_agent" "text" DEFAULT NULL::"text", "_old_data" "jsonb" DEFAULT NULL::"jsonb", "_new_data" "jsonb" DEFAULT NULL::"jsonb", "_metadata" "jsonb" DEFAULT NULL::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit'
    AS $$
DECLARE
    _log_id UUID;
BEGIN
    INSERT INTO audit.logs (
        action, table_name, record_id, user_id, user_email,
        ip_address, user_agent, old_data, new_data, metadata
    ) VALUES (
        _action, _table_name, _record_id, _user_id, _user_email,
        _ip_address, _user_agent, _old_data, _new_data, _metadata
    )
    RETURNING id INTO _log_id;
    
    RETURN _log_id;
END;
$$;
ALTER FUNCTION "audit"."log_action"("_action" "text", "_table_name" "text", "_record_id" "uuid", "_user_id" "uuid", "_user_email" "text", "_ip_address" "inet", "_user_agent" "text", "_old_data" "jsonb", "_new_data" "jsonb", "_metadata" "jsonb") OWNER TO "postgres";
--
-- Name: log_event("text", "text", "text", "uuid", "text", "text", "text", "text", "jsonb", "text", "inet", "text", "text"); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE FUNCTION "audit"."log_event"("p_event_type" "text", "p_event_category" "text", "p_action" "text", "p_user_id" "uuid" DEFAULT NULL::"uuid", "p_user_email" "text" DEFAULT NULL::"text", "p_user_name" "text" DEFAULT NULL::"text", "p_resource_type" "text" DEFAULT NULL::"text", "p_resource_id" "text" DEFAULT NULL::"text", "p_details" "jsonb" DEFAULT '{}'::"jsonb", "p_severity" "text" DEFAULT 'info'::"text", "p_ip_address" "inet" DEFAULT NULL::"inet", "p_user_agent" "text" DEFAULT NULL::"text", "p_session_id" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
DECLARE
  v_event_id UUID;
BEGIN
  INSERT INTO audit.events (
    event_type,
    event_category,
    action,
    user_id,
    user_email,
    user_name,
    resource_type,
    resource_id,
    details,
    severity,
    ip_address,
    user_agent,
    session_id
  ) VALUES (
    p_event_type,
    p_event_category,
    p_action,
    p_user_id,
    p_user_email,
    p_user_name,
    p_resource_type,
    p_resource_id,
    p_details,
    p_severity,
    p_ip_address,
    p_user_agent,
    p_session_id
  )
  RETURNING id INTO v_event_id;
  
  RETURN v_event_id;
END;
$$;
ALTER FUNCTION "audit"."log_event"("p_event_type" "text", "p_event_category" "text", "p_action" "text", "p_user_id" "uuid", "p_user_email" "text", "p_user_name" "text", "p_resource_type" "text", "p_resource_id" "text", "p_details" "jsonb", "p_severity" "text", "p_ip_address" "inet", "p_user_agent" "text", "p_session_id" "text") OWNER TO "postgres";
--
-- Name: purge_old_archives(integer); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE FUNCTION "audit"."purge_old_archives"("p_older_than_days" integer DEFAULT 365) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
DECLARE
  v_deleted INTEGER;
BEGIN
  DELETE FROM audit.archived_records
  WHERE archived_at < now() - (p_older_than_days || ' days')::INTERVAL;
  GET DIAGNOSTICS v_deleted = ROW_COUNT;
  RETURN v_deleted;
END;
$$;
ALTER FUNCTION "audit"."purge_old_archives"("p_older_than_days" integer) OWNER TO "postgres";
--
-- Name: run_all_archival(); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE FUNCTION "audit"."run_all_archival"() RETURNS TABLE("source_schema" "text", "source_table" "text", "archived_count" integer, "deleted_count" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
DECLARE
  r RECORD;
  result RECORD;
BEGIN
  FOR r IN
    SELECT rp.source_schema AS s, rp.source_table AS t
    FROM audit.retention_policy rp
    WHERE rp.archive_enabled = true
  LOOP
    SELECT * INTO result FROM audit.archive_old_records(r.s, r.t);
    source_schema := r.s;
    source_table := r.t;
    archived_count := result.archived_count;
    deleted_count := result.deleted_count;
    RETURN NEXT;
  END LOOP;
END;
$$;
ALTER FUNCTION "audit"."run_all_archival"() OWNER TO "postgres";
--
-- Name: trigger_authorized_users_audit(); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE FUNCTION "audit"."trigger_authorized_users_audit"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
DECLARE
  v_action TEXT;
  v_details JSONB;
  v_user_id UUID;
  v_user_email TEXT;
BEGIN
  -- Obtener usuario actual
  v_user_id := internal.get_authorized_user_id(auth.uid());
  
  SELECT email INTO v_user_email 
  FROM internal.authorized_users 
  WHERE id = v_user_id;

  IF TG_OP = 'INSERT' THEN
    v_action := 'USER_CREATED';
    v_details := jsonb_build_object(
      'new_user_email', NEW.email,
      'new_user_name', NEW.full_name,
      'department', NEW.department
    );
    
    PERFORM audit.log_event(
      'USER_MANAGEMENT',
      'security',
      v_action,
      v_user_id,
      v_user_email,
      NULL,
      'authorized_user',
      NEW.id::TEXT,
      v_details,
      'info'
    );
    
  ELSIF TG_OP = 'UPDATE' THEN
    v_action := 'USER_UPDATED';
    v_details := jsonb_build_object(
      'user_email', NEW.email,
      'changes', jsonb_build_object(
        'full_name', CASE WHEN OLD.full_name != NEW.full_name THEN jsonb_build_object('old', OLD.full_name, 'new', NEW.full_name) ELSE NULL END,
        'is_active', CASE WHEN OLD.is_active != NEW.is_active THEN jsonb_build_object('old', OLD.is_active, 'new', NEW.is_active) ELSE NULL END,
        'department', CASE WHEN OLD.department != NEW.department THEN jsonb_build_object('old', OLD.department, 'new', NEW.department) ELSE NULL END
      )
    );
    
    -- Detectar desactivaci├│n de usuario
    IF OLD.is_active = true AND NEW.is_active = false THEN
      v_action := 'USER_DEACTIVATED';
      v_details := v_details || jsonb_build_object('severity_note', 'User access revoked');
    END IF;
    
    PERFORM audit.log_event(
      'USER_MANAGEMENT',
      'security',
      v_action,
      v_user_id,
      v_user_email,
      NULL,
      'authorized_user',
      NEW.id::TEXT,
      v_details,
      CASE WHEN v_action = 'USER_DEACTIVATED' THEN 'warning' ELSE 'info' END
    );
    
  ELSIF TG_OP = 'DELETE' THEN
    v_action := 'USER_DELETED';
    v_details := jsonb_build_object(
      'deleted_user_email', OLD.email,
      'deleted_user_name', OLD.full_name
    );
    
    PERFORM audit.log_event(
      'USER_MANAGEMENT',
      'security',
      v_action,
      v_user_id,
      v_user_email,
      NULL,
      'authorized_user',
      OLD.id::TEXT,
      v_details,
      'warning'
    );
  END IF;
  
  RETURN COALESCE(NEW, OLD);
END;
$$;
ALTER FUNCTION "audit"."trigger_authorized_users_audit"() OWNER TO "postgres";
--
-- Name: trigger_clients_audit(); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE FUNCTION "audit"."trigger_clients_audit"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
DECLARE
  v_action TEXT;
  v_details JSONB;
  v_user_id UUID;
  v_user_email TEXT;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  
  SELECT email INTO v_user_email 
  FROM internal.authorized_users 
  WHERE id = v_user_id;

  IF TG_OP = 'INSERT' THEN
    v_action := 'CLIENT_CREATED';
    v_details := jsonb_build_object(
      'company_name', NEW.company_name,
      'contact_email', NEW.contact_email
    );
    
  ELSIF TG_OP = 'UPDATE' THEN
    v_action := 'CLIENT_UPDATED';
    v_details := jsonb_build_object(
      'company_name', NEW.company_name,
      'contact_email', NEW.contact_email
    );
    
  ELSIF TG_OP = 'DELETE' THEN
    v_action := 'CLIENT_DELETED';
    v_details := jsonb_build_object(
      'company_name', OLD.company_name,
      'contact_email', OLD.contact_email
    );
  END IF;
  
  PERFORM audit.log_event(
    'DATA_MODIFICATION',
    'crm',
    v_action,
    v_user_id,
    v_user_email,
    NULL,
    'client',
    COALESCE(NEW.id, OLD.id)::TEXT,
    v_details,
    CASE WHEN TG_OP = 'DELETE' THEN 'warning' ELSE 'info' END
  );
  
  RETURN COALESCE(NEW, OLD);
END;
$$;
ALTER FUNCTION "audit"."trigger_clients_audit"() OWNER TO "postgres";
--
-- Name: trigger_user_roles_audit(); Type: FUNCTION; Schema: audit; Owner: postgres
--

CREATE FUNCTION "audit"."trigger_user_roles_audit"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'audit', 'public'
    AS $$
DECLARE
  v_action TEXT;
  v_details JSONB;
  v_admin_id UUID;
  v_admin_email TEXT;
  v_target_email TEXT;
BEGIN
  -- Obtener admin actual
  v_admin_id := internal.get_authorized_user_id(auth.uid());
  
  SELECT email INTO v_admin_email 
  FROM internal.authorized_users 
  WHERE id = v_admin_id;

  IF TG_OP = 'INSERT' THEN
    -- Obtener email del usuario al que se le asigna el rol
    SELECT email INTO v_target_email 
    FROM internal.authorized_users 
    WHERE auth_user_id = NEW.user_id;
    
    v_action := 'ROLE_ASSIGNED';
    v_details := jsonb_build_object(
      'target_user_email', v_target_email,
      'role', NEW.role
    );
    
    PERFORM audit.log_event(
      'ROLE_CHANGE',
      'security',
      v_action,
      v_admin_id,
      v_admin_email,
      NULL,
      'user_role',
      NEW.id::TEXT,
      v_details,
      'warning'
    );
    
  ELSIF TG_OP = 'DELETE' THEN
    SELECT email INTO v_target_email 
    FROM internal.authorized_users 
    WHERE auth_user_id = OLD.user_id;
    
    v_action := 'ROLE_REVOKED';
    v_details := jsonb_build_object(
      'target_user_email', v_target_email,
      'role', OLD.role
    );
    
    PERFORM audit.log_event(
      'ROLE_CHANGE',
      'security',
      v_action,
      v_admin_id,
      v_admin_email,
      NULL,
      'user_role',
      OLD.id::TEXT,
      v_details,
      'warning'
    );
  END IF;
  
  RETURN COALESCE(NEW, OLD);
END;
$$;
ALTER FUNCTION "audit"."trigger_user_roles_audit"() OWNER TO "postgres";
--
-- Name: cleanup_old_snapshots(integer); Type: FUNCTION; Schema: backup; Owner: postgres
--

CREATE FUNCTION "backup"."cleanup_old_snapshots"("p_keep_days" integer DEFAULT 30) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'backup'
    AS $$
DECLARE
  v_deleted integer;
BEGIN
  DELETE FROM backup.daily_snapshots
  WHERE snapshot_date < CURRENT_DATE - p_keep_days;
  GET DIAGNOSTICS v_deleted = ROW_COUNT;
  RETURN v_deleted;
END;
$$;
ALTER FUNCTION "backup"."cleanup_old_snapshots"("p_keep_days" integer) OWNER TO "postgres";
--
-- Name: get_snapshot("text", "text", "date"); Type: FUNCTION; Schema: backup; Owner: postgres
--

CREATE FUNCTION "backup"."get_snapshot"("p_schema" "text", "p_table" "text", "p_date" "date" DEFAULT CURRENT_DATE) RETURNS "jsonb"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'backup'
    AS $$
  SELECT data FROM backup.daily_snapshots
  WHERE table_schema = p_schema AND table_name = p_table AND snapshot_date = p_date;
$$;
ALTER FUNCTION "backup"."get_snapshot"("p_schema" "text", "p_table" "text", "p_date" "date") OWNER TO "postgres";
--
-- Name: list_snapshots("date"); Type: FUNCTION; Schema: backup; Owner: postgres
--

CREATE FUNCTION "backup"."list_snapshots"("p_date" "date" DEFAULT NULL::"date") RETURNS TABLE("table_schema" "text", "table_name" "text", "snapshot_date" "date", "row_count" integer, "created_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'backup'
    AS $$
  SELECT s.table_schema, s.table_name, s.snapshot_date, s.row_count, s.created_at
  FROM backup.daily_snapshots s
  WHERE (p_date IS NULL OR s.snapshot_date = p_date)
  ORDER BY s.snapshot_date DESC, s.table_schema, s.table_name;
$$;
