--
-- Name: run_daily_backup(); Type: FUNCTION; Schema: backup; Owner: postgres
--

CREATE FUNCTION "backup"."run_daily_backup"() RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'backup', 'public'
    AS $$
DECLARE
  v_tables text[][] := ARRAY[
    -- CRM
    ARRAY['crm', 'clients'],
    ARRAY['crm', 'client_notes'],
    -- Projects
    ARRAY['projects', 'projects'],
    ARRAY['projects', 'project_sites'],
    ARRAY['projects', 'site_technician_assignments'],
    ARRAY['projects', 'site_visits'],
    -- Quotes
    ARRAY['quotes', 'quotes'],
    ARRAY['quotes', 'quote_lines'],
    -- Sales / Invoices
    ARRAY['sales', 'invoices'],
    ARRAY['sales', 'invoice_lines'],
    ARRAY['sales', 'payments'],
    -- Purchases
    ARRAY['purchases', 'purchase_invoices'],
    ARRAY['purchases', 'purchase_invoice_lines'],
    ARRAY['purchases', 'purchase_payments'],
    ARRAY['purchases', 'purchase_orders'],
    ARRAY['purchases', 'purchase_order_lines'],
    -- Internal
    ARRAY['internal', 'suppliers'],
    ARRAY['internal', 'technicians'],
    ARRAY['internal', 'authorized_users'],
    ARRAY['internal', 'company_settings'],
    ARRAY['internal', 'company_bank_accounts'],
    -- Payroll
    ARRAY['payroll', 'partners'],
    ARRAY['payroll', 'payroll_runs'],
    ARRAY['payroll', 'partner_compensation_runs'],
    -- Accounting
    ARRAY['accounting', 'journal_entries'],
    ARRAY['accounting', 'journal_entry_lines'],
    -- AI
    ARRAY['ai', 'conversations'],
    ARRAY['ai', 'conversation_members'],
    ARRAY['ai', 'messages'],
    ARRAY['ai', 'chat_requests']
  ];
  v_rec text[];
  v_result jsonb := '[]'::jsonb;
  v_count integer;
BEGIN
  FOREACH v_rec SLICE 1 IN ARRAY v_tables
  LOOP
    BEGIN
      v_count := backup.snapshot_table(v_rec[1], v_rec[2]);
      v_result := v_result || jsonb_build_object(
        'schema', v_rec[1], 'table', v_rec[2], 'rows', v_count, 'status', 'ok'
      );
    EXCEPTION WHEN OTHERS THEN
      v_result := v_result || jsonb_build_object(
        'schema', v_rec[1], 'table', v_rec[2], 'status', 'error', 'message', SQLERRM
      );
    END;
  END LOOP;

  RETURN jsonb_build_object('date', CURRENT_DATE, 'tables', v_result);
END;
$$;
ALTER FUNCTION "backup"."run_daily_backup"() OWNER TO "postgres";
--
-- Name: snapshot_table("text", "text"); Type: FUNCTION; Schema: backup; Owner: postgres
--

CREATE FUNCTION "backup"."snapshot_table"("p_schema" "text", "p_table" "text") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'backup', 'public'
    AS $$
DECLARE
  v_data jsonb;
  v_count integer;
BEGIN
  EXECUTE format(
    'SELECT COALESCE(jsonb_agg(row_to_json(t)), ''[]''::jsonb) FROM %I.%I t',
    p_schema, p_table
  ) INTO v_data;

  v_count := jsonb_array_length(v_data);

  INSERT INTO backup.daily_snapshots (table_schema, table_name, snapshot_date, row_count, data)
  VALUES (p_schema, p_table, CURRENT_DATE, v_count, v_data)
  ON CONFLICT (table_schema, table_name, snapshot_date)
  DO UPDATE SET data = EXCLUDED.data, row_count = EXCLUDED.row_count, created_at = now();

  RETURN v_count;
END;
$$;
ALTER FUNCTION "backup"."snapshot_table"("p_schema" "text", "p_table" "text") OWNER TO "postgres";
--
-- Name: apply_stock_movement(); Type: FUNCTION; Schema: catalog; Owner: postgres
--

CREATE FUNCTION "catalog"."apply_stock_movement"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'catalog'
    AS $$
DECLARE v_delta NUMERIC(12,3); v_track BOOLEAN;
BEGIN
  SELECT track_stock INTO v_track FROM catalog.products WHERE id = NEW.product_id;
  IF NOT v_track THEN RETURN NEW; END IF;
  v_delta := CASE WHEN NEW.movement_type IN ('IN', 'RETURN_IN') THEN NEW.quantity WHEN NEW.movement_type IN ('OUT', 'RETURN_OUT') THEN -NEW.quantity WHEN NEW.movement_type = 'ADJUST' THEN NEW.quantity ELSE 0 END;
  UPDATE catalog.products SET stock_quantity = GREATEST(0, COALESCE(stock_quantity, 0) + v_delta), updated_at = now() WHERE id = NEW.product_id;
  RETURN NEW;
END;
$$;
ALTER FUNCTION "catalog"."apply_stock_movement"() OWNER TO "postgres";
--
-- Name: calculate_margin(); Type: FUNCTION; Schema: catalog; Owner: postgres
--

CREATE FUNCTION "catalog"."calculate_margin"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'catalog'
    AS $$
DECLARE v_sale_effective NUMERIC(12,2);
BEGIN
  NEW.updated_at := now();
  v_sale_effective := NEW.sale_price * (1 - COALESCE(NEW.discount_percent, 0) / 100);
  IF NEW.cost_price IS NOT NULL AND NEW.cost_price >= 0 AND v_sale_effective > 0 THEN
    NEW.margin_percentage := ((v_sale_effective - NEW.cost_price) / v_sale_effective) * 100;
  ELSE
    NEW.margin_percentage := NULL;
  END IF;
  RETURN NEW;
END;
$$;
ALTER FUNCTION "catalog"."calculate_margin"() OWNER TO "postgres";
--
-- Name: check_product_category_domain(); Type: FUNCTION; Schema: catalog; Owner: postgres
--

CREATE FUNCTION "catalog"."check_product_category_domain"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'catalog'
    AS $$
DECLARE v_cat_domain catalog.category_domain;
BEGIN
  IF NEW.category_id IS NULL THEN RETURN NEW; END IF;
  SELECT domain INTO v_cat_domain FROM catalog.categories WHERE id = NEW.category_id;
  IF v_cat_domain IS NULL THEN RETURN NEW; END IF;
  IF NEW.product_type = 'PRODUCT' AND v_cat_domain != 'PRODUCT' THEN RAISE EXCEPTION 'Un producto solo puede asignarse a categor├¡as de dominio PRODUCT'; END IF;
  IF NEW.product_type = 'SERVICE' AND v_cat_domain != 'SERVICE' THEN RAISE EXCEPTION 'Un servicio solo puede asignarse a categor├¡as de dominio SERVICE'; END IF;
  RETURN NEW;
END;
$$;
ALTER FUNCTION "catalog"."check_product_category_domain"() OWNER TO "postgres";
--
-- Name: on_invoice_line_stock(); Type: FUNCTION; Schema: catalog; Owner: postgres
--

CREATE FUNCTION "catalog"."on_invoice_line_stock"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'catalog', 'sales', 'internal'
    AS $$
DECLARE
  v_ptype catalog.product_type;
  v_track BOOLEAN;
  v_qty NUMERIC(12,3);
  v_delta NUMERIC(12,3);
  v_comp RECORD;
  v_user_id UUID;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());

  IF TG_OP = 'DELETE' THEN
    IF OLD.product_id IS NULL THEN RETURN OLD; END IF;
    SELECT product_type, track_stock, COALESCE(OLD.quantity, 0) INTO v_ptype, v_track, v_qty
    FROM catalog.products WHERE id = OLD.product_id;
    IF v_ptype = 'BUNDLE' THEN
      FOR v_comp IN
        SELECT pb.component_product_id, pb.quantity * v_qty AS qty
        FROM catalog.product_bundles pb
        JOIN catalog.products pr ON pr.id = pb.component_product_id
        WHERE pb.bundle_product_id = OLD.product_id AND pr.track_stock
      LOOP
        INSERT INTO catalog.stock_movements (product_id, movement_type, quantity, reference_schema, reference_table, reference_id, notes, created_by)
        VALUES (v_comp.component_product_id, 'ADJUST', v_comp.qty, 'sales', 'invoice_lines', OLD.id, 'Revert bundle line delete', v_user_id);
      END LOOP;
    ELSIF v_track AND v_qty != 0 THEN
      INSERT INTO catalog.stock_movements (product_id, movement_type, quantity, reference_schema, reference_table, reference_id, notes, created_by)
      VALUES (OLD.product_id, 'ADJUST', v_qty, 'sales', 'invoice_lines', OLD.id, 'Revert line delete', v_user_id);
    END IF;
    RETURN OLD;
  END IF;

  IF NEW.product_id IS NULL THEN RETURN NEW; END IF;

  SELECT product_type, track_stock INTO v_ptype, v_track FROM catalog.products WHERE id = NEW.product_id;

  IF TG_OP = 'INSERT' THEN
    v_qty := COALESCE(NEW.quantity, 0);
    IF v_qty <= 0 THEN RETURN NEW; END IF;

    IF v_ptype = 'BUNDLE' THEN
      FOR v_comp IN
        SELECT pb.component_product_id, pb.quantity * v_qty AS qty
        FROM catalog.product_bundles pb
        JOIN catalog.products pr ON pr.id = pb.component_product_id
        WHERE pb.bundle_product_id = NEW.product_id AND pr.track_stock
      LOOP
        IF NOT EXISTS (SELECT 1 FROM catalog.stock_movements WHERE reference_table = 'invoice_lines' AND reference_id = NEW.id AND product_id = v_comp.component_product_id AND movement_type = 'OUT') THEN
          INSERT INTO catalog.stock_movements (product_id, movement_type, quantity, reference_schema, reference_table, reference_id, notes, created_by)
          VALUES (v_comp.component_product_id, 'OUT', v_comp.qty, 'sales', 'invoice_lines', NEW.id, 'Bundle component', v_user_id);
        END IF;
      END LOOP;
      RETURN NEW;
    END IF;

    IF NOT v_track THEN RETURN NEW; END IF;
    IF NOT EXISTS (SELECT 1 FROM catalog.stock_movements WHERE reference_table = 'invoice_lines' AND reference_id = NEW.id AND product_id = NEW.product_id AND movement_type = 'OUT') THEN
      INSERT INTO catalog.stock_movements (product_id, movement_type, quantity, reference_schema, reference_table, reference_id, notes, created_by)
      VALUES (NEW.product_id, 'OUT', v_qty, 'sales', 'invoice_lines', NEW.id, 'Invoice line', v_user_id);
    END IF;
    RETURN NEW;
  END IF;

  IF TG_OP = 'UPDATE' AND OLD.quantity IS DISTINCT FROM NEW.quantity THEN
    v_delta := COALESCE(OLD.quantity, 0) - COALESCE(NEW.quantity, 0);
    IF v_delta = 0 THEN RETURN NEW; END IF;

    IF v_ptype = 'BUNDLE' THEN
      FOR v_comp IN
        SELECT pb.component_product_id, pb.quantity * v_delta AS qty
        FROM catalog.product_bundles pb
        JOIN catalog.products pr ON pr.id = pb.component_product_id
        WHERE pb.bundle_product_id = NEW.product_id AND pr.track_stock
      LOOP
        INSERT INTO catalog.stock_movements (product_id, movement_type, quantity, reference_schema, reference_table, reference_id, notes, created_by)
        VALUES (v_comp.component_product_id, 'ADJUST', v_comp.qty, 'sales', 'invoice_lines', NEW.id, 'Bundle line qty change', v_user_id);
      END LOOP;
    ELSIF v_track THEN
      INSERT INTO catalog.stock_movements (product_id, movement_type, quantity, reference_schema, reference_table, reference_id, notes, created_by)
      VALUES (NEW.product_id, 'ADJUST', v_delta, 'sales', 'invoice_lines', NEW.id, 'Invoice line qty change', v_user_id);
    END IF;
  END IF;
  RETURN NEW;
END;
$$;
ALTER FUNCTION "catalog"."on_invoice_line_stock"() OWNER TO "postgres";
--
-- Name: FUNCTION "on_invoice_line_stock"(); Type: COMMENT; Schema: catalog; Owner: postgres
--

COMMENT ON FUNCTION "catalog"."on_invoice_line_stock"() IS 'Ventas: OUT por l├¡nea (producto simple o componentes si BUNDLE). UPDATE/DELETE ajustan/revierten. Idempotencia por (reference_table, reference_id, product_id).';
--
-- Name: on_purchase_invoice_line_stock(); Type: FUNCTION; Schema: catalog; Owner: postgres
--

CREATE FUNCTION "catalog"."on_purchase_invoice_line_stock"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'catalog', 'sales', 'internal'
    AS $$
DECLARE v_track BOOLEAN; v_qty NUMERIC(12,3); v_user_id UUID;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF TG_OP = 'DELETE' THEN SELECT track_stock, COALESCE(OLD.quantity, 0) INTO v_track, v_qty FROM catalog.products WHERE id = OLD.product_id; IF v_track AND OLD.product_id IS NOT NULL AND v_qty != 0 THEN INSERT INTO catalog.stock_movements (product_id, movement_type, quantity, reference_schema, reference_table, reference_id, notes, created_by) VALUES (OLD.product_id, 'ADJUST', -v_qty, 'sales', 'purchase_invoice_lines', OLD.id, 'Revert purchase line delete', v_user_id); END IF; RETURN OLD; END IF;
  IF NEW.product_id IS NULL THEN RETURN NEW; END IF;
  SELECT track_stock INTO v_track FROM catalog.products WHERE id = NEW.product_id;
  IF NOT v_track THEN RETURN NEW; END IF;
  IF TG_OP = 'INSERT' THEN v_qty := COALESCE(NEW.quantity, 0); IF v_qty <= 0 THEN RETURN NEW; END IF; IF NOT EXISTS (SELECT 1 FROM catalog.stock_movements WHERE reference_table = 'purchase_invoice_lines' AND reference_id = NEW.id AND movement_type = 'IN') THEN INSERT INTO catalog.stock_movements (product_id, movement_type, quantity, reference_schema, reference_table, reference_id, notes, created_by) VALUES (NEW.product_id, 'IN', v_qty, 'sales', 'purchase_invoice_lines', NEW.id, 'Purchase line', v_user_id); END IF; RETURN NEW; END IF;
  IF TG_OP = 'UPDATE' AND OLD.quantity IS DISTINCT FROM NEW.quantity THEN v_qty := COALESCE(NEW.quantity, 0) - COALESCE(OLD.quantity, 0); IF v_qty != 0 THEN INSERT INTO catalog.stock_movements (product_id, movement_type, quantity, reference_schema, reference_table, reference_id, notes, created_by) VALUES (NEW.product_id, 'ADJUST', v_qty, 'sales', 'purchase_invoice_lines', NEW.id, 'Purchase line qty change', v_user_id); END IF; END IF;
  RETURN NEW;
END;
$$;
ALTER FUNCTION "catalog"."on_purchase_invoice_line_stock"() OWNER TO "postgres";
--
-- Name: sync_stock_alert(); Type: FUNCTION; Schema: catalog; Owner: postgres
--

CREATE FUNCTION "catalog"."sync_stock_alert"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'catalog'
    AS $$
BEGIN
  IF NOT NEW.track_stock OR NEW.min_stock_alert IS NULL THEN RETURN NEW; END IF;
  IF COALESCE(NEW.stock_quantity, 0) <= NEW.min_stock_alert THEN
    IF NOT EXISTS (SELECT 1 FROM catalog.stock_alerts WHERE product_id = NEW.id AND status = 'open') THEN INSERT INTO catalog.stock_alerts (product_id, status) VALUES (NEW.id, 'open'); END IF;
  ELSE
    UPDATE catalog.stock_alerts SET status = 'resolved', resolved_at = now() WHERE product_id = NEW.id AND status = 'open';
  END IF;
  RETURN NEW;
END;
$$;
ALTER FUNCTION "catalog"."sync_stock_alert"() OWNER TO "postgres";
--
-- Name: calculate_profile_score("uuid"); Type: FUNCTION; Schema: crm; Owner: postgres
--

CREATE FUNCTION "crm"."calculate_profile_score"("p_client_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'crm'
    AS $$

DECLARE

  v_score INTEGER := 30; -- Base score

  v_client crm.clients%ROWTYPE;

  v_has_contact BOOLEAN;

BEGIN

  SELECT * INTO v_client FROM crm.clients WHERE id = p_client_id;

  

  IF NOT FOUND THEN

    RETURN 0;

  END IF;

  

  -- +10 for tax_id

  IF v_client.tax_id IS NOT NULL THEN

    v_score := v_score + 10;

  END IF;

  

  -- +10 for billing_address complete

  IF v_client.billing_address IS NOT NULL AND v_client.billing_city IS NOT NULL THEN

    v_score := v_score + 10;

  END IF;

  

  -- +5 for website

  IF v_client.website IS NOT NULL THEN

    v_score := v_score + 5;

  END IF;

  

  -- +5 for social media

  IF v_client.instagram_handle IS NOT NULL OR v_client.tiktok_handle IS NOT NULL THEN

    v_score := v_score + 5;

  END IF;

  

  -- +10 for industry_sector

  IF v_client.industry_sector IS NOT NULL THEN

    v_score := v_score + 10;

  END IF;

  

  -- +5 for number_of_locations > 1

  IF v_client.number_of_locations > 1 THEN

    v_score := v_score + 5;

  END IF;

  

  -- +10 for approximate_budget

  IF v_client.approximate_budget IS NOT NULL THEN

    v_score := v_score + 10;

  END IF;

  

  -- +10 for extra contact

  SELECT EXISTS(SELECT 1 FROM crm.contacts WHERE client_id = p_client_id) INTO v_has_contact;

  IF v_has_contact THEN

    v_score := v_score + 10;

  END IF;

  

  -- Removed reference to crm.locations table as it was dropped.

  -- This fixes the "relation crm.locations does not exist" error.

  

  RETURN LEAST(v_score, 100);

END;

$$;
ALTER FUNCTION "crm"."calculate_profile_score"("p_client_id" "uuid") OWNER TO "postgres";
--
-- Name: can_access_client("uuid"); Type: FUNCTION; Schema: crm; Owner: postgres
--

CREATE FUNCTION "crm"."can_access_client"("p_client_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'crm', 'public'
    AS $$
  SELECT 
    internal.is_admin() OR 
    internal.is_manager() OR 
    internal.is_readonly() OR
    (internal.is_sales() AND EXISTS (
      SELECT 1 FROM crm.clients 
      WHERE id = p_client_id 
      AND assigned_to = internal.get_authorized_user_id(auth.uid())
    ))
$$;
