    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'crm'
    AS $$
BEGIN
  IF NEW.client_number IS NULL OR NEW.client_number = '' THEN
    NEW.client_number := 'CLI-' || LPAD(nextval('crm.client_number_seq')::TEXT, 6, '0');
