-- Name: get_canvassing_location("uuid"); Type: FUNCTION; Schema: crm; Owner: postgres
--

CREATE FUNCTION "crm"."get_canvassing_location"("p_location_id" "uuid") RETURNS TABLE("id" "uuid", "status" "crm"."canvassing_status", "address" "text", "city" "text", "province" "text", "postal_code" "text", "country" "text", "latitude" numeric, "longitude" numeric, "location_notes" "text", "contact_first_name" "text", "contact_last_name" "text", "contact_phone_primary" "text", "contact_phone_secondary" "text", "contact_email_primary" "text", "contact_email_secondary" "text", "preferred_contact_method" "text", "best_contact_time" "text", "priority" "text", "lead_score" integer, "lead_source" "text", "assigned_to" "uuid", "team_id" "uuid", "property_type" "text", "property_status" "text", "owner_name" "text", "construction_year" integer, "property_size_sqm" numeric, "number_of_floors" integer, "roof_condition" "text", "facade_condition" "text", "roof_type" "text", "last_renovation_date" "date", "product_interest" "text"[], "estimated_budget" numeric, "need_urgency" "text", "competitors_contacted" boolean, "competitors_list" "text", "main_objections" "text", "interest_level" integer, "appointment_date" "date", "appointment_time" time without time zone, "appointment_type" "text", "callback_date" "date", "callback_time" time without time zone, "reminder_enabled" boolean, "reminder_time_before" "text", "general_notes" "text", "visit_notes" "text", "internal_notes" "text", "tags" "text"[], "custom_field_1" "text", "custom_field_2" "text", "custom_field_3" "text", "custom_field_4" "text", "custom_field_5" "text", "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'crm', 'public'
    AS $$

DECLARE

  v_user_id UUID;

BEGIN

  v_user_id := internal.get_authorized_user_id(auth.uid());

  

  -- Verificar permisos: solo el creador o admin/manager

  IF NOT EXISTS (

    SELECT 1 FROM crm.location 

    WHERE id = p_location_id 

    AND (created_by = v_user_id OR internal.is_admin() OR internal.is_manager())

  ) THEN

    RAISE EXCEPTION 'No tienes permiso para ver este punto de Canvassing';

  END IF;

  

  RETURN QUERY

  SELECT 

    l.id,

    l.status,

    l.address,

    l.city,

    l.province,

    l.postal_code,

    l.country,

    l.latitude,

    l.longitude,

    l.location_notes,

    l.contact_first_name,

    l.contact_last_name,

    l.contact_phone_primary,

    l.contact_phone_secondary,

    l.contact_email_primary,

    l.contact_email_secondary,

    l.preferred_contact_method::TEXT,

    l.best_contact_time::TEXT,

    l.priority::TEXT,

    l.lead_score,

    l.lead_source,

    l.assigned_to,

    l.team_id,

    l.property_type::TEXT,

    l.property_status::TEXT,

    l.owner_name,

    l.construction_year,

    l.property_size_sqm,

    l.number_of_floors,

    l.roof_condition::TEXT,

    l.facade_condition::TEXT,

    l.roof_type::TEXT,

    l.last_renovation_date,

    l.product_interest,

    l.estimated_budget,

    l.need_urgency::TEXT,

    l.competitors_contacted,

    l.competitors_list,

    l.main_objections,

    l.interest_level,

    l.appointment_date,

    l.appointment_time,

    l.appointment_type::TEXT,

    l.callback_date,

    l.callback_time,

    l.reminder_enabled,

    l.reminder_time_before,

    l.general_notes,

    l.visit_notes,

    l.internal_notes,

    l.tags,

    l.custom_field_1,

    l.custom_field_2,

    l.custom_field_3,

    l.custom_field_4,

    l.custom_field_5,

    l.created_at,

    l.updated_at

  FROM crm.location l

  WHERE l.id = p_location_id;

END;

$$;
ALTER FUNCTION "crm"."get_canvassing_location"("p_location_id" "uuid") OWNER TO "postgres";
--
-- Name: list_user_canvassing_locations("uuid"); Type: FUNCTION; Schema: crm; Owner: postgres
--

CREATE FUNCTION "crm"."list_user_canvassing_locations"("p_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "status" "crm"."canvassing_status", "address" "text", "city" "text", "province" "text", "postal_code" "text", "latitude" numeric, "longitude" numeric, "contact_first_name" "text", "contact_last_name" "text", "contact_phone_primary" "text", "contact_email_primary" "text", "priority" "crm"."canvassing_priority", "lead_score" integer, "appointment_date" "date", "callback_date" "date", "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'crm', 'public'
    AS $$

DECLARE

  v_user_id UUID;

BEGIN

  -- Si no se proporciona user_id, usar el del usuario autenticado

  v_user_id := COALESCE(p_user_id, internal.get_authorized_user_id(auth.uid()));

  

  -- Verificar permisos: solo el propio usuario o admin/manager

  IF v_user_id != internal.get_authorized_user_id(auth.uid()) AND 

     NOT (internal.is_admin() OR internal.is_manager()) THEN

    RAISE EXCEPTION 'No tienes permiso para ver estos puntos de Canvassing';

  END IF;

  

  RETURN QUERY

  SELECT 

    l.id,

    l.status,

    l.address,

    l.city,

    l.province,

    l.postal_code,

    l.latitude,

    l.longitude,

    l.contact_first_name,

    l.contact_last_name,

    l.contact_phone_primary,

    l.contact_email_primary,

    l.priority,

    l.lead_score,

    l.appointment_date,

    l.callback_date,

    l.created_at,

    l.updated_at

  FROM crm.location l

  WHERE l.created_by = v_user_id

  ORDER BY l.created_at DESC;

END;

$$;
ALTER FUNCTION "crm"."list_user_canvassing_locations"("p_user_id" "uuid") OWNER TO "postgres";
