--
-- Name: log_location_status_change(); Type: FUNCTION; Schema: crm; Owner: postgres
--

CREATE FUNCTION "crm"."log_location_status_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'crm', 'public'
    AS $$
DECLARE
  v_user_id uuid;
  v_status_label_old text;
  v_status_label_new text;
BEGIN
  -- Only proceed if status actually changed
  IF OLD.status IS DISTINCT FROM NEW.status THEN
    -- Get current user
    v_user_id := internal.get_authorized_user_id(auth.uid());
    
    -- Map status codes to labels for readable notes
    SELECT CASE OLD.status
      WHEN 'NOT_VISITED' THEN 'No Visitado'
      WHEN 'VISITED_NO_CONTACT' THEN 'Visitado Sin Contacto'
      WHEN 'VISITED_CONTACTED' THEN 'Visitado y Contactado'
      WHEN 'INTERESTED' THEN 'Interesado'
      WHEN 'CALLBACK_SCHEDULED' THEN 'Callback Programado'
      WHEN 'MEETING_SCHEDULED' THEN 'Reuni├│n Programada'
      WHEN 'PROPOSAL_SENT' THEN 'Propuesta Enviada'
      WHEN 'NEGOTIATING' THEN 'En Negociaci├│n'
      WHEN 'CONVERTED' THEN 'Convertido a Cliente'
      WHEN 'NOT_INTERESTED' THEN 'No Interesado'
      WHEN 'CLOSED_PERMANENTLY' THEN 'Cerrado Permanentemente'
      ELSE OLD.status
    END INTO v_status_label_old;
    
    SELECT CASE NEW.status
      WHEN 'NOT_VISITED' THEN 'No Visitado'
      WHEN 'VISITED_NO_CONTACT' THEN 'Visitado Sin Contacto'
      WHEN 'VISITED_CONTACTED' THEN 'Visitado y Contactado'
      WHEN 'INTERESTED' THEN 'Interesado'
      WHEN 'CALLBACK_SCHEDULED' THEN 'Callback Programado'
      WHEN 'MEETING_SCHEDULED' THEN 'Reuni├│n Programada'
      WHEN 'PROPOSAL_SENT' THEN 'Propuesta Enviada'
      WHEN 'NEGOTIATING' THEN 'En Negociaci├│n'
      WHEN 'CONVERTED' THEN 'Convertido a Cliente'
      WHEN 'NOT_INTERESTED' THEN 'No Interesado'
      WHEN 'CLOSED_PERMANENTLY' THEN 'Cerrado Permanentemente'
      ELSE NEW.status
    END INTO v_status_label_new;
    
    -- Insert status change note
    INSERT INTO crm.location_notes (
      location_id,
      note_type,
      content,
      created_by
    ) VALUES (
      NEW.id,
      'STATUS_CHANGE'::crm.location_note_type,
      'Estado cambiado de "' || v_status_label_old || '" a "' || v_status_label_new || '"',
      v_user_id
    );
  END IF;
  
  RETURN NEW;
END;
$$;
ALTER FUNCTION "crm"."log_location_status_change"() OWNER TO "postgres";
