--
-- Name: update_location_status_history(); Type: FUNCTION; Schema: crm; Owner: postgres
--

CREATE FUNCTION "crm"."update_location_status_history"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'crm', 'public'
    AS $$

DECLARE

  v_user_id UUID;

  v_user_name TEXT;

  v_history JSONB;

BEGIN

  -- Solo actualizar si cambi├│ el status

  IF OLD.status IS DISTINCT FROM NEW.status THEN

    v_user_id := internal.get_authorized_user_id(auth.uid());

    

    -- Obtener nombre del usuario

    SELECT full_name INTO v_user_name

    FROM internal.authorized_users

    WHERE id = v_user_id;

    

    -- Obtener historial existente o inicializar

    v_history := COALESCE(NEW.status_history, '[]'::JSONB);

    

    -- A├▒adir nueva entrada al historial con motivo (se actualizar├í desde la app si se proporciona)

    v_history := v_history || jsonb_build_array(

      jsonb_build_object(

        'status', NEW.status::TEXT,

        'previous_status', OLD.status::TEXT,

        'date', now()::TEXT,

        'user_id', v_user_id::TEXT,

        'user_name', COALESCE(v_user_name, 'Usuario desconocido'),

        'reason', NULL -- Se actualizar├í desde la aplicaci├│n si se proporciona

      )

    );

    

    NEW.status_history := v_history;

    NEW.modified_by := v_user_id;

  END IF;

  

  RETURN NEW;

END;

$$;
ALTER FUNCTION "crm"."update_location_status_history"() OWNER TO "postgres";
--
-- Name: admin_update_payroll_settings("jsonb", "text"); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."admin_update_payroll_settings"("p_patch" "jsonb", "p_reason" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal', 'public'
    AS $$
DECLARE
  v_row internal.payroll_settings%ROWTYPE;
  v_old jsonb;
  v_new jsonb;
  v_user_id uuid;
  v_is_admin boolean;
BEGIN
  IF p_reason IS NULL OR trim(p_reason) = '' THEN
    RAISE EXCEPTION 'Reason obligatorio';
  END IF;

  v_user_id := auth.uid();
  SELECT EXISTS (
    SELECT 1 FROM internal.authorized_users au
    JOIN internal.user_roles ur ON ur.user_id = au.id
    JOIN internal.roles r ON r.id = ur.role_id
    WHERE au.auth_user_id = v_user_id AND r.name = 'admin'
  ) INTO v_is_admin;

  IF NOT v_is_admin THEN
    RAISE EXCEPTION 'Solo administradores pueden modificar payroll_settings';
  END IF;

  SELECT * INTO v_row FROM internal.payroll_settings ORDER BY updated_at DESC LIMIT 1;

  IF v_row.id IS NULL THEN
    INSERT INTO internal.payroll_settings (scope, bonus_enabled, bonus_percent, bonus_cap_amount, min_profit_to_pay_bonus, bonus_reference_mode, bonus_requires_closed_period, default_irpf_rate, version, updated_by)
    VALUES (
      COALESCE((p_patch->>'scope')::text, 'company'),
      COALESCE((p_patch->>'bonus_enabled')::boolean, true),
      LEAST(100, GREATEST(0, COALESCE((p_patch->>'bonus_percent')::numeric, 10))),
      GREATEST(0, COALESCE((p_patch->>'bonus_cap_amount')::numeric, 600)),
      GREATEST(0, COALESCE((p_patch->>'min_profit_to_pay_bonus')::numeric, 0)),
      COALESCE((p_patch->>'bonus_reference_mode')::text, 'NET_PROFIT_PREV_MONTH'),
      COALESCE((p_patch->>'bonus_requires_closed_period')::boolean, false),
      (p_patch->>'default_irpf_rate')::numeric,
      1,
      (SELECT id FROM internal.authorized_users WHERE auth_user_id = v_user_id LIMIT 1)
    );
    RETURN;
  END IF;

  v_old := to_jsonb(v_row);
  v_new := v_old || p_patch;

  UPDATE internal.payroll_settings SET
    bonus_enabled = COALESCE((v_new->>'bonus_enabled')::boolean, bonus_enabled),
    bonus_percent = LEAST(100, GREATEST(0, COALESCE((v_new->>'bonus_percent')::numeric, bonus_percent))),
    bonus_cap_amount = GREATEST(0, COALESCE((v_new->>'bonus_cap_amount')::numeric, bonus_cap_amount)),
    min_profit_to_pay_bonus = GREATEST(0, COALESCE((v_new->>'min_profit_to_pay_bonus')::numeric, min_profit_to_pay_bonus)),
    bonus_reference_mode = COALESCE((v_new->>'bonus_reference_mode')::text, bonus_reference_mode),
    bonus_requires_closed_period = COALESCE((v_new->>'bonus_requires_closed_period')::boolean, bonus_requires_closed_period),
    default_irpf_rate = (v_new->>'default_irpf_rate')::numeric,
    version = version + 1,
    updated_at = now(),
    updated_by = (SELECT id FROM internal.authorized_users WHERE auth_user_id = v_user_id LIMIT 1)
  WHERE id = v_row.id;

  INSERT INTO internal.payroll_settings_audit (settings_id, changed_by, old_values, new_values, reason)
  VALUES (v_row.id, (SELECT id FROM internal.authorized_users WHERE auth_user_id = v_user_id LIMIT 1), v_old, v_new, p_reason);
END;
$$;
ALTER FUNCTION "internal"."admin_update_payroll_settings"("p_patch" "jsonb", "p_reason" "text") OWNER TO "postgres";
--
-- Name: admin_update_report_settings("jsonb"); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."admin_update_report_settings"("p_patch" "jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal', 'public'
    AS $$
DECLARE
  v_user_id uuid;
  v_is_admin boolean;
  v_row internal.report_settings%ROWTYPE;
BEGIN
  v_user_id := auth.uid();
  SELECT EXISTS (
    SELECT 1 FROM internal.authorized_users au
    JOIN internal.user_roles ur ON ur.user_id = au.id
    JOIN internal.roles r ON r.id = ur.role_id
    WHERE au.auth_user_id = v_user_id AND r.name = 'admin'
  ) INTO v_is_admin;

  IF NOT v_is_admin THEN
    RAISE EXCEPTION 'Solo administradores pueden modificar report_settings';
  END IF;

  SELECT * INTO v_row FROM internal.report_settings WHERE scope = 'company' LIMIT 1;

  IF v_row.id IS NULL THEN
    INSERT INTO internal.report_settings (scope, monthly_report_auto_send_enabled, auto_send_on_close,
      recipients_to, recipients_cc, from_email, email_subject_template,
      include_pdf_attachment, use_signed_link_instead_of_attachment,
      signed_link_expiry_days, template_version, language, updated_by)
    VALUES (
      'company',
      COALESCE((p_patch->>'monthly_report_auto_send_enabled')::boolean, false),
      COALESCE((p_patch->>'auto_send_on_close')::boolean, true),
      COALESCE((p_patch->'recipients_to')::text[], '{}'),
      COALESCE((p_patch->'recipients_cc')::text[], '{}'),
      (p_patch->>'from_email')::text,
      COALESCE((p_patch->>'email_subject_template')::text, 'Informe cierre contable ÔÇô {Mes} {A├▒o}'),
      COALESCE((p_patch->>'include_pdf_attachment')::boolean, false),
      COALESCE((p_patch->>'use_signed_link_instead_of_attachment')::boolean, true),
      COALESCE((p_patch->>'signed_link_expiry_days')::integer, 30),
      COALESCE((p_patch->>'template_version')::text, 'v1'),
      COALESCE((p_patch->>'language')::text, 'ES'),
      (SELECT id FROM internal.authorized_users WHERE auth_user_id = v_user_id LIMIT 1)
    );
    RETURN;
  END IF;

  UPDATE internal.report_settings SET
    monthly_report_auto_send_enabled = COALESCE((p_patch->>'monthly_report_auto_send_enabled')::boolean, monthly_report_auto_send_enabled),
    auto_send_on_close = COALESCE((p_patch->>'auto_send_on_close')::boolean, auto_send_on_close),
    recipients_to = COALESCE((p_patch->'recipients_to')::text[], recipients_to),
    recipients_cc = COALESCE((p_patch->'recipients_cc')::text[], recipients_cc),
    from_email = COALESCE((p_patch->>'from_email')::text, from_email),
    email_subject_template = COALESCE((p_patch->>'email_subject_template')::text, email_subject_template),
    include_pdf_attachment = COALESCE((p_patch->>'include_pdf_attachment')::boolean, include_pdf_attachment),
    use_signed_link_instead_of_attachment = COALESCE((p_patch->>'use_signed_link_instead_of_attachment')::boolean, use_signed_link_instead_of_attachment),
    signed_link_expiry_days = COALESCE((p_patch->>'signed_link_expiry_days')::integer, signed_link_expiry_days),
    template_version = COALESCE((p_patch->>'template_version')::text, template_version),
    language = COALESCE((p_patch->>'language')::text, language),
    updated_at = now(),
    updated_by = (SELECT id FROM internal.authorized_users WHERE auth_user_id = v_user_id LIMIT 1)
  WHERE id = v_row.id;
END;
$$;
ALTER FUNCTION "internal"."admin_update_report_settings"("p_patch" "jsonb") OWNER TO "postgres";
