--
-- Name: partner_payroll_profiles; Type: TABLE; Schema: internal; Owner: postgres
--

CREATE TABLE "internal"."partner_payroll_profiles" (
    "partner_id" "uuid" NOT NULL,
    "base_salary" numeric(12,2) DEFAULT 0 NOT NULL,
    "irpf_rate" numeric(5,2),
    "bonus_enabled_override" boolean,
    "bonus_cap_override" numeric(12,2),
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_by" "uuid"
);
ALTER TABLE "internal"."partner_payroll_profiles" OWNER TO "postgres";
--
-- Name: admin_upsert_partner_payroll_profile("uuid", numeric, numeric, boolean, numeric); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."admin_upsert_partner_payroll_profile"("p_partner_id" "uuid", "p_base_salary" numeric DEFAULT NULL::numeric, "p_irpf_rate" numeric DEFAULT NULL::numeric, "p_bonus_enabled_override" boolean DEFAULT NULL::boolean, "p_bonus_cap_override" numeric DEFAULT NULL::numeric) RETURNS "internal"."partner_payroll_profiles"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal'
    AS $$
DECLARE
  v_user_id UUID;
  v_is_admin BOOLEAN;
  v_result RECORD;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;

  SELECT EXISTS (
    SELECT 1 FROM public.user_roles ur
    WHERE ur.user_id = auth.uid() AND ur.role = 'admin'
  ) INTO v_is_admin;

  IF NOT v_is_admin THEN
    RAISE EXCEPTION 'Solo administradores pueden modificar perfiles de n├│mina';
  END IF;

  IF NOT EXISTS (SELECT 1 FROM internal.partners WHERE id = p_partner_id) THEN
    RAISE EXCEPTION 'Socio no encontrado';
  END IF;

  IF p_base_salary IS NOT NULL AND p_base_salary < 0 THEN
    RAISE EXCEPTION 'base_salary debe ser >= 0';
  END IF;
  IF p_irpf_rate IS NOT NULL AND (p_irpf_rate < 0 OR p_irpf_rate > 100) THEN
    RAISE EXCEPTION 'irpf_rate debe estar entre 0 y 100';
  END IF;
  IF p_bonus_cap_override IS NOT NULL AND p_bonus_cap_override < 0 THEN
    RAISE EXCEPTION 'bonus_cap_override debe ser >= 0';
  END IF;

  INSERT INTO internal.partner_payroll_profiles (
    partner_id, base_salary, irpf_rate, bonus_enabled_override, bonus_cap_override, updated_by
  )
  VALUES (
    p_partner_id,
    COALESCE(p_base_salary, 0),
    COALESCE(p_irpf_rate, 19),
    p_bonus_enabled_override,
    p_bonus_cap_override,
    v_user_id
  )
  ON CONFLICT (partner_id) DO UPDATE SET
    base_salary = CASE WHEN p_base_salary IS NOT NULL THEN p_base_salary ELSE partner_payroll_profiles.base_salary END,
    irpf_rate = CASE WHEN p_irpf_rate IS NOT NULL THEN p_irpf_rate ELSE partner_payroll_profiles.irpf_rate END,
    bonus_enabled_override = CASE WHEN p_bonus_enabled_override IS NOT NULL THEN p_bonus_enabled_override ELSE partner_payroll_profiles.bonus_enabled_override END,
    bonus_cap_override = CASE WHEN p_bonus_cap_override IS NOT NULL THEN p_bonus_cap_override ELSE partner_payroll_profiles.bonus_cap_override END,
    updated_at = now(),
    updated_by = v_user_id;

  SELECT * INTO v_result FROM internal.partner_payroll_profiles WHERE partner_id = p_partner_id;
  RETURN v_result;
END;
$$;
ALTER FUNCTION "internal"."admin_upsert_partner_payroll_profile"("p_partner_id" "uuid", "p_base_salary" numeric, "p_irpf_rate" numeric, "p_bonus_enabled_override" boolean, "p_bonus_cap_override" numeric) OWNER TO "postgres";
--
-- Name: assert_period_not_closed("date"); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."assert_period_not_closed"("p_date" "date") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'accounting', 'public'
    AS $$
DECLARE
  v_year int;
  v_month int;
  v_closed boolean;
BEGIN
  v_year := EXTRACT(YEAR FROM p_date)::int;
  v_month := EXTRACT(MONTH FROM p_date)::int;
  SELECT accounting.is_period_closed(v_year, v_month) INTO v_closed;
  IF v_closed THEN
    RAISE WARNING 'Periodo %/% est├í cerrado', v_year, v_month;
  END IF;
  RETURN true;
END;
$$;
ALTER FUNCTION "internal"."assert_period_not_closed"("p_date" "date") OWNER TO "postgres";
--
-- Name: calculate_partner_productivity_bonus("uuid", integer, integer); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."calculate_partner_productivity_bonus"("p_partner_id" "uuid", "p_year" integer, "p_month" integer) RETURNS TABLE("base_amount" numeric, "productivity_bonus" numeric, "gross_amount" numeric, "irpf_amount" numeric, "net_amount" numeric, "bonus_reference_year" integer, "bonus_reference_month" integer, "bonus_reference_net_profit" numeric, "bonus_percent_applied" numeric, "bonus_cap_applied" numeric, "bonus_policy_version" integer, "bonus_enabled" boolean, "message" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal', 'public'
    AS $$
DECLARE
  v_settings RECORD;
  v_profile RECORD;
  v_base numeric := 0;
  v_bonus numeric := 0;
  v_irpf numeric;
  v_net numeric;
  v_ref_year int;
  v_ref_month int;
  v_ref_start date;
  v_ref_end date;
  v_summary RECORD;
  v_net_profit numeric;
  v_msg text;
BEGIN
  SELECT * INTO v_settings FROM internal.payroll_settings ORDER BY updated_at DESC LIMIT 1;
  IF v_settings.id IS NULL THEN
    RETURN QUERY SELECT 0::numeric, 0::numeric, 0::numeric, 0::numeric, 0::numeric,
      NULL::int, NULL::int, NULL::numeric, NULL::numeric, NULL::numeric, NULL::int,
      false, 'No hay configuraci├│n de n├│minas'::text;
    RETURN;
  END IF;

  SELECT * INTO v_profile FROM internal.partner_payroll_profiles WHERE partner_id = p_partner_id;
  v_base := COALESCE(v_profile.base_salary, 0);

  v_ref_month := p_month - 1;
  v_ref_year := p_year;
  IF v_ref_month <= 0 THEN
    v_ref_month := v_ref_month + 12;
    v_ref_year := v_ref_year - 1;
  END IF;

  v_ref_start := make_date(v_ref_year, v_ref_month, 1);
  v_ref_end := (v_ref_start + interval '1 month' - interval '1 day')::date;

  IF v_settings.bonus_enabled AND COALESCE(v_profile.bonus_enabled_override, true) THEN
    IF v_settings.bonus_requires_closed_period THEN
      IF NOT accounting.is_period_closed(v_ref_year, v_ref_month) THEN
        RETURN QUERY SELECT v_base, 0::numeric, v_base, 
          ROUND(v_base * COALESCE(v_profile.irpf_rate, v_settings.default_irpf_rate, 19) / 100, 2),
          v_base - ROUND(v_base * COALESCE(v_profile.irpf_rate, v_settings.default_irpf_rate, 19) / 100, 2),
          v_ref_year, v_ref_month, NULL::numeric, NULL::numeric, NULL::numeric, v_settings.version,
          false, 'Mes anterior no cerrado'::text;
        RETURN;
      END IF;
    END IF;

    SELECT * INTO v_summary FROM accounting.get_period_profit_summary(v_ref_start, v_ref_end);
    v_net_profit := COALESCE(v_summary.net_profit, 0);

    IF v_net_profit < v_settings.min_profit_to_pay_bonus THEN
      RETURN QUERY SELECT v_base, 0::numeric, v_base,
        ROUND(v_base * COALESCE(v_profile.irpf_rate, v_settings.default_irpf_rate, 19) / 100, 2),
        v_base - ROUND(v_base * COALESCE(v_profile.irpf_rate, v_settings.default_irpf_rate, 19) / 100, 2),
        v_ref_year, v_ref_month, v_net_profit, NULL::numeric, NULL::numeric, v_settings.version,
        true, format('RN ref %s < umbral %s', v_net_profit, v_settings.min_profit_to_pay_bonus);
      RETURN;
    END IF;

    v_bonus := LEAST(
      ROUND(v_net_profit * v_settings.bonus_percent / 100, 2),
      COALESCE(v_profile.bonus_cap_override, v_settings.bonus_cap_amount)
    );
  END IF;

  v_irpf := ROUND((v_base + v_bonus) * COALESCE(v_profile.irpf_rate, v_settings.default_irpf_rate, 19) / 100, 2);
  v_net := v_base + v_bonus - v_irpf;

  RETURN QUERY SELECT
    v_base,
    v_bonus,
    v_base + v_bonus,
    v_irpf,
    v_net,
    v_ref_year,
    v_ref_month,
    v_net_profit,
    CASE WHEN v_bonus > 0 THEN v_settings.bonus_percent ELSE NULL END,
    CASE WHEN v_bonus > 0 THEN COALESCE(v_profile.bonus_cap_override, v_settings.bonus_cap_amount) ELSE NULL END,
    v_settings.version,
    v_settings.bonus_enabled,
    CASE WHEN v_bonus > 0 THEN format('Bonus: %s%% de RN %s ref %s/%s', v_settings.bonus_percent, v_net_profit, v_ref_year, v_ref_month) ELSE NULL END;
END;
$$;
ALTER FUNCTION "internal"."calculate_partner_productivity_bonus"("p_partner_id" "uuid", "p_year" integer, "p_month" integer) OWNER TO "postgres";
--
-- Name: can_access_client("uuid"); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."can_access_client"("p_client_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'internal', 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1 FROM crm.clients c
    WHERE c.id = p_client_id
    AND c.deleted_at IS NULL
    AND (
      -- User is assigned to this client
      c.assigned_to = internal.get_authorized_user_id(auth.uid())
      OR
      -- User is admin
      internal.is_admin()
    )
  )
$$;
ALTER FUNCTION "internal"."can_access_client"("p_client_id" "uuid") OWNER TO "postgres";
--
-- Name: create_partner_compensation_run_from_policy("uuid", integer, integer); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."create_partner_compensation_run_from_policy"("p_partner_id" "uuid", "p_year" integer, "p_month" integer) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal', 'public'
    AS $$
DECLARE
  v_run_id uuid;
  v_compensation_number text;
  v_calc RECORD;
  v_user_id uuid;
  v_irpf_rate numeric;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;

  SELECT * INTO v_calc FROM internal.calculate_partner_productivity_bonus(p_partner_id, p_year, p_month) LIMIT 1;

  v_irpf_rate := COALESCE((SELECT irpf_rate FROM internal.partner_payroll_profiles WHERE partner_id = p_partner_id), 19);

  SELECT 'RET-' || p_year::text || '-' || LPAD((COALESCE(MAX(CAST(SUBSTRING(compensation_number FROM 10) AS integer)), 0) + 1)::text, 4, '0')
  INTO v_compensation_number
  FROM internal.partner_compensation_runs
  WHERE compensation_number LIKE 'RET-' || p_year::text || '-%';

  INSERT INTO internal.partner_compensation_runs (
    partner_id, compensation_number, period_year, period_month,
    gross_amount, irpf_rate, irpf_amount, net_amount,
    base_amount, productivity_bonus,
    bonus_reference_year, bonus_reference_month, bonus_reference_net_profit,
    bonus_percent_applied, bonus_cap_applied, bonus_policy_version,
    notes, status, created_by
  ) VALUES (
    p_partner_id, v_compensation_number, p_year, p_month,
    v_calc.gross_amount, v_irpf_rate, v_calc.irpf_amount, v_calc.net_amount,
    v_calc.base_amount, v_calc.productivity_bonus,
    v_calc.bonus_reference_year, v_calc.bonus_reference_month, v_calc.bonus_reference_net_profit,
    v_calc.bonus_percent_applied, v_calc.bonus_cap_applied, v_calc.bonus_policy_version,
    format('Base: %s | Bonus: %s | Bruto: %s', COALESCE(v_calc.base_amount,0), COALESCE(v_calc.productivity_bonus,0), v_calc.gross_amount) ||
      CASE WHEN v_calc.message IS NOT NULL THEN E'\n' || v_calc.message ELSE '' END,
    'DRAFT', v_user_id
  )
  RETURNING id INTO v_run_id;

  RETURN v_run_id;
END;
$$;
ALTER FUNCTION "internal"."create_partner_compensation_run_from_policy"("p_partner_id" "uuid", "p_year" integer, "p_month" integer) OWNER TO "postgres";
--
-- Name: create_supplier("text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text"); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."create_supplier"("p_company_name" "text", "p_category" "text" DEFAULT NULL::"text", "p_tax_id" "text" DEFAULT NULL::"text", "p_contact_email" "text" DEFAULT NULL::"text", "p_contact_phone" "text" DEFAULT NULL::"text", "p_address" "text" DEFAULT NULL::"text", "p_city" "text" DEFAULT NULL::"text", "p_province" "text" DEFAULT NULL::"text", "p_postal_code" "text" DEFAULT NULL::"text", "p_country" "text" DEFAULT 'Espa├▒a'::"text", "p_payment_terms" "text" DEFAULT NULL::"text") RETURNS TABLE("supplier_id" "uuid", "supplier_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal', 'public'
    AS $_$
DECLARE
    v_supplier_id UUID;
    v_supplier_number TEXT;
    v_last_number INTEGER;
BEGIN
    IF p_category IS NOT NULL AND p_category NOT IN ('SOFTWARE', 'EXTERNAL_SERVICES', 'MATERIAL') THEN
        RAISE EXCEPTION 'Categor├¡a inv├ílida. Debe ser: SOFTWARE, EXTERNAL_SERVICES o MATERIAL';
    END IF;
    
    SELECT COALESCE(MAX(
        CASE 
            WHEN s.supplier_number ~ '^PRV-[0-9]+$' THEN
                CAST(SUBSTRING(s.supplier_number FROM 5) AS INTEGER)
            ELSE 0
        END
    ), 0)
    INTO v_last_number
    FROM internal.suppliers s
    WHERE s.supplier_number LIKE 'PRV-%';
    
    v_last_number := GREATEST(v_last_number + 1, 1);
    v_supplier_number := 'PRV-' || LPAD(v_last_number::TEXT, 6, '0');
    
    WHILE EXISTS (SELECT 1 FROM internal.suppliers s2 WHERE s2.supplier_number = v_supplier_number) LOOP
        v_last_number := v_last_number + 1;
        v_supplier_number := 'PRV-' || LPAD(v_last_number::TEXT, 6, '0');
    END LOOP;
    
    INSERT INTO internal.suppliers (
        supplier_number, company_name, category, tax_id,
        contact_email, contact_phone, address, city,
        province, postal_code, country, payment_terms, status
    ) VALUES (
        v_supplier_number, p_company_name, p_category, p_tax_id,
        p_contact_email, p_contact_phone, p_address, p_city,
        p_province, p_postal_code, p_country, p_payment_terms, 'ACTIVE'
    )
    RETURNING id INTO v_supplier_id;
    
    RETURN QUERY SELECT v_supplier_id, v_supplier_number;
END;
$_$;
ALTER FUNCTION "internal"."create_supplier"("p_company_name" "text", "p_category" "text", "p_tax_id" "text", "p_contact_email" "text", "p_contact_phone" "text", "p_address" "text", "p_city" "text", "p_province" "text", "p_postal_code" "text", "p_country" "text", "p_payment_terms" "text") OWNER TO "postgres";
--
-- Name: create_technician("text", "internal"."technician_type", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text"[], numeric, numeric, numeric, "text", "text", "text"); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."create_technician"("p_company_name" "text", "p_type" "internal"."technician_type" DEFAULT 'FREELANCER'::"internal"."technician_type", "p_legal_name" "text" DEFAULT NULL::"text", "p_tax_id" "text" DEFAULT NULL::"text", "p_contact_name" "text" DEFAULT NULL::"text", "p_contact_phone" "text" DEFAULT NULL::"text", "p_contact_phone_secondary" "text" DEFAULT NULL::"text", "p_contact_email" "text" DEFAULT NULL::"text", "p_billing_email" "text" DEFAULT NULL::"text", "p_address" "text" DEFAULT NULL::"text", "p_city" "text" DEFAULT NULL::"text", "p_province" "text" DEFAULT NULL::"text", "p_postal_code" "text" DEFAULT NULL::"text", "p_country" "text" DEFAULT 'Espa├▒a'::"text", "p_specialties" "text"[] DEFAULT '{}'::"text"[], "p_hourly_rate" numeric DEFAULT NULL::numeric, "p_daily_rate" numeric DEFAULT NULL::numeric, "p_monthly_salary" numeric DEFAULT NULL::numeric, "p_iban" "text" DEFAULT NULL::"text", "p_payment_terms" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text") RETURNS TABLE("technician_id" "uuid", "technician_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal', 'public'
    AS $$
DECLARE
    v_technician_id UUID;
    v_technician_number TEXT;
    v_last_number INTEGER;
BEGIN
    -- Generar n├║mero de t├®cnico
    SELECT COALESCE(MAX(CAST(SUBSTRING(technician_number FROM 4) AS INTEGER)), 0) + 1
    INTO v_last_number
    FROM internal.technicians
    WHERE technician_number LIKE 'TEC-%';
    
    v_technician_number := 'TEC-' || LPAD(v_last_number::TEXT, 6, '0');
    
    -- Insertar t├®cnico
    INSERT INTO internal.technicians (
        technician_number,
        type,
        company_name,
        legal_name,
        tax_id,
        contact_name,
        contact_phone,
        contact_phone_secondary,
        contact_email,
        billing_email,
        address,
        city,
        province,
        postal_code,
        country,
        specialties,
        hourly_rate,
        daily_rate,
        monthly_salary,
        iban,
        payment_terms,
        notes,
        created_by
    ) VALUES (
        v_technician_number,
        p_type,
        p_company_name,
        p_legal_name,
        p_tax_id,
        p_contact_name,
        p_contact_phone,
        p_contact_phone_secondary,
        p_contact_email,
        p_billing_email,
        p_address,
        p_city,
        p_province,
        p_postal_code,
        p_country,
        p_specialties,
        p_hourly_rate,
        p_daily_rate,
        p_monthly_salary,
        p_iban,
        p_payment_terms,
        p_notes,
        auth.uid()
    )
    RETURNING id INTO v_technician_id;
    
    RETURN QUERY SELECT v_technician_id, v_technician_number;
END;
$$;
ALTER FUNCTION "internal"."create_technician"("p_company_name" "text", "p_type" "internal"."technician_type", "p_legal_name" "text", "p_tax_id" "text", "p_contact_name" "text", "p_contact_phone" "text", "p_contact_phone_secondary" "text", "p_contact_email" "text", "p_billing_email" "text", "p_address" "text", "p_city" "text", "p_province" "text", "p_postal_code" "text", "p_country" "text", "p_specialties" "text"[], "p_hourly_rate" numeric, "p_daily_rate" numeric, "p_monthly_salary" numeric, "p_iban" "text", "p_payment_terms" "text", "p_notes" "text") OWNER TO "postgres";
