--
-- Name: generate_partner_compensations_for_month(integer, integer, "text"); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."generate_partner_compensations_for_month"("p_year" integer, "p_month" integer, "p_mode" "text" DEFAULT 'STRICT_CLOSED_REQUIRED'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal', 'public'
    AS $$
DECLARE
  v_settings RECORD;
  v_ref_year int;
  v_ref_month int;
  v_ref_closed boolean;
  v_partner RECORD;
  v_run_id uuid;
  v_created_ids uuid[] := '{}';
  v_skips jsonb := '[]'::jsonb;
  v_created_count int := 0;
  v_skipped_existing int := 0;
  v_skipped_inactive int := 0;
  v_user_id uuid;
  v_can_create boolean := true;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;

  SELECT * INTO v_settings FROM internal.payroll_settings ORDER BY updated_at DESC LIMIT 1;
  IF v_settings.id IS NULL THEN
    RETURN jsonb_build_object(
      'created_count', 0,
      'skipped_existing_count', 0,
      'skipped_inactive_count', 0,
      'created_ids', '[]'::jsonb,
      'skips', jsonb_build_array(jsonb_build_object('reason', 'NO_PAYROLL_SETTINGS', 'message', 'No hay configuraci├│n de n├│minas'))
    );
  END IF;

  -- M-1 para bonus
  v_ref_month := p_month - 1;
  v_ref_year := p_year;
  IF v_ref_month <= 0 THEN
    v_ref_month := v_ref_month + 12;
    v_ref_year := v_ref_year - 1;
  END IF;

  v_ref_closed := accounting.is_period_closed(v_ref_year, v_ref_month);

  IF p_mode = 'STRICT_CLOSED_REQUIRED' AND v_settings.bonus_requires_closed_period AND NOT v_ref_closed THEN
    RETURN jsonb_build_object(
      'created_count', 0,
      'skipped_existing_count', 0,
      'skipped_inactive_count', 0,
      'created_ids', '[]'::jsonb,
      'skips', jsonb_build_array(jsonb_build_object(
        'reason', 'PERIOD_NOT_CLOSED',
        'message', format('El mes de referencia %s/%s no est├í cerrado. Cierre el mes antes de generar n├│minas.', v_ref_year, v_ref_month)
      ))
    );
  END IF;

  FOR v_partner IN
    SELECT p.id, p.partner_number, p.full_name, p.status
    FROM internal.partners p
    WHERE p.status = 'ACTIVE'
  LOOP
    IF EXISTS (
      SELECT 1 FROM internal.partner_compensation_runs
      WHERE partner_id = v_partner.id AND period_year = p_year AND period_month = p_month
    ) THEN
      v_skipped_existing := v_skipped_existing + 1;
      v_skips := v_skips || jsonb_build_object('partner_id', v_partner.id, 'partner_number', v_partner.partner_number, 'reason', 'ALREADY_EXISTS');
      CONTINUE;
    END IF;

    BEGIN
      SELECT internal.create_partner_compensation_run_from_policy(v_partner.id, p_year, p_month) INTO v_run_id;
      v_created_count := v_created_count + 1;
      v_created_ids := array_append(v_created_ids, v_run_id);
    EXCEPTION WHEN unique_violation THEN
      v_skipped_existing := v_skipped_existing + 1;
      v_skips := v_skips || jsonb_build_object('partner_id', v_partner.id, 'partner_number', v_partner.partner_number, 'reason', 'ALREADY_EXISTS_CONCURRENT');
    END;
  END LOOP;

  RETURN jsonb_build_object(
    'created_count', v_created_count,
    'skipped_existing_count', v_skipped_existing,
    'skipped_inactive_count', v_skipped_inactive,
    'created_ids', to_jsonb(v_created_ids),
    'skips', v_skips
  );
END;
$$;
ALTER FUNCTION "internal"."generate_partner_compensations_for_month"("p_year" integer, "p_month" integer, "p_mode" "text") OWNER TO "postgres";
--
-- Name: generate_preliminary_invoice_number(); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."generate_preliminary_invoice_number"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
  v_max_num int;
  v_next_num int;
BEGIN
  SELECT COALESCE(MAX(SUBSTRING(preliminary_number FROM 'F-BORR-([0-9]+)')::int), 0)
  INTO v_max_num
  FROM sales.invoices
  WHERE preliminary_number LIKE 'F-BORR-%';

  v_next_num := v_max_num + 1;
  RETURN 'F-BORR-' || LPAD(v_next_num::text, 4, '0');
END;
$$;
ALTER FUNCTION "internal"."generate_preliminary_invoice_number"() OWNER TO "postgres";
--
-- Name: generate_product_number("uuid", "uuid"); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."generate_product_number"("p_category_id" "uuid", "p_subcategory_id" "uuid") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal', 'public'
    AS $$
DECLARE
  v_category_code TEXT;
  v_subcategory_code TEXT;
  v_next_number INTEGER;
  v_prefix TEXT;
BEGIN
  -- Get category code
  SELECT code INTO v_category_code
  FROM internal.product_categories
  WHERE id = p_category_id;
  
  IF v_category_code IS NULL THEN
    RAISE EXCEPTION 'Category not found';
  END IF;
  
  -- Get subcategory code if provided
  IF p_subcategory_id IS NOT NULL THEN
    SELECT code INTO v_subcategory_code
    FROM internal.product_subcategories
    WHERE id = p_subcategory_id AND category_id = p_category_id;
    
    IF v_subcategory_code IS NULL THEN
      RAISE EXCEPTION 'Subcategory not found or does not belong to category';
    END IF;
    
    v_prefix := v_category_code || '-' || v_subcategory_code || '-';
  ELSE
    v_prefix := v_category_code || '-00-';
  END IF;
  
  -- Get next number for this prefix
  SELECT COALESCE(MAX(
    CAST(NULLIF(REGEXP_REPLACE(product_number, '^' || v_prefix, ''), '') AS INTEGER)
  ), 0) + 1
  INTO v_next_number
  FROM internal.products
  WHERE product_number LIKE v_prefix || '%';
  
  RETURN v_prefix || LPAD(v_next_number::TEXT, 4, '0');
END;
$$;
ALTER FUNCTION "internal"."generate_product_number"("p_category_id" "uuid", "p_subcategory_id" "uuid") OWNER TO "postgres";
--
-- Name: generate_purchase_order_number(); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."generate_purchase_order_number"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
  v_year int;
  v_short_year text;
  v_next_num int;
BEGIN
  v_year := EXTRACT(YEAR FROM CURRENT_DATE)::int;
  v_short_year := LPAD((v_year % 100)::text, 2, '0');

  INSERT INTO sales.purchase_order_sequences (year, last_number)
  VALUES (v_year, 1)
  ON CONFLICT (year) DO UPDATE SET last_number = sales.purchase_order_sequences.last_number + 1
  RETURNING last_number INTO v_next_num;

  RETURN 'PO-' || v_short_year || '-' || LPAD(v_next_num::text, 6, '0');
END;
$$;
ALTER FUNCTION "internal"."generate_purchase_order_number"() OWNER TO "postgres";
