--
-- Name: get_or_create_partner_account_code("uuid"); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."get_or_create_partner_account_code"("p_partner_id" "uuid") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal', 'public'
    AS $$
DECLARE
  v_account_code text;
  v_next_number int;
BEGIN
  -- Check if partner already has account code
  SELECT account_code INTO v_account_code
  FROM internal.partners
  WHERE id = p_partner_id;
  
  IF v_account_code IS NOT NULL THEN
    RETURN v_account_code;
  END IF;
  
  -- Generate next account code (465001, 465002, etc.)
  SELECT COALESCE(MAX(CAST(SUBSTRING(account_code FROM 4) AS integer)), 0) + 1
  INTO v_next_number
  FROM internal.partners
  WHERE account_code IS NOT NULL AND account_code LIKE '465%';
  
  v_account_code := '465' || LPAD(v_next_number::text, 3, '0');
  
  -- Update partner with new account code
  UPDATE internal.partners
  SET account_code = v_account_code
  WHERE id = p_partner_id;
  
  -- Ensure account exists in chart of accounts
  INSERT INTO accounting.chart_of_accounts (account_code, account_name, account_type, description, is_active)
  VALUES (
    v_account_code,
    (SELECT 'Retribuciones pdtes. socio ' || full_name FROM internal.partners WHERE id = p_partner_id),
    'LIABILITY',
    'Cuenta de retribuciones pendientes de pago al socio',
    true
  )
  ON CONFLICT (account_code) DO NOTHING;
  
  RETURN v_account_code;
END;
$$;
ALTER FUNCTION "internal"."get_or_create_partner_account_code"("p_partner_id" "uuid") OWNER TO "postgres";
