--

CREATE FUNCTION "internal"."link_auth_user"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal'
    AS $$
BEGIN
  -- Buscar si el email existe en authorized_users y vincular
  UPDATE internal.authorized_users
  SET 
    auth_user_id = NEW.id,
    last_login_at = now(),
    updated_at = now()
  WHERE email = NEW.email
    AND auth_user_id IS NULL;
  
  -- Si el email no est├í en la allowlist, registrar pero no vincular
  -- (el usuario no tendr├í acceso a la app)
  
  RETURN NEW;
END;
$$;
