-- Name: list_partner_payroll_profiles("text"); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."list_partner_payroll_profiles"("p_status" "text" DEFAULT 'ACTIVE'::"text") RETURNS TABLE("partner_id" "uuid", "partner_number" "text", "partner_name" "text", "base_salary" numeric, "irpf_rate" numeric, "bonus_enabled_override" boolean, "bonus_cap_override" numeric, "updated_at" timestamp with time zone)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'internal'
    AS $$
  SELECT
    p.id AS partner_id,
    p.partner_number,
    p.full_name AS partner_name,
    COALESCE(ppp.base_salary, 0) AS base_salary,
    COALESCE(ppp.irpf_rate, 19) AS irpf_rate,
    ppp.bonus_enabled_override,
    ppp.bonus_cap_override,
    ppp.updated_at
  FROM internal.partners p
  LEFT JOIN internal.partner_payroll_profiles ppp ON ppp.partner_id = p.id
  WHERE (p_status IS NULL OR p.status = p_status)
  ORDER BY p.partner_number;
$$;
ALTER FUNCTION "internal"."list_partner_payroll_profiles"("p_status" "text") OWNER TO "postgres";
