--
-- Name: recalculate_partner_compensation_run("uuid"); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."recalculate_partner_compensation_run"("p_run_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal', 'public'
    AS $$
DECLARE
  v_run RECORD;
  v_calc RECORD;
  v_irpf_rate numeric;
BEGIN
  SELECT * INTO v_run FROM internal.partner_compensation_runs WHERE id = p_run_id;
  IF v_run.id IS NULL THEN
    RAISE EXCEPTION 'Compensaci├│n no encontrada';
  END IF;

  IF v_run.status != 'DRAFT' THEN
    RAISE EXCEPTION 'Solo se puede recalcular una n├│mina en estado DRAFT. Estado actual: %', v_run.status;
  END IF;

  SELECT * INTO v_calc FROM internal.calculate_partner_productivity_bonus(
    v_run.partner_id, v_run.period_year, v_run.period_month
  ) LIMIT 1;

  v_irpf_rate := COALESCE((SELECT irpf_rate FROM internal.partner_payroll_profiles WHERE partner_id = v_run.partner_id), 19);

  UPDATE internal.partner_compensation_runs SET
    base_amount = v_calc.base_amount,
    productivity_bonus = v_calc.productivity_bonus,
    gross_amount = v_calc.gross_amount,
    irpf_rate = v_irpf_rate,
    irpf_amount = v_calc.irpf_amount,
    net_amount = v_calc.net_amount,
    bonus_reference_year = v_calc.bonus_reference_year,
    bonus_reference_month = v_calc.bonus_reference_month,
    bonus_reference_net_profit = v_calc.bonus_reference_net_profit,
    bonus_percent_applied = v_calc.bonus_percent_applied,
    bonus_cap_applied = v_calc.bonus_cap_applied,
    bonus_policy_version = v_calc.bonus_policy_version,
    notes = format('Base: %s | Bonus: %s | Bruto: %s', COALESCE(v_calc.base_amount,0), COALESCE(v_calc.productivity_bonus,0), v_calc.gross_amount) ||
      CASE WHEN v_calc.message IS NOT NULL THEN E'\n' || v_calc.message ELSE '' END,
    updated_at = now()
  WHERE id = p_run_id;
END;
$$;
