-- Name: user_has_role("uuid", "text"); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."user_has_role"("p_auth_user_id" "uuid", "p_role_name" "text") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'internal'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM internal.user_roles ur
    JOIN internal.roles r ON r.id = ur.role_id
    JOIN internal.authorized_users au ON au.id = ur.user_id
    WHERE au.auth_user_id = p_auth_user_id
      AND r.name = p_role_name
      AND au.is_active = true
      AND (ur.expires_at IS NULL OR ur.expires_at > now())
  )
$$;
