--
-- Name: validate_task_status(); Type: FUNCTION; Schema: internal; Owner: postgres
--

CREATE FUNCTION "internal"."validate_task_status"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'internal', 'public'
    AS $$
BEGIN
  IF NEW.status NOT IN ('TODO', 'IN_PROGRESS', 'BLOCKED', 'DONE', 'CANCELLED') THEN
    RAISE EXCEPTION 'Invalid task status: %', NEW.status;
  END IF;
  IF NEW.priority NOT IN ('LOW', 'MEDIUM', 'HIGH', 'URGENT') THEN
    RAISE EXCEPTION 'Invalid task priority: %', NEW.priority;
  END IF;
  IF NEW.status = 'DONE' AND NEW.completed_at IS NULL THEN
    NEW.completed_at := now();
  END IF;
  IF NEW.status <> 'DONE' THEN
    NEW.completed_at := NULL;
  END IF;
  NEW.updated_at := now();
  RETURN NEW;
END;
$$;
ALTER FUNCTION "internal"."validate_task_status"() OWNER TO "postgres";
