-- Name: auto_update_project_on_invoice_created(); Type: FUNCTION; Schema: projects; Owner: postgres
--

CREATE FUNCTION "projects"."auto_update_project_on_invoice_created"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Si la factura viene de un presupuesto y tiene proyecto asociado
  IF NEW.source_quote_id IS NOT NULL AND NEW.project_id IS NOT NULL THEN
    UPDATE projects.projects
    SET status = 'COMPLETED'
    WHERE id = NEW.project_id
      AND status = 'IN_PROGRESS';
  END IF;
  
  RETURN NEW;
END;
$$;
ALTER FUNCTION "projects"."auto_update_project_on_invoice_created"() OWNER TO "postgres";
