-- Name: FUNCTION "auto_update_project_on_invoice_issued"(); Type: COMMENT; Schema: projects; Owner: postgres
--

COMMENT ON FUNCTION "projects"."auto_update_project_on_invoice_issued"() IS 'Autom├íticamente cambia el proyecto a INVOICED cuando se emite una factura';
--
-- Name: auto_update_project_on_invoice_paid(); Type: FUNCTION; Schema: projects; Owner: postgres
--

CREATE FUNCTION "projects"."auto_update_project_on_invoice_paid"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Cuando la factura pasa a PAID (totalmente pagada) y tiene proyecto
  IF NEW.status = 'PAID' AND OLD.status != 'PAID' AND NEW.project_id IS NOT NULL THEN
    -- Verificar que no hay otras facturas pendientes del proyecto
    IF NOT EXISTS (
      SELECT 1 FROM sales.invoices
      WHERE project_id = NEW.project_id
        AND id != NEW.id
        AND status NOT IN ('PAID', 'CANCELLED')
    ) THEN
      UPDATE projects.projects
      SET status = 'CLOSED'
      WHERE id = NEW.project_id
        AND status = 'INVOICED';
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$;
ALTER FUNCTION "projects"."auto_update_project_on_invoice_paid"() OWNER TO "postgres";
--
-- Name: FUNCTION "auto_update_project_on_invoice_paid"(); Type: COMMENT; Schema: projects; Owner: postgres
--

COMMENT ON FUNCTION "projects"."auto_update_project_on_invoice_paid"() IS 'Autom├íticamente cambia el proyecto a CLOSED cuando todas las facturas del proyecto est├ín pagadas';
--
-- Name: auto_update_project_site_mode(); Type: FUNCTION; Schema: projects; Owner: postgres
--

CREATE FUNCTION "projects"."auto_update_project_site_mode"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'projects', 'public'
    AS $$
DECLARE
  v_project_id UUID;
  v_active_count INTEGER;
  v_current_default UUID;
  v_new_default UUID;
  v_new_mode projects.site_mode;
BEGIN
  IF TG_OP = 'DELETE' THEN
    v_project_id := OLD.project_id;
  ELSE
    v_project_id := NEW.project_id;
  END IF;

  SELECT COUNT(*) INTO v_active_count
  FROM projects.project_sites
  WHERE project_id = v_project_id AND is_active = true;

  IF v_active_count >= 2 THEN
    v_new_mode := 'MULTI_SITE'::projects.site_mode;
  ELSIF v_active_count = 1 THEN
    v_new_mode := 'SINGLE_SITE'::projects.site_mode;
  ELSE
    v_new_mode := NULL;
  END IF;

  SELECT default_site_id INTO v_current_default
  FROM projects.projects WHERE id = v_project_id;

  IF v_current_default IS NOT NULL AND EXISTS (
    SELECT 1 FROM projects.project_sites
    WHERE id = v_current_default AND project_id = v_project_id AND is_active = true
  ) THEN
    v_new_default := v_current_default;
  ELSE
    SELECT id INTO v_new_default
    FROM projects.project_sites
    WHERE project_id = v_project_id AND is_active = true
    ORDER BY created_at ASC
    LIMIT 1;
  END IF;

  UPDATE projects.projects
  SET site_mode = v_new_mode,
      default_site_id = v_new_default
  WHERE id = v_project_id
    AND (site_mode IS DISTINCT FROM v_new_mode OR default_site_id IS DISTINCT FROM v_new_default);

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  ELSE
    RETURN NEW;
  END IF;
END;
$$;
ALTER FUNCTION "projects"."auto_update_project_site_mode"() OWNER TO "postgres";
--
-- Name: can_access_project("uuid"); Type: FUNCTION; Schema: projects; Owner: postgres
--

CREATE FUNCTION "projects"."can_access_project"("p_project_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'projects', 'public'
    AS $$
  SELECT 
    internal.is_admin() OR 
    internal.is_manager() OR 
    internal.is_readonly() OR
    (internal.is_tech() AND EXISTS (
      SELECT 1 FROM projects.projects 
      WHERE id = p_project_id 
      AND (
        assigned_to = internal.get_authorized_user_id(auth.uid()) OR
        internal.get_authorized_user_id(auth.uid()) = ANY(assigned_team)
      )
    )) OR
    (internal.is_sales() AND EXISTS (
      SELECT 1 FROM projects.projects p
      JOIN sales.quotes q ON p.quote_id = q.id
      WHERE p.id = p_project_id 
      AND q.assigned_to = internal.get_authorized_user_id(auth.uid())
    ))
$$;
ALTER FUNCTION "projects"."can_access_project"("p_project_id" "uuid") OWNER TO "postgres";
