--

CREATE FUNCTION "projects"."generate_project_number"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'projects', 'public'
    AS $$
BEGIN
  IF NEW.project_number IS NULL OR NEW.project_number = '' THEN
    IF NEW.project_type = 'CUSTOMER_ORDER' THEN
      NEW.project_number := audit.get_next_number('WO');
    ELSE
      NEW.project_number := audit.get_next_number('PRJ');
    END IF;
  END IF;
  RETURN NEW;
END;
$$;
ALTER FUNCTION "projects"."generate_project_number"() OWNER TO "postgres";
--
-- Name: get_next_project_number(); Type: FUNCTION; Schema: projects; Owner: postgres
--

CREATE FUNCTION "projects"."get_next_project_number"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'projects'
    AS $_$
DECLARE
  v_number INTEGER;
  v_project_number TEXT;
BEGIN
  -- Lock to prevent concurrent access
  LOCK TABLE projects.projects IN EXCLUSIVE MODE;
  
  -- Get next value from sequence
  SELECT COALESCE(MAX(CAST(NULLIF(project_number, '') AS INTEGER)), 0) + 1 
  INTO v_number
  FROM projects.projects
  WHERE project_number ~ '^\d+$';
  
  -- Format as 6-digit number with leading zeros
  v_project_number := LPAD(v_number::TEXT, 6, '0');
  
  RETURN v_project_number;
END;
$_$;
ALTER FUNCTION "projects"."get_next_project_number"() OWNER TO "postgres";
--
-- Name: get_project_financial_stats("uuid"); Type: FUNCTION; Schema: projects; Owner: postgres
--

CREATE FUNCTION "projects"."get_project_financial_stats"("p_project_id" "uuid") RETURNS TABLE("total_budget" numeric, "total_invoiced" numeric, "total_expenses" numeric, "margin" numeric, "margin_percentage" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'projects', 'public'
    AS $$
DECLARE
  v_budget NUMERIC := 0;
  v_invoiced NUMERIC := 0;
  v_expenses NUMERIC := 0;
  v_purchase_invoices NUMERIC := 0;
  v_project_expenses NUMERIC := 0;
  v_margin NUMERIC := 0;
BEGIN
  -- Budget: Sum of APPROVED quotes subtotals for this project (from quotes.quotes)
  SELECT COALESCE(SUM(subtotal), 0)
  INTO v_budget
  FROM quotes.quotes
  WHERE project_id = p_project_id
    AND status = 'APPROVED';

  -- Invoiced: Sum of ISSUED invoices subtotals only (exclude DRAFT and CANCELLED)
  -- Facturas emitidas: ISSUED, SENT, PAID, PARTIAL, OVERDUE
  SELECT COALESCE(SUM(subtotal), 0)
  INTO v_invoiced
  FROM sales.invoices
  WHERE project_id = p_project_id
    AND status IN ('ISSUED', 'SENT', 'PAID', 'PARTIAL', 'OVERDUE');

  -- Expenses: Sum of project expenses (amount is already without taxes)
  SELECT COALESCE(SUM(amount), 0)
  INTO v_project_expenses
  FROM projects.expenses
  WHERE project_id = p_project_id;

  -- Purchase Invoices: Sum of purchase invoices subtotals (exclude CANCELLED)
  SELECT COALESCE(SUM(subtotal), 0)
  INTO v_purchase_invoices
  FROM sales.purchase_invoices
  WHERE project_id = p_project_id
    AND status != 'CANCELLED';

  -- Total expenses = Purchase Invoices + Project Expenses
  v_expenses := v_purchase_invoices + v_project_expenses;

  -- Margin = Issued Invoices - Purchase Invoices - Expenses
  v_margin := v_invoiced - v_expenses;
  
  -- Calculate margin percentage: (margin / invoiced) * 100
  -- Only calculate if there's invoiced amount
  RETURN QUERY SELECT 
    v_budget, 
    v_invoiced, 
    v_expenses, 
    v_margin,
    CASE WHEN v_invoiced > 0 THEN (v_margin / v_invoiced) * 100 ELSE 0 END;
END;
$$;
ALTER FUNCTION "projects"."get_project_financial_stats"("p_project_id" "uuid") OWNER TO "postgres";
--
-- Name: get_projects_portfolio_summary(); Type: FUNCTION; Schema: projects; Owner: postgres
--

CREATE FUNCTION "projects"."get_projects_portfolio_summary"() RETURNS TABLE("total_active_projects" bigint, "total_pipeline_value" numeric, "avg_project_ticket" numeric, "max_project_value" numeric, "min_project_value" numeric, "total_invoiced_ytd" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'projects', 'public'
    AS $$

DECLARE

  v_active_count BIGINT;

  v_pipeline NUMERIC;

  v_avg_ticket NUMERIC;

  v_max_val NUMERIC;

  v_min_val NUMERIC;

  v_invoiced_ytd NUMERIC;

BEGIN

  -- Active Projects

  SELECT COUNT(*) INTO v_active_count

  FROM projects.projects

  WHERE status IN ('IN_PROGRESS', 'PLANNED');

  -- Pipeline Value: Sum of Budget of Active Projects

  SELECT COALESCE(SUM(q.total), 0)

  INTO v_pipeline

  FROM quotes.quotes q

  JOIN projects.projects p ON p.id = q.project_id

  WHERE p.status IN ('IN_PROGRESS', 'PLANNED')

    AND q.status = 'APPROVED';

    

  -- Avg/Max/Min Ticket (Based on Total Invoiced per Project)

  WITH project_totals AS (

    SELECT 

      project_id, 

      SUM(total) as project_total 

    FROM sales.invoices 

    WHERE status != 'CANCELLED' AND project_id IS NOT NULL

    GROUP BY project_id

  )

  SELECT 

    AVG(project_total),

    MAX(project_total),

    MIN(project_total)

  INTO 

    v_avg_ticket,

    v_max_val,

    v_min_val

  FROM project_totals;

  -- Total Invoiced YTD

  SELECT COALESCE(SUM(total), 0)

  INTO v_invoiced_ytd

  FROM sales.invoices

  WHERE status != 'CANCELLED'

    AND issue_date >= DATE_TRUNC('year', CURRENT_DATE);

  RETURN QUERY SELECT 

    v_active_count,

    v_pipeline,

    COALESCE(v_avg_ticket, 0),

    COALESCE(v_max_val, 0),

    COALESCE(v_min_val, 0),

    v_invoiced_ytd;

END;

$$;
ALTER FUNCTION "projects"."get_projects_portfolio_summary"() OWNER TO "postgres";
--
-- Name: trg_block_locked_site_edits(); Type: FUNCTION; Schema: projects; Owner: postgres
--

CREATE FUNCTION "projects"."trg_block_locked_site_edits"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'projects', 'public'
    AS $$
BEGIN
  -- If site is INVOICED or CLOSED, block changes to planning/execution fields
  IF OLD.site_status IN ('INVOICED', 'CLOSED') THEN
    -- Allow only notes and is_active changes
    IF (
      NEW.planned_start_date IS DISTINCT FROM OLD.planned_start_date OR
      NEW.planned_end_date IS DISTINCT FROM OLD.planned_end_date OR
      NEW.planned_days IS DISTINCT FROM OLD.planned_days OR
      NEW.actual_start_at IS DISTINCT FROM OLD.actual_start_at OR
      NEW.actual_end_at IS DISTINCT FROM OLD.actual_end_at
    ) THEN
      RAISE EXCEPTION 'No se pueden modificar fechas de un sitio en estado %', OLD.site_status;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;
ALTER FUNCTION "projects"."trg_block_locked_site_edits"() OWNER TO "postgres";
