-- Name: update_project_hours(); Type: FUNCTION; Schema: projects; Owner: postgres
--

CREATE FUNCTION "projects"."update_project_hours"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'projects'
    AS $$
DECLARE
  v_total_hours NUMERIC(8,2);
BEGIN
  SELECT COALESCE(SUM(actual_hours), 0)
  INTO v_total_hours
  FROM projects.project_tasks
  WHERE project_id = COALESCE(NEW.project_id, OLD.project_id);
  
  UPDATE projects.projects
  SET actual_hours = v_total_hours, updated_at = now()
  WHERE id = COALESCE(NEW.project_id, OLD.project_id);
  
  RETURN COALESCE(NEW, OLD);
END;
$$;
