-- Name: add_client_note("uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."add_client_note"("p_client_id" "uuid", "p_content" "text", "p_note_type" "text" DEFAULT 'manual'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_user_id UUID;
    v_user_name TEXT;
    v_note_id UUID;
BEGIN
    -- Obtener informaci├│n del usuario actual
    SELECT au.id, au.full_name 
    INTO v_user_id, v_user_name
    FROM internal.authorized_users au
    WHERE au.auth_user_id = auth.uid();
    
    IF v_user_id IS NULL THEN
        RAISE EXCEPTION 'Usuario no autorizado';
    END IF;
    
    -- Insertar la nota
    INSERT INTO crm.client_notes (
        client_id,
        note_type,
        content,
        user_id,
        user_name
    ) VALUES (
        p_client_id,
        p_note_type,
        p_content,
        v_user_id,
        v_user_name
    )
    RETURNING id INTO v_note_id;
    
    RETURN v_note_id;
END;
$$;
