--
-- Name: add_invoice_line("uuid", "text", "text", numeric, numeric, numeric, numeric, "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."add_invoice_line"("p_invoice_id" "uuid", "p_concept" "text", "p_description" "text" DEFAULT NULL::"text", "p_quantity" numeric DEFAULT 1, "p_unit_price" numeric DEFAULT 0, "p_discount_percent" numeric DEFAULT 0, "p_tax_rate" numeric DEFAULT 21, "p_tax_id" "uuid" DEFAULT NULL::"uuid", "p_product_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_is_locked BOOLEAN;
  v_line_id UUID;
  v_max_order INTEGER;
BEGIN
  SELECT is_locked INTO v_is_locked FROM sales.invoices WHERE id = p_invoice_id;
  IF COALESCE(v_is_locked, false) THEN
    RAISE EXCEPTION 'No se pueden a├▒adir l├¡neas a una factura bloqueada';
  END IF;

  -- Obtener el m├íximo line_order para esta factura
  SELECT COALESCE(MAX(line_order), 0) INTO v_max_order
  FROM sales.invoice_lines
  WHERE invoice_id = p_invoice_id;

  -- Insertar l├¡nea sin tax_id ni product_id (esas columnas no existen en la tabla)
  INSERT INTO sales.invoice_lines (
    invoice_id, 
    concept, 
    description, 
    quantity, 
    unit_price, 
    discount_percent, 
    tax_rate,
    line_order
  )
  VALUES (
    p_invoice_id, 
    p_concept, 
    p_description, 
    p_quantity, 
    p_unit_price,
    p_discount_percent, 
    p_tax_rate,
    v_max_order + 1
  )
  RETURNING id INTO v_line_id;

  RETURN v_line_id;
END;
$$;
ALTER FUNCTION "public"."add_invoice_line"("p_invoice_id" "uuid", "p_concept" "text", "p_description" "text", "p_quantity" numeric, "p_unit_price" numeric, "p_discount_percent" numeric, "p_tax_rate" numeric, "p_tax_id" "uuid", "p_product_id" "uuid") OWNER TO "postgres";
--
-- Name: add_location_note("uuid", "text", "text", "text"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."add_location_note"("p_location_id" "uuid", "p_content" "text", "p_note_type" "text" DEFAULT 'INTERNAL'::"text", "p_attachments" "text"[] DEFAULT NULL::"text"[]) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$

DECLARE

  v_note_id UUID;

  v_user_id UUID;

  v_note_type_enum crm.location_note_type;

BEGIN

  v_user_id := internal.get_authorized_user_id(auth.uid());

  

  -- Verificar permisos: solo el creador de la ubicaci├│n o admin/manager

  IF NOT EXISTS (

    SELECT 1 FROM crm.location loc

    WHERE loc.id = p_location_id 

    AND (loc.created_by = v_user_id OR internal.is_admin() OR internal.is_manager())

  ) THEN

    RAISE EXCEPTION 'No tienes permiso para a├▒adir notas a esta ubicaci├│n';

  END IF;

  

  -- Convertir TEXT a ENUM

  v_note_type_enum := p_note_type::crm.location_note_type;

  

  INSERT INTO crm.location_notes (

    location_id,

    note_type,

    content,

    attachments,

    created_by

  ) VALUES (

    p_location_id,

    v_note_type_enum,

    p_content,

    p_attachments,

    v_user_id

  )

  RETURNING id INTO v_note_id;

  

  RETURN v_note_id;

END;

$$;
ALTER FUNCTION "public"."add_location_note"("p_location_id" "uuid", "p_content" "text", "p_note_type" "text", "p_attachments" "text"[]) OWNER TO "postgres";
--
-- Name: add_pack_item("uuid", "uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."add_pack_item"("p_pack_id" "uuid", "p_product_id" "uuid", "p_quantity" integer DEFAULT 1) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_item_id UUID;
BEGIN
  INSERT INTO internal.product_pack_items (pack_id, product_id, quantity)
  VALUES (p_pack_id, p_product_id, p_quantity)
  ON CONFLICT (pack_id, product_id) DO UPDATE SET quantity = product_pack_items.quantity + p_quantity
  RETURNING id INTO v_item_id;
  
  -- Recalculate pack prices
  PERFORM public.update_product_pack(p_pack_id);
  
  RETURN v_item_id;
END;
$$;
ALTER FUNCTION "public"."add_pack_item"("p_pack_id" "uuid", "p_product_id" "uuid", "p_quantity" integer) OWNER TO "postgres";
