--
-- Name: add_purchase_invoice_line("uuid", "text", "text", numeric, numeric, numeric, numeric, numeric, "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."add_purchase_invoice_line"("p_invoice_id" "uuid", "p_concept" "text", "p_description" "text" DEFAULT NULL::"text", "p_quantity" numeric DEFAULT 1, "p_unit_price" numeric DEFAULT 0, "p_tax_rate" numeric DEFAULT 21, "p_withholding_tax_rate" numeric DEFAULT 0, "p_discount_percent" numeric DEFAULT 0, "p_product_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_line_id UUID;
    v_line_order INTEGER;
BEGIN
    -- Calcular line_order
    SELECT COALESCE(MAX(line_order), 0) + 1
    INTO v_line_order
    FROM sales.purchase_invoice_lines
    WHERE purchase_invoice_id = p_invoice_id;

    -- Insertar l├¡nea
    INSERT INTO sales.purchase_invoice_lines (
        purchase_invoice_id,
        concept,
        description,
        quantity,
        unit_price,
        tax_rate,
        withholding_tax_rate,
        discount_percent,
        line_order,
        product_id
    ) VALUES (
        p_invoice_id,
        p_concept,
        p_description,
        p_quantity,
        p_unit_price,
        p_tax_rate,
        COALESCE(p_withholding_tax_rate, 0),
        COALESCE(p_discount_percent, 0),
        v_line_order,
        p_product_id
    )
    RETURNING id INTO v_line_id;

    -- Recalcular totales de la factura
    PERFORM public.recalculate_purchase_invoice(p_invoice_id);

    RETURN v_line_id;
END;
$$;
ALTER FUNCTION "public"."add_purchase_invoice_line"("p_invoice_id" "uuid", "p_concept" "text", "p_description" "text", "p_quantity" numeric, "p_unit_price" numeric, "p_tax_rate" numeric, "p_withholding_tax_rate" numeric, "p_discount_percent" numeric, "p_product_id" "uuid") OWNER TO "postgres";
--
-- Name: add_purchase_order_line("uuid", "text", "text", numeric, "text", numeric, numeric, numeric, numeric, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."add_purchase_order_line"("p_order_id" "uuid", "p_concept" "text", "p_description" "text" DEFAULT NULL::"text", "p_quantity" numeric DEFAULT 1, "p_unit" "text" DEFAULT 'ud'::"text", "p_unit_price" numeric DEFAULT 0, "p_tax_rate" numeric DEFAULT 21.00, "p_withholding_rate" numeric DEFAULT 0, "p_discount_percent" numeric DEFAULT 0, "p_group_name" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_line_id UUID;
    v_next_order INTEGER;
BEGIN
    -- Obtener siguiente orden
    SELECT COALESCE(MAX(line_order), 0) + 1
    INTO v_next_order
    FROM sales.purchase_order_lines
    WHERE purchase_order_id = p_order_id;
    
    INSERT INTO sales.purchase_order_lines (
        purchase_order_id,
        line_order,
        concept,
        description,
        quantity,
        unit,
        unit_price,
        tax_rate,
        withholding_rate,
        discount_percent,
        group_name
    ) VALUES (
        p_order_id,
        v_next_order,
        p_concept,
        p_description,
        p_quantity,
        p_unit,
        p_unit_price,
        p_tax_rate,
        p_withholding_rate,
        p_discount_percent,
        p_group_name
    )
    RETURNING id INTO v_line_id;
    
    RETURN v_line_id;
END;
$$;
ALTER FUNCTION "public"."add_purchase_order_line"("p_order_id" "uuid", "p_concept" "text", "p_description" "text", "p_quantity" numeric, "p_unit" "text", "p_unit_price" numeric, "p_tax_rate" numeric, "p_withholding_rate" numeric, "p_discount_percent" numeric, "p_group_name" "text") OWNER TO "postgres";
--
-- Name: add_quote_line("uuid", "text", "text", numeric, numeric, numeric, numeric, "text", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."add_quote_line"("p_quote_id" "uuid", "p_concept" "text", "p_description" "text" DEFAULT NULL::"text", "p_quantity" numeric DEFAULT 1, "p_unit_price" numeric DEFAULT 0, "p_tax_rate" numeric DEFAULT 21, "p_discount_percent" numeric DEFAULT 0, "p_group_name" "text" DEFAULT NULL::"text", "p_line_order" integer DEFAULT NULL::integer) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_line_id UUID;
  v_line_order INTEGER;
BEGIN
  -- Check user authorization
  IF internal.get_authorized_user_id(auth.uid()) IS NULL THEN
    RAISE EXCEPTION 'User not authorized';
  END IF;
  
  -- Get next line_order if not provided
  IF p_line_order IS NULL THEN
    SELECT COALESCE(MAX(line_order), 0) + 1 INTO v_line_order
    FROM quotes.quote_lines
    WHERE quote_id = p_quote_id;
  ELSE
    v_line_order := p_line_order;
  END IF;
  
  -- Insert the line (subtotal, tax_amount y total son GENERATED, no se insertan)
  INSERT INTO quotes.quote_lines (
    quote_id,
    line_order,
    concept,
    description,
    quantity,
    unit_price,
    tax_rate,
    discount_percent,
    group_name
  )
  VALUES (
    p_quote_id,
    v_line_order,
    p_concept,
    p_description,
    p_quantity,
    p_unit_price,
    p_tax_rate,
    p_discount_percent,
    p_group_name
  )
  RETURNING id INTO v_line_id;
  
  -- Update quote totals
  PERFORM quotes.update_quote_totals(p_quote_id);
  
  RETURN v_line_id;
END;
$$;
ALTER FUNCTION "public"."add_quote_line"("p_quote_id" "uuid", "p_concept" "text", "p_description" "text", "p_quantity" numeric, "p_unit_price" numeric, "p_tax_rate" numeric, "p_discount_percent" numeric, "p_group_name" "text", "p_line_order" integer) OWNER TO "postgres";
