--
-- Name: approve_purchase_invoice("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."approve_purchase_invoice"("p_invoice_id" "uuid") RETURNS TABLE("invoice_number" "text", "is_locked" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'sales', 'internal', 'public'
    AS $_$
DECLARE
  v_definitive TEXT;
  v_row sales.purchase_invoices%ROWTYPE;
  v_inv TEXT;
  v_already_paid BOOLEAN;
BEGIN
  SELECT * INTO v_row FROM sales.purchase_invoices WHERE id = p_invoice_id FOR UPDATE;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Factura de compra no encontrada: %', p_invoice_id;
  END IF;

  IF v_row.internal_purchase_number IS NOT NULL THEN
    RETURN QUERY SELECT v_row.internal_purchase_number::TEXT, COALESCE(v_row.is_locked, false);
    RETURN;
  END IF;

  v_inv := v_row.invoice_number;

  IF v_row.document_type IN ('EXPENSE', 'TICKET') THEN
    IF v_inv IS NOT NULL AND v_inv ~ '^TICKET-BORR-[0-9]{2}-[0-9]{6}$' THEN
      v_definitive := 'TICKET-' || substring(v_inv from 13 for 9);
    ELSE
      v_definitive := 'TICKET-' || to_char(CURRENT_DATE, 'YY') || '-' || lpad(nextval('sales.purchase_invoice_ticket_seq')::TEXT, 6, '0');
    END IF;
  ELSE
    IF v_inv IS NOT NULL AND v_inv ~ '^C-BORR-[0-9]{2}-[0-9]{6}$' THEN
      v_definitive := 'C-' || substring(v_inv from 8 for 9);
    ELSE
      v_definitive := public.generate_internal_purchase_number(v_row.document_type, v_row.supplier_id, v_row.technician_id);
    END IF;
  END IF;

  v_already_paid := (v_row.status = 'PAID') OR (v_row.total IS NOT NULL AND v_row.total <> 0 AND v_row.paid_amount >= v_row.total);

  IF v_already_paid THEN
    UPDATE sales.purchase_invoices
    SET internal_purchase_number = v_definitive,
        is_locked = true,
        updated_at = now()
    WHERE id = p_invoice_id;
  ELSE
    UPDATE sales.purchase_invoices
    SET status = 'APPROVED',
        internal_purchase_number = v_definitive,
        is_locked = true,
        updated_at = now()
    WHERE id = p_invoice_id;
  END IF;

  RETURN QUERY SELECT v_definitive, true;
END;
$_$;
ALTER FUNCTION "public"."approve_purchase_invoice"("p_invoice_id" "uuid") OWNER TO "postgres";
--
-- Name: approve_purchase_order("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."approve_purchase_order"("p_order_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_approved_by UUID;
BEGIN
    SELECT id INTO v_approved_by
    FROM internal.authorized_users
    WHERE auth_user_id = auth.uid();
    
    UPDATE sales.purchase_orders
    SET 
        status = 'APPROVED',
        approved_by = v_approved_by,
        approved_at = NOW()
    WHERE id = p_order_id
      AND status IN ('DRAFT', 'PENDING_APPROVAL');
    
    RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."approve_purchase_order"("p_order_id" "uuid") OWNER TO "postgres";
--
-- Name: archive_project_site("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."archive_project_site"("p_site_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_project_id UUID; v_is_default BOOLEAN;
BEGIN
  IF auth.uid() IS NULL THEN RAISE EXCEPTION 'Authentication required'; END IF;
  SELECT ps.project_id, (p.default_site_id = ps.id) INTO v_project_id, v_is_default
  FROM projects.project_sites ps JOIN projects.projects p ON p.id = ps.project_id WHERE ps.id = p_site_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Site not found'; END IF;
  IF (SELECT COUNT(*) FROM projects.project_sites WHERE project_id = v_project_id AND is_active = TRUE) <= 1 THEN
    RAISE EXCEPTION 'Cannot archive the last active site';
  END IF;
  UPDATE projects.project_sites SET is_active = FALSE WHERE id = p_site_id;
  IF v_is_default THEN
    UPDATE projects.projects SET default_site_id = (
      SELECT id FROM projects.project_sites WHERE project_id = v_project_id AND is_active = TRUE AND id != p_site_id
      ORDER BY created_at ASC LIMIT 1
    ) WHERE id = v_project_id;
  END IF;
  RETURN TRUE;
END; $$;
ALTER FUNCTION "public"."archive_project_site"("p_site_id" "uuid") OWNER TO "postgres";
