--

CREATE FUNCTION "public"."assign_user_role"("p_user_id" "uuid", "p_role_name" "text", "p_assigned_by" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal'
    AS $$
DECLARE
  v_role_id uuid;
BEGIN
  SELECT id INTO v_role_id FROM internal.roles WHERE name = p_role_name;
  
  IF v_role_id IS NULL THEN
    RETURN FALSE;
  END IF;
  
  INSERT INTO internal.user_roles (user_id, role_id, assigned_by)
  VALUES (p_user_id, v_role_id, p_assigned_by)
  ON CONFLICT DO NOTHING;
  
  RETURN TRUE;
END;
$$;
