--
-- Name: assign_worker_type("uuid", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."assign_worker_type"("p_user_id" "uuid", "p_worker_type" "text", "p_tax_id" "text" DEFAULT NULL::"text", "p_iban" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_email text;
  v_user_name text;
  v_linked_id uuid;
  v_partner_number text;
  v_employee_number text;
BEGIN
  -- Get user info
  SELECT email, full_name INTO v_user_email, v_user_name
  FROM internal.authorized_users
  WHERE id = p_user_id;
  
  IF v_user_email IS NULL THEN
    RAISE EXCEPTION 'Usuario no encontrado';
  END IF;

  IF p_worker_type = 'PARTNER' THEN
    -- Check if already linked to a partner
    SELECT linked_partner_id INTO v_linked_id
    FROM internal.authorized_users
    WHERE id = p_user_id AND linked_partner_id IS NOT NULL;
    
    IF v_linked_id IS NULL THEN
      -- Create new partner
      SELECT partner_id, partner_number INTO v_linked_id, v_partner_number
      FROM public.create_partner(
        p_full_name := v_user_name,
        p_tax_id := p_tax_id,
        p_email := v_user_email
      );
    END IF;
    
    -- Update user with partner link
    UPDATE internal.authorized_users
    SET worker_type = 'PARTNER',
        linked_partner_id = v_linked_id,
        linked_employee_id = NULL,
        tax_id = COALESCE(p_tax_id, tax_id),
        iban = COALESCE(p_iban, iban)
    WHERE id = p_user_id;
    
  ELSIF p_worker_type = 'EMPLOYEE' THEN
    -- Check if already linked to an employee
    SELECT linked_employee_id INTO v_linked_id
    FROM internal.authorized_users
    WHERE id = p_user_id AND linked_employee_id IS NOT NULL;
    
    IF v_linked_id IS NULL THEN
      -- Generate employee number
      SELECT 'EMP-' || LPAD((COALESCE(MAX(CAST(SUBSTRING(employee_number FROM 5) AS integer)), 0) + 1)::text, 4, '0')
      INTO v_employee_number
      FROM internal.employees;
      
      -- Create new employee
      INSERT INTO internal.employees (
        employee_number,
        full_name,
        email,
        tax_id,
        status
      ) VALUES (
        v_employee_number,
        v_user_name,
        v_user_email,
        p_tax_id,
        'ACTIVE'
      )
      RETURNING id INTO v_linked_id;
    END IF;
    
    -- Update user with employee link
    UPDATE internal.authorized_users
    SET worker_type = 'EMPLOYEE',
        linked_employee_id = v_linked_id,
        linked_partner_id = NULL,
        tax_id = COALESCE(p_tax_id, tax_id),
        iban = COALESCE(p_iban, iban)
    WHERE id = p_user_id;
    
  ELSE
    -- Clear worker type
    UPDATE internal.authorized_users
    SET worker_type = NULL
    WHERE id = p_user_id;
  END IF;
  
  RETURN v_linked_id;
END;
$$;
ALTER FUNCTION "public"."assign_worker_type"("p_user_id" "uuid", "p_worker_type" "text", "p_tax_id" "text", "p_iban" "text") OWNER TO "postgres";
--
-- Name: audit_get_stats(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."audit_get_stats"("p_days" integer DEFAULT 7) RETURNS TABLE("total_events" bigint, "security_events" bigint, "warning_events" bigint, "error_events" bigint, "events_by_category" "jsonb", "events_by_type" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_since TIMESTAMPTZ;
BEGIN
  -- Only admins can access audit stats
  IF NOT internal.is_admin() THEN
    RAISE EXCEPTION 'Access denied: Admin role required';
  END IF;

  v_since := NOW() - (p_days || ' days')::INTERVAL;

  RETURN QUERY
  SELECT
    (SELECT COUNT(*) FROM audit.events WHERE created_at >= v_since)::BIGINT AS total_events,
    (SELECT COUNT(*) FROM audit.events WHERE created_at >= v_since AND event_category = 'security')::BIGINT AS security_events,
    (SELECT COUNT(*) FROM audit.events WHERE created_at >= v_since AND severity = 'warning')::BIGINT AS warning_events,
    (SELECT COUNT(*) FROM audit.events WHERE created_at >= v_since AND severity = 'error')::BIGINT AS error_events,
    (
      SELECT COALESCE(jsonb_object_agg(event_category, cnt), '{}'::JSONB)
      FROM (
        SELECT event_category, COUNT(*) AS cnt
        FROM audit.events
        WHERE created_at >= v_since
        GROUP BY event_category
      ) sub
    ) AS events_by_category,
    (
      SELECT COALESCE(jsonb_object_agg(event_type, cnt), '{}'::JSONB)
      FROM (
        SELECT event_type, COUNT(*) AS cnt
        FROM audit.events
        WHERE created_at >= v_since
        GROUP BY event_type
        ORDER BY cnt DESC
        LIMIT 10
      ) sub
    ) AS events_by_type;
END;
$$;
ALTER FUNCTION "public"."audit_get_stats"("p_days" integer) OWNER TO "postgres";
--
-- Name: audit_list_events(integer, integer, "text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."audit_list_events"("p_limit" integer DEFAULT 50, "p_offset" integer DEFAULT 0, "p_search" "text" DEFAULT NULL::"text", "p_event_category" "text" DEFAULT NULL::"text", "p_severity" "text" DEFAULT NULL::"text", "p_event_type" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "event_type" "text", "event_category" "text", "severity" "text", "user_id" "uuid", "user_email" "text", "user_name" "text", "resource_type" "text", "resource_id" "text", "details" "jsonb", "ip_address" "inet", "user_agent" "text", "session_id" "text", "created_at" timestamp with time zone, "total_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Only admins can access audit logs
  IF NOT internal.is_admin() THEN
    RAISE EXCEPTION 'Access denied: Admin role required';
  END IF;

  RETURN QUERY
  WITH filtered AS (
    SELECT 
      e.id,
      e.event_type,
      e.event_category,
      e.severity,
      e.user_id,
      e.user_email,
      e.user_name,
      e.resource_type,
      e.resource_id,
      e.details,
      e.ip_address,
      e.user_agent,
      e.session_id,
      e.created_at
    FROM audit.events e
    WHERE 
      (p_search IS NULL OR (
        e.event_type ILIKE '%' || p_search || '%' OR
        e.user_email ILIKE '%' || p_search || '%' OR
        e.user_name ILIKE '%' || p_search || '%' OR
        e.resource_id ILIKE '%' || p_search || '%'
      ))
      AND (p_event_category IS NULL OR e.event_category = p_event_category)
      AND (p_severity IS NULL OR e.severity = p_severity)
      AND (p_event_type IS NULL OR e.event_type = p_event_type)
    ORDER BY e.created_at DESC
  ),
  counted AS (
    SELECT COUNT(*) AS cnt FROM filtered
  )
  SELECT 
    f.id,
    f.event_type,
    f.event_category,
    f.severity,
    f.user_id,
    f.user_email,
    f.user_name,
    f.resource_type,
    f.resource_id,
    f.details,
    f.ip_address,
    f.user_agent,
    f.session_id,
    f.created_at,
    c.cnt AS total_count
  FROM filtered f, counted c
  LIMIT p_limit
  OFFSET p_offset;
END;
$$;
ALTER FUNCTION "public"."audit_list_events"("p_limit" integer, "p_offset" integer, "p_search" "text", "p_event_category" "text", "p_severity" "text", "p_event_type" "text") OWNER TO "postgres";
