--
-- Name: confirm_purchase_invoice("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."confirm_purchase_invoice"("p_invoice_id" "uuid") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_invoice RECORD;
    v_internal_number TEXT;
BEGIN
    -- Obtener factura
    SELECT * INTO v_invoice
    FROM sales.purchase_invoices
    WHERE id = p_invoice_id;
    
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Factura no encontrada';
    END IF;
    
    -- Verificar que no est├® ya confirmada
    IF v_invoice.status = 'CONFIRMED' THEN
        RAISE EXCEPTION 'La factura ya est├í confirmada';
    END IF;
    
    -- Generar n├║mero interno si no existe
    IF v_invoice.internal_purchase_number IS NULL THEN
        v_internal_number := public.generate_internal_purchase_number();
        
        -- Verificar que no exista (por si acaso)
        WHILE EXISTS (SELECT 1 FROM sales.purchase_invoices WHERE internal_purchase_number = v_internal_number) LOOP
            v_internal_number := public.generate_internal_purchase_number();
        END LOOP;
    ELSE
        v_internal_number := v_invoice.internal_purchase_number;
    END IF;
    
    -- Actualizar factura a CONFIRMED y bloquear
    UPDATE sales.purchase_invoices
    SET
        status = 'CONFIRMED',
        internal_purchase_number = v_internal_number,
        is_locked = true,
        locked_at = NOW(),
        updated_at = NOW()
    WHERE id = p_invoice_id;
    
    RETURN v_internal_number;
END;
$$;
ALTER FUNCTION "public"."confirm_purchase_invoice"("p_invoice_id" "uuid") OWNER TO "postgres";
