--
-- Name: create_bank_transfer("uuid", "text", "uuid", "text", numeric, "date", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_bank_transfer"("p_source_bank_id" "uuid", "p_source_bank_name" "text", "p_target_bank_id" "uuid", "p_target_bank_name" "text", "p_amount" numeric, "p_transfer_date" "date" DEFAULT CURRENT_DATE, "p_notes" "text" DEFAULT NULL::"text") RETURNS TABLE("entry_id" "uuid", "entry_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_source_code TEXT;
  v_target_code TEXT;
  v_entry_id UUID;
  v_entry_number TEXT;
  v_user_id UUID;
BEGIN
  IF p_source_bank_id = p_target_bank_id THEN
    RAISE EXCEPTION 'El banco origen y destino deben ser diferentes';
  END IF;
  
  IF p_amount <= 0 THEN
    RAISE EXCEPTION 'El importe debe ser positivo';
  END IF;
  
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;
  
  SELECT accounting_code INTO v_source_code
  FROM internal.company_bank_accounts
  WHERE id = p_source_bank_id AND is_active = TRUE;
  
  SELECT accounting_code INTO v_target_code
  FROM internal.company_bank_accounts
  WHERE id = p_target_bank_id AND is_active = TRUE;
  
  IF v_source_code IS NULL OR v_target_code IS NULL THEN
    RAISE EXCEPTION 'Cuenta bancaria no encontrada';
  END IF;
  
  v_entry_number := accounting.get_next_entry_number();
  
  INSERT INTO accounting.journal_entries (
    entry_number, entry_date, entry_type, description,
    reference_type, is_locked, created_by
  ) VALUES (
    v_entry_number, p_transfer_date,
    'BANK_TRANSFER'::accounting.journal_entry_type,
    'Traspaso ' || p_source_bank_name || ' ÔåÆ ' || p_target_bank_name || COALESCE(' - ' || p_notes, ''),
    'BANK_TRANSFER', FALSE, v_user_id
  )
  RETURNING id INTO v_entry_id;
  
  INSERT INTO accounting.journal_entry_lines (journal_entry_id, line_order, account_code, description, amount, debit_credit)
  VALUES (v_entry_id, 1, v_target_code, 'Traspaso desde ' || p_source_bank_name, p_amount, 'DEBIT');
  
  INSERT INTO accounting.journal_entry_lines (journal_entry_id, line_order, account_code, description, amount, debit_credit)
  VALUES (v_entry_id, 2, v_source_code, 'Traspaso a ' || p_target_bank_name, p_amount, 'CREDIT');
  
  RETURN QUERY SELECT v_entry_id, v_entry_number;
END;
$$;
ALTER FUNCTION "public"."create_bank_transfer"("p_source_bank_id" "uuid", "p_source_bank_name" "text", "p_target_bank_id" "uuid", "p_target_bank_name" "text", "p_amount" numeric, "p_transfer_date" "date", "p_notes" "text") OWNER TO "postgres";
--
-- Name: create_canvassing_location("text", numeric, numeric, "text", "text", "text", "text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_canvassing_location"("p_status" "text", "p_latitude" numeric, "p_longitude" numeric, "p_company_name" "text", "p_address" "text" DEFAULT NULL::"text", "p_city" "text" DEFAULT NULL::"text", "p_province" "text" DEFAULT NULL::"text", "p_postal_code" "text" DEFAULT NULL::"text", "p_country" "text" DEFAULT 'ES'::"text", "p_location_references" "text" DEFAULT NULL::"text") RETURNS TABLE("location_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$

DECLARE

  v_location_id UUID;

  v_user_id UUID;

  v_status crm.canvassing_status;

BEGIN

  v_user_id := internal.get_authorized_user_id(auth.uid());

  

  IF v_user_id IS NULL THEN

    RAISE EXCEPTION 'Usuario no autenticado';

  END IF;

  

  -- Validar campos obligatorios

  IF p_status IS NULL OR p_status = '' THEN

    RAISE EXCEPTION 'El estado del lead (PIN) es obligatorio';

  END IF;

  

  IF p_latitude IS NULL OR p_longitude IS NULL THEN

    RAISE EXCEPTION 'Las coordenadas son obligatorias';

  END IF;

  

  IF p_company_name IS NULL OR p_company_name = '' OR p_company_name = 'Sin nombre' THEN

    RAISE EXCEPTION 'El nombre del comercio es obligatorio';

  END IF;

  

  -- Convertir TEXT a ENUM

  v_status := p_status::crm.canvassing_status;

  

  INSERT INTO crm.location (

    created_by, -- Autoasignado autom├íticamente

    status, -- OBLIGATORIO

    latitude, -- OBLIGATORIO

    longitude, -- OBLIGATORIO

    company_name, -- OBLIGATORIO

    address,

    city,

    province,

    postal_code,

    country,

    location_references

  ) VALUES (

    v_user_id,

    v_status,

    p_latitude,

    p_longitude,

    p_company_name,

    p_address,

    p_city,

    p_province,

    p_postal_code,

    p_country,

    p_location_references

  )

  RETURNING id INTO v_location_id;

  

  RETURN QUERY SELECT v_location_id;

END;

$$;
ALTER FUNCTION "public"."create_canvassing_location"("p_status" "text", "p_latitude" numeric, "p_longitude" numeric, "p_company_name" "text", "p_address" "text", "p_city" "text", "p_province" "text", "p_postal_code" "text", "p_country" "text", "p_location_references" "text") OWNER TO "postgres";
