-- Name: create_catalog_product("text", "text", "catalog"."product_type", "uuid", "catalog"."unit_type", numeric, numeric, numeric, "uuid", "text", boolean, numeric, "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_catalog_product"("p_sku" "text", "p_name" "text", "p_product_type" "catalog"."product_type", "p_category_id" "uuid" DEFAULT NULL::"uuid", "p_unit" "catalog"."unit_type" DEFAULT 'ud'::"catalog"."unit_type", "p_cost_price" numeric DEFAULT NULL::numeric, "p_sale_price" numeric DEFAULT 0, "p_discount_percent" numeric DEFAULT 0, "p_tax_rate_id" "uuid" DEFAULT NULL::"uuid", "p_description" "text" DEFAULT NULL::"text", "p_track_stock" boolean DEFAULT false, "p_min_stock_alert" numeric DEFAULT NULL::numeric, "p_supplier_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_id UUID; v_tax UUID;
BEGIN
  IF NOT internal.is_admin() THEN RAISE EXCEPTION 'Only admins can create products'; END IF;
  v_tax := COALESCE(p_tax_rate_id, (SELECT id FROM catalog.tax_rates WHERE is_default = true LIMIT 1));
  INSERT INTO catalog.products (sku, name, description, product_type, category_id, unit, cost_price, sale_price, discount_percent, tax_rate_id, track_stock, min_stock_alert, supplier_id)
  VALUES (p_sku, p_name, p_description, p_product_type, p_category_id, p_unit, p_cost_price, p_sale_price, p_discount_percent, v_tax, p_track_stock, p_min_stock_alert, p_supplier_id)
  RETURNING id INTO v_id;
  RETURN v_id;
END;
$$;
ALTER FUNCTION "public"."create_catalog_product"("p_sku" "text", "p_name" "text", "p_product_type" "catalog"."product_type", "p_category_id" "uuid", "p_unit" "catalog"."unit_type", "p_cost_price" numeric, "p_sale_price" numeric, "p_discount_percent" numeric, "p_tax_rate_id" "uuid", "p_description" "text", "p_track_stock" boolean, "p_min_stock_alert" numeric, "p_supplier_id" "uuid") OWNER TO "postgres";
