CREATE FUNCTION "public"."create_client"("p_company_name" "text", "p_contact_email" "text", "p_contact_phone" "text", "p_industry_sector" "text" DEFAULT NULL::"text", "p_lead_source" "text" DEFAULT NULL::"text", "p_lead_stage" "text" DEFAULT 'NEW'::"text", "p_tax_id" "text" DEFAULT NULL::"text", "p_legal_name" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text", "p_assigned_to" "uuid" DEFAULT NULL::"uuid", "p_created_by" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("client_id" "uuid", "client_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_client_id UUID;
  v_client_number TEXT;
BEGIN
  INSERT INTO crm.clients (
    company_name, contact_phone, contact_email, lead_stage, lead_source,
    industry_sector, tax_id, legal_name, notes, assigned_to, created_by
  ) VALUES (
    p_company_name, p_contact_phone, p_contact_email, 
    p_lead_stage::crm.lead_stage, 
    p_lead_source::crm.lead_source,
    p_industry_sector::crm.industry_sector, 
    p_tax_id, p_legal_name, p_notes, p_assigned_to, p_created_by
  )
  RETURNING id, clients.client_number INTO v_client_id, v_client_number;
  
  RETURN QUERY SELECT v_client_id, v_client_number;
END;
$$;
