--
-- Name: create_partner("text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_partner"("p_full_name" "text", "p_tax_id" "text" DEFAULT NULL::"text", "p_email" "text" DEFAULT NULL::"text", "p_phone" "text" DEFAULT NULL::"text") RETURNS TABLE("partner_id" "uuid", "partner_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_partner_id uuid;
  v_partner_number text;
  v_next_number int;
BEGIN
  -- Generate next partner number
  SELECT COALESCE(MAX(CAST(SUBSTRING(p.partner_number FROM 5) AS integer)), 0) + 1
  INTO v_next_number
  FROM internal.partners p;
  
  v_partner_number := 'SOC-' || LPAD(v_next_number::text, 4, '0');
  
  -- Insert the new partner
  INSERT INTO internal.partners (
    partner_number,
    full_name,
    tax_id,
    email,
    phone,
    status
  ) VALUES (
    v_partner_number,
    p_full_name,
    p_tax_id,
    p_email,
    p_phone,
    'ACTIVE'
  )
  RETURNING id INTO v_partner_id;
  
  -- Return using the variable names explicitly
  RETURN QUERY SELECT v_partner_id AS partner_id, v_partner_number AS partner_number;
END;
$$;
ALTER FUNCTION "public"."create_partner"("p_full_name" "text", "p_tax_id" "text", "p_email" "text", "p_phone" "text") OWNER TO "postgres";
--
-- Name: create_partner_compensation_run("uuid", integer, integer, numeric, numeric, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_partner_compensation_run"("p_partner_id" "uuid", "p_period_year" integer, "p_period_month" integer, "p_gross_amount" numeric, "p_irpf_rate" numeric DEFAULT 15.0, "p_notes" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_run_id uuid;
  v_compensation_number text;
  v_irpf_amount numeric;
  v_net_amount numeric;
  v_user_id uuid;
  v_partner_account_code text;
BEGIN
  -- Get the INTERNAL user id (not auth.uid())
  v_user_id := internal.get_authorized_user_id(auth.uid());
  
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado para esta operaci├│n';
  END IF;

  -- Calculate amounts
  v_irpf_amount := ROUND(p_gross_amount * (p_irpf_rate / 100), 2);
  v_net_amount := p_gross_amount - v_irpf_amount;

  -- Get or create partner-specific account code
  v_partner_account_code := internal.get_or_create_partner_account_code(p_partner_id);

  -- Generate compensation number
  SELECT 'RET-' || p_period_year::text || '-' || 
         LPAD((COALESCE(MAX(CAST(SUBSTRING(compensation_number FROM 10) AS integer)), 0) + 1)::text, 4, '0')
  INTO v_compensation_number
  FROM internal.partner_compensation_runs
  WHERE compensation_number LIKE 'RET-' || p_period_year::text || '-%';

  -- Insert compensation run
  INSERT INTO internal.partner_compensation_runs (
    partner_id,
    compensation_number,
    period_year,
    period_month,
    gross_amount,
    irpf_rate,
    irpf_amount,
    net_amount,
    notes,
    status,
    created_by
  ) VALUES (
    p_partner_id,
    v_compensation_number,
    p_period_year,
    p_period_month,
    p_gross_amount,
    p_irpf_rate,
    v_irpf_amount,
    v_net_amount,
    p_notes,
    'DRAFT',
    v_user_id  -- Using the internal user id
  )
  RETURNING id INTO v_run_id;

  RETURN v_run_id;
END;
$$;
ALTER FUNCTION "public"."create_partner_compensation_run"("p_partner_id" "uuid", "p_period_year" integer, "p_period_month" integer, "p_gross_amount" numeric, "p_irpf_rate" numeric, "p_notes" "text") OWNER TO "postgres";
