--
-- Name: create_product("uuid", "uuid", "text", "text", numeric, numeric, numeric, "public"."product_type", integer, "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_product"("p_category_id" "uuid", "p_subcategory_id" "uuid" DEFAULT NULL::"uuid", "p_name" "text" DEFAULT NULL::"text", "p_description" "text" DEFAULT NULL::"text", "p_cost_price" numeric DEFAULT 0, "p_base_price" numeric DEFAULT 0, "p_tax_rate" numeric DEFAULT 21, "p_type" "public"."product_type" DEFAULT 'product'::"public"."product_type", "p_stock" integer DEFAULT NULL::integer, "p_default_tax_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("out_product_id" "uuid", "out_product_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_product_id uuid;
  v_product_number text;
  v_category_code text;
  v_subcategory_code text;
  v_next_seq integer;
BEGIN
  SELECT code INTO v_category_code 
  FROM internal.product_categories WHERE id = p_category_id;
  
  IF v_category_code IS NULL THEN
    RAISE EXCEPTION 'Category not found';
  END IF;
  
  IF p_subcategory_id IS NOT NULL THEN
    SELECT code INTO v_subcategory_code 
    FROM internal.product_subcategories WHERE id = p_subcategory_id;
  END IF;
  
  -- Get next sequence number for products within this category and subcategory
  SELECT COALESCE(MAX(
    CAST(SUBSTRING(p.product_number FROM '[0-9]+$') AS integer)
  ), 0) + 1 INTO v_next_seq
  FROM internal.products p
  WHERE p.category_id = p_category_id
    AND (p_subcategory_id IS NULL OR p.subcategory_id = p_subcategory_id);
  
  -- Build product number: CATEGORY-SUBCATEGORY-NNNN
  v_product_number := v_category_code || 
    COALESCE('-' || v_subcategory_code, '') || 
    '-' || LPAD(v_next_seq::text, 4, '0');
  
  INSERT INTO internal.products (
    category_id, subcategory_id, product_number, name, description,
    cost_price, base_price, tax_rate, type, stock, default_tax_id
  ) VALUES (
    p_category_id, p_subcategory_id, v_product_number, 
    COALESCE(p_name, 'Nuevo Producto'), p_description,
    p_cost_price, p_base_price, p_tax_rate, p_type,
    CASE WHEN p_type = 'product' THEN COALESCE(p_stock, 0) ELSE NULL END,
    p_default_tax_id
  )
  RETURNING id INTO v_product_id;
  
  RETURN QUERY SELECT v_product_id, v_product_number;
END;
$_$;
ALTER FUNCTION "public"."create_product"("p_category_id" "uuid", "p_subcategory_id" "uuid", "p_name" "text", "p_description" "text", "p_cost_price" numeric, "p_base_price" numeric, "p_tax_rate" numeric, "p_type" "public"."product_type", "p_stock" integer, "p_default_tax_id" "uuid") OWNER TO "postgres";
--
-- Name: create_product_category("text", "text", "text", integer, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_product_category"("p_code" "text", "p_name" "text", "p_description" "text" DEFAULT NULL::"text", "p_display_order" integer DEFAULT 0, "p_type" "text" DEFAULT 'product'::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_category_id uuid;
BEGIN
  -- Verificar permisos
  IF NOT (internal.is_admin() OR internal.is_manager()) THEN
    RAISE EXCEPTION 'No tienes permisos para crear categor├¡as';
  END IF;
  
  -- Insertar la categor├¡a
  INSERT INTO internal.product_categories (code, name, description, display_order, type)
  VALUES (UPPER(p_code), UPPER(p_name), p_description, p_display_order, p_type)
  RETURNING id INTO v_category_id;
  
  RETURN v_category_id;
END;
$$;
ALTER FUNCTION "public"."create_product_category"("p_code" "text", "p_name" "text", "p_description" "text", "p_display_order" integer, "p_type" "text") OWNER TO "postgres";
--
-- Name: create_product_pack("text", "text", numeric, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_product_pack"("p_name" "text" DEFAULT 'Nuevo pack'::"text", "p_description" "text" DEFAULT NULL::"text", "p_discount_percent" numeric DEFAULT 0, "p_tax_rate" numeric DEFAULT 21) RETURNS TABLE("pack_id" "uuid", "pack_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_pack_number TEXT;
  v_pack_id UUID;
  v_next_number INTEGER;
BEGIN
  -- Generate pack number
  SELECT COALESCE(MAX(
    CAST(NULLIF(REGEXP_REPLACE(product_packs.pack_number, '^PACK-', ''), '') AS INTEGER)
  ), 0) + 1
  INTO v_next_number
  FROM internal.product_packs;
  
  v_pack_number := 'PACK-' || LPAD(v_next_number::TEXT, 4, '0');
  
  -- Insert pack
  INSERT INTO internal.product_packs (pack_number, name, description, discount_percent, tax_rate)
  VALUES (v_pack_number, UPPER(p_name), p_description, p_discount_percent, p_tax_rate)
  RETURNING id INTO v_pack_id;
  
  RETURN QUERY SELECT v_pack_id, v_pack_number;
END;
$$;
ALTER FUNCTION "public"."create_product_pack"("p_name" "text", "p_description" "text", "p_discount_percent" numeric, "p_tax_rate" numeric) OWNER TO "postgres";
