--
-- Name: create_project("uuid", "text", "text", "text", "text", "text", "text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_project"("p_client_id" "uuid", "p_client_order_number" "text" DEFAULT NULL::"text", "p_local_name" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text", "p_project_address" "text" DEFAULT NULL::"text", "p_project_city" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT 'NEGOTIATION'::"text", "p_site_mode" "text" DEFAULT 'SINGLE_SITE'::"text", "p_site_name" "text" DEFAULT NULL::"text", "p_project_type" "text" DEFAULT 'INSTALLATION'::"text") RETURNS TABLE("project_id" "uuid", "project_name" "text", "project_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_user_id UUID;
  v_project_id UUID;
  v_project_number TEXT;
  v_short_number TEXT;
  v_project_name TEXT;
  v_client_name TEXT;
  v_site_id UUID;
  v_site_mode projects.site_mode;
  v_project_type projects.project_type;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Authentication required';
  END IF;

  BEGIN
    v_site_mode := p_site_mode::projects.site_mode;
  EXCEPTION WHEN invalid_text_representation THEN
    RAISE EXCEPTION 'Invalid site_mode: %', p_site_mode;
  END;

  BEGIN
    v_project_type := p_project_type::projects.project_type;
  EXCEPTION WHEN invalid_text_representation THEN
    RAISE EXCEPTION 'Invalid project_type: %', p_project_type;
  END;

  SELECT company_name INTO v_client_name
  FROM crm.clients WHERE id = p_client_id;
  IF v_client_name IS NULL THEN
    RAISE EXCEPTION 'Client not found';
  END IF;

  -- Generate full project number (e.g. PRJ-2026-000026)
  v_project_number := audit.get_next_number('PRJ');
  
  -- Extract just the sequential digits for the display name (e.g. 000026)
  v_short_number := SUBSTRING(v_project_number FROM '[0-9]{6}$');

  -- Build project name using short number only
  v_project_name := v_short_number || ' - ' || v_client_name;
  IF p_client_order_number IS NOT NULL AND p_client_order_number != '' THEN
    v_project_name := v_project_name || ' - ' || p_client_order_number;
  END IF;
  IF p_project_city IS NOT NULL AND p_project_city != '' THEN
    v_project_name := v_project_name || ' - ' || p_project_city;
  END IF;
  IF p_local_name IS NOT NULL AND p_local_name != '' THEN
    v_project_name := v_project_name || ' - ' || p_local_name;
  END IF;

  -- Insert project with full project_number but short project_name
  INSERT INTO projects.projects (
    project_number, project_name, title, project_type,
    client_id, client_order_number,
    local_name, description, project_city, status, created_by, site_mode
  )
  VALUES (
    v_project_number, v_project_name, v_project_name, v_project_type,
    p_client_id, p_client_order_number,
    p_local_name, p_notes, p_project_city, p_status::projects.project_status,
    v_user_id, v_site_mode
  )
  RETURNING id INTO v_project_id;

  -- Create default site
  v_site_id := gen_random_uuid();
  INSERT INTO projects.project_sites (id, project_id, site_name, city)
  VALUES (
    v_site_id,
    v_project_id,
    COALESCE(NULLIF(p_site_name, ''), COALESCE(p_local_name, 'Sitio Principal')),
    p_project_city
  );

  -- Set default site
  UPDATE projects.projects
  SET default_site_id = v_site_id
  WHERE id = v_project_id;

  RETURN QUERY SELECT v_project_id, v_project_name, v_project_number;
END;
$_$;
ALTER FUNCTION "public"."create_project"("p_client_id" "uuid", "p_client_order_number" "text", "p_local_name" "text", "p_notes" "text", "p_project_address" "text", "p_project_city" "text", "p_status" "text", "p_site_mode" "text", "p_site_name" "text", "p_project_type" "text") OWNER TO "postgres";
--
-- Name: create_project_site("uuid", "text", "text", "text", "text", "text", "text", double precision, double precision, "text", "text", "text", "text", "text", "text", boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_project_site"("p_project_id" "uuid", "p_site_name" "text", "p_address" "text" DEFAULT NULL::"text", "p_city" "text" DEFAULT NULL::"text", "p_postal_code" "text" DEFAULT NULL::"text", "p_province" "text" DEFAULT NULL::"text", "p_country" "text" DEFAULT 'ES'::"text", "p_latitude" double precision DEFAULT NULL::double precision, "p_longitude" double precision DEFAULT NULL::double precision, "p_contact_name" "text" DEFAULT NULL::"text", "p_contact_phone" "text" DEFAULT NULL::"text", "p_contact_email" "text" DEFAULT NULL::"text", "p_site_reference" "text" DEFAULT NULL::"text", "p_floor_area" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text", "p_set_as_default" boolean DEFAULT false) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_site_id UUID;
BEGIN
  IF auth.uid() IS NULL THEN RAISE EXCEPTION 'Authentication required'; END IF;
  IF NOT EXISTS (SELECT 1 FROM projects.projects WHERE id = p_project_id) THEN RAISE EXCEPTION 'Project not found'; END IF;
  INSERT INTO projects.project_sites (project_id, site_name, address, city, postal_code, province, country,
    latitude, longitude, contact_name, contact_phone, contact_email, site_reference, floor_area, notes)
  VALUES (p_project_id, p_site_name, p_address, p_city, p_postal_code, p_province, p_country,
    p_latitude, p_longitude, p_contact_name, p_contact_phone, p_contact_email, p_site_reference, p_floor_area, p_notes)
  RETURNING id INTO v_site_id;
  IF p_set_as_default THEN UPDATE projects.projects SET default_site_id = v_site_id WHERE id = p_project_id; END IF;
  RETURN v_site_id;
END; $$;
ALTER FUNCTION "public"."create_project_site"("p_project_id" "uuid", "p_site_name" "text", "p_address" "text", "p_city" "text", "p_postal_code" "text", "p_province" "text", "p_country" "text", "p_latitude" double precision, "p_longitude" double precision, "p_contact_name" "text", "p_contact_phone" "text", "p_contact_email" "text", "p_site_reference" "text", "p_floor_area" "text", "p_notes" "text", "p_set_as_default" boolean) OWNER TO "postgres";
--
-- Name: create_purchase_invoice("text", "text", "text", "uuid", "uuid", "uuid", "date", "date", "text", "text", "text", "text", "text", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_purchase_invoice"("p_invoice_number" "text", "p_document_type" "text" DEFAULT 'INVOICE'::"text", "p_status" "text" DEFAULT 'DRAFT'::"text", "p_supplier_id" "uuid" DEFAULT NULL::"uuid", "p_technician_id" "uuid" DEFAULT NULL::"uuid", "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_issue_date" "date" DEFAULT CURRENT_DATE, "p_due_date" "date" DEFAULT NULL::"date", "p_notes" "text" DEFAULT NULL::"text", "p_file_path" "text" DEFAULT NULL::"text", "p_file_name" "text" DEFAULT NULL::"text", "p_expense_category" "text" DEFAULT NULL::"text", "p_supplier_invoice_number" "text" DEFAULT NULL::"text", "p_client_id" "uuid" DEFAULT NULL::"uuid", "p_site_id" "uuid" DEFAULT NULL::"uuid") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'internal', 'sales'
    AS $$
DECLARE
  v_invoice_id uuid;
  v_user_id uuid;
  v_site_mode text;
  v_default_site_id uuid;
  v_final_site_id uuid;
  v_requested_status text;
  v_final_status text;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  v_final_site_id := p_site_id;
  v_requested_status := upper(coalesce(trim(p_status), ''));

  IF p_project_id IS NOT NULL THEN
    SELECT pp.site_mode, pp.default_site_id
    INTO v_site_mode, v_default_site_id
    FROM projects.projects pp
    WHERE pp.id = p_project_id;

    IF v_site_mode = 'MULTI_SITE' AND v_final_site_id IS NULL THEN
      RAISE EXCEPTION 'site_id is required for MULTI_SITE projects';
    END IF;

    IF v_site_mode = 'SINGLE_SITE' AND v_final_site_id IS NULL THEN
      v_final_site_id := v_default_site_id;
    END IF;

    IF v_final_site_id IS NOT NULL AND NOT EXISTS (
      SELECT 1
      FROM projects.project_sites ps
      WHERE ps.id = v_final_site_id
        AND ps.project_id = p_project_id
        AND ps.is_active = true
    ) THEN
      RAISE EXCEPTION 'site_id does not belong to this project or is inactive';
    END IF;
  ELSE
    v_final_site_id := NULL;
  END IF;

  v_final_status := CASE
    WHEN v_requested_status = '' THEN 'DRAFT'
    WHEN v_requested_status IN ('SCANNED', 'PENDING') THEN 'DRAFT'
    WHEN v_requested_status = 'REGISTERED' THEN 'APPROVED'
    ELSE v_requested_status
  END;

  INSERT INTO sales.purchase_invoices (
    invoice_number,
    document_type,
    status,
    supplier_id,
    technician_id,
    project_id,
    issue_date,
    due_date,
    notes,
    file_path,
    file_name,
    expense_category,
    supplier_invoice_number,
    client_id,
    site_id,
    created_by
  ) VALUES (
    p_invoice_number,
    p_document_type,
    v_final_status,
    p_supplier_id,
    p_technician_id,
    p_project_id,
    COALESCE(p_issue_date, CURRENT_DATE),
    p_due_date,
    p_notes,
    p_file_path,
    p_file_name,
    p_expense_category,
    p_supplier_invoice_number,
    p_client_id,
    v_final_site_id,
    v_user_id
  )
  RETURNING id INTO v_invoice_id;

  RETURN v_invoice_id::text;
END;
$$;
ALTER FUNCTION "public"."create_purchase_invoice"("p_invoice_number" "text", "p_document_type" "text", "p_status" "text", "p_supplier_id" "uuid", "p_technician_id" "uuid", "p_project_id" "uuid", "p_issue_date" "date", "p_due_date" "date", "p_notes" "text", "p_file_path" "text", "p_file_name" "text", "p_expense_category" "text", "p_supplier_invoice_number" "text", "p_client_id" "uuid", "p_site_id" "uuid") OWNER TO "postgres";
--
-- Name: create_purchase_order("uuid", "uuid", "uuid", "date", "text", "text", "date", "date", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_purchase_order"("p_supplier_id" "uuid" DEFAULT NULL::"uuid", "p_technician_id" "uuid" DEFAULT NULL::"uuid", "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_issue_date" "date" DEFAULT NULL::"date", "p_notes" "text" DEFAULT NULL::"text", "p_internal_notes" "text" DEFAULT NULL::"text", "p_expected_start_date" "date" DEFAULT NULL::"date", "p_expected_end_date" "date" DEFAULT NULL::"date", "p_site_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_order_id UUID; v_user_id UUID; v_po_number TEXT;
  v_site_mode TEXT; v_default_site_id UUID; v_final_site_id UUID;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  v_final_site_id := p_site_id;
  IF p_project_id IS NOT NULL THEN
    SELECT pp.site_mode, pp.default_site_id INTO v_site_mode, v_default_site_id FROM projects.projects pp WHERE pp.id = p_project_id;
    IF v_site_mode = 'SINGLE_SITE' AND v_final_site_id IS NULL THEN v_final_site_id := v_default_site_id; END IF;
    IF v_final_site_id IS NOT NULL AND NOT EXISTS (SELECT 1 FROM projects.project_sites ps WHERE ps.id = v_final_site_id AND ps.project_id = p_project_id AND ps.is_active = true) THEN
      RAISE EXCEPTION 'site_id does not belong to this project or is inactive';
    END IF;
  END IF;

  v_po_number := internal.generate_purchase_order_number();
  INSERT INTO sales.purchase_orders (po_number, supplier_id, technician_id, project_id, issue_date, notes, internal_notes, expected_start_date, expected_end_date, created_by, site_id)
  VALUES (v_po_number, p_supplier_id, p_technician_id, p_project_id, COALESCE(p_issue_date, CURRENT_DATE), p_notes, p_internal_notes, p_expected_start_date, p_expected_end_date, v_user_id, v_final_site_id)
  RETURNING sales.purchase_orders.id INTO v_order_id;

  PERFORM internal.log_audit_event(v_user_id, 'purchase_order.created', 'PURCHASE_ORDER', v_order_id::TEXT,
    jsonb_build_object('po_number', v_po_number, 'site_id', v_final_site_id), 'info', 'FINANCIAL');
  RETURN v_order_id;
END;
$$;
ALTER FUNCTION "public"."create_purchase_order"("p_supplier_id" "uuid", "p_technician_id" "uuid", "p_project_id" "uuid", "p_issue_date" "date", "p_notes" "text", "p_internal_notes" "text", "p_expected_start_date" "date", "p_expected_end_date" "date", "p_site_id" "uuid") OWNER TO "postgres";
