CREATE FUNCTION "public"."create_quote"("p_client_id" "uuid", "p_project_name" "text" DEFAULT NULL::"text", "p_created_by" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_quote_id UUID;
BEGIN
  INSERT INTO quotes.quotes (client_id, project_name, created_by)
  VALUES (p_client_id, p_project_name, p_created_by)
  RETURNING id INTO v_quote_id;
  
  RETURN v_quote_id;
END;
$$;
ALTER FUNCTION "public"."create_quote"("p_client_id" "uuid", "p_project_name" "text", "p_created_by" "uuid") OWNER TO "postgres";
--
-- Name: create_quote_with_number("uuid", "uuid", "text", "date", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_quote_with_number"("p_client_id" "uuid", "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_project_name" "text" DEFAULT NULL::"text", "p_valid_until" "date" DEFAULT NULL::"date", "p_site_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("quote_id" "uuid", "quote_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'sales', 'accounting', 'internal', 'crm', 'quotes'
    AS $$
DECLARE
  v_quote_id UUID;
  v_quote_number TEXT;
  v_user_id UUID;
  v_project_name TEXT;
  v_site_mode TEXT;
  v_default_site_id UUID;
  v_final_site_id UUID;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());

  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'User not authorized';
  END IF;

  -- Resolve project name
  IF p_project_id IS NOT NULL AND p_project_name IS NULL THEN
    SELECT pp.project_name INTO v_project_name FROM projects.projects pp WHERE pp.id = p_project_id;
  ELSE
    v_project_name := p_project_name;
  END IF;

  -- Resolve site_id based on project site_mode
  v_final_site_id := p_site_id;
  IF p_project_id IS NOT NULL THEN
    SELECT pp.site_mode, pp.default_site_id
      INTO v_site_mode, v_default_site_id
      FROM projects.projects pp WHERE pp.id = p_project_id;

    IF v_site_mode = 'MULTI_SITE' AND v_final_site_id IS NULL THEN
      RAISE EXCEPTION 'site_id is required for MULTI_SITE projects';
    END IF;

    IF v_site_mode = 'SINGLE_SITE' AND v_final_site_id IS NULL THEN
      v_final_site_id := v_default_site_id;
    END IF;

    IF v_final_site_id IS NOT NULL AND NOT EXISTS (
      SELECT 1 FROM projects.project_sites ps
      WHERE ps.id = v_final_site_id AND ps.project_id = p_project_id AND ps.is_active = true
    ) THEN
      RAISE EXCEPTION 'site_id does not belong to this project or is inactive';
    END IF;
  END IF;

  -- Generate DRAFT quote number using the correct function
  v_quote_number := quotes.get_next_draft_number();

  -- Insert the new quote
  INSERT INTO quotes.quotes (
    client_id, project_id, project_name, quote_number,
    valid_until, created_by, site_id, status
  )
  VALUES (
    p_client_id, p_project_id, v_project_name, v_quote_number,
    COALESCE(p_valid_until, CURRENT_DATE + INTERVAL '30 days'),
    v_user_id, v_final_site_id, 'DRAFT'
  )
  RETURNING quotes.quotes.id INTO v_quote_id;

  RETURN QUERY SELECT v_quote_id, v_quote_number;
END;
$$;
ALTER FUNCTION "public"."create_quote_with_number"("p_client_id" "uuid", "p_project_id" "uuid", "p_project_name" "text", "p_valid_until" "date", "p_site_id" "uuid") OWNER TO "postgres";
