CREATE FUNCTION "public"."create_tax"("p_name" "text", "p_code" "text", "p_rate" numeric, "p_tax_type" "text", "p_description" "text" DEFAULT NULL::"text", "p_is_default" boolean DEFAULT false) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_tax_id uuid;
BEGIN
  -- Si es default, quitar el default actual del mismo tipo
  IF p_is_default THEN
    UPDATE internal.taxes SET is_default = false WHERE tax_type = p_tax_type AND is_default = true;
  END IF;

  INSERT INTO internal.taxes (name, code, rate, tax_type, description, is_default)
  VALUES (p_name, p_code, p_rate, p_tax_type, p_description, p_is_default)
  RETURNING id INTO v_tax_id;

  RETURN v_tax_id;
END;
$$;
ALTER FUNCTION "public"."create_tax"("p_name" "text", "p_code" "text", "p_rate" numeric, "p_tax_type" "text", "p_description" "text", "p_is_default" boolean) OWNER TO "postgres";
--
-- Name: create_tax_payment("uuid", "text", "text", numeric, "date", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_tax_payment"("p_bank_account_id" "uuid", "p_bank_name" "text", "p_tax_type" "text", "p_amount" numeric, "p_payment_date" "date" DEFAULT CURRENT_DATE, "p_period" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text") RETURNS TABLE("entry_id" "uuid", "entry_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_bank_code text;
  v_liability_account text;
  v_entry_id uuid;
  v_entry_number text;
  v_user_id uuid;
  v_description text;
  v_tax_label text;
BEGIN
  IF p_amount IS NULL OR p_amount <= 0 THEN
    RAISE EXCEPTION 'El importe debe ser positivo';
  END IF;

  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;

  SELECT accounting_code INTO v_bank_code
  FROM internal.company_bank_accounts
  WHERE id = p_bank_account_id AND is_active = TRUE;
  IF v_bank_code IS NULL THEN
    RAISE EXCEPTION 'Cuenta bancaria no encontrada';
  END IF;

  v_tax_label := CASE p_tax_type
    WHEN 'IVA' THEN 'IVA (Modelo 303)'
    WHEN 'IRPF' THEN 'IRPF (Modelo 111)'
    WHEN 'IS' THEN 'Impuesto de Sociedades'
    WHEN 'AEAT' THEN 'Impuestos AEAT'
    ELSE 'Impuesto '
  END;

  v_liability_account := CASE p_tax_type
    WHEN 'IVA' THEN '477000'
    WHEN 'IRPF' THEN '475100'
    WHEN 'IS' THEN '475200'
    WHEN 'AEAT' THEN '475200'
    ELSE NULL
  END;
  IF v_liability_account IS NULL THEN
    RAISE EXCEPTION 'Tipo de impuesto no v├ílido: %. Use IVA, IRPF, IS o AEAT', p_tax_type;
  END IF;

  v_description := 'Pago ' || v_tax_label || COALESCE(' - ' || NULLIF(TRIM(p_period), ''), '') || COALESCE(' - ' || NULLIF(TRIM(p_notes), ''), '');
  v_description := TRIM(BOTH ' -' FROM v_description);

  v_entry_number := accounting.get_next_entry_number();

  INSERT INTO accounting.journal_entries (
    entry_number, entry_date, entry_type, description,
    reference_type, is_locked, created_by
  ) VALUES (
    v_entry_number,
    p_payment_date,
    'TAX_PAYMENT'::accounting.journal_entry_type,
    v_description,
    'TAX_PAYMENT',
    FALSE,
    v_user_id
  )
  RETURNING id INTO v_entry_id;

  INSERT INTO accounting.journal_entry_lines (journal_entry_id, line_order, account_code, description, amount, debit_credit)
  VALUES (v_entry_id, 1, v_liability_account, 'Pago a Hacienda - ' || v_tax_label, p_amount, 'DEBIT');

  INSERT INTO accounting.journal_entry_lines (journal_entry_id, line_order, account_code, description, amount, debit_credit)
  VALUES (v_entry_id, 2, v_bank_code, 'Pago impuesto desde ' || COALESCE(p_bank_name, 'Banco'), p_amount, 'CREDIT');

  RETURN QUERY SELECT v_entry_id, v_entry_number;
END;
$$;
ALTER FUNCTION "public"."create_tax_payment"("p_bank_account_id" "uuid", "p_bank_name" "text", "p_tax_type" "text", "p_amount" numeric, "p_payment_date" "date", "p_period" "text", "p_notes" "text") OWNER TO "postgres";
