-- Name: create_technician("text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text"[], numeric, numeric, numeric, "text", "text", "text", numeric, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."create_technician"("p_company_name" "text", "p_type" "text" DEFAULT 'FREELANCER'::"text", "p_legal_name" "text" DEFAULT NULL::"text", "p_tax_id" "text" DEFAULT NULL::"text", "p_contact_name" "text" DEFAULT NULL::"text", "p_contact_phone" "text" DEFAULT NULL::"text", "p_contact_phone_secondary" "text" DEFAULT NULL::"text", "p_contact_email" "text" DEFAULT NULL::"text", "p_billing_email" "text" DEFAULT NULL::"text", "p_address" "text" DEFAULT NULL::"text", "p_city" "text" DEFAULT NULL::"text", "p_province" "text" DEFAULT NULL::"text", "p_postal_code" "text" DEFAULT NULL::"text", "p_country" "text" DEFAULT 'Espa├▒a'::"text", "p_specialties" "text"[] DEFAULT '{}'::"text"[], "p_hourly_rate" numeric DEFAULT NULL::numeric, "p_daily_rate" numeric DEFAULT NULL::numeric, "p_monthly_salary" numeric DEFAULT NULL::numeric, "p_iban" "text" DEFAULT NULL::"text", "p_payment_terms" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text", "p_vat_rate" numeric DEFAULT NULL::numeric, "p_withholding_tax_rate" numeric DEFAULT NULL::numeric) RETURNS TABLE("technician_id" "uuid", "technician_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_user_id UUID;
    v_technician_id UUID;
    v_technician_number TEXT;
    v_next_number INTEGER;
BEGIN
    v_user_id := internal.get_authorized_user_id(auth.uid());
    IF v_user_id IS NULL THEN
        RAISE EXCEPTION 'Usuario no autorizado';
    END IF;
    
    IF NOT (internal.is_admin() OR internal.is_manager()) THEN
        RAISE EXCEPTION 'No tienes permisos para crear t├®cnicos';
    END IF;
    
    v_next_number := nextval('internal.technician_number_seq');
    v_technician_number := 'TEC-' || LPAD(v_next_number::TEXT, 6, '0');
    
    INSERT INTO internal.technicians (
        technician_number, type, company_name, legal_name, tax_id,
        contact_name, contact_phone, contact_phone_secondary,
        contact_email, billing_email, address, city, province,
        postal_code, country, specialties, hourly_rate, daily_rate,
        monthly_salary, iban, payment_terms, notes, vat_rate,
        withholding_tax_rate, created_by
    ) VALUES (
        v_technician_number, p_type::internal.technician_type,
        p_company_name, p_legal_name, p_tax_id,
        p_contact_name, p_contact_phone, p_contact_phone_secondary,
        p_contact_email, p_billing_email, p_address, p_city, p_province,
        p_postal_code, p_country, p_specialties, p_hourly_rate, p_daily_rate,
        p_monthly_salary, p_iban, p_payment_terms, p_notes, p_vat_rate,
        p_withholding_tax_rate, v_user_id
    ) RETURNING id INTO v_technician_id;
    
    RETURN QUERY SELECT v_technician_id, v_technician_number;
END;
$$;
ALTER FUNCTION "public"."create_technician"("p_company_name" "text", "p_type" "text", "p_legal_name" "text", "p_tax_id" "text", "p_contact_name" "text", "p_contact_phone" "text", "p_contact_phone_secondary" "text", "p_contact_email" "text", "p_billing_email" "text", "p_address" "text", "p_city" "text", "p_province" "text", "p_postal_code" "text", "p_country" "text", "p_specialties" "text"[], "p_hourly_rate" numeric, "p_daily_rate" numeric, "p_monthly_salary" numeric, "p_iban" "text", "p_payment_terms" "text", "p_notes" "text", "p_vat_rate" numeric, "p_withholding_tax_rate" numeric) OWNER TO "postgres";
