-- Name: delete_catalog_product("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."delete_catalog_product"("p_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$ BEGIN IF NOT internal.is_admin() THEN RAISE EXCEPTION 'Only admins can delete products'; END IF; DELETE FROM catalog.products WHERE id = p_id; RETURN FOUND; END; $$;
ALTER FUNCTION "public"."delete_catalog_product"("p_id" "uuid") OWNER TO "postgres";
--
-- Name: delete_client("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."delete_client"("p_client_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'crm'
    AS $$
BEGIN
  UPDATE crm.clients
  SET deleted_at = now(), updated_at = now()
  WHERE id = p_client_id AND deleted_at IS NULL;
  
  RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."delete_client"("p_client_id" "uuid") OWNER TO "postgres";
--
-- Name: delete_external_credit_provider("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."delete_external_credit_provider"("p_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT internal.is_admin() THEN
    RAISE EXCEPTION 'Solo administradores pueden eliminar proveedores de cr├®dito';
  END IF;

  -- Check no operations exist
  IF EXISTS (SELECT 1 FROM accounting.credit_operations WHERE provider_id = p_id) THEN
    RAISE EXCEPTION 'No se puede eliminar: existen operaciones de cr├®dito asociadas';
  END IF;

  DELETE FROM accounting.external_credit_providers WHERE id = p_id;
  RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."delete_external_credit_provider"("p_id" "uuid") OWNER TO "postgres";
--
-- Name: delete_invoice_line("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."delete_invoice_line"("p_line_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$

DECLARE

  v_invoice_id UUID;

  v_is_locked BOOLEAN;

BEGIN

  SELECT invoice_id INTO v_invoice_id FROM sales.invoice_lines WHERE id = p_line_id;

  SELECT is_locked INTO v_is_locked FROM sales.invoices WHERE id = v_invoice_id;

  

  IF COALESCE(v_is_locked, false) THEN

    RAISE EXCEPTION 'No se pueden eliminar l├¡neas de una factura bloqueada';

  END IF;



  DELETE FROM sales.invoice_lines WHERE id = p_line_id;

  RETURN FOUND;

END;

$$;
ALTER FUNCTION "public"."delete_invoice_line"("p_line_id" "uuid") OWNER TO "postgres";
--
-- Name: delete_partner_compensation_run("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."delete_partner_compensation_run"("p_compensation_run_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_status TEXT;
BEGIN
  SELECT status INTO v_status FROM accounting.partner_compensation_runs WHERE id = p_compensation_run_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Retribuci├│n no encontrada: %', p_compensation_run_id; END IF;
  IF v_status != 'DRAFT' THEN RAISE EXCEPTION 'Solo se pueden eliminar retribuciones en estado DRAFT. Estado actual: %', v_status; END IF;
  DELETE FROM accounting.partner_compensation_runs WHERE id = p_compensation_run_id;
  RETURN TRUE;
END;
$$;
ALTER FUNCTION "public"."delete_partner_compensation_run"("p_compensation_run_id" "uuid") OWNER TO "postgres";
