--
-- Name: delete_purchase_invoice("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."delete_purchase_invoice"("p_invoice_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_status TEXT;
  v_file_path TEXT;
BEGIN
  -- Get the invoice status and file path
  SELECT status, file_path INTO v_status, v_file_path
  FROM sales.purchase_invoices
  WHERE id = p_invoice_id;
  
  -- Check if invoice exists
  IF v_status IS NULL THEN
    RAISE EXCEPTION 'Factura de compra no encontrada';
  END IF;
  
  -- Only allow deletion of DRAFT or PENDING invoices
  IF v_status NOT IN ('DRAFT', 'PENDING') THEN
    RAISE EXCEPTION 'Solo se pueden eliminar facturas en estado Borrador o Pendiente';
  END IF;
  
  -- Delete associated lines first (correct column name)
  DELETE FROM sales.purchase_invoice_lines
  WHERE purchase_invoice_id = p_invoice_id;
  
  -- Delete associated payments if any (correct column name)
  DELETE FROM sales.purchase_invoice_payments
  WHERE purchase_invoice_id = p_invoice_id;
  
  -- Delete the invoice
  DELETE FROM sales.purchase_invoices
  WHERE id = p_invoice_id;
  
  RETURN TRUE;
END;
$$;
ALTER FUNCTION "public"."delete_purchase_invoice"("p_invoice_id" "uuid") OWNER TO "postgres";
--
-- Name: delete_purchase_invoice_line("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."delete_purchase_invoice_line"("p_line_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_is_locked BOOLEAN;
    v_invoice_id UUID;
BEGIN
    -- Obtener invoice_id y verificar bloqueo
    SELECT 
        pi.is_locked,
        pil.purchase_invoice_id
    INTO 
        v_is_locked,
        v_invoice_id
    FROM sales.purchase_invoice_lines pil
    JOIN sales.purchase_invoices pi ON pil.purchase_invoice_id = pi.id
    WHERE pil.id = p_line_id;
    
    IF NOT FOUND THEN
        RAISE EXCEPTION 'L├¡nea no encontrada';
    END IF;
    
    IF v_is_locked THEN
        RAISE EXCEPTION 'No se pueden eliminar l├¡neas de una factura bloqueada';
    END IF;
    
    -- Eliminar l├¡nea
    DELETE FROM sales.purchase_invoice_lines WHERE id = p_line_id;
    
    -- Recalcular totales de la factura
    IF v_invoice_id IS NOT NULL THEN
        PERFORM public.recalculate_purchase_invoice(v_invoice_id);
    END IF;
    
    RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."delete_purchase_invoice_line"("p_line_id" "uuid") OWNER TO "postgres";
--
-- Name: delete_purchase_order("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."delete_purchase_order"("p_order_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_status TEXT;
BEGIN
    SELECT status::TEXT INTO v_status
    FROM sales.purchase_orders
    WHERE id = p_order_id;
    
    IF v_status NOT IN ('DRAFT', 'CANCELLED') THEN
        RAISE EXCEPTION 'Solo se pueden eliminar pedidos en estado BORRADOR o CANCELADO';
    END IF;
    
    -- Las l├¡neas se eliminan autom├íticamente por CASCADE
    DELETE FROM sales.purchase_orders WHERE id = p_order_id;
    
    RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."delete_purchase_order"("p_order_id" "uuid") OWNER TO "postgres";
