-- Name: delete_technician("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."delete_technician"("p_technician_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_invoice_count INTEGER;
BEGIN
    -- Check if technician exists
    IF NOT EXISTS (SELECT 1 FROM internal.technicians WHERE id = p_technician_id) THEN
        RAISE EXCEPTION 'El t├®cnico no existe';
    END IF;

    -- Check for associated purchase invoices
    SELECT COUNT(*) INTO v_invoice_count
    FROM sales.purchase_invoices
    WHERE technician_id = p_technician_id;

    IF v_invoice_count > 0 THEN
        RAISE EXCEPTION 'No se puede eliminar el t├®cnico porque tiene % factura(s) de compra asociada(s)', v_invoice_count;
    END IF;

    -- Delete the technician
    DELETE FROM internal.technicians WHERE id = p_technician_id;

    RETURN TRUE;
END;
$$;
ALTER FUNCTION "public"."delete_technician"("p_technician_id" "uuid") OWNER TO "postgres";
