--
-- Name: finance_cancel_invoice("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."finance_cancel_invoice"("p_invoice_id" "uuid", "p_reason" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT internal.is_admin() THEN
    RAISE EXCEPTION 'Only admin can cancel invoices';
  END IF;
  
  UPDATE finance.invoices
  SET 
    status = 'CANCELLED',
    internal_notes = COALESCE(internal_notes || E'\n', '') || 'Cancelada: ' || COALESCE(p_reason, 'Sin motivo especificado'),
    updated_at = now()
  WHERE id = p_invoice_id
    AND deleted_at IS NULL;
  
  RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."finance_cancel_invoice"("p_invoice_id" "uuid", "p_reason" "text") OWNER TO "postgres";
--
-- Name: finance_create_invoice("uuid", "uuid", "uuid", "text", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."finance_create_invoice"("p_client_id" "uuid", "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_source_quote_id" "uuid" DEFAULT NULL::"uuid", "p_project_name" "text" DEFAULT NULL::"text", "p_due_date" "date" DEFAULT NULL::"date") RETURNS TABLE("invoice_id" "uuid", "preliminary_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_invoice_id UUID;
  v_preliminary_number TEXT;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'User not authorized';
  END IF;
  
  INSERT INTO finance.invoices (
    client_id,
    project_id,
    source_quote_id,
    project_name,
    due_date,
    created_by
  )
  VALUES (
    p_client_id,
    p_project_id,
    p_source_quote_id,
    p_project_name,
    COALESCE(p_due_date, CURRENT_DATE + INTERVAL '30 days'),
    v_user_id
  )
  RETURNING id, finance.invoices.preliminary_number INTO v_invoice_id, v_preliminary_number;
  
  RETURN QUERY SELECT v_invoice_id, v_preliminary_number;
END;
$$;
ALTER FUNCTION "public"."finance_create_invoice"("p_client_id" "uuid", "p_project_id" "uuid", "p_source_quote_id" "uuid", "p_project_name" "text", "p_due_date" "date") OWNER TO "postgres";
--
-- Name: finance_create_rectificativa("uuid", "text", "text", "uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."finance_create_rectificativa"("p_original_invoice_id" "uuid", "p_rectification_type" "text", "p_rectification_reason" "text", "p_line_ids" "uuid"[] DEFAULT NULL::"uuid"[]) RETURNS TABLE("rectificativa_id" "uuid", "rectificativa_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'sales', 'accounting', 'internal', 'audit'
    AS $$
DECLARE
  v_user_id UUID;
  v_original RECORD;
  v_rect_id UUID;
  v_rect_number TEXT;
  v_year INTEGER;
  v_next_number INTEGER;
  v_line RECORD;
  v_subtotal NUMERIC := 0;
  v_tax_amount NUMERIC := 0;
  v_total NUMERIC := 0;
  v_je_id UUID;
  v_je_number TEXT;
  v_je_seq INTEGER;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;

  IF p_rectification_type NOT IN ('TOTAL', 'PARTIAL') THEN
    RAISE EXCEPTION 'rectification_type debe ser TOTAL o PARTIAL';
  END IF;

  IF p_rectification_reason IS NULL OR trim(p_rectification_reason) = '' THEN
    RAISE EXCEPTION 'El motivo de rectificaci├│n es obligatorio';
  END IF;

  SELECT inv.id, inv.status, inv.invoice_number, inv.client_id,
         inv.project_id, inv.subtotal, inv.tax_amount, inv.total,
         inv.paid_amount, inv.invoice_type, inv.rectified_by_invoice_id
  INTO v_original
  FROM sales.invoices inv
  WHERE inv.id = p_original_invoice_id;

  IF v_original.id IS NULL THEN
    RAISE EXCEPTION 'Factura original no encontrada';
  END IF;

  IF v_original.status NOT IN ('ISSUED', 'SENT', 'PAID', 'PARTIAL', 'OVERDUE') THEN
    RAISE EXCEPTION 'Solo se pueden rectificar facturas emitidas (estado actual: %)', v_original.status;
  END IF;

  IF v_original.invoice_type = 'RECTIFICATIVA' THEN
    RAISE EXCEPTION 'No se puede rectificar una factura rectificativa';
  END IF;

  IF v_original.rectified_by_invoice_id IS NOT NULL THEN
    RAISE EXCEPTION 'Esta factura ya ha sido rectificada';
  END IF;

  IF p_rectification_type = 'PARTIAL' AND (p_line_ids IS NULL OR array_length(p_line_ids, 1) = 0) THEN
    RAISE EXCEPTION 'Rectificaci├│n parcial requiere al menos una l├¡nea';
  END IF;

  -- Generate rectificativa number: R-YY-XXXXXX
  v_year := EXTRACT(YEAR FROM CURRENT_DATE)::INTEGER;
  
  INSERT INTO audit.sequence_counters (prefix, year, current_number, last_generated_at)
  VALUES ('RECT', v_year, 1, now())
  ON CONFLICT (prefix, year) DO UPDATE
  SET current_number = audit.sequence_counters.current_number + 1,
      last_generated_at = now()
  RETURNING current_number INTO v_next_number;

  v_rect_number := 'R-' || RIGHT(v_year::TEXT, 2) || '-' || LPAD(v_next_number::TEXT, 6, '0');

  -- Create rectificativa invoice header
  v_rect_id := gen_random_uuid();

  INSERT INTO sales.invoices (
    id, invoice_number, client_id, project_id,
    status, issue_date, due_date,
    subtotal, tax_amount, total, paid_amount, pending_amount,
    is_locked, locked_at,
    invoice_type, original_invoice_id, rectification_reason, rectification_type,
    is_number_definitive, number_assigned_at,
    created_by, created_at, updated_at
  ) VALUES (
    v_rect_id, v_rect_number, v_original.client_id, v_original.project_id,
    'ISSUED', CURRENT_DATE, CURRENT_DATE + INTERVAL '30 days',
    0, 0, 0, 0, 0,
    true, now(),
    'RECTIFICATIVA', p_original_invoice_id, trim(p_rectification_reason), p_rectification_type,
    true, now(),
    v_user_id, now(), now()
  );

  -- Copy lines (negative amounts)
  FOR v_line IN
    SELECT il.*
    FROM sales.invoice_lines il
    WHERE il.invoice_id = p_original_invoice_id
      AND (p_rectification_type = 'TOTAL' OR il.id = ANY(p_line_ids))
    ORDER BY il.line_order
  LOOP
    INSERT INTO sales.invoice_lines (
      id, invoice_id, concept, description,
      quantity, unit_price, tax_rate, discount_percent,
      line_order, created_at, updated_at
    ) VALUES (
      gen_random_uuid(), v_rect_id, v_line.concept, v_line.description,
      -1 * v_line.quantity, v_line.unit_price, v_line.tax_rate, v_line.discount_percent,
      v_line.line_order, now(), now()
    );

    -- Accumulate totals
    DECLARE
      line_base NUMERIC;
      line_tax NUMERIC;
    BEGIN
      line_base := v_line.quantity * v_line.unit_price * (1 - v_line.discount_percent / 100.0);
      line_tax := line_base * (v_line.tax_rate / 100.0);
      v_subtotal := v_subtotal + line_base;
      v_tax_amount := v_tax_amount + line_tax;
    END;
  END LOOP;

  v_total := v_subtotal + v_tax_amount;

  -- Update rectificativa totals (negative values)
  UPDATE sales.invoices
  SET subtotal = -1 * v_subtotal,
      tax_amount = -1 * v_tax_amount,
      total = -1 * v_total,
      pending_amount = -1 * v_total
  WHERE id = v_rect_id;

  -- Mark original as RECTIFIED
  UPDATE sales.invoices
  SET status = 'RECTIFIED',
      rectified_by_invoice_id = v_rect_id,
      updated_at = now()
  WHERE id = p_original_invoice_id;

  -- Create reversal journal entry if original had accounting entry
  -- Generate journal entry number
  INSERT INTO audit.sequence_counters (prefix, year, current_number, last_generated_at)
  VALUES ('JE', v_year, 1, now())
  ON CONFLICT (prefix, year) DO UPDATE
  SET current_number = audit.sequence_counters.current_number + 1,
      last_generated_at = now()
  RETURNING current_number INTO v_je_seq;

  v_je_number := 'AS-' || v_year || '-' || LPAD(v_je_seq::TEXT, 4, '0');
  v_je_id := gen_random_uuid();

  INSERT INTO accounting.journal_entries (
    id, entry_number, entry_date, entry_type, description,
    reference_id, reference_type, project_id,
    is_locked, locked_at, created_by, is_automatic
  ) VALUES (
    v_je_id, v_je_number, CURRENT_DATE, 'INVOICE_RECTIFICATION',
    'Rectificativa ' || v_rect_number || ' sobre ' || v_original.invoice_number,
    v_rect_id, 'RECTIFICATIVA', v_original.project_id,
    true, now(), v_user_id, true
  );

  -- Reversal entry lines: Debit 700x (reverse revenue), Credit 430 (reverse receivable)
  INSERT INTO accounting.journal_entry_lines (id, journal_entry_id, account_code, debit_credit, amount, third_party_id, third_party_type, description, line_order)
  VALUES
    (gen_random_uuid(), v_je_id, '7000', 'DEBIT', v_subtotal,
     v_original.client_id, 'CLIENT', 'Anulaci├│n ingreso por rectificativa', 1),
    (gen_random_uuid(), v_je_id, '4770', 'DEBIT', v_tax_amount,
     NULL, NULL, 'Anulaci├│n IVA repercutido', 2),
    (gen_random_uuid(), v_je_id, '4300', 'CREDIT', v_total,
     v_original.client_id, 'CLIENT', 'Anulaci├│n cuenta a cobrar', 3);

  -- If original was PAID: create refund journal entry (payment reversal)
  IF v_original.status = 'PAID' OR v_original.paid_amount > 0 THEN
    DECLARE
      v_refund_je_id UUID;
      v_refund_je_number TEXT;
      v_refund_seq INTEGER;
      v_refund_amount NUMERIC;
    BEGIN
      v_refund_amount := LEAST(v_original.paid_amount, v_total);

      INSERT INTO audit.sequence_counters (prefix, year, current_number, last_generated_at)
      VALUES ('JE', v_year, 1, now())
      ON CONFLICT (prefix, year) DO UPDATE
      SET current_number = audit.sequence_counters.current_number + 1,
          last_generated_at = now()
      RETURNING current_number INTO v_refund_seq;

      v_refund_je_number := 'A-' || v_year || '-' || LPAD(v_refund_seq::TEXT, 4, '0');
      v_refund_je_id := gen_random_uuid();

      INSERT INTO accounting.journal_entries (
        id, entry_number, entry_date, entry_type, description,
        reference_id, reference_type, project_id,
        is_locked, locked_at, created_by, is_automatic
      ) VALUES (
        v_refund_je_id, v_refund_je_number, CURRENT_DATE, 'REIMBURSEMENT',
        'Devoluci├│n por rectificativa ' || v_rect_number || ' (original: ' || v_original.invoice_number || ')',
        v_rect_id, 'RECTIFICATIVA', v_original.project_id,
        true, now(), v_user_id, true
      );

      -- Debit 4300 (client owes us less), Credit 572 (bank refund)
      INSERT INTO accounting.journal_entry_lines (id, journal_entry_id, account_code, debit_credit, amount, third_party_id, third_party_type, description, line_order)
      VALUES
        (gen_random_uuid(), v_refund_je_id, '4300', 'DEBIT', v_refund_amount,
         v_original.client_id, 'CLIENT', 'Reembolso al cliente', 1),
        (gen_random_uuid(), v_refund_je_id, '5720', 'CREDIT', v_refund_amount,
         NULL, NULL, 'Salida de banco por devoluci├│n', 2);
    END;
  END IF;

  RETURN QUERY SELECT v_rect_id, v_rect_number;
END;
$$;
ALTER FUNCTION "public"."finance_create_rectificativa"("p_original_invoice_id" "uuid", "p_rectification_type" "text", "p_rectification_reason" "text", "p_line_ids" "uuid"[]) OWNER TO "postgres";
