--
-- Name: finance_delete_payment("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."finance_delete_payment"("p_payment_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_payment RECORD;
BEGIN
  -- Validar usuario
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;
  
  -- Obtener datos del pago
  SELECT id, invoice_id, is_confirmed
  INTO v_payment
  FROM sales.invoice_payments
  WHERE id = p_payment_id;
  
  IF v_payment.id IS NULL THEN
    RETURN false;
  END IF;
  
  -- Solo permitir eliminar si est├í confirmado o es admin
  -- (Aqu├¡ se podr├¡a a├▒adir validaci├│n de rol admin si es necesario)
  
  -- Eliminar pago (el trigger recalcular├í autom├íticamente)
  DELETE FROM sales.invoice_payments
  WHERE id = p_payment_id;
  
  RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."finance_delete_payment"("p_payment_id" "uuid") OWNER TO "postgres";
