CREATE FUNCTION "public"."finance_get_client_payments"("p_client_id" "uuid") RETURNS TABLE("payment_id" "uuid", "invoice_id" "uuid", "invoice_number" "text", "payment_date" "date", "amount" numeric, "payment_method" "text", "total_invoice" numeric, "project_id" "uuid", "project_name" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    ip.id AS payment_id,
    i.id AS invoice_id,
    i.invoice_number,
    ip.payment_date,
    ip.amount,
    ip.payment_method,
    i.total AS total_invoice,
    i.project_id,
    i.project_name
  FROM sales.invoice_payments ip
  JOIN sales.invoices i ON i.id = ip.invoice_id
  WHERE i.client_id = p_client_id
    AND ip.is_confirmed = true
  ORDER BY ip.payment_date DESC;
END;
$$;
