-- Name: finance_get_invoice("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."finance_get_invoice"("p_invoice_id" "uuid") RETURNS TABLE("id" "uuid", "invoice_number" "text", "preliminary_number" "text", "client_id" "uuid", "client_name" "text", "project_id" "uuid", "project_name" "text", "project_number" "text", "source_quote_id" "uuid", "source_quote_number" "text", "status" "text", "issue_date" "date", "due_date" "date", "subtotal" numeric, "discount_amount" numeric, "tax_amount" numeric, "total" numeric, "paid_amount" numeric, "pending_amount" numeric, "notes" "text", "internal_notes" "text", "payment_terms" "text", "is_locked" boolean, "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "created_by" "uuid", "created_by_name" "text", "site_id" "uuid", "site_name" "text", "site_city" "text", "locked_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'sales', 'accounting', 'internal', 'crm', 'quotes'
    AS $$
BEGIN
  RETURN QUERY
  SELECT i.id, i.invoice_number, i.preliminary_number, i.client_id, c.company_name,
    i.project_id, i.project_name, COALESCE(pp.project_number, '')::TEXT, i.source_quote_id,
    COALESCE(sq.quote_number, '')::TEXT, i.status::TEXT, i.issue_date, i.due_date,
    i.subtotal, i.discount_amount, i.tax_amount, i.total, i.paid_amount, i.pending_amount,
    i.notes, i.internal_notes, i.payment_terms, i.is_locked, i.created_at, i.updated_at,
    i.created_by, COALESCE(au.full_name, '')::TEXT,
    i.site_id, ps.site_name, ps.city,
    i.locked_at
  FROM sales.invoices i
  LEFT JOIN crm.clients c ON c.id = i.client_id
  LEFT JOIN projects.projects pp ON pp.id = i.project_id
  LEFT JOIN quotes.quotes sq ON sq.id = i.source_quote_id
  LEFT JOIN internal.authorized_users au ON au.id = i.created_by
  LEFT JOIN projects.project_sites ps ON ps.id = i.site_id
  WHERE i.id = p_invoice_id;
END;
$$;
ALTER FUNCTION "public"."finance_get_invoice"("p_invoice_id" "uuid") OWNER TO "postgres";
--
-- Name: finance_get_invoice_lines("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."finance_get_invoice_lines"("p_invoice_id" "uuid") RETURNS TABLE("id" "uuid", "line_order" integer, "product_id" "uuid", "concept" "text", "description" "text", "quantity" numeric, "unit" "text", "unit_price" numeric, "discount_percent" numeric, "tax_rate" numeric, "subtotal" numeric, "tax_amount" numeric, "total" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_is_service_role BOOLEAN;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  v_is_service_role := COALESCE(current_setting('request.jwt.claim.role', true), '') = 'service_role';

  IF v_user_id IS NULL AND NOT v_is_service_role THEN
    RAISE EXCEPTION 'User not authorized';
  END IF;

  RETURN QUERY
  SELECT
    il.id,
    il.line_order,
    NULL::UUID AS product_id,
    il.concept,
    il.description,
    il.quantity,
    'ud'::TEXT AS unit,
    il.unit_price,
    COALESCE(il.discount_percent, 0) AS discount_percent,
    COALESCE(il.tax_rate, 0) AS tax_rate,
    il.quantity * il.unit_price * (1 - COALESCE(il.discount_percent, 0) / 100) AS subtotal,
    il.quantity * il.unit_price * (1 - COALESCE(il.discount_percent, 0) / 100) * (COALESCE(il.tax_rate, 0) / 100) AS tax_amount,
    il.quantity * il.unit_price * (1 - COALESCE(il.discount_percent, 0) / 100) * (1 + COALESCE(il.tax_rate, 0) / 100) AS total
  FROM sales.invoice_lines il
  WHERE il.invoice_id = p_invoice_id
  ORDER BY il.line_order;
END;
$$;
ALTER FUNCTION "public"."finance_get_invoice_lines"("p_invoice_id" "uuid") OWNER TO "postgres";
