CREATE FUNCTION "public"."finance_get_invoice_payments"("p_invoice_id" "uuid") RETURNS TABLE("id" "uuid", "amount" numeric, "payment_date" "date", "payment_method" "text", "bank_reference" "text", "notes" "text", "is_confirmed" boolean, "registered_by" "uuid", "registered_by_name" "text", "created_at" timestamp with time zone, "company_bank_account_id" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$

BEGIN

  RETURN QUERY

  SELECT 

    ip.id,

    ip.amount,

    ip.payment_date,

    ip.payment_method,

    ip.bank_reference,

    ip.notes,

    ip.is_confirmed,

    ip.registered_by,

    au.full_name AS registered_by_name,

    ip.created_at,

    ip.company_bank_account_id

  FROM sales.invoice_payments ip

  LEFT JOIN internal.authorized_users au ON au.id = ip.registered_by

