--
-- Name: finance_get_tax_summary(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."finance_get_tax_summary"("p_fiscal_year" integer DEFAULT NULL::integer, "p_fiscal_quarter" integer DEFAULT NULL::integer) RETURNS TABLE("tax_code" "text", "tax_type" "text", "tax_rate" numeric, "total_base" numeric, "total_tax" numeric, "transaction_count" bigint, "fiscal_period" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_year INTEGER;
BEGIN
  IF internal.get_authorized_user_id(auth.uid()) IS NULL THEN
    RAISE EXCEPTION 'User not authorized';
  END IF;
  
  v_year := COALESCE(p_fiscal_year, EXTRACT(YEAR FROM CURRENT_DATE)::INTEGER);
  
  RETURN QUERY
  SELECT 
    ts.tax_code,
    ts.tax_type,
    ts.tax_rate,
    SUM(ts.tax_base) AS total_base,
    SUM(ts.tax_amount) AS total_tax,
    COUNT(*) AS transaction_count,
    CASE 
      WHEN p_fiscal_quarter IS NOT NULL THEN 
        v_year::TEXT || ' - Q' || p_fiscal_quarter::TEXT
      ELSE 
        v_year::TEXT
    END AS fiscal_period
  FROM finance.tax_summary ts
  WHERE ts.fiscal_year = v_year
    AND (p_fiscal_quarter IS NULL OR ts.fiscal_quarter = p_fiscal_quarter)
  GROUP BY ts.tax_code, ts.tax_type, ts.tax_rate, v_year, p_fiscal_quarter
  ORDER BY ts.tax_type, ts.tax_code;
END;
$$;
ALTER FUNCTION "public"."finance_get_tax_summary"("p_fiscal_year" integer, "p_fiscal_quarter" integer) OWNER TO "postgres";
--
-- Name: finance_issue_invoice("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."finance_issue_invoice"("p_invoice_id" "uuid") RETURNS TABLE("invoice_number" "text", "issue_date" "date")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'sales', 'accounting', 'internal', 'audit'
    AS $$
DECLARE
  v_invoice RECORD;
  v_user_id UUID;
  v_year INTEGER;
  v_next_number INTEGER;
  v_invoice_number TEXT;
  v_current_invoice_number TEXT;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;
  
  SELECT 
    inv.id, 
    inv.status, 
    inv.invoice_number, 
    inv.issue_date,
    inv.preliminary_number
  INTO v_invoice
  FROM sales.invoices inv
  WHERE inv.id = p_invoice_id;
  
  IF v_invoice.id IS NULL THEN
    RAISE EXCEPTION 'Factura no encontrada';
  END IF;
  
  IF v_invoice.status != 'DRAFT' THEN
    RAISE EXCEPTION 'Solo se pueden emitir facturas en estado DRAFT';
  END IF;
  
  v_current_invoice_number := v_invoice.invoice_number;
  
  IF v_current_invoice_number IS NULL OR v_current_invoice_number = '' OR v_current_invoice_number LIKE '%BORR%' THEN
    v_year := EXTRACT(YEAR FROM CURRENT_DATE)::INTEGER;
    
    INSERT INTO audit.sequence_counters (prefix, year, current_number, last_generated_at)
    VALUES ('INV', v_year, 1, now())
    ON CONFLICT (prefix, year) DO UPDATE
    SET current_number = audit.sequence_counters.current_number + 1,
        last_generated_at = now()
    RETURNING current_number INTO v_next_number;
    
    v_invoice_number := 'F-' || RIGHT(v_year::TEXT, 2) || '-' || LPAD(v_next_number::TEXT, 6, '0');
  ELSE
    v_invoice_number := v_current_invoice_number;
  END IF;
  
  UPDATE sales.invoices inv
  SET
    preliminary_number = CASE 
      WHEN inv.preliminary_number IS NULL THEN v_current_invoice_number 
      ELSE inv.preliminary_number 
    END,
    invoice_number = v_invoice_number,
    issue_date = CURRENT_DATE,
    due_date = CURRENT_DATE + INTERVAL '30 days',
    status = 'ISSUED',
    is_locked = true,
    locked_at = now(),
    is_number_definitive = true,
    number_assigned_at = now(),
    updated_at = now()
  WHERE inv.id = p_invoice_id;
  
  RETURN QUERY
  SELECT 
    v_invoice_number,
    CURRENT_DATE;
END;
$$;
ALTER FUNCTION "public"."finance_issue_invoice"("p_invoice_id" "uuid") OWNER TO "postgres";
--
-- Name: finance_list_invoices("text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."finance_list_invoices"("p_search" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "invoice_number" "text", "preliminary_number" "text", "source_quote_id" "uuid", "source_quote_number" "text", "source_quote_order_number" "text", "client_id" "uuid", "client_name" "text", "project_id" "uuid", "project_number" "text", "project_name" "text", "client_order_number" "text", "status" "text", "issue_date" "date", "due_date" "date", "subtotal" numeric, "tax_amount" numeric, "total" numeric, "paid_amount" numeric, "pending_amount" numeric, "is_locked" boolean, "created_by" "uuid", "created_by_name" "text", "created_at" timestamp with time zone, "payment_bank_name" "text", "payment_bank_id" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    i.id,
    i.invoice_number,
    i.preliminary_number,
    i.source_quote_id,
    q.quote_number AS source_quote_number,
    q.order_number AS source_quote_order_number,
    i.client_id,
    c.company_name AS client_name,
    i.project_id,
    p.project_number,
    COALESCE(p.project_name, i.project_name) AS project_name,
    COALESCE(p.client_order_number, i.order_number) AS client_order_number,
    i.status,
    i.issue_date,
    i.due_date,
    COALESCE(i.subtotal, 0) AS subtotal,
    COALESCE(i.tax_amount, 0) AS tax_amount,
    COALESCE(i.total, 0) AS total,
    COALESCE(i.paid_amount, 0) AS paid_amount,
    COALESCE(i.pending_amount, 0) AS pending_amount,
    COALESCE(i.is_locked, false) AS is_locked,
    i.created_by,
    au.full_name AS created_by_name,
    i.created_at,
    -- Obtener el nombre del banco del ├║ltimo pago confirmado
    (
      SELECT ba.bank_name
      FROM (
        SELECT 
          ip.company_bank_account_id,
          ip.payment_date,
          (SELECT bank_acc->>'bank' 
           FROM internal.company_preferences cp,
                jsonb_array_elements(cp.bank_accounts) AS bank_acc
           WHERE bank_acc->>'id' = ip.company_bank_account_id
           LIMIT 1
          ) AS bank_name
        FROM sales.invoice_payments ip
        WHERE ip.invoice_id = i.id
          AND ip.is_confirmed = true
          AND ip.company_bank_account_id IS NOT NULL
        ORDER BY ip.payment_date DESC, ip.created_at DESC
        LIMIT 1
      ) ba
    ) AS payment_bank_name,
    -- Obtener el ID del banco del ├║ltimo pago confirmado
    (
      SELECT ip.company_bank_account_id
      FROM sales.invoice_payments ip
      WHERE ip.invoice_id = i.id
        AND ip.is_confirmed = true
        AND ip.company_bank_account_id IS NOT NULL
      ORDER BY ip.payment_date DESC, ip.created_at DESC
      LIMIT 1
    ) AS payment_bank_id
  FROM sales.invoices i
  LEFT JOIN crm.clients c ON c.id = i.client_id
  LEFT JOIN projects.projects p ON p.id = i.project_id
  LEFT JOIN quotes.quotes q ON q.id = i.source_quote_id
  LEFT JOIN internal.authorized_users au ON au.id = i.created_by
  WHERE 
    (p_status IS NULL OR i.status = p_status)
    AND (
      p_search IS NULL 
      OR i.invoice_number ILIKE '%' || p_search || '%'
      OR i.preliminary_number ILIKE '%' || p_search || '%'
      OR c.company_name ILIKE '%' || p_search || '%'
      OR COALESCE(p.project_name, i.project_name) ILIKE '%' || p_search || '%'
      OR p.project_number ILIKE '%' || p_search || '%'
    )
  ORDER BY i.created_at DESC;
END;
$$;
ALTER FUNCTION "public"."finance_list_invoices"("p_search" "text", "p_status" "text") OWNER TO "postgres";
--
-- Name: finance_register_payment("uuid", numeric, "date", "text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."finance_register_payment"("p_invoice_id" "uuid", "p_amount" numeric, "p_payment_date" "date", "p_payment_method" "text", "p_bank_reference" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text", "p_company_bank_account_id" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_invoice RECORD;
  v_user_id UUID;
  v_payment_id UUID;
  v_current_total_paid NUMERIC(12,2);
  v_entry_id UUID;
BEGIN
  -- Validar usuario
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;
  
  -- Validar amount
  IF p_amount <= 0 THEN
    RAISE EXCEPTION 'El importe del pago debe ser mayor que 0';
  END IF;
  
  -- Obtener datos de la factura
  SELECT id, total, paid_amount, status, is_locked, issue_date
  INTO v_invoice
  FROM sales.invoices
  WHERE id = p_invoice_id;
  
  IF v_invoice.id IS NULL THEN
    RAISE EXCEPTION 'Factura no encontrada';
  END IF;
  
  -- Validar estado de factura
  IF v_invoice.status NOT IN ('ISSUED', 'PARTIAL', 'OVERDUE') THEN
    RAISE EXCEPTION 'Solo se pueden registrar pagos en facturas emitidas, parcialmente pagadas o vencidas';
  END IF;
  
  -- Calcular total actual de pagos
  SELECT COALESCE(SUM(amount), 0)
  INTO v_current_total_paid
  FROM sales.invoice_payments
  WHERE invoice_id = p_invoice_id
    AND is_confirmed = true;
  
  -- Validar que no exceda el total
  IF (v_current_total_paid + p_amount) > (COALESCE(v_invoice.total, 0) + 0.01) THEN
    RAISE EXCEPTION 'El importe del pago excede el saldo pendiente de la factura';
  END IF;
  
  -- Insertar pago
  INSERT INTO sales.invoice_payments (
    invoice_id,
    amount,
    payment_date,
    payment_method,
    bank_reference,
    notes,
    registered_by,
    company_bank_account_id
  )
  VALUES (
    p_invoice_id,
    p_amount,
    p_payment_date,
    p_payment_method,
    p_bank_reference,
    p_notes,
    v_user_id,
    p_company_bank_account_id
  )
  RETURNING id INTO v_payment_id;
  
  -- Generar asiento contable autom├íticamente si la factura es del 2026 o posterior
  IF v_invoice.issue_date >= '2026-01-01' AND p_payment_date >= '2026-01-01' THEN
    BEGIN
      -- Deshabilitar temporalmente el trigger de rec├ílculo de IS para evitar loops
      ALTER TABLE accounting.journal_entry_lines DISABLE TRIGGER trigger_auto_recalculate_corporate_tax;
      
      -- Crear asiento contable
      v_entry_id := accounting.create_invoice_payment_entry(
        v_payment_id,
        p_payment_date
      );
      
      -- Rehabilitar el trigger
      ALTER TABLE accounting.journal_entry_lines ENABLE TRIGGER trigger_auto_recalculate_corporate_tax;
      
    EXCEPTION WHEN OTHERS THEN
      -- Asegurar que el trigger se rehabilite incluso si hay error
      ALTER TABLE accounting.journal_entry_lines ENABLE TRIGGER trigger_auto_recalculate_corporate_tax;
      -- No fallar el registro del pago si falla la contabilizaci├│n
      -- Solo registrar en logs (podr├¡as usar RAISE WARNING en producci├│n)
      RAISE WARNING 'Error al generar asiento contable para pago %: %', v_payment_id, SQLERRM;
    END;
  END IF;
  
  RETURN v_payment_id;
END;
$$;
ALTER FUNCTION "public"."finance_register_payment"("p_invoice_id" "uuid", "p_amount" numeric, "p_payment_date" "date", "p_payment_method" "text", "p_bank_reference" "text", "p_notes" "text", "p_company_bank_account_id" "text") OWNER TO "postgres";
--
-- Name: FUNCTION "finance_register_payment"("p_invoice_id" "uuid", "p_amount" numeric, "p_payment_date" "date", "p_payment_method" "text", "p_bank_reference" "text", "p_notes" "text", "p_company_bank_account_id" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."finance_register_payment"("p_invoice_id" "uuid", "p_amount" numeric, "p_payment_date" "date", "p_payment_method" "text", "p_bank_reference" "text", "p_notes" "text", "p_company_bank_account_id" "text") IS 'Registra un pago de cliente y genera autom├íticamente el asiento contable si la factura y el pago son del 2026 o posterior.';
--
-- Name: finance_update_invoice("uuid", "uuid", "uuid", "text", "date", "text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."finance_update_invoice"("p_invoice_id" "uuid", "p_client_id" "uuid" DEFAULT NULL::"uuid", "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_project_name" "text" DEFAULT NULL::"text", "p_due_date" "date" DEFAULT NULL::"date", "p_notes" "text" DEFAULT NULL::"text", "p_internal_notes" "text" DEFAULT NULL::"text", "p_payment_terms" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_invoice RECORD;
  v_user_id UUID;
  v_has_payments BOOLEAN;
BEGIN
  -- Validar usuario
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;
  
  -- Obtener datos de la factura
  SELECT id, is_locked, status, client_id, project_id
  INTO v_invoice
  FROM sales.invoices
  WHERE id = p_invoice_id;
  
  IF v_invoice.id IS NULL THEN
    RETURN false;
  END IF;
  
  -- Validar que no est├® bloqueada (excepto para cambiar status a CANCELLED)
  IF v_invoice.is_locked = true AND (p_status IS NULL OR p_status != 'CANCELLED') THEN
    RAISE EXCEPTION 'No se puede editar una factura bloqueada';
  END IF;
  
  -- Verificar si hay pagos registrados
  SELECT EXISTS(SELECT 1 FROM sales.invoice_payments WHERE invoice_id = p_invoice_id)
  INTO v_has_payments;
  
  -- No permitir cambiar cliente o proyecto si hay pagos
  IF v_has_payments THEN
    IF (p_client_id IS NOT NULL AND p_client_id != v_invoice.client_id) OR
       (p_project_id IS NOT NULL AND p_project_id != v_invoice.project_id) THEN
      RAISE EXCEPTION 'No se puede modificar el cliente o proyecto de una factura con pagos registrados';
    END IF;
  END IF;
  
  -- Actualizar factura
  UPDATE sales.invoices
  SET
    client_id = COALESCE(p_client_id, client_id),
    project_id = COALESCE(p_project_id, project_id),
    project_name = COALESCE(p_project_name, project_name),
    due_date = COALESCE(p_due_date, due_date),
    notes = COALESCE(p_notes, notes),
    internal_notes = COALESCE(p_internal_notes, internal_notes),
    payment_terms = COALESCE(p_payment_terms, payment_terms),
    status = COALESCE(p_status, status),
    updated_at = now()
  WHERE id = p_invoice_id;
  
  RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."finance_update_invoice"("p_invoice_id" "uuid", "p_client_id" "uuid", "p_project_id" "uuid", "p_project_name" "text", "p_due_date" "date", "p_notes" "text", "p_internal_notes" "text", "p_payment_terms" "text", "p_status" "text") OWNER TO "postgres";
