--
-- Name: finance_update_payment("uuid", numeric, "date", "text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."finance_update_payment"("p_payment_id" "uuid", "p_amount" numeric DEFAULT NULL::numeric, "p_payment_date" "date" DEFAULT NULL::"date", "p_payment_method" "text" DEFAULT NULL::"text", "p_bank_reference" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text", "p_company_bank_account_id" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$

DECLARE

  v_user_id UUID;

  v_payment RECORD;

  v_invoice RECORD;

  v_new_total_paid NUMERIC(12,2);

BEGIN

  -- Validar usuario

  v_user_id := internal.get_authorized_user_id(auth.uid());

  IF v_user_id IS NULL THEN

    RAISE EXCEPTION 'Usuario no autorizado';

  END IF;

  

  -- Obtener datos del pago actual

  SELECT * INTO v_payment

  FROM sales.invoice_payments

  WHERE id = p_payment_id;

  

  IF v_payment.id IS NULL THEN

    RETURN false;

  END IF;

  

  -- Obtener total de la factura

  SELECT total FROM sales.invoices WHERE id = v_payment.invoice_id INTO v_invoice;

  

  -- Si se cambia el importe, validar que el nuevo total no exceda el de la factura

  IF p_amount IS NOT NULL AND p_amount != v_payment.amount THEN

    SELECT COALESCE(SUM(amount), 0) - v_payment.amount + p_amount

    INTO v_new_total_paid

    FROM sales.invoice_payments

    WHERE invoice_id = v_payment.invoice_id

      AND is_confirmed = true;

      

    IF v_new_total_paid > (v_invoice.total + 0.01) THEN

      RAISE EXCEPTION 'El nuevo importe total de pagos excede el total de la factura';

    END IF;

  END IF;

  

  -- Actualizar registro

  UPDATE sales.invoice_payments

  SET

    amount = COALESCE(p_amount, amount),

    payment_date = COALESCE(p_payment_date, payment_date),

    payment_method = COALESCE(p_payment_method, payment_method),

    bank_reference = COALESCE(p_bank_reference, bank_reference),

    notes = COALESCE(p_notes, notes),

    company_bank_account_id = COALESCE(p_company_bank_account_id, company_bank_account_id),

    updated_at = now()

  WHERE id = p_payment_id;

  

  -- El trigger de la tabla se encargar├í de recalcular el status de la factura

  

  RETURN FOUND;

END;

$$;
ALTER FUNCTION "public"."finance_update_payment"("p_payment_id" "uuid", "p_amount" numeric, "p_payment_date" "date", "p_payment_method" "text", "p_bank_reference" "text", "p_notes" "text", "p_company_bank_account_id" "text") OWNER TO "postgres";
--
-- Name: fix_purchase_payments_bank_to_caixabank("text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."fix_purchase_payments_bank_to_caixabank"("p_revolut_bank_id" "text", "p_caixabank_bank_id" "text") RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_updated INTEGER;
BEGIN
  IF p_revolut_bank_id IS NULL OR p_caixabank_bank_id IS NULL THEN
    RAISE EXCEPTION 'Se requieren ambos par├ímetros: p_revolut_bank_id y p_caixabank_bank_id';
  END IF;

  IF p_revolut_bank_id = p_caixabank_bank_id THEN
    RAISE EXCEPTION 'Los IDs de Revolut y CaixaBank deben ser diferentes';
  END IF;

  UPDATE sales.purchase_invoice_payments
  SET company_bank_account_id = p_caixabank_bank_id
  WHERE company_bank_account_id = p_revolut_bank_id;

  GET DIAGNOSTICS v_updated = ROW_COUNT;

  RETURN v_updated;
END;
$$;
ALTER FUNCTION "public"."fix_purchase_payments_bank_to_caixabank"("p_revolut_bank_id" "text", "p_caixabank_bank_id" "text") OWNER TO "postgres";
--
-- Name: FUNCTION "fix_purchase_payments_bank_to_caixabank"("p_revolut_bank_id" "text", "p_caixabank_bank_id" "text"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."fix_purchase_payments_bank_to_caixabank"("p_revolut_bank_id" "text", "p_caixabank_bank_id" "text") IS 'Reasigna pagos de compras de Revolut a CaixaBank. Revolut debe usarse solo para n├│minas. Ejecutar desde SQL Editor con los IDs de Ajustes > Preferencias.';
