CREATE FUNCTION "public"."generate_internal_purchase_number"("p_document_type" "text" DEFAULT NULL::"text", "p_supplier_id" "uuid" DEFAULT NULL::"uuid", "p_technician_id" "uuid" DEFAULT NULL::"uuid") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_year TEXT;
  v_next INTEGER;
BEGIN
  v_year := to_char(CURRENT_DATE, 'YY');
  v_next := nextval('sales.purchase_invoice_definitive_seq');
  RETURN 'C-' || v_year || '-' || lpad(v_next::TEXT, 6, '0');
END;
$$;
