    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_account_code TEXT;
BEGIN
  -- Buscar en chart_of_accounts donde la descripci├│n contiene el ID del banco
  SELECT account_code INTO v_account_code
  FROM accounting.chart_of_accounts
  WHERE account_code LIKE '572%'
    AND description LIKE '%[ID:' || p_bank_account_id::TEXT || ']%'
  LIMIT 1;
  
  RETURN v_account_code;
END;
$$;
