--

CREATE FUNCTION "public"."get_canvassing_location"("p_location_id" "uuid") RETURNS TABLE("id" "uuid", "status" "text", "address" "text", "city" "text", "province" "text", "postal_code" "text", "country" "text", "latitude" numeric, "longitude" numeric, "location_references" "text", "company_name" "text", "business_type" "text", "business_size_sqm" numeric, "business_floors" integer, "business_hours" "text", "years_in_operation" integer, "contact_first_name" "text", "contact_last_name" "text", "contact_position" "text", "contact_phone_primary" "text", "contact_phone_secondary" "text", "contact_email_primary" "text", "preferred_contact_method" "text", "best_contact_time" "text", "is_decision_maker" boolean, "secondary_contact_name" "text", "secondary_contact_phone" "text", "priority" "text", "lead_score" integer, "lead_source" "text", "assigned_to" "uuid", "team_id" "uuid", "av_solutions_required" "text"[], "solution_details" "text", "number_of_screens" integer, "equipment_locations" "text", "estimated_budget_range" "text", "project_urgency" "text", "has_current_av_installation" boolean, "current_provider" "text", "installation_age_years" integer, "current_installation_problems" "text", "has_maintenance_contract" boolean, "maintenance_contract_provider" "text", "maintenance_contract_end_date" "date", "has_requested_competitor_quotes" boolean, "competitors_contacted" "text", "interest_level" integer, "purchase_phase" "text", "main_objections" "text"[], "objections_other" "text", "economic_decision_maker_identified" boolean, "approval_process" "text", "appointment_date" "date", "appointment_time" time without time zone, "appointment_type" "text", "appointment_location" "text", "callback_date" "date", "callback_time" time without time zone, "reminder_enabled" boolean, "reminder_time_before" "text", "photos" "text"[], "videos" "text"[], "documents" "text"[], "technical_service_type" "text", "maintenance_frequency" "text", "proposed_maintenance_contract" boolean, "maintenance_contract_value" numeric, "existing_equipment" "text", "has_active_warranties" boolean, "warranty_end_date" "date", "local_access_info" "text", "tags" "text"[], "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "status_history" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$

DECLARE

  v_user_id UUID;

BEGIN

  v_user_id := internal.get_authorized_user_id(auth.uid());

  

  -- Verificar permisos: solo el creador o admin/manager

  IF NOT EXISTS (

    SELECT 1 FROM crm.location loc

    WHERE loc.id = p_location_id 

    AND (loc.created_by = v_user_id OR internal.is_admin() OR internal.is_manager())

  ) THEN

    RAISE EXCEPTION 'No tienes permiso para ver este punto de Canvassing';

  END IF;

  

  RETURN QUERY

  SELECT 

    l.id,

    l.status::TEXT,

    -- A. Ubicaci├│n

    l.address,

    l.city,

    l.province,

    l.postal_code,

    l.country,

    l.latitude,

    l.longitude,

    l.location_references,

    -- B. Negocio

    l.company_name,

    l.business_type::TEXT,

    l.business_size_sqm,

    l.business_floors,

    l.business_hours,

    l.years_in_operation,

    -- C. Contacto

    l.contact_first_name,

    l.contact_last_name,

    l.contact_position,

    l.contact_phone_primary,

    l.contact_phone_secondary,

    l.contact_email_primary,

    l.preferred_contact_method::TEXT,

    l.best_contact_time::TEXT,

    l.is_decision_maker,

    l.secondary_contact_name,

    l.secondary_contact_phone,

    -- D. Estado

    l.priority::TEXT,

    l.lead_score,

    l.lead_source,

    l.assigned_to,

    l.team_id,

    -- E. Soluciones AV

    l.av_solutions_required::TEXT[],

    l.solution_details,

    l.number_of_screens,

    l.equipment_locations,

    l.estimated_budget_range,

    l.project_urgency,

    -- F. Situaci├│n Actual

    l.has_current_av_installation,

    l.current_provider,

    l.installation_age_years,

    l.current_installation_problems,

    l.has_maintenance_contract,

    l.maintenance_contract_provider,

    l.maintenance_contract_end_date,

    l.has_requested_competitor_quotes,

    l.competitors_contacted,

    -- G. Comercial

    l.interest_level,

    l.purchase_phase::TEXT,

    l.main_objections::TEXT[],

    l.objections_other,

    l.economic_decision_maker_identified,

    l.approval_process,

    -- H. Citas

    l.appointment_date,

    l.appointment_time,

    l.appointment_type::TEXT,

    l.appointment_location,

    l.callback_date,

    l.callback_time,

    l.reminder_enabled,

    l.reminder_time_before,

    -- I. Archivos

    l.photos,

    l.videos,

    l.documents,

    -- J. T├®cnico

    l.technical_service_type::TEXT,

    l.maintenance_frequency::TEXT,

    l.proposed_maintenance_contract,

    l.maintenance_contract_value,

    l.existing_equipment,

    l.has_active_warranties,

    l.warranty_end_date,

    l.local_access_info,

    -- K. Tags

    l.tags,

    -- Tracking

    l.created_at,

    l.updated_at,

    l.status_history

  FROM crm.location l

  WHERE l.id = p_location_id;

END;

$$;
ALTER FUNCTION "public"."get_canvassing_location"("p_location_id" "uuid") OWNER TO "postgres";
--
-- Name: get_catalog_explorer_tree(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_catalog_explorer_tree"() RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'catalog'
    AS $$
DECLARE
  v_categories JSON;
  v_products JSON;
  v_image_counts JSON;
BEGIN
  -- Categories hierarchy
  SELECT COALESCE(json_agg(row_to_json(c)), '[]'::json)
  INTO v_categories
  FROM (
    SELECT id, name, slug, parent_id, domain::text, sort_order
    FROM catalog.categories
    WHERE is_active = true
    ORDER BY sort_order, name
  ) c;

  -- Products (active only)
  SELECT COALESCE(json_agg(row_to_json(p)), '[]'::json)
  INTO v_products
  FROM (
    SELECT id, sku, name, product_type::text, category_id
    FROM catalog.products
    WHERE is_active = true
    ORDER BY sku
  ) p;

  -- Image counts per product from minio_files
  SELECT COALESCE(json_object_agg(source_id, cnt), '{}'::json)
  INTO v_image_counts
  FROM (
    SELECT source_id, COUNT(*)::int AS cnt
    FROM public.minio_files
    WHERE source_table = 'catalog.products'
      AND deleted_at IS NULL
    GROUP BY source_id
  ) ic;

  RETURN json_build_object(
    'categories', v_categories,
    'products', v_products,
    'image_counts', v_image_counts
  );
END;
$$;
ALTER FUNCTION "public"."get_catalog_explorer_tree"() OWNER TO "postgres";
--
-- Name: get_catalog_product_detail("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_catalog_product_detail"("p_product_id" "uuid") RETURNS TABLE("id" "uuid", "sku" "text", "name" "text", "description" "text", "product_type" "catalog"."product_type", "category_id" "uuid", "category_name" "text", "supplier_id" "uuid", "supplier_name" "text", "unit" "catalog"."unit_type", "cost_price" numeric, "sale_price" numeric, "discount_percent" numeric, "sale_price_effective" numeric, "tax_rate_id" "uuid", "tax_rate" numeric, "margin_percentage" numeric, "margin_amount" numeric, "track_stock" boolean, "stock_quantity" numeric, "min_stock_alert" numeric, "is_active" boolean, "has_low_stock_alert" boolean, "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF auth.uid() IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF;
  RETURN QUERY
  SELECT
    p.id,
    p.sku,
    p.name,
    p.description,
    p.product_type,
    p.category_id,
    c.name::TEXT AS category_name,
    p.supplier_id,
    s.company_name::TEXT AS supplier_name,
    p.unit,
    p.cost_price,
    p.sale_price,
    p.discount_percent,
    (p.sale_price * (1 - COALESCE(p.discount_percent, 0) / 100))::NUMERIC AS sale_price_effective,
    p.tax_rate_id,
    (SELECT tr.rate FROM catalog.tax_rates tr WHERE tr.id = p.tax_rate_id)::NUMERIC AS tax_rate,
    p.margin_percentage,
    (p.sale_price * (1 - COALESCE(p.discount_percent, 0) / 100) - COALESCE(p.cost_price, 0))::NUMERIC AS margin_amount,
    p.track_stock,
    COALESCE(p.stock_quantity, 0)::NUMERIC(12,3),
    p.min_stock_alert::NUMERIC(12,3),
    p.is_active,
    EXISTS (SELECT 1 FROM catalog.stock_alerts sa WHERE sa.product_id = p.id AND sa.status = 'open') AS has_low_stock_alert,
    p.created_at,
    p.updated_at
  FROM catalog.products p
  LEFT JOIN catalog.categories c ON c.id = p.category_id
  LEFT JOIN internal.suppliers s ON s.id = p.supplier_id
  WHERE p.id = p_product_id;
END;
$$;
ALTER FUNCTION "public"."get_catalog_product_detail"("p_product_id" "uuid") OWNER TO "postgres";
--
-- Name: get_catalog_product_storage_path("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_catalog_product_storage_path"("p_product_id" "uuid") RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'catalog'
    AS $$
DECLARE
  v_product RECORD;
  v_slugs TEXT[] := ARRAY[]::TEXT[];
BEGIN
  SELECT p.id, p.sku, p.name, p.product_type, p.category_id
  INTO v_product
  FROM catalog.products p
  WHERE p.id = p_product_id AND p.is_active;

  IF NOT FOUND THEN
    RETURN json_build_object('ok', false, 'error', 'Product not found');
  END IF;

  IF v_product.category_id IS NOT NULL THEN
    WITH RECURSIVE cat_chain AS (
      SELECT id, slug, parent_id, 1 AS depth
      FROM catalog.categories WHERE id = v_product.category_id
      UNION ALL
      SELECT c.id, c.slug, c.parent_id, cc.depth + 1
      FROM catalog.categories c
      JOIN cat_chain cc ON cc.parent_id = c.id
    )
    SELECT array_agg(slug ORDER BY depth DESC) INTO v_slugs FROM cat_chain;
  END IF;

  RETURN json_build_object(
    'ok', true,
    'sku', v_product.sku,
    'name', v_product.name,
    'product_type', v_product.product_type,
    'category_slugs', COALESCE(v_slugs, ARRAY[]::TEXT[])
  );
END;
$$;
ALTER FUNCTION "public"."get_catalog_product_storage_path"("p_product_id" "uuid") OWNER TO "postgres";
