CREATE FUNCTION "public"."get_client"("p_client_id" "uuid") RETURNS TABLE("id" "uuid", "client_number" "text", "company_name" "text", "contact_email" "text", "contact_phone" "text", "tax_id" "text", "legal_name" "text", "billing_address" "text", "billing_city" "text", "billing_province" "text", "billing_postal_code" "text", "billing_country" "text", "website" "text", "instagram_handle" "text", "tiktok_handle" "text", "linkedin_url" "text", "number_of_locations" integer, "industry_sector" "text", "approximate_budget" numeric, "urgency" "text", "target_objectives" "text"[], "lead_stage" "text", "lead_source" "text", "assigned_to" "uuid", "next_follow_up_date" "date", "estimated_close_date" "date", "lost_reason" "text", "notes" "text", "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    c.id,
    c.client_number,
    c.company_name,
    c.contact_email,
    c.contact_phone,
    c.tax_id,
    c.legal_name,
    c.billing_address,
    c.billing_city,
    c.billing_province,
    c.billing_postal_code,
    c.billing_country,
    c.website,
    c.instagram_handle,
    c.tiktok_handle,
    c.linkedin_url,
    c.number_of_locations,
    c.industry_sector::text,  -- Cast enum to text
    c.approximate_budget,
    c.urgency::text,          -- Cast enum to text
    c.target_objectives,
    c.lead_stage::text,       -- Cast enum to text
    c.lead_source::text,      -- Cast enum to text
    c.assigned_to,
    c.next_follow_up_date,
    c.estimated_close_date,
    c.lost_reason,
    c.notes,
    c.created_at,
    c.updated_at
  FROM crm.clients c
  WHERE c.id = p_client_id
    AND c.deleted_at IS NULL;
END;
$$;
ALTER FUNCTION "public"."get_client"("p_client_id" "uuid") OWNER TO "postgres";
--
-- Name: get_client_balances("date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_client_balances"("p_as_of_date" "date" DEFAULT CURRENT_DATE) RETURNS TABLE("client_id" "text", "client_number" "text", "client_name" "text", "debit_balance" numeric, "credit_balance" numeric, "net_balance" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    c.id::TEXT,
    c.client_number,
    c.company_name,
    COALESCE(SUM(CASE WHEN jel.debit_credit = 'DEBIT' THEN jel.amount ELSE 0 END), 0) as debit_balance,
    COALESCE(SUM(CASE WHEN jel.debit_credit = 'CREDIT' THEN jel.amount ELSE 0 END), 0) as credit_balance,
    COALESCE(SUM(CASE WHEN jel.debit_credit = 'DEBIT' THEN jel.amount ELSE -jel.amount END), 0) as net_balance
  FROM crm.clients c
  LEFT JOIN accounting.journal_entry_lines jel ON jel.third_party_id = c.id
    AND jel.third_party_type = 'CLIENT'
    AND jel.account_code = '430000'
  LEFT JOIN accounting.journal_entries je ON jel.journal_entry_id = je.id
    AND je.entry_date <= p_as_of_date
  WHERE c.deleted_at IS NULL
  GROUP BY c.id, c.client_number, c.company_name
  HAVING COALESCE(SUM(CASE WHEN jel.debit_credit = 'DEBIT' THEN jel.amount ELSE -jel.amount END), 0) != 0
  ORDER BY net_balance DESC;
END;
$$;
ALTER FUNCTION "public"."get_client_balances"("p_as_of_date" "date") OWNER TO "postgres";
