CREATE FUNCTION "public"."get_company_settings"() RETURNS TABLE("id" "uuid", "legal_name" "text", "tax_id" "text", "commercial_name" "text", "company_type" "text", "vat_number" "text", "fiscal_address" "text", "fiscal_postal_code" "text", "fiscal_city" "text", "fiscal_province" "text", "country" "text", "billing_email" "text", "billing_phone" "text", "website" "text", "logo_url" "text", "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
