-- Name: get_current_user_info(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_current_user_info"() RETURNS TABLE("user_id" "uuid", "email" "text", "full_name" "text", "department" "internal"."department_type", "roles" "text"[], "phone" "text", "job_position" "text", "theme_preference" "text", "last_otp_verified_at" timestamp with time zone, "otp_verified_for_today" boolean)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'internal', 'public'
    AS $$
  SELECT
    au.id,
    au.email,
    au.full_name,
    au.department,
    COALESCE(ARRAY_AGG(r.name ORDER BY r.level) FILTER (WHERE r.name IS NOT NULL), ARRAY[]::TEXT[]) AS roles,
    au.phone,
    au.job_position,
    COALESCE(au.theme_preference, 'light') AS theme_preference,
    au.last_otp_verified_at,
    (
      au.last_otp_verified_at IS NOT NULL
      AND (au.last_otp_verified_at AT TIME ZONE 'Europe/Madrid')::DATE = (now() AT TIME ZONE 'Europe/Madrid')::DATE
    ) AS otp_verified_for_today
  FROM internal.authorized_users au
  LEFT JOIN internal.user_roles ur ON ur.user_id = au.id
  LEFT JOIN internal.roles r ON r.id = ur.role_id
  WHERE au.auth_user_id = auth.uid()
    AND au.is_active = true
    AND (ur.expires_at IS NULL OR ur.expires_at > now() OR ur.id IS NULL)
  GROUP BY
    au.id,
    au.email,
    au.full_name,
    au.department,
    au.phone,
    au.job_position,
    au.theme_preference,
    au.last_otp_verified_at;
$$;
ALTER FUNCTION "public"."get_current_user_info"() OWNER TO "postgres";
--
-- Name: get_dashboard_metrics("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_dashboard_metrics"("p_period" "text" DEFAULT 'quarter'::"text") RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_start_date DATE;
  v_end_date DATE;
  v_result JSON;
  v_kpis JSON;
  v_taxes JSON;
  v_profitability JSON;
  v_revenue_chart JSON;
  
  -- KPI variables
  v_invoices_amount NUMERIC := 0;
  v_invoices_count INTEGER := 0;
  v_quotes_amount NUMERIC := 0;
  v_quotes_count INTEGER := 0;
  v_active_projects INTEGER := 0;
  v_pending_amount NUMERIC := 0;
  v_pending_count INTEGER := 0;
  v_total_clients INTEGER := 0;
  
  -- Tax variables
  v_tax_collected NUMERIC := 0;
  v_tax_paid NUMERIC := 0;
  
  -- Profitability variables
  v_total_revenue NUMERIC := 0;
  v_total_expenses NUMERIC := 0;
  v_profit NUMERIC := 0;
  v_margin NUMERIC := 0;
BEGIN
  -- Calculate date range based on period
  v_end_date := CURRENT_DATE;
  
  IF p_period = 'year' THEN
    v_start_date := DATE_TRUNC('year', CURRENT_DATE);
  ELSE -- Default to quarter
    v_start_date := DATE_TRUNC('quarter', CURRENT_DATE);
  END IF;

  -- ========== KPIs ==========
  
  -- Invoices issued in period (ISSUED, PARTIAL are valid status)
  SELECT 
    COALESCE(SUM(i.total), 0),
    COUNT(*)
  INTO v_invoices_amount, v_invoices_count
  FROM sales.invoices i
  WHERE i.issue_date >= v_start_date
    AND i.issue_date <= v_end_date
    AND i.status IN ('ISSUED', 'PARTIAL');

  -- Quotes in period (DRAFT, SENT are active status - APPROVED means accepted)
  SELECT 
    COALESCE(SUM(q.total), 0),
    COUNT(*)
  INTO v_quotes_amount, v_quotes_count
  FROM quotes.quotes q
  WHERE q.created_at >= v_start_date
    AND q.created_at <= v_end_date
    AND q.status IN ('DRAFT', 'SENT');

  -- Active projects (IN_PROGRESS, PLANNED)
  SELECT COUNT(*)
  INTO v_active_projects
  FROM projects.projects p
  WHERE p.status IN ('IN_PROGRESS', 'PLANNED');

  -- Pending invoices (amount and count) - only ISSUED and PARTIAL have pending amounts
  SELECT 
    COALESCE(SUM(COALESCE(i.total, 0) - COALESCE(i.paid_amount, 0)), 0),
    COUNT(*)
  INTO v_pending_amount, v_pending_count
  FROM sales.invoices i
  WHERE i.status IN ('ISSUED', 'PARTIAL');

  -- Total clients
  SELECT COUNT(*)
  INTO v_total_clients
  FROM crm.clients;

  -- Build KPIs JSON
  v_kpis := json_build_object(
    'invoicesAmount', v_invoices_amount,
    'invoicesCount', v_invoices_count,
    'quotesAmount', v_quotes_amount,
    'quotesCount', v_quotes_count,
    'activeProjects', v_active_projects,
    'pendingAmount', v_pending_amount,
    'pendingCount', v_pending_count,
    'totalClients', v_total_clients
  );

  -- ========== TAXES ==========
  
  -- VAT collected (from issued invoices)
  SELECT COALESCE(SUM(i.tax_amount), 0)
  INTO v_tax_collected
  FROM sales.invoices i
  WHERE i.issue_date >= v_start_date
    AND i.issue_date <= v_end_date
    AND i.status IN ('ISSUED', 'PARTIAL');

  -- VAT paid (from purchase invoices) - check if any exist
  SELECT COALESCE(SUM(pi.tax_amount), 0)
  INTO v_tax_paid
  FROM sales.purchase_invoices pi
  WHERE pi.issue_date >= v_start_date
    AND pi.issue_date <= v_end_date;

  v_taxes := json_build_object(
    'collected', v_tax_collected,
    'paid', v_tax_paid
  );

  -- ========== PROFITABILITY ==========
  
  -- Total revenue (sum of paid amounts from invoices)
  SELECT COALESCE(SUM(COALESCE(i.paid_amount, 0)), 0)
  INTO v_total_revenue
  FROM sales.invoices i
  WHERE i.issue_date >= v_start_date
    AND i.issue_date <= v_end_date;

  -- Total expenses (sum of purchase invoices)
  SELECT COALESCE(SUM(pi.total), 0)
  INTO v_total_expenses
  FROM sales.purchase_invoices pi
  WHERE pi.issue_date >= v_start_date
    AND pi.issue_date <= v_end_date;

  -- If no expenses data but there is revenue, estimate expenses at 65%
  IF v_total_expenses = 0 AND v_total_revenue > 0 THEN
    v_total_expenses := v_total_revenue * 0.65;
  END IF;

  v_profit := v_total_revenue - v_total_expenses;
  
  IF v_total_revenue > 0 THEN
    v_margin := (v_profit / v_total_revenue) * 100;
  ELSE
    v_margin := 0;
  END IF;

  v_profitability := json_build_object(
    'margin', ROUND(v_margin, 1),
    'profit', ROUND(v_profit, 2)
  );

  -- ========== REVENUE CHART (Last 6 months) ==========
  
  WITH months AS (
    SELECT generate_series(
      DATE_TRUNC('month', CURRENT_DATE) - INTERVAL '5 months',
      DATE_TRUNC('month', CURRENT_DATE),
      '1 month'::interval
    ) AS month_date
  ),
  monthly_revenue AS (
    SELECT 
      DATE_TRUNC('month', i.issue_date) AS month_date,
      COALESCE(SUM(i.total), 0) AS revenue
    FROM sales.invoices i
    WHERE i.issue_date >= DATE_TRUNC('month', CURRENT_DATE) - INTERVAL '5 months'
      AND i.status IN ('ISSUED', 'PARTIAL')
    GROUP BY DATE_TRUNC('month', i.issue_date)
  ),
  monthly_expenses AS (
    SELECT 
      DATE_TRUNC('month', pi.issue_date) AS month_date,
      COALESCE(SUM(pi.total), 0) AS expenses
    FROM sales.purchase_invoices pi
    WHERE pi.issue_date >= DATE_TRUNC('month', CURRENT_DATE) - INTERVAL '5 months'
    GROUP BY DATE_TRUNC('month', pi.issue_date)
  )
  SELECT json_agg(
    json_build_object(
      'month', TO_CHAR(m.month_date, 'Mon'),
      'revenue', COALESCE(mr.revenue, 0),
      'expenses', COALESCE(me.expenses, COALESCE(mr.revenue, 0) * 0.4)
    ) ORDER BY m.month_date
  )
  INTO v_revenue_chart
  FROM months m
  LEFT JOIN monthly_revenue mr ON DATE_TRUNC('month', mr.month_date) = m.month_date
  LEFT JOIN monthly_expenses me ON DATE_TRUNC('month', me.month_date) = m.month_date;

  -- If no chart data, create empty array
  IF v_revenue_chart IS NULL THEN
    v_revenue_chart := '[]'::json;
  END IF;

  -- ========== BUILD FINAL RESULT ==========

  v_result := json_build_object(
    'kpis', v_kpis,
    'taxes', v_taxes,
    'profitability', v_profitability,
    'revenueChart', v_revenue_chart,
    'period', json_build_object(
      'type', p_period,
      'startDate', v_start_date,
      'endDate', v_end_date
    )
  );

  RETURN v_result;
END;
$$;
ALTER FUNCTION "public"."get_dashboard_metrics"("p_period" "text") OWNER TO "postgres";
--
-- Name: get_fiscal_quarter_data(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_fiscal_quarter_data"("p_year" integer, "p_quarter" integer) RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'sales', 'crm'
    AS $$
DECLARE
  result JSON;
  quarter_start DATE;
  quarter_end DATE;
BEGIN
  quarter_start := make_date(p_year, (p_quarter - 1) * 3 + 1, 1);
  quarter_end := (quarter_start + INTERVAL '3 months' - INTERVAL '1 day')::DATE;

  SELECT json_build_object(
    'quarter_start', quarter_start,
    'quarter_end', quarter_end,
    'ventas', COALESCE((
      SELECT json_agg(row_to_json(v))
      FROM (
        SELECT
          i.invoice_number,
          i.issue_date,
          i.status,
          COALESCE(c.company_name, 'Sin cliente') AS client_name,
          c.tax_id AS client_nif,
          i.subtotal::NUMERIC(12,2),
          i.tax_amount::NUMERIC(12,2),
          i.total::NUMERIC(12,2),
          i.paid_amount::NUMERIC(12,2),
          i.pending_amount::NUMERIC(12,2)
        FROM sales.invoices i
        LEFT JOIN crm.clients c ON c.id = i.client_id
        WHERE i.issue_date BETWEEN quarter_start AND quarter_end
          AND i.status IN ('ISSUED', 'PAID', 'PARTIALLY_PAID')
        ORDER BY i.issue_date, i.invoice_number
      ) v
    ), '[]'::JSON),
    'compras', COALESCE((
      SELECT json_agg(row_to_json(cc))
      FROM (
        SELECT
          pi.invoice_number,
          pi.internal_purchase_number,
          pi.supplier_invoice_number,
          pi.issue_date,
          pi.status,
          pi.document_type,
          COALESCE(pi.supplier_name, 'Sin proveedor') AS supplier_name,
          pi.supplier_tax_id AS supplier_nif,
          pi.subtotal::NUMERIC(12,2),
          pi.tax_amount::NUMERIC(12,2),
          pi.withholding_amount::NUMERIC(12,2),
          pi.retention_amount::NUMERIC(12,2),
          pi.total::NUMERIC(12,2),
          pi.paid_amount::NUMERIC(12,2),
          pi.pending_amount::NUMERIC(12,2),
          pi.expense_category
        FROM sales.purchase_invoices pi
        WHERE pi.issue_date BETWEEN quarter_start AND quarter_end
          AND pi.status IN ('APPROVED', 'CONFIRMED', 'PAID', 'PARTIALLY_PAID')
        ORDER BY pi.document_type, pi.issue_date, pi.invoice_number
      ) cc
    ), '[]'::JSON),
    'totales', (
      SELECT json_build_object(
        'ventas_subtotal', COALESCE(SUM(CASE WHEN src = 'venta' THEN subtotal END), 0)::NUMERIC(12,2),
        'ventas_iva', COALESCE(SUM(CASE WHEN src = 'venta' THEN tax_amount END), 0)::NUMERIC(12,2),
        'ventas_total', COALESCE(SUM(CASE WHEN src = 'venta' THEN total END), 0)::NUMERIC(12,2),
        'compras_subtotal', COALESCE(SUM(CASE WHEN src = 'compra' AND dtype = 'INVOICE' THEN subtotal END), 0)::NUMERIC(12,2),
        'compras_iva', COALESCE(SUM(CASE WHEN src = 'compra' AND dtype = 'INVOICE' THEN tax_amount END), 0)::NUMERIC(12,2),
        'compras_retencion', COALESCE(SUM(CASE WHEN src = 'compra' AND dtype = 'INVOICE' THEN COALESCE(withholding_amount, 0) + COALESCE(retention_amount, 0) END), 0)::NUMERIC(12,2),
        'compras_total', COALESCE(SUM(CASE WHEN src = 'compra' AND dtype = 'INVOICE' THEN total END), 0)::NUMERIC(12,2),
        'tickets_subtotal', COALESCE(SUM(CASE WHEN src = 'compra' AND dtype = 'EXPENSE' THEN subtotal END), 0)::NUMERIC(12,2),
        'tickets_iva', COALESCE(SUM(CASE WHEN src = 'compra' AND dtype = 'EXPENSE' THEN tax_amount END), 0)::NUMERIC(12,2),
        'tickets_total', COALESCE(SUM(CASE WHEN src = 'compra' AND dtype = 'EXPENSE' THEN total END), 0)::NUMERIC(12,2),
        'iva_repercutido', COALESCE(SUM(CASE WHEN src = 'venta' THEN tax_amount END), 0)::NUMERIC(12,2),
        'iva_soportado', COALESCE(SUM(CASE WHEN src = 'compra' THEN tax_amount END), 0)::NUMERIC(12,2),
        'iva_a_declarar', (COALESCE(SUM(CASE WHEN src = 'venta' THEN tax_amount END), 0) - COALESCE(SUM(CASE WHEN src = 'compra' THEN tax_amount END), 0))::NUMERIC(12,2)
      )
      FROM (
        SELECT 'venta' AS src, NULL AS dtype, subtotal, tax_amount, total, 0::NUMERIC AS withholding_amount, 0::NUMERIC AS retention_amount
        FROM sales.invoices
        WHERE issue_date BETWEEN quarter_start AND quarter_end
          AND status IN ('ISSUED', 'PAID', 'PARTIALLY_PAID')
        UNION ALL
        SELECT 'compra', document_type, subtotal, tax_amount, total, withholding_amount, retention_amount
        FROM sales.purchase_invoices
        WHERE issue_date BETWEEN quarter_start AND quarter_end
          AND status IN ('APPROVED', 'CONFIRMED', 'PAID', 'PARTIALLY_PAID')
      ) agg
    )
  ) INTO result;

  RETURN result;
END;
$$;
ALTER FUNCTION "public"."get_fiscal_quarter_data"("p_year" integer, "p_quarter" integer) OWNER TO "postgres";
--
-- Name: get_invoice("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_invoice"("p_invoice_id" "uuid") RETURNS TABLE("id" "uuid", "invoice_number" "text", "client_id" "uuid", "client_name" "text", "project_id" "uuid", "project_name" "text", "project_number" "text", "source_quote_id" "uuid", "status" "text", "subtotal" numeric, "tax_amount" numeric, "total" numeric, "issue_date" "date", "due_date" "date", "notes" "text", "invoice_hash" "text", "created_by" "uuid", "created_by_name" "text", "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'User not authorized';
  END IF;

  RETURN QUERY
  SELECT 
    i.id,
    i.invoice_number,
    i.client_id,
    c.company_name AS client_name,
    i.project_id,
    COALESCE(p.project_name, i.project_name) AS project_name,
    p.project_number,
    i.source_quote_id,
    i.status::TEXT,
    i.subtotal,
    i.tax_amount,
    i.total,
    i.issue_date,
    i.due_date,
    i.notes,
    i.invoice_hash,
    i.created_by,
    u.full_name AS created_by_name,
    i.created_at,
    i.updated_at
  FROM sales.invoices i
  LEFT JOIN crm.clients c ON i.client_id = c.id
  LEFT JOIN projects.projects p ON i.project_id = p.id
  LEFT JOIN internal.authorized_users u ON i.created_by = u.id
  WHERE i.id = p_invoice_id AND i.deleted_at IS NULL;
END;
$$;
ALTER FUNCTION "public"."get_invoice"("p_invoice_id" "uuid") OWNER TO "postgres";
