--
-- Name: get_irpf_summary("date", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_irpf_summary"("p_period_start" "date" DEFAULT NULL::"date", "p_period_end" "date" DEFAULT NULL::"date") RETURNS numeric
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_irpf NUMERIC(12,2) := 0;
  v_start DATE;
  v_end DATE;
BEGIN
  -- Usar a├▒o actual si no se especifica per├¡odo
  v_start := COALESCE(p_period_start, DATE_TRUNC('year', CURRENT_DATE)::DATE);
  v_end := COALESCE(p_period_end, (DATE_TRUNC('year', CURRENT_DATE) + INTERVAL '1 year - 1 day')::DATE);
  
  -- Sumar todo el IRPF retenido (cuenta 475100, movimientos CREDIT = retenci├│n)
  SELECT COALESCE(SUM(jel.amount), 0)
  INTO v_irpf
  FROM accounting.journal_entry_lines jel
  JOIN accounting.journal_entries je ON jel.journal_entry_id = je.id
  WHERE jel.account_code = '475100'
    AND jel.debit_credit = 'CREDIT'
    AND je.entry_date BETWEEN v_start AND v_end;
  
  RETURN v_irpf;
END;
$$;
ALTER FUNCTION "public"."get_irpf_summary"("p_period_start" "date", "p_period_end" "date") OWNER TO "postgres";
--
-- Name: get_journal_entry_lines("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_journal_entry_lines"("p_entry_id" "uuid") RETURNS TABLE("id" "uuid", "account_code" "text", "account_name" "text", "description" "text", "debit_amount" numeric, "credit_amount" numeric, "third_party_id" "uuid", "third_party_type" "text", "third_party_name" "text", "line_order" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    jel.id,
    jel.account_code,
    coa.account_name,
    jel.description,
    jel.debit_amount,
    jel.credit_amount,
    jel.third_party_id,
    jel.third_party_type::TEXT,
    CASE 
      WHEN jel.third_party_type = 'CLIENT' THEN 
        (SELECT c.company_name FROM crm.clients c WHERE c.id = jel.third_party_id)
      WHEN jel.third_party_type = 'SUPPLIER' THEN 
        (SELECT s.company_name FROM internal.suppliers s WHERE s.id = jel.third_party_id)
      WHEN jel.third_party_type = 'TECHNICIAN' THEN 
        (SELECT t.company_name FROM internal.technicians t WHERE t.id = jel.third_party_id)
      WHEN jel.third_party_type = 'EMPLOYEE' THEN 
        (SELECT e.full_name FROM internal.employees e WHERE e.id = jel.third_party_id)
      ELSE NULL
    END AS third_party_name,
    jel.line_order
  FROM accounting.journal_entry_lines jel
  LEFT JOIN accounting.chart_of_accounts coa ON coa.account_code = jel.account_code
  WHERE jel.journal_entry_id = p_entry_id
  ORDER BY jel.line_order;
END;
$$;
ALTER FUNCTION "public"."get_journal_entry_lines"("p_entry_id" "uuid") OWNER TO "postgres";
