--
-- Name: get_next_invoice_number(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_next_invoice_number"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_year integer;
    v_number integer;
    v_invoice_number text;
BEGIN
    v_year := EXTRACT(YEAR FROM CURRENT_DATE);
    
    INSERT INTO sales.invoice_sequences (year, last_number)
    VALUES (v_year, 1)
    ON CONFLICT (year) DO UPDATE
    SET last_number = sales.invoice_sequences.last_number + 1,
        updated_at = now()
    RETURNING last_number INTO v_number;
    
    v_invoice_number := 'F-' || TO_CHAR(v_year, 'FM00') || '-' || LPAD(v_number::text, 6, '0');
    
    RETURN v_invoice_number;
END;
$$;
ALTER FUNCTION "public"."get_next_invoice_number"() OWNER TO "postgres";
--
-- Name: get_next_pending_monthly_report(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_next_pending_monthly_report"() RETURNS TABLE("id" "uuid", "year" integer, "month" integer, "retry_count" integer)
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT mr.id, mr.year, mr.month, COALESCE(mr.retry_count, 0)
  FROM accounting.monthly_reports mr
  WHERE mr.status IN ('PENDING', 'FAILED')
    AND mr.run_after <= now()
  ORDER BY mr.updated_at ASC
  LIMIT 1;
$$;
ALTER FUNCTION "public"."get_next_pending_monthly_report"() OWNER TO "postgres";
