--
-- Name: get_project("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_project"("p_project_id" "uuid") RETURNS TABLE("id" "uuid", "client_id" "uuid", "client_name" "text", "client_order_number" "text", "created_at" timestamp with time zone, "created_by" "uuid", "created_by_name" "text", "local_name" "text", "notes" "text", "project_address" "text", "project_city" "text", "project_name" "text", "project_number" "text", "quote_id" "uuid", "status" "text", "updated_at" timestamp with time zone, "site_mode" "text", "default_site_id" "uuid", "default_site_name" "text", "default_site_address" "text", "default_site_city" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF auth.uid() IS NULL THEN RAISE EXCEPTION 'Authentication required'; END IF;
  RETURN QUERY
  SELECT p.id, p.client_id, c.company_name, p.client_order_number,
    p.created_at, p.created_by, COALESCE(au.full_name, ''),
    p.local_name, p.description, ''::TEXT, p.project_city,
    p.project_name, p.project_number, p.quote_id, p.status::TEXT,
    p.updated_at,
    p.site_mode::TEXT, p.default_site_id,
    ps.site_name, ps.address, ps.city
  FROM projects.projects p
  LEFT JOIN crm.clients c ON c.id = p.client_id
  LEFT JOIN internal.authorized_users au ON au.id = p.created_by
  LEFT JOIN projects.project_sites ps ON ps.id = p.default_site_id
  WHERE p.id = p_project_id;
END; $$;
