--
-- Name: get_project_history("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_project_history"("p_project_id" "uuid") RETURNS TABLE("id" "uuid", "event_type" "text", "event_category" "text", "action" "text", "description" "text", "user_name" "text", "user_email" "text", "created_at" timestamp with time zone, "details" "jsonb", "severity" "text", "resource_type" "text", "resource_id" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  -- Eventos de auditor├¡a directos del proyecto
  SELECT 
    e.id,
    e.event_type::TEXT,
    e.event_category::TEXT,
    e.action::TEXT,
    CASE 
      WHEN e.event_type = 'project_created' THEN 'Proyecto creado'
      WHEN e.event_type = 'project_updated' THEN 'Proyecto modificado'
      WHEN e.event_type = 'project_status_changed' THEN 'Estado del proyecto cambiado'
      ELSE e.event_type::TEXT
    END AS description,
    COALESCE(e.user_name, 'Sistema')::TEXT AS user_name,
    COALESCE(e.user_email, '')::TEXT AS user_email,
    e.created_at,
    e.details,
    e.severity::TEXT,
    e.resource_type::TEXT,
    e.resource_id::TEXT
  FROM audit.events e
  WHERE (e.resource_type = 'project' AND e.resource_id = p_project_id::TEXT)
     OR (e.details->>'project_id' = p_project_id::TEXT)
  
  UNION ALL
  
  -- Eventos de presupuestos vinculados al proyecto
  SELECT 
    e.id,
    e.event_type::TEXT,
    e.event_category::TEXT,
    e.action::TEXT,
    CASE 
      WHEN e.event_type = 'quote_created' THEN 'Presupuesto creado: ' || COALESCE(e.details->>'quote_number', '')
      WHEN e.event_type = 'quote_updated' THEN 'Presupuesto modificado: ' || COALESCE(e.details->>'quote_number', '')
      WHEN e.event_type = 'quote_status_changed' THEN 'Estado presupuesto cambiado: ' || COALESCE(e.details->>'quote_number', '')
      WHEN e.event_type = 'quote_line_added' THEN 'L├¡nea a├▒adida a presupuesto: ' || COALESCE(e.details->>'quote_number', '')
      WHEN e.event_type = 'quote_line_updated' THEN 'L├¡nea modificada en presupuesto'
      WHEN e.event_type = 'quote_line_deleted' THEN 'L├¡nea eliminada de presupuesto'
      ELSE 'Presupuesto: ' || e.event_type::TEXT
    END AS description,
    COALESCE(e.user_name, 'Sistema')::TEXT AS user_name,
    COALESCE(e.user_email, '')::TEXT AS user_email,
    e.created_at,
    e.details,
    e.severity::TEXT,
    e.resource_type::TEXT,
    e.resource_id::TEXT
  FROM audit.events e
  WHERE e.event_category = 'quotes'
    AND e.resource_id IN (
      SELECT q.id::TEXT FROM quotes.quotes q WHERE q.project_id = p_project_id
    )
  
  UNION ALL
  
  -- Eventos de facturas vinculadas al proyecto
  SELECT 
    e.id,
    e.event_type::TEXT,
    e.event_category::TEXT,
    e.action::TEXT,
    CASE 
      WHEN e.event_type = 'invoice_created' THEN 'Factura creada: ' || COALESCE(e.details->>'invoice_number', e.details->>'preliminary_number', '')
      WHEN e.event_type = 'invoice_issued' THEN 'Factura emitida: ' || COALESCE(e.details->>'invoice_number', '')
      WHEN e.event_type = 'invoice_updated' THEN 'Factura modificada'
      WHEN e.event_type = 'invoice_status_changed' THEN 'Estado factura cambiado'
      WHEN e.event_type = 'payment_registered' THEN 'Pago registrado: ' || COALESCE((e.details->>'amount')::TEXT, '') || 'Ôé¼'
      ELSE 'Factura: ' || e.event_type::TEXT
    END AS description,
    COALESCE(e.user_name, 'Sistema')::TEXT AS user_name,
    COALESCE(e.user_email, '')::TEXT AS user_email,
    e.created_at,
    e.details,
    e.severity::TEXT,
    e.resource_type::TEXT,
    e.resource_id::TEXT
  FROM audit.events e
  WHERE e.event_category = 'invoices'
    AND e.resource_id IN (
      SELECT i.id::TEXT FROM sales.invoices i WHERE i.project_id = p_project_id
    )
  
  UNION ALL
  
  -- Asientos contables vinculados al proyecto
  SELECT 
    e.id,
    e.event_type::TEXT,
    e.event_category::TEXT,
    e.action::TEXT,
    CASE 
      WHEN e.event_type = 'journal_entry_created' THEN 'Asiento contable: ' || COALESCE(e.details->>'entry_number', '')
      ELSE 'Contabilidad: ' || e.event_type::TEXT
    END AS description,
    COALESCE(e.user_name, 'Sistema')::TEXT AS user_name,
    COALESCE(e.user_email, '')::TEXT AS user_email,
    e.created_at,
    e.details,
    e.severity::TEXT,
    e.resource_type::TEXT,
    e.resource_id::TEXT
  FROM audit.events e
  WHERE e.event_category = 'accounting'
    AND e.details->>'project_id' = p_project_id::TEXT
  
  ORDER BY created_at DESC;
END;
$$;
ALTER FUNCTION "public"."get_project_history"("p_project_id" "uuid") OWNER TO "postgres";
