-- Name: get_provider_purchase_invoices("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_provider_purchase_invoices"("p_provider_id" "uuid", "p_provider_type" "text") RETURNS TABLE("id" "uuid", "invoice_number" "text", "supplier_invoice_number" "text", "internal_purchase_number" "text", "document_type" "text", "issue_date" "date", "due_date" "date", "subtotal" numeric, "tax_amount" numeric, "withholding_amount" numeric, "total" numeric, "paid_amount" numeric, "pending_amount" numeric, "status" "text", "project_id" "uuid", "project_name" "text", "project_number" "text", "client_name" "text", "file_path" "text", "file_name" "text", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    pi.id,
    pi.invoice_number,
    pi.supplier_invoice_number,
    pi.internal_purchase_number,
    pi.document_type,
    pi.issue_date,
    pi.due_date,
    COALESCE(pi.subtotal, 0) as subtotal,
    COALESCE(pi.tax_amount, 0) as tax_amount,
    COALESCE(pi.withholding_amount, 0) as withholding_amount,
    COALESCE(pi.total, 0) as total,
    COALESCE(pi.paid_amount, 0) as paid_amount,
    COALESCE(pi.pending_amount, 0) as pending_amount,
    pi.status,
    pi.project_id,
    p.title as project_name,
    p.project_number,
    c.company_name as client_name,
    pi.file_path,
    pi.file_name,
    pi.created_at
  FROM sales.purchase_invoices pi
  LEFT JOIN projects.projects p ON pi.project_id = p.id
  LEFT JOIN crm.clients c ON p.client_id = c.id
  WHERE 
    (p_provider_type = 'TECHNICIAN' AND pi.technician_id = p_provider_id)
    OR (p_provider_type = 'SUPPLIER' AND pi.supplier_id = p_provider_id)
  ORDER BY pi.issue_date DESC, pi.created_at DESC;
END;
$$;
ALTER FUNCTION "public"."get_provider_purchase_invoices"("p_provider_id" "uuid", "p_provider_type" "text") OWNER TO "postgres";
