CREATE FUNCTION "public"."get_purchase_invoice"("p_invoice_id" "uuid") RETURNS TABLE("id" "uuid", "invoice_number" "text", "internal_purchase_number" "text", "supplier_invoice_number" "text", "document_type" "text", "status" "text", "supplier_id" "uuid", "supplier_name" "text", "supplier_number" "text", "supplier_tax_id" "text", "technician_id" "uuid", "technician_name" "text", "technician_number" "text", "technician_tax_id" "text", "project_id" "uuid", "project_name" "text", "project_number" "text", "client_id" "uuid", "issue_date" "date", "due_date" "date", "tax_base" numeric, "tax_amount" numeric, "total" numeric, "paid_amount" numeric, "pending_amount" numeric, "notes" "text", "internal_notes" "text", "expense_category" "text", "manual_beneficiary_name" "text", "file_path" "text", "file_name" "text", "is_locked" boolean, "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "created_by" "uuid", "created_by_name" "text", "withholding_amount" numeric, "site_id" "uuid", "site_name" "text", "site_city" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    pi.id,
    pi.invoice_number,
    pi.internal_purchase_number,
    pi.supplier_invoice_number,
    pi.document_type::TEXT,
    pi.status::TEXT,
    pi.supplier_id,
    COALESCE(s.company_name, '')::TEXT,
    COALESCE(s.supplier_number, '')::TEXT,
    COALESCE(s.tax_id, '')::TEXT,
    pi.technician_id,
    COALESCE(t.company_name, '')::TEXT,
    COALESCE(t.technician_number, '')::TEXT,
    COALESCE(t.tax_id, '')::TEXT,
    pi.project_id,
    COALESCE(pp.project_name, '')::TEXT,
    COALESCE(pp.project_number, '')::TEXT,
    pi.client_id,
    pi.issue_date,
    pi.due_date,
    pi.subtotal,
    pi.tax_amount,
    pi.total,
    pi.paid_amount,
    pi.pending_amount,
    pi.notes,
    pi.internal_notes,
    pi.expense_category,
    pi.manual_beneficiary_name,
    pi.file_path,
    pi.file_name,
    pi.is_locked,
    pi.created_at,
    pi.updated_at,
    pi.created_by,
    COALESCE(au.full_name, '')::TEXT,
    pi.withholding_amount,
    pi.site_id,
    ps.site_name,
    ps.city
  FROM sales.purchase_invoices pi
  LEFT JOIN internal.suppliers s ON s.id = pi.supplier_id
  LEFT JOIN internal.technicians t ON t.id = pi.technician_id
  LEFT JOIN projects.projects pp ON pp.id = pi.project_id
  LEFT JOIN internal.authorized_users au ON au.id = pi.created_by
  LEFT JOIN projects.project_sites ps ON ps.id = pi.site_id
  WHERE pi.id = p_invoice_id;
END;
$$;
