CREATE FUNCTION "public"."get_purchase_invoice_lines"("p_invoice_id" "uuid") RETURNS TABLE("id" "uuid", "concept" "text", "description" "text", "quantity" numeric, "unit_price" numeric, "tax_rate" numeric, "withholding_tax_rate" numeric, "discount_percent" numeric, "subtotal" numeric, "tax_amount" numeric, "withholding_amount" numeric, "total" numeric, "product_id" "uuid", "line_order" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    pil.id,
    pil.concept,
    pil.description,
    pil.quantity,
    pil.unit_price,
    pil.tax_rate,
    COALESCE(pil.withholding_tax_rate, 0) AS withholding_tax_rate,
    COALESCE(pil.discount_percent, 0) AS discount_percent,
    round(COALESCE(pil.subtotal, 0)::numeric, 2) AS subtotal,
    round(COALESCE(pil.tax_amount, 0)::numeric, 2) AS tax_amount,
    round(COALESCE(pil.withholding_amount, 0)::numeric, 2) AS withholding_amount,
    round(COALESCE(pil.total, 0)::numeric, 2) AS total,
    pil.product_id,
    pil.line_order
  FROM sales.purchase_invoice_lines pil
  WHERE pil.purchase_invoice_id = p_invoice_id
  ORDER BY pil.line_order;
END;
$$;
