CREATE FUNCTION "public"."get_quote"("p_quote_id" "uuid") RETURNS TABLE("id" "uuid", "quote_number" "text", "client_id" "uuid", "client_name" "text", "project_id" "uuid", "project_name" "text", "status" "text", "subtotal" numeric, "tax_rate" numeric, "tax_amount" numeric, "total" numeric, "notes" "text", "valid_until" "date", "issue_date" "date", "order_number" "text", "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "created_by" "uuid", "created_by_name" "text", "site_id" "uuid", "site_name" "text", "site_city" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'sales', 'accounting', 'internal', 'crm', 'quotes'
    AS $$
BEGIN
  PERFORM quotes.expire_overdue_quotes();

  RETURN QUERY
  SELECT q.id, q.quote_number, q.client_id, c.company_name, q.project_id, q.project_name,
    q.status::TEXT, q.subtotal, q.tax_rate, q.tax_amount, q.total, q.notes, q.valid_until, q.issue_date, q.order_number,
    q.created_at, q.updated_at, q.created_by, COALESCE(au.full_name, '')::TEXT,
    q.site_id, ps.site_name, ps.city
  FROM quotes.quotes q
  LEFT JOIN crm.clients c ON c.id = q.client_id
  LEFT JOIN internal.authorized_users au ON au.id = q.created_by
  LEFT JOIN projects.project_sites ps ON ps.id = q.site_id
  WHERE q.id = p_quote_id;
END;
$$;
ALTER FUNCTION "public"."get_quote"("p_quote_id" "uuid") OWNER TO "postgres";
