-- Name: get_quote_archive_metadata("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_quote_archive_metadata"("p_quote_id" "uuid") RETURNS TABLE("archived_pdf_path" "text", "archived_pdf_file_name" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'quotes', 'sales'
    AS $$
BEGIN
  IF auth.uid() IS NULL OR NOT sales.can_access_quote(p_quote_id) THEN
    RAISE EXCEPTION 'Access denied';
  END IF;

  RETURN QUERY
  SELECT
    q.archived_pdf_path,
    q.archived_pdf_file_name
  FROM quotes.quotes q
  WHERE q.id = p_quote_id;
END;
$$;
ALTER FUNCTION "public"."get_quote_archive_metadata"("p_quote_id" "uuid") OWNER TO "postgres";
--
-- Name: get_quote_lines("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_quote_lines"("p_quote_id" "uuid") RETURNS TABLE("id" "uuid", "line_order" integer, "concept" "text", "description" "text", "quantity" numeric, "unit_price" numeric, "tax_rate" numeric, "discount_percent" numeric, "subtotal" numeric, "tax_amount" numeric, "total" numeric, "group_name" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_is_service_role BOOLEAN;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  v_is_service_role := COALESCE(current_setting('request.jwt.claim.role', true), '') = 'service_role';

  IF v_user_id IS NULL AND NOT v_is_service_role THEN
    RAISE EXCEPTION 'User not authorized';
  END IF;

  RETURN QUERY
  SELECT
    ql.id,
    ql.line_order,
    ql.concept,
    ql.description,
    ql.quantity,
    ql.unit_price,
    ql.tax_rate,
    ql.discount_percent,
    ql.subtotal,
    ql.tax_amount,
    ql.total,
    ql.group_name
  FROM quotes.quote_lines ql
  WHERE ql.quote_id = p_quote_id
  ORDER BY ql.line_order ASC;
END;
$$;
ALTER FUNCTION "public"."get_quote_lines"("p_quote_id" "uuid") OWNER TO "postgres";
