-- Name: get_sales_by_product_category("date", "date", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_sales_by_product_category"("p_period_start" "date" DEFAULT NULL::"date", "p_period_end" "date" DEFAULT NULL::"date", "p_status" "text" DEFAULT NULL::"text") RETURNS TABLE("category_id" "uuid", "category_name" "text", "category_code" "text", "category_type" "text", "invoice_count" bigint, "line_count" bigint, "total_subtotal" numeric, "total_tax" numeric, "total_amount" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  RETURN QUERY
  WITH filtered_invoices AS (
    SELECT i.id, i.issue_date
    FROM sales.invoices i
    WHERE (p_status IS NULL OR i.status = p_status)
      AND (p_period_start IS NULL OR i.issue_date >= p_period_start)
      AND (p_period_end IS NULL OR i.issue_date <= p_period_end)
  ),
  line_data AS (
    SELECT 
      fi.id as invoice_id,
      il.id as line_id,
      il.subtotal,
      il.tax_amount,
      il.total,
      COALESCE(il.product_id, '00000000-0000-0000-0000-000000000000'::uuid) as cat_id
    FROM filtered_invoices fi
    JOIN sales.invoice_lines il ON il.invoice_id = fi.id
  ),
  aggregated AS (
    SELECT 
      COALESCE(
        (SELECT p.category_id FROM internal.products p WHERE p.id = ld.cat_id),
        '00000000-0000-0000-0000-000000000000'::uuid
      ) as final_cat_id,
      COUNT(DISTINCT ld.invoice_id) as inv_count,
      COUNT(ld.line_id) as ln_count,
      SUM(ld.subtotal) as sum_subtotal,
      SUM(ld.tax_amount) as sum_tax,
      SUM(ld.total) as sum_total
    FROM line_data ld
    GROUP BY 1
  )
  SELECT 
    a.final_cat_id as category_id,
    COALESCE(c.name, 'Sin Categor├¡a')::TEXT as category_name,
    COALESCE(c.code, 'OTHER')::TEXT as category_code,
    COALESCE(c.type, 'product')::TEXT as category_type,
    a.inv_count as invoice_count,
    a.ln_count as line_count,
    COALESCE(a.sum_subtotal, 0) as total_subtotal,
    COALESCE(a.sum_tax, 0) as total_tax,
    COALESCE(a.sum_total, 0) as total_amount
  FROM aggregated a
  LEFT JOIN internal.product_categories c ON c.id = a.final_cat_id
  ORDER BY a.sum_total DESC;
END;
$$;
ALTER FUNCTION "public"."get_sales_by_product_category"("p_period_start" "date", "p_period_end" "date", "p_status" "text") OWNER TO "postgres";
--
-- Name: get_site_financials("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_site_financials"("p_site_id" "uuid") RETURNS TABLE("quoted_total" numeric, "quoted_count" integer, "invoiced_total" numeric, "invoiced_count" integer, "paid_total" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    COALESCE((
      SELECT SUM(q.total) FROM sales.quotes q WHERE q.site_id = p_site_id AND q.status NOT IN ('REJECTED','EXPIRED')
    ), 0)::NUMERIC AS quoted_total,
    COALESCE((
      SELECT COUNT(*)::INTEGER FROM sales.quotes q WHERE q.site_id = p_site_id AND q.status NOT IN ('REJECTED','EXPIRED')
    ), 0)::INTEGER AS quoted_count,
    COALESCE((
      SELECT SUM(i.total) FROM sales.invoices i WHERE i.site_id = p_site_id AND i.doc_status != 'CANCELLED'
    ), 0)::NUMERIC AS invoiced_total,
    COALESCE((
      SELECT COUNT(*)::INTEGER FROM sales.invoices i WHERE i.site_id = p_site_id AND i.doc_status != 'CANCELLED'
    ), 0)::INTEGER AS invoiced_count,
    COALESCE((
      SELECT SUM(ip.amount) FROM sales.invoice_payments ip
      JOIN sales.invoices i ON i.id = ip.invoice_id
      WHERE i.site_id = p_site_id AND i.doc_status != 'CANCELLED'
    ), 0)::NUMERIC AS paid_total;
END;
$$;
ALTER FUNCTION "public"."get_site_financials"("p_site_id" "uuid") OWNER TO "postgres";
--
-- Name: get_suggested_project_status("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."get_suggested_project_status"("p_project_id" "uuid") RETURNS TABLE("suggested_status" "text", "reason" "text", "site_summary" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_total INTEGER;
  v_closed INTEGER;
  v_invoiced INTEGER;
  v_in_progress INTEGER;
  v_ready INTEGER;
  v_scheduled INTEGER;
  v_planned INTEGER;
BEGIN
  SELECT
    COUNT(*),
    COUNT(*) FILTER (WHERE ps.site_status = 'CLOSED'),
    COUNT(*) FILTER (WHERE ps.site_status = 'INVOICED'),
    COUNT(*) FILTER (WHERE ps.site_status = 'IN_PROGRESS'),
    COUNT(*) FILTER (WHERE ps.site_status = 'READY_TO_INVOICE'),
    COUNT(*) FILTER (WHERE ps.site_status = 'SCHEDULED'),
    COUNT(*) FILTER (WHERE ps.site_status = 'PLANNED')
  INTO v_total, v_closed, v_invoiced, v_in_progress, v_ready, v_scheduled, v_planned
  FROM projects.project_sites ps
  WHERE ps.project_id = p_project_id AND ps.is_active = true;

  IF v_total = 0 THEN
    RETURN QUERY SELECT 'NEGOTIATION'::TEXT, 'Sin sitios activos'::TEXT,
      jsonb_build_object('total', 0);
    RETURN;
  END IF;

  -- All closed
  IF v_closed = v_total THEN
    RETURN QUERY SELECT 'CLOSED'::TEXT, 'Todos los sitios est├ín cerrados'::TEXT,
      jsonb_build_object('total', v_total, 'closed', v_closed);
    RETURN;
  END IF;

  -- All invoiced or closed
  IF (v_invoiced + v_closed) = v_total THEN
    RETURN QUERY SELECT 'INVOICED'::TEXT, 'Todos los sitios facturados o cerrados'::TEXT,
      jsonb_build_object('total', v_total, 'invoiced', v_invoiced, 'closed', v_closed);
    RETURN;
  END IF;

  -- All completed (ready + invoiced + closed)
  IF (v_ready + v_invoiced + v_closed) = v_total THEN
    RETURN QUERY SELECT 'COMPLETED'::TEXT, 'Todos los sitios listos para facturar o ya facturados'::TEXT,
      jsonb_build_object('total', v_total, 'ready', v_ready, 'invoiced', v_invoiced, 'closed', v_closed);
    RETURN;
  END IF;

  -- Any in progress or ready
  IF v_in_progress > 0 OR v_ready > 0 THEN
    RETURN QUERY SELECT 'IN_PROGRESS'::TEXT,
      format('%s sitio(s) en ejecuci├│n, %s listo(s) para facturar', v_in_progress, v_ready)::TEXT,
      jsonb_build_object('total', v_total, 'in_progress', v_in_progress, 'ready', v_ready, 'invoiced', v_invoiced, 'closed', v_closed);
    RETURN;
  END IF;

  -- All planned/scheduled
  RETURN QUERY SELECT 'NEGOTIATION'::TEXT,
    format('%s sitio(s) planificados, %s programados', v_planned, v_scheduled)::TEXT,
    jsonb_build_object('total', v_total, 'planned', v_planned, 'scheduled', v_scheduled);
END;
$$;
ALTER FUNCTION "public"."get_suggested_project_status"("p_project_id" "uuid") OWNER TO "postgres";
