    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        t.id,
        t.technician_number,
        t.type::TEXT,
        t.company_name,
        t.legal_name,
        t.tax_id,
        t.contact_name,
        t.contact_phone,
        t.contact_phone_secondary,
        t.contact_email,
        t.billing_email,
        t.address,
        t.city,
        t.province,
        t.postal_code,
        t.country,
        t.latitude,
        t.longitude,
        t.specialties,
        t.hourly_rate,
        t.daily_rate,
        t.iban,
