--

CREATE FUNCTION "public"."get_worker_detail"("p_user_id" "uuid") RETURNS TABLE("id" "uuid", "full_name" "text", "email" "text", "phone" "text", "department" "text", "job_position" "text", "is_active" boolean, "created_at" timestamp with time zone, "last_login_at" timestamp with time zone, "roles" "text"[], "worker_type" "text", "tax_id" "text", "iban" "text", "irpf_rate" numeric, "address" "text", "city" "text", "postal_code" "text", "province" "text", "linked_partner_id" "uuid", "linked_partner_number" "text", "linked_partner_account_code" "text", "linked_employee_id" "uuid", "linked_employee_number" "text", "ss_regime" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    au.id,
    au.full_name,
    au.email,
    au.phone,
    au.department::text,
    au.job_position,
    au.is_active,
    au.created_at,
    au.last_login_at,
    COALESCE(
      (SELECT array_agg(ur.role::text) 
       FROM public.user_roles ur 
       WHERE ur.user_id = internal.get_auth_user_id(au.id)),
      ARRAY[]::text[]
    ) as roles,
    au.worker_type,
    au.tax_id,
    au.iban,
    COALESCE(au.irpf_rate, 19) as irpf_rate,
    au.address,
    au.city,
    au.postal_code,
    au.province,
    au.linked_partner_id,
    p.partner_number as linked_partner_number,
    p.account_code as linked_partner_account_code,
    au.linked_employee_id,
    e.employee_number as linked_employee_number,
    COALESCE(au.ss_regime, 'RETA') as ss_regime
  FROM internal.authorized_users au
  LEFT JOIN internal.partners p ON p.id = au.linked_partner_id
  LEFT JOIN internal.employees e ON e.id = au.linked_employee_id
  WHERE au.id = p_user_id;
END;
$$;
ALTER FUNCTION "public"."get_worker_detail"("p_user_id" "uuid") OWNER TO "postgres";
