--

CREATE FUNCTION "public"."insert_contact_message"("_nombre" "text", "_empresa" "text", "_email" "text", "_telefono" "text", "_tipo_solicitud" "text", "_tipo_espacio" "text", "_mensaje" "text", "_ip_address" "inet" DEFAULT NULL::"inet", "_user_agent" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
