CREATE FUNCTION "public"."list_assignable_users"() RETURNS TABLE("id" "uuid", "full_name" "text", "email" "text", "department" "text")
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'internal'
    AS $$
  SELECT 
    au.id,
    au.full_name,
    au.email,
    au.department::text
  FROM internal.authorized_users au
  WHERE au.is_active = true
  ORDER BY au.full_name;
$$;
ALTER FUNCTION "public"."list_assignable_users"() OWNER TO "postgres";
--
-- Name: list_authorized_users(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_authorized_users"() RETURNS TABLE("id" "uuid", "email" "text", "full_name" "text", "phone" "text", "department" "text", "job_position" "text", "is_active" boolean, "created_at" timestamp with time zone, "last_login_at" timestamp with time zone, "setup_completed" boolean, "roles" "text"[], "invitation_sent_at" timestamp with time zone, "invitation_expires_at" timestamp with time zone, "invitation_days_remaining" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    au.id,
    au.email,
    au.full_name,
    au.phone,
    au.department::TEXT,
    au.job_position,
    au.is_active,
    au.created_at,
    au.last_login_at,
    au.setup_completed,
    COALESCE(
      (SELECT array_agg(r.name ORDER BY r.level)
       FROM internal.user_roles ur
       JOIN internal.roles r ON r.id = ur.role_id
       WHERE ur.user_id = au.id),
      ARRAY[]::TEXT[]
    ) as roles,
    (SELECT it.created_at 
     FROM internal.invitation_tokens it 
     WHERE it.user_id = au.id AND it.used_at IS NULL 
     ORDER BY it.created_at DESC LIMIT 1) as invitation_sent_at,
    (SELECT it.expires_at 
     FROM internal.invitation_tokens it 
     WHERE it.user_id = au.id AND it.used_at IS NULL 
     ORDER BY it.created_at DESC LIMIT 1) as invitation_expires_at,
    (SELECT GREATEST(0, EXTRACT(DAY FROM (it.expires_at - NOW()))::INTEGER)
     FROM internal.invitation_tokens it 
     WHERE it.user_id = au.id AND it.used_at IS NULL 
     ORDER BY it.created_at DESC LIMIT 1) as invitation_days_remaining
  FROM internal.authorized_users au
  ORDER BY au.created_at DESC;
END;
$$;
ALTER FUNCTION "public"."list_authorized_users"() OWNER TO "postgres";
--
-- Name: list_bank_account_movements("text", "date", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_bank_account_movements"("p_account_code" "text", "p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date") RETURNS TABLE("id" "uuid", "entry_number" "text", "entry_date" "date", "entry_type" "text", "description" "text", "debit_amount" numeric, "credit_amount" numeric, "running_balance" numeric, "reference_id" "uuid", "reference_type" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  WITH filtered_lines AS (
    SELECT
      jel.id AS line_id,
      je.entry_number,
      je.entry_date,
      je.entry_type::TEXT,
      COALESCE(jel.description, je.description) AS line_desc,
      CASE WHEN jel.debit_credit = 'DEBIT' THEN jel.amount ELSE 0 END AS debit,
      CASE WHEN jel.debit_credit = 'CREDIT' THEN jel.amount ELSE 0 END AS credit,
      je.reference_id,
      je.reference_type
    FROM accounting.journal_entry_lines jel
    JOIN accounting.journal_entries je ON jel.journal_entry_id = je.id
    WHERE jel.account_code = p_account_code
      AND (p_start_date IS NULL OR je.entry_date >= p_start_date)
      AND (p_end_date IS NULL OR je.entry_date <= p_end_date)
    ORDER BY je.entry_date ASC, je.entry_number ASC, jel.line_order ASC
  ),
  with_balance AS (
    SELECT
      fl.line_id,
      fl.entry_number,
      fl.entry_date,
      fl.entry_type,
      fl.line_desc,
      fl.debit,
      fl.credit,
      fl.reference_id,
      fl.reference_type,
      SUM(fl.debit - fl.credit) OVER (ORDER BY fl.entry_date, fl.entry_number, fl.line_id) AS running
    FROM filtered_lines fl
  )
  SELECT
    wb.line_id AS id,
    wb.entry_number,
    wb.entry_date,
    wb.entry_type,
    wb.line_desc AS description,
    wb.debit AS debit_amount,
    wb.credit AS credit_amount,
    wb.running AS running_balance,
    wb.reference_id,
    wb.reference_type
  FROM with_balance wb;
END;
$$;
ALTER FUNCTION "public"."list_bank_account_movements"("p_account_code" "text", "p_start_date" "date", "p_end_date" "date") OWNER TO "postgres";
--
-- Name: FUNCTION "list_bank_account_movements"("p_account_code" "text", "p_start_date" "date", "p_end_date" "date"); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION "public"."list_bank_account_movements"("p_account_code" "text", "p_start_date" "date", "p_end_date" "date") IS 'Movimientos de una cuenta bancaria (572xxx) para la vista detalle. Incluye traspasos (BANK_TRANSFER), cobros, pagos, etc.';
--
-- Name: list_bank_accounts_with_balances("date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_bank_accounts_with_balances"("p_as_of_date" "date" DEFAULT CURRENT_DATE) RETURNS TABLE("bank_account_id" "uuid", "bank_name" "text", "account_code" "text", "balance" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  WITH balances AS (
    SELECT
      jel.account_code,
      SUM(CASE WHEN jel.debit_credit = 'DEBIT' THEN jel.amount ELSE 0 END) -
      SUM(CASE WHEN jel.debit_credit = 'CREDIT' THEN jel.amount ELSE 0 END) AS net_balance
    FROM accounting.journal_entries je
    JOIN accounting.journal_entry_lines jel ON jel.journal_entry_id = je.id
    WHERE jel.account_code LIKE '572%'
      AND jel.account_code != '572000'
      AND je.entry_date <= p_as_of_date
    GROUP BY jel.account_code
  )
  SELECT
    cba.id AS bank_account_id,
    cba.bank_name,
    cba.accounting_code AS account_code,
    COALESCE(b.net_balance, 0)::numeric AS balance
  FROM internal.company_bank_accounts cba
  LEFT JOIN balances b ON b.account_code = cba.accounting_code
  WHERE cba.is_active = TRUE
  ORDER BY cba.accounting_code;
END;
$$;
ALTER FUNCTION "public"."list_bank_accounts_with_balances"("p_as_of_date" "date") OWNER TO "postgres";
