CREATE FUNCTION "public"."list_cash_movements"("p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date", "p_bank_account_code" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 500, "p_offset" integer DEFAULT 0) RETURNS TABLE("movement_id" "uuid", "entry_id" "uuid", "entry_number" "text", "entry_date" "date", "entry_type" "text", "movement_type" "text", "amount" numeric, "bank_account_code" "text", "bank_account_name" "text", "counterpart_account_code" "text", "counterpart_account_name" "text", "third_party_id" "uuid", "third_party_type" "text", "third_party_name" "text", "description" "text", "payment_method" "text", "bank_reference" "text", "reference_id" "uuid", "reference_type" "text", "is_locked" boolean, "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT * FROM accounting.list_cash_movements(
    p_start_date,
    p_end_date,
    p_bank_account_code,
    p_limit,
    p_offset
  );
END;
$$;
