--
-- Name: list_catalog_products("catalog"."category_domain", "uuid", "text", boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_catalog_products"("p_domain" "catalog"."category_domain" DEFAULT NULL::"catalog"."category_domain", "p_category_id" "uuid" DEFAULT NULL::"uuid", "p_search" "text" DEFAULT NULL::"text", "p_include_inactive" boolean DEFAULT false) RETURNS TABLE("id" "uuid", "sku" "text", "name" "text", "description" "text", "product_type" "catalog"."product_type", "category_id" "uuid", "category_name" "text", "supplier_id" "uuid", "supplier_name" "text", "unit" "catalog"."unit_type", "cost_price" numeric, "sale_price" numeric, "discount_percent" numeric, "sale_price_effective" numeric, "tax_rate" numeric, "margin_percentage" numeric, "track_stock" boolean, "stock_quantity" numeric, "min_stock_alert" numeric, "is_active" boolean, "has_low_stock_alert" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF auth.uid() IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF;
  RETURN QUERY
  SELECT
    p.id,
    p.sku,
    p.name,
    p.description,
    p.product_type,
    p.category_id,
    c.name::TEXT AS category_name,
    p.supplier_id,
    s.company_name::TEXT AS supplier_name,
    p.unit,
    p.cost_price,
    p.sale_price,
    p.discount_percent,
    (p.sale_price * (1 - COALESCE(p.discount_percent, 0) / 100))::NUMERIC AS sale_price_effective,
    (SELECT tr.rate FROM catalog.tax_rates tr WHERE tr.id = p.tax_rate_id)::NUMERIC AS tax_rate,
    p.margin_percentage,
    p.track_stock,
    COALESCE(p.stock_quantity, 0)::NUMERIC(12,3),
    p.min_stock_alert::NUMERIC(12,3),
    p.is_active,
    EXISTS (SELECT 1 FROM catalog.stock_alerts sa WHERE sa.product_id = p.id AND sa.status = 'open') AS has_low_stock_alert
  FROM catalog.products p
  LEFT JOIN catalog.categories c ON c.id = p.category_id
  LEFT JOIN internal.suppliers s ON s.id = p.supplier_id
  WHERE (p_domain IS NULL OR c.domain = p_domain)
    AND (p_category_id IS NULL OR p.category_id = p_category_id)
    AND (p_search IS NULL OR p_search = '' OR p.name ILIKE '%' || p_search || '%' OR p.sku ILIKE '%' || p_search || '%' OR p.description ILIKE '%' || p_search || '%')
    AND (p_include_inactive OR p.is_active)
    AND p.product_type != 'BUNDLE'
  ORDER BY p.sku;
END;
$$;
ALTER FUNCTION "public"."list_catalog_products"("p_domain" "catalog"."category_domain", "p_category_id" "uuid", "p_search" "text", "p_include_inactive" boolean) OWNER TO "postgres";
