-- Name: list_clients("text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_clients"("p_search" "text" DEFAULT NULL::"text", "p_lead_stage" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "client_number" "text", "company_name" "text", "legal_name" "text", "tax_id" "text", "contact_email" "text", "contact_phone" "text", "industry_sector" "text", "lead_source" "text", "lead_stage" "text", "urgency" "text", "notes" "text", "assigned_to" "uuid", "assigned_to_name" "text", "next_follow_up_date" "date", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    c.id,
    c.client_number,
    c.company_name,
    c.legal_name,
    c.tax_id,
    c.contact_email,
    c.contact_phone,
    c.industry_sector::text,  -- Cast enum to text
    c.lead_source::text,
    c.lead_stage::text,
    c.urgency::text,
    c.notes,
    c.assigned_to,
    au.full_name as assigned_to_name,
    c.next_follow_up_date,
    c.created_at
  FROM crm.clients c
  LEFT JOIN internal.authorized_users au ON au.id = c.assigned_to
  WHERE c.deleted_at IS NULL
    AND (p_search IS NULL OR p_search = '' OR 
         c.company_name ILIKE '%' || p_search || '%' OR
         c.legal_name ILIKE '%' || p_search || '%' OR
         c.contact_email ILIKE '%' || p_search || '%' OR
         c.client_number ILIKE '%' || p_search || '%')
    AND (p_lead_stage IS NULL OR p_lead_stage = '' OR c.lead_stage::text = p_lead_stage)
  ORDER BY c.created_at DESC;
END;
$$;
ALTER FUNCTION "public"."list_clients"("p_search" "text", "p_lead_stage" "text") OWNER TO "postgres";
--
-- Name: list_clients_for_map("uuid", "text"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_clients_for_map"("p_assigned_to" "uuid" DEFAULT NULL::"uuid", "p_lead_stages" "text"[] DEFAULT NULL::"text"[]) RETURNS TABLE("id" "uuid", "client_number" "text", "company_name" "text", "legal_name" "text", "contact_email" "text", "contact_phone" "text", "lead_stage" "text", "latitude" numeric, "longitude" numeric, "full_address" "text", "assigned_to" "uuid", "assigned_to_name" "text", "created_at" timestamp with time zone, "notes_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    c.id,
    c.client_number,
    c.company_name,
    c.legal_name,
    c.contact_email,
    c.contact_phone,
    c.lead_stage::text,
    c.latitude,
    c.longitude,
    -- Usar full_address si existe, sino construir desde billing fields
    COALESCE(
      c.full_address,
      NULLIF(
        TRIM(
          CONCAT_WS(', ',
            NULLIF(c.billing_address, ''),
            NULLIF(c.billing_postal_code, ''),
            NULLIF(c.billing_city, ''),
            NULLIF(c.billing_province, ''),
            CASE WHEN c.billing_country IS NOT NULL AND c.billing_country NOT IN ('ES', 'Espa├▒a') THEN c.billing_country ELSE NULL END
          )
        ),
        ''
      )
    ) AS full_address,
    c.assigned_to,
    u.full_name AS assigned_to_name,
    c.created_at,
    (SELECT COUNT(*) FROM crm.client_notes cn WHERE cn.client_id = c.id) AS notes_count
  FROM crm.clients c
  LEFT JOIN internal.authorized_users u ON c.assigned_to = u.id
  WHERE c.deleted_at IS NULL
    AND (p_assigned_to IS NULL OR c.assigned_to = p_assigned_to)
    AND (p_lead_stages IS NULL OR c.lead_stage::text = ANY(p_lead_stages));
END;
$$;
ALTER FUNCTION "public"."list_clients_for_map"("p_assigned_to" "uuid", "p_lead_stages" "text"[]) OWNER TO "postgres";
--
-- Name: list_company_bank_accounts(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_company_bank_accounts"() RETURNS TABLE("id" "uuid", "bank_name" "text", "holder_name" "text", "iban" "text", "accounting_code" "text", "notes" "text", "is_active" boolean)
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT 
    id,
    bank_name,
    holder_name,
    iban,
    accounting_code,
