--
-- Name: list_invoices("text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_invoices"("p_search" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "invoice_number" "text", "source_quote_id" "uuid", "source_quote_number" "text", "client_id" "uuid", "client_name" "text", "project_id" "uuid", "project_name" "text", "status" "text", "issue_date" "date", "due_date" "date", "subtotal" numeric, "tax_amount" numeric, "total" numeric, "created_by" "uuid", "created_by_name" "text", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        i.id, i.invoice_number, i.source_quote_id, q.quote_number as source_quote_number,
        i.client_id, c.company_name as client_name, i.project_id, i.project_name,
        i.status, i.issue_date, i.due_date,
        COALESCE(SUM(il.quantity * il.unit_price * (1 - il.discount_percent / 100)), 0)::numeric as subtotal,
        COALESCE(SUM(il.quantity * il.unit_price * (1 - il.discount_percent / 100) * il.tax_rate / 100), 0)::numeric as tax_amount,
        COALESCE(SUM(il.quantity * il.unit_price * (1 - il.discount_percent / 100) * (1 + il.tax_rate / 100)), 0)::numeric as total,
        i.created_by,
        COALESCE((SELECT raw_user_meta_data->>'full_name' FROM auth.users WHERE auth.users.id = i.created_by), 'Usuario') as created_by_name,
        i.created_at
    FROM sales.invoices i
    LEFT JOIN crm.clients c ON i.client_id = c.id
    LEFT JOIN quotes.quotes q ON i.source_quote_id = q.id
    LEFT JOIN sales.invoice_lines il ON i.id = il.invoice_id
    WHERE (p_status IS NULL OR i.status = p_status)
      AND (p_search IS NULL OR 
           i.invoice_number ILIKE '%' || p_search || '%' OR
           c.company_name ILIKE '%' || p_search || '%' OR
           i.project_name ILIKE '%' || p_search || '%')
    GROUP BY i.id, i.invoice_number, i.source_quote_id, q.quote_number, i.client_id, 
             c.company_name, i.project_id, i.project_name, i.status, i.issue_date, i.due_date,
             i.created_by, i.created_at
    ORDER BY i.created_at DESC;
END;
$$;
ALTER FUNCTION "public"."list_invoices"("p_search" "text", "p_status" "text") OWNER TO "postgres";
--
-- Name: list_journal_entries("date", "date", "text", "text", "uuid", "text", integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_journal_entries"("p_start_date" "date" DEFAULT NULL::"date", "p_end_date" "date" DEFAULT NULL::"date", "p_entry_type" "text" DEFAULT NULL::"text", "p_reference_type" "text" DEFAULT NULL::"text", "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_search" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 100, "p_offset" integer DEFAULT 0) RETURNS TABLE("id" "uuid", "entry_number" "text", "entry_date" "date", "entry_type" "text", "description" "text", "reference_id" "uuid", "reference_type" "text", "project_id" "uuid", "project_name" "text", "is_locked" boolean, "created_by_name" "text", "created_at" timestamp with time zone, "total_debit" numeric, "total_credit" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_entry_type_enum accounting.journal_entry_type;
BEGIN
  -- Convertir TEXT a enum si se proporciona
  IF p_entry_type IS NOT NULL THEN
    v_entry_type_enum := p_entry_type::accounting.journal_entry_type;
  END IF;
  
  RETURN QUERY
  SELECT 
    je.id,
    je.entry_number,
    je.entry_date,
    je.entry_type::TEXT,
    je.description,
    je.reference_id,
    je.reference_type,
    je.project_id,
    p.title as project_name,
    je.is_locked,
    au.full_name as created_by_name,
    je.created_at,
    COALESCE(SUM(CASE WHEN jel.debit_credit = 'DEBIT' THEN jel.amount ELSE 0 END), 0) as total_debit,
    COALESCE(SUM(CASE WHEN jel.debit_credit = 'CREDIT' THEN jel.amount ELSE 0 END), 0) as total_credit
  FROM accounting.journal_entries je
  LEFT JOIN projects.projects p ON je.project_id = p.id
  LEFT JOIN internal.authorized_users au ON je.created_by = au.id
  LEFT JOIN accounting.journal_entry_lines jel ON jel.journal_entry_id = je.id
  WHERE 
    (p_start_date IS NULL OR je.entry_date >= p_start_date)
    AND (p_end_date IS NULL OR je.entry_date <= p_end_date)
    AND (p_entry_type IS NULL OR je.entry_type = v_entry_type_enum)
    AND (p_reference_type IS NULL OR je.reference_type = p_reference_type)
    AND (p_project_id IS NULL OR je.project_id = p_project_id)
    AND (p_search IS NULL OR 
         je.description ILIKE '%' || p_search || '%' OR
         je.entry_number ILIKE '%' || p_search || '%')
  GROUP BY je.id, je.entry_number, je.entry_date, je.entry_type, je.description,
           je.reference_id, je.reference_type, je.project_id, p.title,
           je.is_locked, au.full_name, je.created_at
  ORDER BY je.entry_date DESC, je.entry_number DESC
  LIMIT p_limit
  OFFSET p_offset;
END;
$$;
ALTER FUNCTION "public"."list_journal_entries"("p_start_date" "date", "p_end_date" "date", "p_entry_type" "text", "p_reference_type" "text", "p_project_id" "uuid", "p_search" "text", "p_limit" integer, "p_offset" integer) OWNER TO "postgres";
--
-- Name: list_location_notes("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_location_notes"("p_location_id" "uuid") RETURNS TABLE("id" "uuid", "note_type" "text", "content" "text", "attachments" "text"[], "created_by" "uuid", "created_by_name" "text", "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "edited_at" timestamp with time zone, "edited_by" "uuid", "edited_by_name" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$

DECLARE

  v_user_id UUID;

BEGIN

  v_user_id := internal.get_authorized_user_id(auth.uid());

  

  -- Verificar permisos: solo el creador de la ubicaci├│n o admin/manager

  IF NOT EXISTS (

    SELECT 1 FROM crm.location loc

    WHERE loc.id = p_location_id 

    AND (loc.created_by = v_user_id OR internal.is_admin() OR internal.is_manager())

  ) THEN

    RAISE EXCEPTION 'No tienes permiso para ver las notas de esta ubicaci├│n';

  END IF;

  

  RETURN QUERY

  SELECT 

    ln.id,

    ln.note_type::TEXT,

    ln.content,

    ln.attachments,

    ln.created_by,

    au_created.full_name AS created_by_name,

    ln.created_at,

    ln.updated_at,

    ln.edited_at,

    ln.edited_by,

    au_edited.full_name AS edited_by_name

  FROM crm.location_notes ln

  LEFT JOIN internal.authorized_users au_created ON au_created.id = ln.created_by

  LEFT JOIN internal.authorized_users au_edited ON au_edited.id = ln.edited_by

  WHERE ln.location_id = p_location_id

  ORDER BY ln.created_at DESC;

END;

$$;
ALTER FUNCTION "public"."list_location_notes"("p_location_id" "uuid") OWNER TO "postgres";
