CREATE FUNCTION "public"."list_product_categories"() RETURNS TABLE("id" "uuid", "name" "text", "code" "text", "description" "text", "display_order" integer, "is_active" boolean, "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "subcategory_count" bigint, "product_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    c.id,
    c.name,
    c.code,
    c.description,
    c.display_order,
    c.is_active,
    c.created_at,
    c.updated_at,
    (SELECT COUNT(*) FROM internal.product_subcategories s WHERE s.category_id = c.id) as subcategory_count,
    (SELECT COUNT(*) FROM internal.products p WHERE p.category_id = c.id) as product_count
  FROM internal.product_categories c
  ORDER BY c.display_order, c.name;
END;
$$;
ALTER FUNCTION "public"."list_product_categories"() OWNER TO "postgres";
--
-- Name: list_product_packs("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_product_packs"("p_search" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "pack_number" "text", "name" "text", "description" "text", "base_price" numeric, "discount_percent" numeric, "final_price" numeric, "price_with_tax" numeric, "tax_rate" numeric, "product_count" bigint, "is_active" boolean, "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    pp.id,
    pp.pack_number,
    pp.name,
    pp.description,
    pp.base_price,
    pp.discount_percent,
    pp.final_price,
    ROUND(pp.final_price * (1 + pp.tax_rate / 100), 2) AS price_with_tax,
    pp.tax_rate,
    COUNT(ppi.id) AS product_count,
    pp.is_active,
    pp.created_at,
    pp.updated_at
  FROM internal.product_packs pp
  LEFT JOIN internal.product_pack_items ppi ON pp.id = ppi.pack_id
  WHERE p_search IS NULL OR p_search = '' OR 
        pp.name ILIKE '%' || p_search || '%' OR 
        pp.pack_number ILIKE '%' || p_search || '%'
  GROUP BY pp.id
  ORDER BY pp.pack_number;
END;
$$;
ALTER FUNCTION "public"."list_product_packs"("p_search" "text") OWNER TO "postgres";
--
-- Name: list_product_subcategories("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_product_subcategories"("p_category_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "category_id" "uuid", "category_name" "text", "category_code" "text", "name" "text", "code" "text", "description" "text", "display_order" integer, "is_active" boolean, "product_count" bigint, "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- Verify user is authenticated
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  RETURN QUERY
  SELECT 
    s.id,
    s.category_id,
    c.name as category_name,
    c.code as category_code,
    s.name,
    s.code,
    s.description,
    s.display_order,
    s.is_active,
    COALESCE((SELECT COUNT(*) FROM internal.products p WHERE p.subcategory_id = s.id), 0) as product_count,
    s.created_at,
    s.updated_at
  FROM internal.product_subcategories s
  JOIN internal.product_categories c ON c.id = s.category_id
  WHERE (p_category_id IS NULL OR s.category_id = p_category_id)
  ORDER BY c.display_order, c.name, s.display_order, s.name;
END;
$$;
ALTER FUNCTION "public"."list_product_subcategories"("p_category_id" "uuid") OWNER TO "postgres";
--
-- Name: list_products("text", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_products"("p_search" "text" DEFAULT NULL::"text", "p_category_id" "uuid" DEFAULT NULL::"uuid", "p_subcategory_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "product_number" "text", "category_id" "uuid", "category_name" "text", "category_code" "text", "subcategory_id" "uuid", "subcategory_name" "text", "subcategory_code" "text", "name" "text", "description" "text", "cost_price" numeric, "base_price" numeric, "price_with_tax" numeric, "tax_rate" numeric, "default_tax_id" "uuid", "is_active" boolean, "type" "public"."product_type", "stock" integer, "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    p.id,
    p.product_number,
    p.category_id,
    c.name AS category_name,
    c.code AS category_code,
    p.subcategory_id,
    s.name AS subcategory_name,
    s.code AS subcategory_code,
    p.name,
    p.description,
    p.cost_price,
    p.base_price,
    ROUND(p.base_price * (1 + COALESCE(t.rate, p.tax_rate, 21) / 100), 2) AS price_with_tax,
    COALESCE(t.rate, p.tax_rate, 21) AS tax_rate,
    p.default_tax_id,
    p.is_active,
    p.type,
    p.stock,
    p.created_at,
    p.updated_at
  FROM internal.products p
  LEFT JOIN internal.product_categories c ON p.category_id = c.id
  LEFT JOIN internal.product_subcategories s ON p.subcategory_id = s.id
  LEFT JOIN internal.taxes t ON p.default_tax_id = t.id
  WHERE 
    (p_search IS NULL OR p.name ILIKE '%' || p_search || '%' OR p.product_number ILIKE '%' || p_search || '%')
    AND (p_category_id IS NULL OR p.category_id = p_category_id)
    AND (p_subcategory_id IS NULL OR p.subcategory_id = p_subcategory_id)
  ORDER BY p.product_number;
END;
$$;
ALTER FUNCTION "public"."list_products"("p_search" "text", "p_category_id" "uuid", "p_subcategory_id" "uuid") OWNER TO "postgres";
