CREATE FUNCTION "public"."list_project_purchase_orders"("p_project_id" "uuid") RETURNS TABLE("id" "uuid", "po_number" "text", "supplier_name" "text", "technician_name" "text", "status" "text", "issue_date" "date", "expected_start_date" "date", "expected_end_date" "date", "subtotal" numeric, "total" numeric, "linked_purchase_invoice_id" "uuid", "linked_invoice_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        po.id,
        po.po_number,
        po.supplier_name,
        COALESCE(t.contact_name, t.company_name) AS technician_name,
        po.status::TEXT,
        po.issue_date,
        po.expected_start_date,
        po.expected_end_date,
        po.subtotal,
        po.total,
        po.linked_purchase_invoice_id,
        pi.internal_purchase_number AS linked_invoice_number
    FROM sales.purchase_orders po
    LEFT JOIN internal.technicians t ON po.technician_id = t.id
    LEFT JOIN sales.purchase_invoices pi ON po.linked_purchase_invoice_id = pi.id
    WHERE po.project_id = p_project_id
    ORDER BY po.created_at DESC;
END;
$$;
