--
-- Name: list_project_quotes("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_project_quotes"("p_project_id" "uuid") RETURNS TABLE("id" "uuid", "quote_number" "text", "client_id" "uuid", "client_name" "text", "project_id" "uuid", "project_number" "text", "project_name" "text", "order_number" "text", "status" "text", "subtotal" numeric, "tax_amount" numeric, "total" numeric, "valid_until" "date", "created_at" timestamp with time zone, "created_by" "uuid", "created_by_name" "text", "site_id" "uuid", "site_name" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    IF internal.get_authorized_user_id(auth.uid()) IS NULL THEN
        RAISE EXCEPTION 'User not authorized';
    END IF;

    RETURN QUERY
    SELECT 
        q.id,
        q.quote_number,
        q.client_id,
        c.company_name AS client_name,
        q.project_id,
        p.project_number,
        COALESCE(p.project_name, q.project_name) AS project_name,
        q.order_number,
        q.status::TEXT,
        q.subtotal,
        q.tax_amount,
        q.total,
        q.valid_until,
        q.created_at,
        q.created_by,
        COALESCE(u.full_name, 'Sistema') AS created_by_name,
        q.site_id,
        ps.site_name
    FROM quotes.quotes q
    LEFT JOIN crm.clients c ON q.client_id = c.id
    LEFT JOIN projects.projects p ON q.project_id = p.id
    LEFT JOIN internal.authorized_users u ON q.created_by = u.id
    LEFT JOIN projects.project_sites ps ON q.site_id = ps.id
    WHERE q.project_id = p_project_id
    ORDER BY q.created_at DESC;
END;
$$;
ALTER FUNCTION "public"."list_project_quotes"("p_project_id" "uuid") OWNER TO "postgres";
--
-- Name: list_project_sites("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_project_sites"("p_project_id" "uuid") RETURNS TABLE("id" "uuid", "project_id" "uuid", "site_name" "text", "site_reference" "text", "address" "text", "city" "text", "postal_code" "text", "province" "text", "country" "text", "contact_name" "text", "contact_phone" "text", "contact_email" "text", "notes" "text", "floor_area" "text", "latitude" double precision, "longitude" double precision, "is_default" boolean, "is_active" boolean, "planned_start_date" "date", "planned_end_date" "date", "planned_days" integer, "actual_start_at" timestamp with time zone, "actual_end_at" timestamp with time zone, "site_status" "text", "assignment_count" bigint, "visit_count" bigint, "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'sales', 'accounting', 'internal', 'crm', 'quotes'
    AS $$
DECLARE
  v_default_site_id UUID;
BEGIN
  -- Get the project's default_site_id
  SELECT p.default_site_id INTO v_default_site_id
  FROM projects.projects p WHERE p.id = p_project_id;

  RETURN QUERY
  SELECT
    ps.id, ps.project_id, ps.site_name, ps.site_reference,
    ps.address, ps.city, ps.postal_code, ps.province, ps.country,
    ps.contact_name, ps.contact_phone, ps.contact_email,
    ps.notes, ps.floor_area, ps.latitude, ps.longitude,
    (ps.id = v_default_site_id) AS is_default, ps.is_active,
    ps.planned_start_date, ps.planned_end_date, ps.planned_days,
    ps.actual_start_at, ps.actual_end_at, ps.site_status,
    (SELECT count(*) FROM projects.site_technician_assignments a WHERE a.site_id = ps.id)::BIGINT AS assignment_count,
    (SELECT count(*) FROM projects.site_visits v WHERE v.site_id = ps.id)::BIGINT AS visit_count,
    ps.created_at, ps.updated_at
  FROM projects.project_sites ps
  WHERE ps.project_id = p_project_id
  ORDER BY ps.is_active DESC, ps.site_name;
END;
$$;
ALTER FUNCTION "public"."list_project_sites"("p_project_id" "uuid") OWNER TO "postgres";
--
-- Name: list_project_technicians("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_project_technicians"("p_project_id" "uuid") RETURNS TABLE("technician_id" "uuid", "technician_number" "text", "technician_name" "text", "technician_type" "text", "technician_tax_id" "text", "total_invoiced" numeric, "invoice_count" bigint, "last_invoice_date" "date", "first_invoice_date" "date")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        t.id as technician_id,
        t.technician_number,
        t.company_name as technician_name,
        t.type::TEXT as technician_type,
        t.tax_id as technician_tax_id,
        COALESCE(SUM(pi.total), 0) as total_invoiced,
        COUNT(pi.id) as invoice_count,
        MAX(pi.issue_date) as last_invoice_date,
        MIN(pi.issue_date) as first_invoice_date
    FROM sales.purchase_invoices pi
    INNER JOIN internal.technicians t ON pi.technician_id = t.id
    WHERE pi.project_id = p_project_id
      AND pi.technician_id IS NOT NULL
      AND pi.supplier_id IS NULL  -- Solo t├®cnicos, no proveedores
    GROUP BY t.id, t.technician_number, t.company_name, t.type, t.tax_id
    ORDER BY total_invoiced DESC, last_invoice_date DESC;
END;
$$;
ALTER FUNCTION "public"."list_project_technicians"("p_project_id" "uuid") OWNER TO "postgres";
--
-- Name: list_projects("text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_projects"("p_status" "text" DEFAULT NULL::"text", "p_search" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "project_number" "text", "client_id" "uuid", "client_name" "text", "status" "text", "project_address" "text", "project_city" "text", "client_order_number" "text", "local_name" "text", "project_name" "text", "created_by" "uuid", "created_by_name" "text", "created_at" timestamp with time zone, "assigned_to_name" "text", "budget" numeric, "site_mode" "text", "default_site_id" "uuid")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'sales', 'accounting', 'internal', 'crm', 'quotes'
    AS $$
  SELECT
    p.id,
    p.project_number,
    p.client_id,
    c.company_name as client_name,
    p.status::text,
    p.description as project_address,
    p.project_city,
    p.client_order_number,
    p.local_name,
    COALESCE(p.project_name, p.title) as project_name,
    p.created_by,
    au.full_name as created_by_name,
    p.created_at,
    assigned_au.full_name as assigned_to_name,
    COALESCE((
      SELECT SUM(q.subtotal)
      FROM quotes.quotes q
      WHERE q.project_id = p.id
        AND q.status NOT IN ('REJECTED', 'EXPIRED')
    ), 0) as budget,
    p.site_mode::text,
    p.default_site_id
  FROM projects.projects p
  LEFT JOIN crm.clients c ON c.id = p.client_id
  LEFT JOIN internal.authorized_users au ON au.id = p.created_by
  LEFT JOIN internal.authorized_users assigned_au ON assigned_au.id = p.assigned_to
  WHERE p.deleted_at IS NULL
    AND (p_status IS NULL OR p.status::text = p_status)
    AND (p_search IS NULL OR
         p.project_number ILIKE '%' || p_search || '%' OR
         COALESCE(p.project_name, p.title) ILIKE '%' || p_search || '%' OR
         c.company_name ILIKE '%' || p_search || '%' OR
         p.local_name ILIKE '%' || p_search || '%' OR
         p.client_order_number ILIKE '%' || p_search || '%')
  ORDER BY p.project_number DESC;
$$;
ALTER FUNCTION "public"."list_projects"("p_status" "text", "p_search" "text") OWNER TO "postgres";
--
-- Name: list_purchase_invoices("text", "text", "uuid", "uuid", "text", "uuid", integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_purchase_invoices"("p_search" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT NULL::"text", "p_supplier_id" "uuid" DEFAULT NULL::"uuid", "p_technician_id" "uuid" DEFAULT NULL::"uuid", "p_document_type" "text" DEFAULT NULL::"text", "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_page" integer DEFAULT 1, "p_page_size" integer DEFAULT 10) RETURNS TABLE("id" "uuid", "invoice_number" "text", "internal_purchase_number" "text", "document_type" "text", "issue_date" "date", "due_date" "date", "subtotal" numeric, "tax_amount" numeric, "retention_amount" numeric, "total" numeric, "paid_amount" numeric, "pending_amount" numeric, "status" "text", "provider_id" "uuid", "provider_name" "text", "provider_type" "text", "provider_tax_id" "text", "file_path" "text", "project_id" "uuid", "project_name" "text", "project_number" "text", "is_locked" boolean, "created_at" timestamp with time zone, "total_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_offset INTEGER;
BEGIN
  v_offset := (p_page - 1) * p_page_size;
  RETURN QUERY
  WITH filtered_invoices AS (
    SELECT
      pi.*,
      COALESCE(s.company_name, t.company_name, NULLIF(trim(pi.manual_beneficiary_name), '')) AS provider_name,
      CASE
        WHEN pi.supplier_id IS NOT NULL THEN 'SUPPLIER'
        WHEN pi.technician_id IS NOT NULL THEN 'TECHNICIAN'
        ELSE 'OTHER'
      END AS provider_type,
      COALESCE(s.tax_id, t.tax_id) AS provider_tax_id,
      COALESCE(p.project_name, p.title) AS proj_name,
      p.project_number AS proj_number
    FROM sales.purchase_invoices pi
    LEFT JOIN internal.suppliers s ON pi.supplier_id = s.id
    LEFT JOIN internal.technicians t ON pi.technician_id = t.id
    LEFT JOIN projects.projects p ON pi.project_id = p.id
    WHERE
      (p_search IS NULL OR
       pi.invoice_number ILIKE '%' || p_search || '%' OR
       pi.internal_purchase_number ILIKE '%' || p_search || '%' OR
       s.company_name ILIKE '%' || p_search || '%' OR
       t.company_name ILIKE '%' || p_search || '%' OR
       pi.manual_beneficiary_name ILIKE '%' || p_search || '%')
      AND (p_status IS NULL OR pi.status = p_status)
      AND (p_supplier_id IS NULL OR pi.supplier_id = p_supplier_id)
      AND (p_technician_id IS NULL OR pi.technician_id = p_technician_id)
      AND (p_project_id IS NULL OR pi.project_id = p_project_id)
      AND (
        p_document_type IS NULL
        OR pi.document_type = p_document_type
        OR (p_document_type = 'EXPENSE' AND pi.document_type IN ('TICKET', 'EXPENSE'))
      )
  )
  SELECT
    fi.id,
    fi.invoice_number,
    fi.internal_purchase_number,
    CASE WHEN fi.document_type = 'TICKET' THEN 'EXPENSE'::TEXT ELSE fi.document_type END,
    fi.issue_date,
    fi.due_date,
    fi.subtotal,
    fi.tax_amount,
    fi.retention_amount,
    fi.total,
    fi.paid_amount,
    fi.pending_amount,
    fi.status,
    COALESCE(fi.supplier_id, fi.technician_id) AS provider_id,
    fi.provider_name,
    fi.provider_type,
    fi.provider_tax_id,
    fi.file_path,
    fi.project_id,
    fi.proj_name AS project_name,
    fi.proj_number AS project_number,
    fi.is_locked,
    fi.created_at,
    (SELECT COUNT(*)::BIGINT FROM filtered_invoices) AS total_count
  FROM filtered_invoices fi
  ORDER BY fi.issue_date DESC NULLS LAST, fi.created_at DESC NULLS LAST
  LIMIT p_page_size
  OFFSET v_offset;
END;
$$;
ALTER FUNCTION "public"."list_purchase_invoices"("p_search" "text", "p_status" "text", "p_supplier_id" "uuid", "p_technician_id" "uuid", "p_document_type" "text", "p_project_id" "uuid", "p_page" integer, "p_page_size" integer) OWNER TO "postgres";
--
-- Name: list_purchase_orders("text", "text", "uuid", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_purchase_orders"("p_search" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT NULL::"text", "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_supplier_id" "uuid" DEFAULT NULL::"uuid", "p_technician_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "po_number" "text", "supplier_id" "uuid", "supplier_name" "text", "technician_id" "uuid", "technician_name" "text", "project_id" "uuid", "project_number" "text", "project_name" "text", "client_name" "text", "status" "text", "issue_date" "date", "expected_start_date" "date", "expected_end_date" "date", "subtotal" numeric, "total" numeric, "linked_purchase_invoice_id" "uuid", "linked_invoice_number" "text", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        po.id,
        po.po_number,
        po.supplier_id,
        po.supplier_name,
        po.technician_id,
        COALESCE(t.contact_name, t.company_name) AS technician_name,
        po.project_id,
        p.project_number,
        p.project_name,
        c.company_name AS client_name,
        po.status::TEXT,
        po.issue_date,
        po.expected_start_date,
        po.expected_end_date,
        po.subtotal,
        po.total,
        po.linked_purchase_invoice_id,
        pi.internal_purchase_number AS linked_invoice_number,
        po.created_at
    FROM sales.purchase_orders po
    LEFT JOIN projects.projects p ON po.project_id = p.id
    LEFT JOIN crm.clients c ON p.client_id = c.id
    LEFT JOIN internal.technicians t ON po.technician_id = t.id
    LEFT JOIN sales.purchase_invoices pi ON po.linked_purchase_invoice_id = pi.id
    WHERE (p_status IS NULL OR po.status::TEXT = p_status)
      AND (p_project_id IS NULL OR po.project_id = p_project_id)
      AND (p_supplier_id IS NULL OR po.supplier_id = p_supplier_id)
      AND (p_technician_id IS NULL OR po.technician_id = p_technician_id)
      AND (
          p_search IS NULL 
          OR po.po_number ILIKE '%' || p_search || '%'
          OR po.supplier_name ILIKE '%' || p_search || '%'
          OR p.project_number ILIKE '%' || p_search || '%'
          OR p.project_name ILIKE '%' || p_search || '%'
          OR t.company_name ILIKE '%' || p_search || '%'
          OR t.contact_name ILIKE '%' || p_search || '%'
      )
    ORDER BY po.created_at DESC;
END;
$$;
ALTER FUNCTION "public"."list_purchase_orders"("p_search" "text", "p_status" "text", "p_project_id" "uuid", "p_supplier_id" "uuid", "p_technician_id" "uuid") OWNER TO "postgres";
