-- Name: list_quote_activity("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_quote_activity"("p_quote_id" "uuid", "p_limit" integer DEFAULT 50) RETURNS TABLE("id" "uuid", "activity_type" "text", "content" "text", "metadata" "jsonb", "created_by" "uuid", "created_by_name" "text", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    qa.id, qa.activity_type, qa.content, qa.metadata,
    qa.created_by, qa.created_by_name, qa.created_at
  FROM quotes.quote_activity qa
  WHERE qa.quote_id = p_quote_id
  ORDER BY qa.created_at DESC
  LIMIT p_limit;
END;
$$;
ALTER FUNCTION "public"."list_quote_activity"("p_quote_id" "uuid", "p_limit" integer) OWNER TO "postgres";
--
-- Name: list_quotes("text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_quotes"("p_search" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "quote_number" "text", "client_id" "uuid", "client_name" "text", "project_id" "uuid", "project_name" "text", "project_number" "text", "order_number" "text", "project_client_order_number" "text", "status" "text", "subtotal" numeric, "tax_amount" numeric, "total" numeric, "valid_until" "date", "issue_date" "date", "created_by" "uuid", "created_by_name" "text", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF internal.get_authorized_user_id(auth.uid()) IS NULL THEN
    RAISE EXCEPTION 'User not authorized';
  END IF;

  PERFORM quotes.expire_overdue_quotes();
  PERFORM quotes.delete_stale_drafts();

  RETURN QUERY
  SELECT 
    q.id,
    q.quote_number,
    q.client_id,
    c.company_name AS client_name,
    q.project_id,
    COALESCE(p.project_name, q.project_name) AS project_name,
    p.project_number,
    q.order_number,
    p.client_order_number AS project_client_order_number,
    q.status::TEXT,
    q.subtotal,
    q.tax_amount,
    q.total,
    q.valid_until,
    q.issue_date,
    q.created_by,
    COALESCE(u.full_name, 'Sistema') AS created_by_name,
    q.created_at
  FROM quotes.quotes q
  LEFT JOIN crm.clients c ON q.client_id = c.id
  LEFT JOIN projects.projects p ON q.project_id = p.id
  LEFT JOIN internal.authorized_users u ON q.created_by = u.id
  WHERE 
    (p_search IS NULL OR 
     q.quote_number ILIKE '%' || p_search || '%' OR
     c.company_name ILIKE '%' || p_search || '%' OR
     COALESCE(p.project_name, q.project_name) ILIKE '%' || p_search || '%')
    AND (p_status IS NULL OR q.status = p_status::quotes.quote_status)
  ORDER BY q.created_at DESC;
END;
$$;
ALTER FUNCTION "public"."list_quotes"("p_search" "text", "p_status" "text") OWNER TO "postgres";
