--
-- Name: list_sales_archive_incidents(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_sales_archive_incidents"() RETURNS TABLE("document_type" "text", "document_id" "uuid", "document_number" "text", "status" "text", "issue_date" "date", "archived_pdf_path" "text", "sharepoint_item_id" "text", "archived_pdf_generated_at" timestamp with time zone, "archived_pdf_last_synced_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'sales', 'quotes', 'internal'
    AS $$
BEGIN
  IF auth.uid() IS NULL OR NOT (internal.is_admin() OR internal.is_manager() OR internal.is_readonly()) THEN
    RAISE EXCEPTION 'Access denied';
  END IF;

  RETURN QUERY
  SELECT
    'invoice'::TEXT,
    i.id,
    COALESCE(i.invoice_number, i.preliminary_number, i.id::TEXT),
    i.status::TEXT,
    i.issue_date,
    i.archived_pdf_path,
    i.sharepoint_item_id,
    i.archived_pdf_generated_at,
    i.archived_pdf_last_synced_at
  FROM sales.invoices i
  WHERE i.status IN ('ISSUED', 'PARTIAL', 'PAID', 'OVERDUE', 'CANCELLED', 'RECTIFIED')
    AND (
      COALESCE(i.archived_pdf_path, '') = ''
      OR COALESCE(i.sharepoint_item_id, '') = ''
      OR COALESCE(i.archived_pdf_hash, '') = ''
    )

  UNION ALL

  SELECT
    'quote'::TEXT,
    q.id,
    COALESCE(q.quote_number, q.preliminary_number, q.id::TEXT),
    q.status::TEXT,
    q.issue_date,
    q.archived_pdf_path,
    q.sharepoint_item_id,
    q.archived_pdf_generated_at,
    q.archived_pdf_last_synced_at
  FROM quotes.quotes q
  WHERE q.status IN ('SENT', 'APPROVED', 'REJECTED', 'EXPIRED', 'INVOICED')
    AND (
      COALESCE(q.archived_pdf_path, '') = ''
      OR COALESCE(q.sharepoint_item_id, '') = ''
      OR COALESCE(q.archived_pdf_hash, '') = ''
    )

  ORDER BY issue_date DESC NULLS LAST, document_type, document_number;
END;
$$;
ALTER FUNCTION "public"."list_sales_archive_incidents"() OWNER TO "postgres";
