-- Name: list_site_assignments("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_site_assignments"("p_site_id" "uuid") RETURNS TABLE("id" "uuid", "site_id" "uuid", "technician_id" "uuid", "technician_name" "text", "technician_number" "text", "role" "text", "date_from" "date", "date_to" "date", "notes" "text", "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    a.id, a.site_id, a.technician_id,
    COALESCE(t.company_name, '')::TEXT AS technician_name,
    COALESCE(t.technician_number, '')::TEXT AS technician_number,
    a.role, a.date_from, a.date_to, a.notes, a.created_at
  FROM projects.site_technician_assignments a
  LEFT JOIN workers.technicians t ON t.id = a.technician_id
  WHERE a.site_id = p_site_id
  ORDER BY a.date_from NULLS LAST, a.created_at;
END;
$$;
