--
-- Name: list_suppliers("text", "text", "text", integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_suppliers"("p_search" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT NULL::"text", "p_category" "text" DEFAULT NULL::"text", "p_page" integer DEFAULT 1, "p_page_size" integer DEFAULT 100) RETURNS TABLE("id" "uuid", "supplier_number" "text", "company_name" "text", "legal_name" "text", "tax_id" "text", "contact_name" "text", "phone" "text", "email" "text", "city" "text", "province" "text", "payment_terms" "text", "status" "text", "category" "text", "created_at" timestamp with time zone, "total_count" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_offset INTEGER;
BEGIN
  v_offset := (p_page - 1) * p_page_size;

  RETURN QUERY
  WITH filtered_suppliers AS (
    SELECT s.*
    FROM internal.suppliers s  -- Referencia expl├¡cita al schema internal
    WHERE
      (p_search IS NULL OR p_search = '' OR
       s.company_name ILIKE '%' || p_search || '%' OR
       s.tax_id ILIKE '%' || p_search || '%' OR
       s.supplier_number ILIKE '%' || p_search || '%' OR
       COALESCE(s.contact_email, '') ILIKE '%' || p_search || '%' OR
       COALESCE(s.contact_phone, '') ILIKE '%' || p_search || '%')
      AND (p_status IS NULL OR p_status = '' OR s.status = p_status)
      AND (p_category IS NULL OR p_category = '' OR s.category = p_category)
  )
  SELECT
    s.id,
    s.supplier_number,
    s.company_name,
    NULL::TEXT as legal_name,
    s.tax_id,
    NULL::TEXT as contact_name,
    s.contact_phone as phone,
    s.contact_email as email,
    s.city,
    s.province,
    s.payment_terms,
    s.status,
    s.category,
    s.created_at,
    (SELECT COUNT(*) FROM filtered_suppliers) as total_count
  FROM filtered_suppliers s
  ORDER BY s.company_name ASC
  LIMIT p_page_size
  OFFSET v_offset;
END;
$$;
ALTER FUNCTION "public"."list_suppliers"("p_search" "text", "p_status" "text", "p_category" "text", "p_page" integer, "p_page_size" integer) OWNER TO "postgres";
