-- Name: list_technicians("text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_technicians"("p_search" "text" DEFAULT NULL::"text", "p_type" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT NULL::"text", "p_specialty" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "technician_number" "text", "type" "text", "company_name" "text", "legal_name" "text", "tax_id" "text", "contact_name" "text", "contact_phone" "text", "contact_email" "text", "city" "text", "province" "text", "specialties" "text"[], "hourly_rate" numeric, "daily_rate" numeric, "status" "text", "rating" integer, "created_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        t.id,
        t.technician_number,
        t.type::TEXT,
        t.company_name,
        t.legal_name,
        t.tax_id,
        t.contact_name,
        t.contact_phone,
        t.contact_email,
        t.city,
        t.province,
        t.specialties,
        t.hourly_rate,
        t.daily_rate,
        t.status::TEXT,
        t.rating,
        t.created_at
    FROM internal.technicians t
    WHERE 
        (p_search IS NULL OR p_search = '' OR 
            t.company_name ILIKE '%' || p_search || '%' OR
            t.legal_name ILIKE '%' || p_search || '%' OR
            t.tax_id ILIKE '%' || p_search || '%' OR
            t.contact_name ILIKE '%' || p_search || '%' OR
            t.technician_number ILIKE '%' || p_search || '%' OR
            t.contact_email ILIKE '%' || p_search || '%')
        AND (p_type IS NULL OR p_type = '' OR t.type::TEXT = p_type)
        AND (p_status IS NULL OR p_status = '' OR t.status::TEXT = p_status)
        AND (p_specialty IS NULL OR p_specialty = '' OR p_specialty = ANY(t.specialties))
    ORDER BY t.created_at DESC;
END;
$$;
ALTER FUNCTION "public"."list_technicians"("p_search" "text", "p_type" "text", "p_status" "text", "p_specialty" "text") OWNER TO "postgres";
