-- Name: list_technicians_for_map("text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_technicians_for_map"("p_type" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT NULL::"text", "p_specialty" "text" DEFAULT NULL::"text") RETURNS TABLE("id" "uuid", "technician_number" "text", "type" "text", "company_name" "text", "contact_name" "text", "contact_phone" "text", "contact_email" "text", "address" "text", "city" "text", "latitude" numeric, "longitude" numeric, "specialties" "text"[], "status" "text", "rating" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        t.id,
        t.technician_number,
        t.type::TEXT,
        t.company_name,
        t.contact_name,
        t.contact_phone,
        t.contact_email,
        t.address,
        t.city,
        t.latitude,
        t.longitude,
        t.specialties,
        t.status::TEXT,
        t.rating
    FROM internal.technicians t
    WHERE 
        t.latitude IS NOT NULL 
        AND t.longitude IS NOT NULL
        AND (p_type IS NULL OR p_type = '' OR t.type::TEXT = p_type)
        AND (p_status IS NULL OR p_status = '' OR t.status::TEXT = p_status)
        AND (p_specialty IS NULL OR p_specialty = '' OR p_specialty = ANY(t.specialties))
    ORDER BY t.company_name;
END;
$$;
ALTER FUNCTION "public"."list_technicians_for_map"("p_type" "text", "p_status" "text", "p_specialty" "text") OWNER TO "postgres";
--
-- Name: list_user_canvassing_locations("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_user_canvassing_locations"("p_user_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "status" "text", "company_name" "text", "address" "text", "city" "text", "province" "text", "postal_code" "text", "latitude" numeric, "longitude" numeric, "contact_first_name" "text", "contact_last_name" "text", "contact_phone_primary" "text", "contact_email_primary" "text", "priority" "text", "lead_score" integer, "appointment_date" "date", "callback_date" "date", "created_at" timestamp with time zone, "updated_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$

DECLARE

  v_user_id UUID;

BEGIN

  -- Si no se proporciona user_id, usar el del usuario autenticado

  v_user_id := COALESCE(p_user_id, internal.get_authorized_user_id(auth.uid()));

  

  -- Verificar permisos: solo el propio usuario o admin/manager

  IF v_user_id != internal.get_authorized_user_id(auth.uid()) AND 

     NOT (internal.is_admin() OR internal.is_manager()) THEN

    RAISE EXCEPTION 'No tienes permiso para ver estos puntos de Canvassing';

  END IF;

  

  RETURN QUERY

  SELECT 

    l.id,

    l.status::TEXT,

    l.company_name,

    l.address,

    l.city,

    l.province,

    l.postal_code,

    l.latitude,

    l.longitude,

    l.contact_first_name,

    l.contact_last_name,

    l.contact_phone_primary,

    l.contact_email_primary,

    l.priority::TEXT,

    l.lead_score,

    l.appointment_date,

    l.callback_date,

    l.created_at,

    l.updated_at

  FROM crm.location l

  WHERE l.created_by = v_user_id

  ORDER BY l.created_at DESC;

END;

$$;
ALTER FUNCTION "public"."list_user_canvassing_locations"("p_user_id" "uuid") OWNER TO "postgres";
--
-- Name: list_workers(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."list_workers"() RETURNS TABLE("id" "uuid", "full_name" "text", "email" "text", "phone" "text", "department" "text", "job_position" "text", "is_active" boolean, "created_at" timestamp with time zone, "last_login_at" timestamp with time zone, "worker_type" "text", "tax_id" "text", "iban" "text", "irpf_rate" numeric, "ss_regime" "text", "linked_partner_id" "uuid", "linked_partner_number" "text", "linked_employee_id" "uuid", "linked_employee_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    au.id,
    au.full_name,
    au.email,
    au.phone,
    au.department::text,
    au.job_position,
    au.is_active,
    au.created_at,
    au.last_login_at,
    au.worker_type,
    au.tax_id,
    au.iban,
    COALESCE(au.irpf_rate, 19) as irpf_rate,
    COALESCE(au.ss_regime, 'RETA') as ss_regime,
    au.linked_partner_id,
    p.partner_number as linked_partner_number,
    au.linked_employee_id,
    e.employee_number as linked_employee_number
  FROM internal.authorized_users au
  LEFT JOIN internal.partners p ON p.id = au.linked_partner_id
  LEFT JOIN internal.employees e ON e.id = au.linked_employee_id
  WHERE au.is_active = true
  ORDER BY au.full_name;
END;
$$;
ALTER FUNCTION "public"."list_workers"() OWNER TO "postgres";
--
-- Name: mark_current_user_otp_verified(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."mark_current_user_otp_verified"() RETURNS timestamp with time zone
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal', 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_verified_at TIMESTAMPTZ := now();
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());

  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'User not authorized';
  END IF;

  UPDATE internal.authorized_users
  SET
    last_otp_verified_at = v_verified_at,
    updated_at = now()
  WHERE id = v_user_id;

  RETURN v_verified_at;
END;
$$;
ALTER FUNCTION "public"."mark_current_user_otp_verified"() OWNER TO "postgres";
