--
-- Name: pay_partner_compensation_run("uuid", "uuid", "text", numeric, "date", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."pay_partner_compensation_run"("p_compensation_run_id" "uuid", "p_bank_account_id" "uuid", "p_bank_name" "text", "p_amount" numeric, "p_payment_date" "date" DEFAULT CURRENT_DATE, "p_payment_method" "text" DEFAULT 'TRANSFER'::"text", "p_notes" "text" DEFAULT NULL::"text") RETURNS TABLE("payment_id" "uuid", "entry_id" "uuid", "entry_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_comp RECORD;
  v_bank_code TEXT;
  v_entry_id UUID;
  v_entry_number TEXT;
  v_payment_id UUID;
  v_new_paid NUMERIC;
  v_new_status TEXT;
  v_user_id UUID;
  v_partner_account_code TEXT;
  v_partner_number_digits INT;
  v_payment_number TEXT;
  v_year INT;
  v_month INT;
  v_day INT;
  v_number INT;
  v_company_bank_id UUID;
BEGIN
  SELECT pcr.*, p.full_name AS partner_name, p.partner_number
  INTO v_comp
  FROM internal.partner_compensation_runs pcr
  JOIN internal.partners p ON p.id = pcr.partner_id
  WHERE pcr.id = p_compensation_run_id;
  
  IF v_comp IS NULL THEN
    RAISE EXCEPTION 'Retribuci├│n no encontrada';
  END IF;
  
  IF v_comp.status NOT IN ('POSTED', 'PARTIAL') THEN
    RAISE EXCEPTION 'La retribuci├│n debe estar en estado POSTED o PARTIAL';
  END IF;
  
  SELECT id, accounting_code INTO v_company_bank_id, v_bank_code
  FROM internal.company_bank_accounts
  WHERE id = p_bank_account_id;
  
  IF v_bank_code IS NULL THEN
    SELECT account_code INTO v_bank_code
    FROM accounting.chart_of_accounts
    WHERE description LIKE '%[ID:' || p_bank_account_id::TEXT || ']%' AND is_active = true;
    v_company_bank_id := NULL;
  END IF;
  
  IF v_bank_code IS NULL THEN
    RAISE EXCEPTION 'Cuenta bancaria no encontrada';
  END IF;
  
  v_partner_number_digits := REGEXP_REPLACE(v_comp.partner_number, '[^0-9]', '', 'g')::INTEGER;
  v_partner_account_code := '465' || LPAD(v_partner_number_digits::TEXT, 3, '0');
  v_user_id := internal.get_authorized_user_id(auth.uid());
  
  v_entry_number := accounting.get_next_entry_number();
  
  INSERT INTO accounting.journal_entries (
    entry_number,
    entry_date,
    entry_type,
    description,
    reference_type,
    reference_id,
    is_automatic,
    created_by
  ) VALUES (
    v_entry_number,
    p_payment_date,
    'PAYMENT_MADE'::accounting.journal_entry_type,
    'Pago retribuci├│n ' || v_comp.compensation_number || ' - ' || v_comp.partner_name,
    'PARTNER_COMPENSATION_PAYMENT',
    p_compensation_run_id,
    TRUE,
    v_user_id
  )
  RETURNING accounting.journal_entries.id INTO v_entry_id;
  
  INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, description, debit_credit, amount, line_order)
  VALUES
    (v_entry_id, v_partner_account_code, 'Pago retribuci├│n ' || v_comp.partner_name, 'DEBIT', p_amount, 1),
    (v_entry_id, v_bank_code, 'Pago desde ' || p_bank_name, 'CREDIT', p_amount, 2);
  
  v_year := EXTRACT(YEAR FROM p_payment_date);
  v_month := EXTRACT(MONTH FROM p_payment_date);
  v_day := EXTRACT(DAY FROM p_payment_date);
  SELECT COALESCE(MAX(CAST(SUBSTRING(payment_number FROM '[0-9]+$') AS INTEGER)), 0) + 1
  INTO v_number
  FROM accounting.payroll_payments
  WHERE payment_number ~ ('^PAG-NOM-' || v_year || LPAD(v_month::TEXT, 2, '0') || LPAD(v_day::TEXT, 2, '0') || '-[0-9]+$');
  v_payment_number := 'PAG-NOM-' || v_year || LPAD(v_month::TEXT, 2, '0') || LPAD(v_day::TEXT, 2, '0') || '-' || LPAD(v_number::TEXT, 4, '0');
  
  INSERT INTO accounting.payroll_payments (
    payment_number,
    partner_compensation_run_id,
    payment_date,
    amount,
    payment_method,
    notes,
    journal_entry_id,
    company_bank_account_id,
    created_by
  ) VALUES (
    v_payment_number,
    p_compensation_run_id,
    p_payment_date,
    p_amount,
    p_payment_method,
    p_notes,
    v_entry_id,
    v_company_bank_id,
    v_user_id
  )
  RETURNING id INTO v_payment_id;
  
  v_new_paid := COALESCE(v_comp.paid_amount, 0) + p_amount;
  
  IF v_new_paid >= v_comp.net_amount THEN
    v_new_status := 'PAID';
  ELSE
    v_new_status := 'PARTIAL';
  END IF;
  
  UPDATE internal.partner_compensation_runs
  SET paid_amount = v_new_paid, status = v_new_status, updated_at = NOW()
  WHERE id = p_compensation_run_id;
  
  RETURN QUERY SELECT v_payment_id, v_entry_id, v_entry_number;
END;
$_$;
ALTER FUNCTION "public"."pay_partner_compensation_run"("p_compensation_run_id" "uuid", "p_bank_account_id" "uuid", "p_bank_name" "text", "p_amount" numeric, "p_payment_date" "date", "p_payment_method" "text", "p_notes" "text") OWNER TO "postgres";
--
-- Name: payroll_calculate_partner_compensation("uuid", integer, integer, numeric, numeric, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."payroll_calculate_partner_compensation"("p_partner_id" "uuid", "p_year" integer, "p_month" integer, "p_base_amount" numeric, "p_irpf_rate" numeric DEFAULT 19.0, "p_dry_run" boolean DEFAULT true) RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'accounting', 'internal'
    AS $$
DECLARE
  v_user_id UUID;
  v_is_locked BOOLEAN;
  v_pnl_basis JSON;
  v_irpf_amount NUMERIC;
  v_net_amount NUMERIC;
  v_gross_amount NUMERIC;
  v_comp_id UUID;
  v_comp_number TEXT;
  v_year_seq INTEGER;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;

  -- Verify period is locked
  SELECT pc.is_locked INTO v_is_locked
  FROM accounting.period_closures pc
  WHERE pc.year = p_year AND pc.month = p_month;

  IF v_is_locked IS NULL OR v_is_locked = false THEN
    RAISE EXCEPTION 'El periodo %/% no est├í cerrado y bloqueado. Cierre el periodo antes de calcular n├│minas.', p_month, p_year;
  END IF;

  -- Get P&L basis for traceability
  v_pnl_basis := payroll_get_partner_compensation_basis(p_year, p_month);

  v_gross_amount := p_base_amount;
  v_irpf_amount := ROUND(v_gross_amount * (p_irpf_rate / 100.0), 2);
  v_net_amount := v_gross_amount - v_irpf_amount;

  IF p_dry_run THEN
    RETURN json_build_object(
      'dry_run', true,
      'partner_id', p_partner_id,
      'year', p_year,
      'month', p_month,
      'gross_amount', v_gross_amount,
      'base_amount', p_base_amount,
      'irpf_rate', p_irpf_rate,
      'irpf_amount', v_irpf_amount,
      'net_amount', v_net_amount,
      'pnl_net_profit', (v_pnl_basis->>'net_profit')::numeric,
      'period_locked', true
    );
  END IF;

  -- Generate compensation number
  INSERT INTO audit.sequence_counters (prefix, year, current_number, last_generated_at)
  VALUES ('COMP', p_year, 1, now())
  ON CONFLICT (prefix, year) DO UPDATE
  SET current_number = audit.sequence_counters.current_number + 1,
      last_generated_at = now()
  RETURNING current_number INTO v_year_seq;

  v_comp_number := 'NP-' || RIGHT(p_year::TEXT, 2) || '-' || LPAD(v_year_seq::TEXT, 4, '0');
  v_comp_id := gen_random_uuid();

  INSERT INTO accounting.partner_compensation_runs (
    id, compensation_number, period_year, period_month,
    partner_id, gross_amount, base_amount,
    irpf_rate, irpf_amount, net_amount,
    status, created_by,
    pnl_reference_year, pnl_reference_month, pnl_reference_net_profit, period_was_locked
  ) VALUES (
    v_comp_id, v_comp_number, p_year, p_month,
    p_partner_id, v_gross_amount, p_base_amount,
    p_irpf_rate, v_irpf_amount, v_net_amount,
    'DRAFT', v_user_id,
    p_year, p_month, (v_pnl_basis->>'net_profit')::numeric, true
  );

  RETURN json_build_object(
    'dry_run', false,
    'compensation_id', v_comp_id,
    'compensation_number', v_comp_number,
    'partner_id', p_partner_id,
    'year', p_year,
    'month', p_month,
    'gross_amount', v_gross_amount,
    'base_amount', p_base_amount,
    'irpf_rate', p_irpf_rate,
    'irpf_amount', v_irpf_amount,
    'net_amount', v_net_amount,
    'pnl_net_profit', (v_pnl_basis->>'net_profit')::numeric
  );
END;
$$;
ALTER FUNCTION "public"."payroll_calculate_partner_compensation"("p_partner_id" "uuid", "p_year" integer, "p_month" integer, "p_base_amount" numeric, "p_irpf_rate" numeric, "p_dry_run" boolean) OWNER TO "postgres";
--
-- Name: payroll_calculate_with_ss("uuid", integer, integer, numeric, numeric, numeric, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."payroll_calculate_with_ss"("p_employee_id" "uuid", "p_year" integer, "p_month" integer, "p_gross_salary" numeric, "p_ss_base" numeric DEFAULT NULL::numeric, "p_irpf_rate" numeric DEFAULT NULL::numeric, "p_dry_run" boolean DEFAULT true) RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'accounting', 'internal'
    AS $$
DECLARE
  v_user_id UUID;
  v_employee RECORD;
  v_ss_base NUMERIC;
  v_irpf_rate NUMERIC;
  v_ss_employee_rate NUMERIC := 6.47;  -- Tipo general contingencias comunes + desempleo + FP
  v_ss_employer_rate NUMERIC := 30.40; -- Tipo general empresa
  v_ss_employee NUMERIC;
  v_ss_employer NUMERIC;
  v_irpf_amount NUMERIC;
  v_net_salary NUMERIC;
  v_run_id UUID;
  v_run_number TEXT;
  v_year_seq INTEGER;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;

  -- Get employee data
  SELECT e.id, e.full_name, e.irpf_rate AS default_irpf,
         e.custom_ss_employee_rate, e.custom_ss_employer_rate, e.gross_salary AS default_salary
  INTO v_employee
  FROM internal.employees e
  WHERE e.id = p_employee_id;

  IF v_employee.id IS NULL THEN
    RAISE EXCEPTION 'Empleado no encontrado';
  END IF;

  -- Use employee custom rates if defined
  IF v_employee.custom_ss_employee_rate IS NOT NULL THEN
    v_ss_employee_rate := v_employee.custom_ss_employee_rate;
  END IF;
  IF v_employee.custom_ss_employer_rate IS NOT NULL THEN
    v_ss_employer_rate := v_employee.custom_ss_employer_rate;
  END IF;

  v_ss_base := COALESCE(p_ss_base, p_gross_salary);
  v_irpf_rate := COALESCE(p_irpf_rate, v_employee.default_irpf, 15.0);

  -- Calculate amounts
  v_ss_employee := ROUND(v_ss_base * (v_ss_employee_rate / 100.0), 2);
  v_ss_employer := ROUND(v_ss_base * (v_ss_employer_rate / 100.0), 2);
  v_irpf_amount := ROUND(p_gross_salary * (v_irpf_rate / 100.0), 2);
  v_net_salary := p_gross_salary - v_ss_employee - v_irpf_amount;

  IF p_dry_run THEN
    RETURN json_build_object(
      'dry_run', true,
      'employee_id', p_employee_id,
      'employee_name', v_employee.full_name,
      'year', p_year,
      'month', p_month,
      'gross_salary', p_gross_salary,
      'ss_base', v_ss_base,
      'ss_employee_rate', v_ss_employee_rate,
      'ss_employee', v_ss_employee,
      'ss_employer_rate', v_ss_employer_rate,
      'ss_employer', v_ss_employer,
      'irpf_rate', v_irpf_rate,
      'irpf_amount', v_irpf_amount,
      'net_salary', v_net_salary,
      'total_cost_company', p_gross_salary + v_ss_employer
    );
  END IF;

  -- Generate payroll run number
  INSERT INTO audit.sequence_counters (prefix, year, current_number, last_generated_at)
  VALUES ('PAYROLL', p_year, 1, now())
  ON CONFLICT (prefix, year) DO UPDATE
  SET current_number = audit.sequence_counters.current_number + 1,
      last_generated_at = now()
  RETURNING current_number INTO v_year_seq;

  v_run_number := 'NE-' || RIGHT(p_year::TEXT, 2) || '-' || LPAD(v_year_seq::TEXT, 4, '0');
  v_run_id := gen_random_uuid();

  INSERT INTO accounting.payroll_runs (
    id, run_number, period_year, period_month,
    employee_id, gross_amount, ss_base,
    ss_company, ss_employee,
    irpf_rate, irpf_amount, net_amount,
    status, created_by, created_at, updated_at
  ) VALUES (
    v_run_id, v_run_number, p_year, p_month,
    p_employee_id, p_gross_salary, v_ss_base,
    v_ss_employer, v_ss_employee,
    v_irpf_rate, v_irpf_amount, v_net_salary,
    'DRAFT', v_user_id, now(), now()
  );

  RETURN json_build_object(
    'dry_run', false,
    'payroll_run_id', v_run_id,
    'run_number', v_run_number,
    'employee_id', p_employee_id,
    'employee_name', v_employee.full_name,
    'gross_salary', p_gross_salary,
    'ss_base', v_ss_base,
    'ss_employee', v_ss_employee,
    'ss_employer', v_ss_employer,
    'irpf_rate', v_irpf_rate,
    'irpf_amount', v_irpf_amount,
    'net_salary', v_net_salary,
    'total_cost_company', p_gross_salary + v_ss_employer
  );
END;
$$;
ALTER FUNCTION "public"."payroll_calculate_with_ss"("p_employee_id" "uuid", "p_year" integer, "p_month" integer, "p_gross_salary" numeric, "p_ss_base" numeric, "p_irpf_rate" numeric, "p_dry_run" boolean) OWNER TO "postgres";
--
-- Name: payroll_get_partner_compensation_basis(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."payroll_get_partner_compensation_basis"("p_year" integer, "p_month" integer) RETURNS json
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'accounting', 'internal'
    AS $$
DECLARE
  v_user_id UUID;
  v_period_start DATE;
  v_period_end DATE;
  v_is_locked BOOLEAN;
  v_total_revenue NUMERIC := 0;
  v_total_expenses NUMERIC := 0;
  v_net_profit NUMERIC := 0;
  v_pnl_row RECORD;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;

  v_period_start := make_date(p_year, p_month, 1);
  v_period_end := (v_period_start + interval '1 month' - interval '1 day')::date;

  -- Check if period is locked
  SELECT pc.is_locked INTO v_is_locked
  FROM accounting.period_closures pc
  WHERE pc.year = p_year AND pc.month = p_month;

  IF v_is_locked IS NULL THEN
    v_is_locked := false;
  END IF;

  -- Get P&L data
  FOR v_pnl_row IN
    SELECT * FROM accounting.get_profit_loss(v_period_start, v_period_end)
  LOOP
    IF v_pnl_row.account_type IN ('REVENUE', 'INCOME') THEN
      v_total_revenue := v_total_revenue + COALESCE(v_pnl_row.amount, 0);
    ELSIF v_pnl_row.account_type IN ('EXPENSE', 'COST') THEN
      v_total_expenses := v_total_expenses + ABS(COALESCE(v_pnl_row.amount, 0));
    END IF;
  END LOOP;

  v_net_profit := v_total_revenue - v_total_expenses;

  RETURN json_build_object(
    'year', p_year,
    'month', p_month,
    'period_start', v_period_start,
    'period_end', v_period_end,
    'is_locked', v_is_locked,
    'total_revenue', v_total_revenue,
    'total_expenses', v_total_expenses,
    'net_profit', v_net_profit
  );
END;
$$;
ALTER FUNCTION "public"."payroll_get_partner_compensation_basis"("p_year" integer, "p_month" integer) OWNER TO "postgres";
--
-- Name: post_partner_compensation_run("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."post_partner_compensation_run"("p_compensation_run_id" "uuid") RETURNS TABLE("entry_id" "uuid", "entry_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_comp RECORD;
  v_entry_id UUID;
  v_entry_number TEXT;
  v_user_id UUID;
  v_partner_account_code TEXT;
  v_partner_number_digits INT;
BEGIN
  SELECT pcr.*, p.full_name AS partner_name, p.partner_number
  INTO v_comp
  FROM internal.partner_compensation_runs pcr
  JOIN internal.partners p ON p.id = pcr.partner_id
  WHERE pcr.id = p_compensation_run_id;
  
  IF v_comp IS NULL THEN
    RAISE EXCEPTION 'Retribuci├│n no encontrada';
  END IF;
  
  IF v_comp.status != 'DRAFT' THEN
    RAISE EXCEPTION 'Solo se pueden aprobar retribuciones en estado DRAFT';
  END IF;
  
  v_user_id := internal.get_authorized_user_id(auth.uid());
  
  v_partner_number_digits := REGEXP_REPLACE(v_comp.partner_number, '[^0-9]', '', 'g')::INTEGER;
  v_partner_account_code := '465' || LPAD(v_partner_number_digits::TEXT, 3, '0');
  
  IF NOT EXISTS (
    SELECT 1 FROM accounting.chart_of_accounts 
    WHERE account_code = v_partner_account_code AND is_active = TRUE
  ) THEN
    RAISE EXCEPTION 'Cuenta contable % no encontrada para el socio. Verifique que el socio tiene cuenta asignada.', v_partner_account_code;
  END IF;
  
  v_entry_number := accounting.get_next_entry_number();
  
  INSERT INTO accounting.journal_entries (
    entry_number,
    entry_date,
    entry_type,
    description,
    reference_type,
    reference_id,
    is_automatic,
    created_by
  ) VALUES (
    v_entry_number,
    CURRENT_DATE,
    'PAYROLL_PARTNER'::accounting.journal_entry_type,
    'Devengo retribuci├│n socio ' || v_comp.compensation_number || ' - ' || v_comp.partner_name,
    'PARTNER_COMPENSATION',
    p_compensation_run_id,
    TRUE,
    v_user_id
  )
  RETURNING accounting.journal_entries.id INTO v_entry_id;
  
  INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, description, debit_credit, amount, line_order)
  VALUES (v_entry_id, '640200', 'Retribuci├│n bruta ' || v_comp.partner_name, 'DEBIT', v_comp.gross_amount, 1);
  
  IF v_comp.irpf_amount > 0 THEN
    INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, description, debit_credit, amount, line_order)
    VALUES (v_entry_id, '475100', 'Retenci├│n IRPF ' || v_comp.partner_name, 'CREDIT', v_comp.irpf_amount, 2);
  END IF;
  
  INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, description, debit_credit, amount, line_order)
  VALUES (v_entry_id, v_partner_account_code, 'Remuneraci├│n pendiente ' || v_comp.partner_name, 'CREDIT', v_comp.net_amount, 3);
  
  UPDATE internal.partner_compensation_runs
  SET status = 'POSTED', journal_entry_id = v_entry_id, updated_at = NOW()
  WHERE id = p_compensation_run_id;
  
  RETURN QUERY SELECT v_entry_id, v_entry_number;
END;
$$;
ALTER FUNCTION "public"."post_partner_compensation_run"("p_compensation_run_id" "uuid") OWNER TO "postgres";
