--
-- Name: reassign_client("uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."reassign_client"("p_client_id" "uuid", "p_new_assignee_id" "uuid", "p_note" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_user_id UUID;
    v_user_name TEXT;
    v_is_admin BOOLEAN;
    v_previous_assignee_id UUID;
    v_previous_assignee_name TEXT;
    v_new_assignee_name TEXT;
    v_note_content TEXT;
BEGIN
    -- Obtener informaci├│n del usuario actual
    SELECT au.id, au.full_name 
    INTO v_user_id, v_user_name
    FROM internal.authorized_users au
    WHERE au.auth_user_id = auth.uid();
    
    IF v_user_id IS NULL THEN
        RAISE EXCEPTION 'Usuario no autorizado';
    END IF;
    
    -- Verificar si es admin
    SELECT EXISTS (
        SELECT 1 FROM public.user_roles ur
        WHERE ur.user_id = auth.uid() AND ur.role = 'admin'
    ) INTO v_is_admin;
    
    IF NOT v_is_admin THEN
        RAISE EXCEPTION 'Solo administradores pueden reasignar clientes';
    END IF;
    
    -- Obtener informaci├│n del asignado anterior
    SELECT c.assigned_to, au.full_name
    INTO v_previous_assignee_id, v_previous_assignee_name
    FROM crm.clients c
    LEFT JOIN internal.authorized_users au ON au.id = c.assigned_to
    WHERE c.id = p_client_id AND c.deleted_at IS NULL;
    
    -- Obtener nombre del nuevo asignado
    SELECT full_name INTO v_new_assignee_name
    FROM internal.authorized_users WHERE id = p_new_assignee_id;
    
    -- Actualizar asignaci├│n
    UPDATE crm.clients
    SET assigned_to = p_new_assignee_id, updated_at = now()
    WHERE id = p_client_id;
    
    -- Crear nota de reasignaci├│n
    v_note_content := 'Lead reasignado de "' || COALESCE(v_previous_assignee_name, 'Sin asignar') || 
                      '" a "' || COALESCE(v_new_assignee_name, 'Sin asignar') || '"';
    IF p_note IS NOT NULL AND p_note != '' THEN
        v_note_content := v_note_content || '. ' || p_note;
    END IF;
    
    INSERT INTO crm.client_notes (
        client_id,
        note_type,
        content,
        previous_assignee_id,
        previous_assignee_name,
        new_assignee_id,
        new_assignee_name,
        user_id,
        user_name
    ) VALUES (
        p_client_id,
        'reassignment',
        v_note_content,
        v_previous_assignee_id,
        v_previous_assignee_name,
        p_new_assignee_id,
        v_new_assignee_name,
        v_user_id,
        v_user_name
    );
    
    RETURN TRUE;
END;
$$;
ALTER FUNCTION "public"."reassign_client"("p_client_id" "uuid", "p_new_assignee_id" "uuid", "p_note" "text") OWNER TO "postgres";
