--
-- Name: recalculate_purchase_invoice("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."recalculate_purchase_invoice"("p_invoice_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_subtotal NUMERIC := 0;
  v_tax_amount NUMERIC := 0;
  v_withholding_amount NUMERIC := 0;
  v_total NUMERIC := 0;
BEGIN
  SELECT
    COALESCE(SUM(round(COALESCE(subtotal, 0)::numeric, 2)), 0),
    COALESCE(SUM(round(COALESCE(tax_amount, 0)::numeric, 2)), 0),
    COALESCE(SUM(round(COALESCE(withholding_amount, 0)::numeric, 2)), 0)
  INTO v_subtotal, v_tax_amount, v_withholding_amount
  FROM sales.purchase_invoice_lines
  WHERE purchase_invoice_id = p_invoice_id;

  v_total := round((v_subtotal + v_tax_amount - v_withholding_amount)::numeric, 2);

  UPDATE sales.purchase_invoices
  SET
    subtotal = round(v_subtotal::numeric, 2),
    tax_amount = round(v_tax_amount::numeric, 2),
    withholding_amount = round(v_withholding_amount::numeric, 2),
    total = v_total,
    updated_at = NOW()
  WHERE id = p_invoice_id;
END;
$$;
ALTER FUNCTION "public"."recalculate_purchase_invoice"("p_invoice_id" "uuid") OWNER TO "postgres";
--
-- Name: recalculate_quote_totals("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."recalculate_quote_totals"("p_quote_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$

DECLARE

  v_subtotal NUMERIC;

  v_tax_amount NUMERIC;

  v_total NUMERIC;

BEGIN

  -- Calculate totals from all non-deleted lines

  SELECT 

    COALESCE(SUM(subtotal), 0),

    COALESCE(SUM(tax_amount), 0),

    COALESCE(SUM(total), 0)

  INTO v_subtotal, v_tax_amount, v_total

  FROM quotes.quote_lines

  WHERE quote_id = p_quote_id;

  

  -- Update quote totals

  UPDATE quotes.quotes SET

    subtotal = v_subtotal,

    tax_amount = v_tax_amount,

    total = v_total,

    updated_at = NOW()

  WHERE id = p_quote_id;

END;

$$;
ALTER FUNCTION "public"."recalculate_quote_totals"("p_quote_id" "uuid") OWNER TO "postgres";
