-- Name: register_purchase_invoice("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."register_purchase_invoice"("p_invoice_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE sales.purchase_invoices
  SET 
    status = 'REGISTERED',
    is_locked = true,
    updated_at = now()
  WHERE id = p_invoice_id
    AND status = 'DRAFT';
  
  RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."register_purchase_invoice"("p_invoice_id" "uuid") OWNER TO "postgres";
