-- Name: register_purchase_payment("uuid", numeric, "date", "text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."register_purchase_payment"("p_invoice_id" "uuid", "p_amount" numeric, "p_payment_date" "date" DEFAULT CURRENT_DATE, "p_payment_method" "text" DEFAULT 'TRANSFER'::"text", "p_bank_reference" "text" DEFAULT NULL::"text", "p_company_bank_account_id" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_payment_id UUID;
  v_user_id UUID;
BEGIN
  -- Obtener usuario actual
  SELECT au.id INTO v_user_id
  FROM internal.authorized_users au
  WHERE au.auth_user_id = auth.uid();
  
  INSERT INTO sales.purchase_invoice_payments (
    purchase_invoice_id,
    amount,
    payment_date,
    payment_method,
    bank_reference,
    company_bank_account_id,
    notes,
    registered_by
  ) VALUES (
    p_invoice_id,
    p_amount,
    p_payment_date,
    p_payment_method,
    p_bank_reference,
    p_company_bank_account_id,
    p_notes,
    v_user_id
  ) RETURNING id INTO v_payment_id;
  
  RETURN v_payment_id;
END;
$$;
