--
-- Name: register_site_visit("uuid", "uuid", "date", timestamp with time zone, timestamp with time zone, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."register_site_visit"("p_site_id" "uuid", "p_technician_id" "uuid", "p_visit_date" "date" DEFAULT NULL::"date", "p_check_in_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_check_out_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_notes" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_id UUID;
  v_current_status TEXT;
  v_has_actual_start BOOLEAN;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());

  -- Insert visit
  INSERT INTO projects.site_visits (site_id, technician_id, visit_date, check_in_at, check_out_at, notes, created_by)
  VALUES (p_site_id, p_technician_id, COALESCE(p_visit_date, CURRENT_DATE), p_check_in_at, p_check_out_at, p_notes, v_user_id)
  RETURNING id INTO v_id;

  -- Auto-transition: first visit ÔåÆ IN_PROGRESS + set actual_start_at
  SELECT ps.site_status, (ps.actual_start_at IS NOT NULL)
  INTO v_current_status, v_has_actual_start
  FROM projects.project_sites ps WHERE ps.id = p_site_id;

  IF v_current_status IN ('PLANNED', 'SCHEDULED') THEN
    UPDATE projects.project_sites
    SET site_status = 'IN_PROGRESS',
        actual_start_at = COALESCE(actual_start_at, COALESCE(p_check_in_at, now())),
        updated_at = now()
    WHERE id = p_site_id;
  END IF;

  RETURN v_id;
END;
$$;
ALTER FUNCTION "public"."register_site_visit"("p_site_id" "uuid", "p_technician_id" "uuid", "p_visit_date" "date", "p_check_in_at" timestamp with time zone, "p_check_out_at" timestamp with time zone, "p_notes" "text") OWNER TO "postgres";
--
-- Name: reimburse_personal_purchase("uuid", "uuid", "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."reimburse_personal_purchase"("p_payment_id" "uuid", "p_bank_account_id" "uuid", "p_reimbursement_date" "date" DEFAULT NULL::"date") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_payment RECORD;
  v_partner RECORD;
  v_partner_account TEXT;
  v_bank_code TEXT;
  v_entry_id UUID;
  v_entry_number TEXT;
  v_user_id UUID;
BEGIN
  IF NOT (internal.is_admin() OR internal.is_manager()) THEN
    RAISE EXCEPTION 'Permisos insuficientes';
  END IF;

  v_user_id := internal.get_authorized_user_id(auth.uid());

  -- Get payment
  SELECT * INTO v_payment FROM sales.purchase_invoice_payments WHERE id = p_payment_id AND payer_type = 'PERSONAL';
  IF NOT FOUND THEN RAISE EXCEPTION 'Pago personal no encontrado'; END IF;
  IF v_payment.reimbursement_status = 'REIMBURSED' THEN RAISE EXCEPTION 'Ya ha sido reembolsado'; END IF;

  -- Get partner
  SELECT * INTO v_partner FROM internal.partners WHERE id = v_payment.payer_person_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'Socio no encontrado'; END IF;

  v_partner_account := COALESCE(v_partner.account_code, '551000');
  v_bank_code := accounting.get_bank_account_code(p_bank_account_id);
  IF v_bank_code IS NULL THEN RAISE EXCEPTION 'Cuenta bancaria no encontrada'; END IF;

  -- Create journal entry: reimburse partner
  SELECT accounting.next_entry_number() INTO v_entry_number;

  INSERT INTO accounting.journal_entries (entry_number, entry_date, entry_type, description, reference_id, reference_type, is_automatic, created_by)
  VALUES (v_entry_number, COALESCE(p_reimbursement_date, CURRENT_DATE), 'REIMBURSEMENT',
          'Reembolso a ' || v_partner.full_name, p_payment_id, 'reimbursement', true, v_user_id)
  RETURNING accounting.journal_entries.id INTO v_entry_id;

  -- DEBE 551/465 Socio (cancelamos deuda)
  INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, debit_amount, credit_amount, description, line_order)
  VALUES (v_entry_id, v_partner_account, v_payment.amount, 0, 'Reembolso gasto personal a ' || v_partner.full_name, 1);

  -- HABER 572 Banco
  INSERT INTO accounting.journal_entry_lines (journal_entry_id, account_code, debit_amount, credit_amount, description, line_order)
  VALUES (v_entry_id, v_bank_code, 0, v_payment.amount, 'Pago reembolso desde banco', 2);

  -- Update payment
  UPDATE sales.purchase_invoice_payments 
  SET reimbursement_status = 'REIMBURSED', 
      reimbursement_date = COALESCE(p_reimbursement_date, CURRENT_DATE),
      reimbursement_journal_entry_id = v_entry_id,
      updated_at = now()
  WHERE id = p_payment_id;

  RETURN true;
END;
$$;
ALTER FUNCTION "public"."reimburse_personal_purchase"("p_payment_id" "uuid", "p_bank_account_id" "uuid", "p_reimbursement_date" "date") OWNER TO "postgres";
