--
-- Name: reorder_quote_line("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."reorder_quote_line"("p_line_id" "uuid", "p_direction" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_quote_id UUID;
  v_current_order INTEGER;
  v_other_line_id UUID;
  v_other_order INTEGER;
BEGIN
  -- Check user authorization
  IF internal.get_authorized_user_id(auth.uid()) IS NULL THEN
    RAISE EXCEPTION 'User not authorized';
  END IF;
  
  -- Get quote_id and current line_order for the line
  SELECT quote_id, line_order INTO v_quote_id, v_current_order
  FROM quotes.quote_lines
  WHERE id = p_line_id;
  
  IF v_quote_id IS NULL THEN
    RETURN FALSE;
  END IF;
  
  -- Find the adjacent line based on direction
  IF p_direction = 'up' THEN
    -- Move up: find line with next lower order
    SELECT id, line_order INTO v_other_line_id, v_other_order
    FROM quotes.quote_lines
    WHERE quote_id = v_quote_id
      AND line_order < v_current_order
    ORDER BY line_order DESC
    LIMIT 1;
  ELSIF p_direction = 'down' THEN
    -- Move down: find line with next higher order
    SELECT id, line_order INTO v_other_line_id, v_other_order
    FROM quotes.quote_lines
    WHERE quote_id = v_quote_id
      AND line_order > v_current_order
    ORDER BY line_order ASC
    LIMIT 1;
  ELSE
    RAISE EXCEPTION 'Invalid direction. Use ''up'' or ''down''';
  END IF;
  
  -- If no adjacent line found, nothing to do
  IF v_other_line_id IS NULL THEN
    RETURN FALSE;
  END IF;
  
  -- Swap the line_order values
  UPDATE quotes.quote_lines
  SET line_order = v_other_order,
      updated_at = NOW()
  WHERE id = p_line_id;
  
  UPDATE quotes.quote_lines
  SET line_order = v_current_order,
      updated_at = NOW()
  WHERE id = v_other_line_id;
  
  RETURN TRUE;
END;
$$;
ALTER FUNCTION "public"."reorder_quote_line"("p_line_id" "uuid", "p_direction" "text") OWNER TO "postgres";
--
-- Name: replace_purchase_invoice_lines("uuid", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."replace_purchase_invoice_lines"("p_invoice_id" "uuid", "p_lines" "jsonb" DEFAULT '[]'::"jsonb") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_line JSONB;
  v_existing RECORD;
BEGIN
  FOR v_existing IN
    SELECT id
    FROM public.get_purchase_invoice_lines(p_invoice_id)
  LOOP
    PERFORM public.delete_purchase_invoice_line(v_existing.id);
  END LOOP;

  FOR v_line IN
    SELECT value
    FROM jsonb_array_elements(COALESCE(p_lines, '[]'::jsonb))
  LOOP
    PERFORM public.add_purchase_invoice_line(
      p_invoice_id := p_invoice_id,
      p_concept := COALESCE(v_line->>'concept', ''),
      p_description := NULLIF(v_line->>'description', ''),
      p_quantity := COALESCE((v_line->>'quantity')::NUMERIC, 0),
      p_unit_price := COALESCE((v_line->>'unit_price')::NUMERIC, 0),
      p_tax_rate := COALESCE((v_line->>'tax_rate')::NUMERIC, 0),
      p_discount_percent := COALESCE((v_line->>'discount_percent')::NUMERIC, 0),
      p_withholding_tax_rate := COALESCE((v_line->>'withholding_tax_rate')::NUMERIC, 0)
    );
  END LOOP;
END;
$$;
ALTER FUNCTION "public"."replace_purchase_invoice_lines"("p_invoice_id" "uuid", "p_lines" "jsonb") OWNER TO "postgres";
