--
-- Name: set_site_actual_dates("uuid", timestamp with time zone, timestamp with time zone, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."set_site_actual_dates"("p_site_id" "uuid", "p_actual_start_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_actual_end_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_mark_ready_to_invoice" boolean DEFAULT false) RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_current_status TEXT;
  v_new_status TEXT;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());

  SELECT ps.site_status INTO v_current_status
  FROM projects.project_sites ps WHERE ps.id = p_site_id;

  IF v_current_status IS NULL THEN
    RAISE EXCEPTION 'Site not found';
  END IF;

  v_new_status := v_current_status;

  -- Start actual ÔåÆ IN_PROGRESS
  IF p_actual_start_at IS NOT NULL AND v_current_status IN ('PLANNED', 'SCHEDULED') THEN
    v_new_status := 'IN_PROGRESS';
  END IF;

  -- End actual + mark ready ÔåÆ READY_TO_INVOICE
  IF p_actual_end_at IS NOT NULL AND p_mark_ready_to_invoice AND v_current_status IN ('IN_PROGRESS', 'SCHEDULED') THEN
    v_new_status := 'READY_TO_INVOICE';
  END IF;

  UPDATE projects.project_sites
  SET
    actual_start_at = COALESCE(p_actual_start_at, actual_start_at),
    actual_end_at = COALESCE(p_actual_end_at, actual_end_at),
    site_status = v_new_status,
    updated_at = now()
  WHERE id = p_site_id;

  RETURN json_build_object('status', v_new_status);
END;
$$;
ALTER FUNCTION "public"."set_site_actual_dates"("p_site_id" "uuid", "p_actual_start_at" timestamp with time zone, "p_actual_end_at" timestamp with time zone, "p_mark_ready_to_invoice" boolean) OWNER TO "postgres";
