--
-- Name: sync_get_invoice_lines_for_archive("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."sync_get_invoice_lines_for_archive"("p_invoice_id" "uuid") RETURNS TABLE("id" "uuid", "line_order" integer, "product_id" "uuid", "concept" "text", "description" "text", "quantity" numeric, "unit" "text", "unit_price" numeric, "discount_percent" numeric, "tax_rate" numeric, "subtotal" numeric, "tax_amount" numeric, "total" numeric)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    il.id,
    il.line_order,
    NULL::UUID AS product_id,
    il.concept,
    il.description,
    il.quantity,
    'ud'::TEXT AS unit,
    il.unit_price,
    COALESCE(il.discount_percent, 0) AS discount_percent,
    COALESCE(il.tax_rate, 0) AS tax_rate,
    il.quantity * il.unit_price * (1 - COALESCE(il.discount_percent, 0) / 100) AS subtotal,
    il.quantity * il.unit_price * (1 - COALESCE(il.discount_percent, 0) / 100) * (COALESCE(il.tax_rate, 0) / 100) AS tax_amount,
    il.quantity * il.unit_price * (1 - COALESCE(il.discount_percent, 0) / 100) * (1 + COALESCE(il.tax_rate, 0) / 100) AS total
  FROM sales.invoice_lines il
  WHERE il.invoice_id = p_invoice_id
  ORDER BY il.line_order;
END;
$$;
ALTER FUNCTION "public"."sync_get_invoice_lines_for_archive"("p_invoice_id" "uuid") OWNER TO "postgres";
