-- Name: sync_get_project_for_archive("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."sync_get_project_for_archive"("p_project_id" "uuid") RETURNS TABLE("id" "uuid", "client_id" "uuid", "client_name" "text", "client_order_number" "text", "created_at" timestamp with time zone, "created_by" "uuid", "created_by_name" "text", "local_name" "text", "notes" "text", "project_address" "text", "project_city" "text", "project_name" "text", "project_number" "text", "quote_id" "uuid", "status" "text", "updated_at" timestamp with time zone, "site_mode" "text", "default_site_id" "uuid", "default_site_name" "text", "default_site_address" "text", "default_site_city" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT p.id, p.client_id, c.company_name, p.client_order_number,
    p.created_at, p.created_by, COALESCE(au.full_name, ''),
    p.local_name, p.description, ''::TEXT, p.project_city,
    p.project_name, p.project_number, p.quote_id, p.status::TEXT,
    p.updated_at,
    p.site_mode::TEXT, p.default_site_id,
    ps.site_name, ps.address, ps.city
  FROM projects.projects p
  LEFT JOIN crm.clients c ON c.id = p.client_id
  LEFT JOIN internal.authorized_users au ON au.id = p.created_by
  LEFT JOIN projects.project_sites ps ON ps.id = p.default_site_id
  WHERE p.id = p_project_id;
END;
$$;
ALTER FUNCTION "public"."sync_get_project_for_archive"("p_project_id" "uuid") OWNER TO "postgres";
--
-- Name: sync_get_quote_lines_for_archive("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."sync_get_quote_lines_for_archive"("p_quote_id" "uuid") RETURNS TABLE("id" "uuid", "line_order" integer, "concept" "text", "description" "text", "quantity" numeric, "unit_price" numeric, "tax_rate" numeric, "discount_percent" numeric, "subtotal" numeric, "tax_amount" numeric, "total" numeric, "group_name" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    ql.id,
    ql.line_order,
    ql.concept,
    ql.description,
    ql.quantity,
    ql.unit_price,
    ql.tax_rate,
    ql.discount_percent,
    ql.subtotal,
    ql.tax_amount,
    ql.total,
    ql.group_name
  FROM quotes.quote_lines ql
  WHERE ql.quote_id = p_quote_id
  ORDER BY ql.line_order ASC;
END;
$$;
ALTER FUNCTION "public"."sync_get_quote_lines_for_archive"("p_quote_id" "uuid") OWNER TO "postgres";
--
-- Name: sync_list_invoices_for_archive(integer, "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."sync_list_invoices_for_archive"("p_limit" integer DEFAULT 50, "p_invoice_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "status" "text", "invoice_number" "text", "preliminary_number" "text", "issue_date" "date", "sharepoint_item_id" "text", "archived_pdf_provider" "text", "archived_pdf_path" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    i.id,
    i.status::TEXT,
    i.invoice_number,
    i.preliminary_number,
    i.issue_date,
    i.sharepoint_item_id,
    i.archived_pdf_provider,
    i.archived_pdf_path
  FROM sales.invoices i
  WHERE
    (
      p_invoice_id IS NOT NULL
      AND i.id = p_invoice_id
    )
    OR (
      p_invoice_id IS NULL
      AND i.status IN ('ISSUED', 'PARTIAL', 'PAID', 'OVERDUE', 'CANCELLED', 'RECTIFIED')
      AND i.sharepoint_item_id IS NULL
      AND COALESCE(i.archived_pdf_provider, '') = ''
      AND COALESCE(i.archived_pdf_path, '') = ''
    )
  ORDER BY i.issue_date ASC NULLS LAST
  LIMIT GREATEST(COALESCE(p_limit, 50), 1);
END;
$$;
ALTER FUNCTION "public"."sync_list_invoices_for_archive"("p_limit" integer, "p_invoice_id" "uuid") OWNER TO "postgres";
--
-- Name: sync_list_quotes_for_archive(integer, "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."sync_list_quotes_for_archive"("p_limit" integer DEFAULT 50, "p_quote_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "status" "text", "quote_number" "text", "issue_date" "date", "sharepoint_item_id" "text", "archived_pdf_provider" "text", "archived_pdf_path" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    q.id,
    q.status::TEXT,
    q.quote_number,
    q.issue_date,
    q.sharepoint_item_id,
    q.archived_pdf_provider,
    q.archived_pdf_path
  FROM quotes.quotes q
  WHERE
    (
      p_quote_id IS NOT NULL
      AND q.id = p_quote_id
    )
    OR (
      p_quote_id IS NULL
      AND q.status IN ('SENT', 'APPROVED', 'REJECTED', 'EXPIRED', 'INVOICED')
      AND q.sharepoint_item_id IS NULL
      AND COALESCE(q.archived_pdf_provider, '') = ''
      AND COALESCE(q.archived_pdf_path, '') = ''
    )
  ORDER BY q.issue_date ASC NULLS LAST, q.created_at ASC
  LIMIT GREATEST(COALESCE(p_limit, 50), 1);
END;
$$;
ALTER FUNCTION "public"."sync_list_quotes_for_archive"("p_limit" integer, "p_quote_id" "uuid") OWNER TO "postgres";
--
-- Name: sync_set_invoice_archive_metadata("uuid", "text", "text", "text", "text", "text", "text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."sync_set_invoice_archive_metadata"("p_invoice_id" "uuid", "p_sharepoint_site_id" "text", "p_sharepoint_drive_id" "text", "p_sharepoint_item_id" "text", "p_sharepoint_web_url" "text" DEFAULT NULL::"text", "p_sharepoint_etag" "text" DEFAULT NULL::"text", "p_archived_pdf_path" "text" DEFAULT NULL::"text", "p_archived_pdf_file_name" "text" DEFAULT NULL::"text", "p_archived_pdf_hash" "text" DEFAULT NULL::"text", "p_archived_record_hash" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'sales'
    AS $$
DECLARE
  v_invoice sales.invoices%ROWTYPE;
BEGIN
  SELECT * INTO v_invoice
  FROM sales.invoices
  WHERE id = p_invoice_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Factura no encontrada: %', p_invoice_id;
  END IF;

  IF v_invoice.status NOT IN ('ISSUED', 'PARTIAL', 'PAID', 'OVERDUE', 'CANCELLED', 'RECTIFIED') THEN
    RAISE EXCEPTION 'Solo se puede archivar una factura emitida o cerrada. Estado actual: %', v_invoice.status;
  END IF;

  UPDATE sales.invoices
  SET archived_pdf_provider = 'SHAREPOINT',
      sharepoint_site_id = p_sharepoint_site_id,
      sharepoint_drive_id = p_sharepoint_drive_id,
      sharepoint_item_id = p_sharepoint_item_id,
      sharepoint_web_url = COALESCE(p_sharepoint_web_url, sharepoint_web_url),
      sharepoint_etag = COALESCE(p_sharepoint_etag, sharepoint_etag),
      archived_pdf_path = COALESCE(p_archived_pdf_path, archived_pdf_path),
      archived_pdf_file_name = COALESCE(p_archived_pdf_file_name, archived_pdf_file_name),
      archived_pdf_hash = COALESCE(p_archived_pdf_hash, archived_pdf_hash),
      archived_record_hash = COALESCE(p_archived_record_hash, archived_record_hash),
      archived_pdf_generated_at = COALESCE(archived_pdf_generated_at, now()),
      archived_pdf_generated_by = COALESCE(archived_pdf_generated_by, v_invoice.created_by),
      archived_pdf_last_synced_at = now(),
      updated_at = now()
  WHERE id = p_invoice_id;

  RETURN true;
END;
$$;
ALTER FUNCTION "public"."sync_set_invoice_archive_metadata"("p_invoice_id" "uuid", "p_sharepoint_site_id" "text", "p_sharepoint_drive_id" "text", "p_sharepoint_item_id" "text", "p_sharepoint_web_url" "text", "p_sharepoint_etag" "text", "p_archived_pdf_path" "text", "p_archived_pdf_file_name" "text", "p_archived_pdf_hash" "text", "p_archived_record_hash" "text") OWNER TO "postgres";
--
-- Name: sync_set_quote_archive_metadata("uuid", "text", "text", "text", "text", "text", "text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."sync_set_quote_archive_metadata"("p_quote_id" "uuid", "p_sharepoint_site_id" "text", "p_sharepoint_drive_id" "text", "p_sharepoint_item_id" "text", "p_sharepoint_web_url" "text" DEFAULT NULL::"text", "p_sharepoint_etag" "text" DEFAULT NULL::"text", "p_archived_pdf_path" "text" DEFAULT NULL::"text", "p_archived_pdf_file_name" "text" DEFAULT NULL::"text", "p_archived_pdf_hash" "text" DEFAULT NULL::"text", "p_archived_record_hash" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'quotes'
    AS $$
DECLARE
  v_quote quotes.quotes%ROWTYPE;
BEGIN
  SELECT * INTO v_quote
  FROM quotes.quotes
  WHERE id = p_quote_id
  FOR UPDATE;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Presupuesto no encontrado: %', p_quote_id;
  END IF;

  IF v_quote.status NOT IN ('SENT', 'APPROVED', 'REJECTED', 'EXPIRED', 'INVOICED') THEN
    RAISE EXCEPTION 'Solo se puede archivar un presupuesto emitido o cerrado. Estado actual: %', v_quote.status;
  END IF;

  UPDATE quotes.quotes
  SET archived_pdf_provider = 'SHAREPOINT',
      sharepoint_site_id = p_sharepoint_site_id,
      sharepoint_drive_id = p_sharepoint_drive_id,
      sharepoint_item_id = p_sharepoint_item_id,
      sharepoint_web_url = COALESCE(p_sharepoint_web_url, sharepoint_web_url),
      sharepoint_etag = COALESCE(p_sharepoint_etag, sharepoint_etag),
      archived_pdf_path = COALESCE(p_archived_pdf_path, archived_pdf_path),
      archived_pdf_file_name = COALESCE(p_archived_pdf_file_name, archived_pdf_file_name),
      archived_pdf_hash = COALESCE(p_archived_pdf_hash, archived_pdf_hash),
      archived_record_hash = COALESCE(p_archived_record_hash, archived_record_hash),
      archived_pdf_generated_at = COALESCE(archived_pdf_generated_at, now()),
      archived_pdf_generated_by = COALESCE(archived_pdf_generated_by, v_quote.created_by),
      archived_pdf_last_synced_at = now(),
      updated_at = now()
  WHERE id = p_quote_id;

  RETURN true;
END;
$$;
ALTER FUNCTION "public"."sync_set_quote_archive_metadata"("p_quote_id" "uuid", "p_sharepoint_site_id" "text", "p_sharepoint_drive_id" "text", "p_sharepoint_item_id" "text", "p_sharepoint_web_url" "text", "p_sharepoint_etag" "text", "p_archived_pdf_path" "text", "p_archived_pdf_file_name" "text", "p_archived_pdf_hash" "text", "p_archived_record_hash" "text") OWNER TO "postgres";
--
-- Name: tasks_add_comment("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."tasks_add_comment"("p_task_id" "uuid", "p_message" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_user_id UUID; v_id UUID;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'Not authorized'; END IF;
  INSERT INTO internal.task_activity (task_id, created_by, type, message) VALUES (p_task_id, v_user_id, 'COMMENT', p_message) RETURNING id INTO v_id;
  UPDATE internal.tasks SET updated_at = now() WHERE id = p_task_id;
  RETURN v_id;
END; $$;
ALTER FUNCTION "public"."tasks_add_comment"("p_task_id" "uuid", "p_message" "text") OWNER TO "postgres";
--
-- Name: tasks_assign("uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."tasks_assign"("p_task_id" "uuid", "p_user_id" "uuid", "p_role" "text" DEFAULT 'ASSIGNEE'::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_caller UUID; v_name TEXT;
BEGIN
  v_caller := internal.get_authorized_user_id(auth.uid());
  IF v_caller IS NULL THEN RAISE EXCEPTION 'Not authorized'; END IF;
  INSERT INTO internal.task_assignees (task_id, user_id, role_in_task) VALUES (p_task_id, p_user_id, p_role)
    ON CONFLICT (task_id, user_id) DO UPDATE SET role_in_task = p_role;
  SELECT full_name INTO v_name FROM internal.authorized_users WHERE id = p_user_id;
  INSERT INTO internal.task_activity (task_id, created_by, type, message, meta)
  VALUES (p_task_id, v_caller, 'ASSIGNMENT', 'Asignado: ' || COALESCE(v_name, ''), jsonb_build_object('user_id', p_user_id, 'role', p_role));
  RETURN true;
END; $$;
ALTER FUNCTION "public"."tasks_assign"("p_task_id" "uuid", "p_user_id" "uuid", "p_role" "text") OWNER TO "postgres";
--
-- Name: tasks_create("text", "text", "text", "date", "date", "uuid", "uuid", "uuid", "uuid", "uuid", "text"[], "uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."tasks_create"("p_title" "text", "p_description" "text" DEFAULT NULL::"text", "p_priority" "text" DEFAULT 'MEDIUM'::"text", "p_due_date" "date" DEFAULT NULL::"date", "p_start_date" "date" DEFAULT NULL::"date", "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_site_id" "uuid" DEFAULT NULL::"uuid", "p_quote_id" "uuid" DEFAULT NULL::"uuid", "p_invoice_id" "uuid" DEFAULT NULL::"uuid", "p_visit_id" "uuid" DEFAULT NULL::"uuid", "p_tags" "text"[] DEFAULT NULL::"text"[], "p_assignee_ids" "uuid"[] DEFAULT NULL::"uuid"[]) RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_user_id UUID; v_task_id UUID; v_assignee UUID;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'Not authorized'; END IF;

  INSERT INTO internal.tasks (created_by, title, description, priority, due_date, start_date,
    project_id, site_id, quote_id, invoice_id, visit_id, tags, source)
  VALUES (v_user_id, p_title, p_description, p_priority, p_due_date, p_start_date,
    p_project_id, p_site_id, p_quote_id, p_invoice_id, p_visit_id, p_tags, 'manual')
  RETURNING id INTO v_task_id;

  INSERT INTO internal.task_assignees (task_id, user_id, role_in_task) VALUES (v_task_id, v_user_id, 'OWNER');

  IF p_assignee_ids IS NOT NULL THEN
    FOREACH v_assignee IN ARRAY p_assignee_ids LOOP
      IF v_assignee <> v_user_id THEN
        INSERT INTO internal.task_assignees (task_id, user_id, role_in_task) VALUES (v_task_id, v_assignee, 'ASSIGNEE') ON CONFLICT DO NOTHING;
      END IF;
    END LOOP;
  END IF;

  INSERT INTO internal.task_activity (task_id, created_by, type, message) VALUES (v_task_id, v_user_id, 'STATUS_CHANGE', 'Tarea creada');
  RETURN v_task_id;
END; $$;
ALTER FUNCTION "public"."tasks_create"("p_title" "text", "p_description" "text", "p_priority" "text", "p_due_date" "date", "p_start_date" "date", "p_project_id" "uuid", "p_site_id" "uuid", "p_quote_id" "uuid", "p_invoice_id" "uuid", "p_visit_id" "uuid", "p_tags" "text"[], "p_assignee_ids" "uuid"[]) OWNER TO "postgres";
--
-- Name: tasks_get("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."tasks_get"("p_task_id" "uuid") RETURNS TABLE("id" "uuid", "title" "text", "description" "text", "status" "text", "priority" "text", "due_date" "date", "start_date" "date", "completed_at" timestamp with time zone, "project_id" "uuid", "project_name" "text", "site_id" "uuid", "site_name" "text", "quote_id" "uuid", "invoice_id" "uuid", "visit_id" "uuid", "tags" "text"[], "source" "text", "is_archived" boolean, "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "created_by" "uuid", "created_by_name" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT t.id, t.title, t.description, t.status::TEXT, t.priority::TEXT,
    t.due_date, t.start_date, t.completed_at,
    t.project_id, COALESCE(pp.project_name, '')::TEXT, t.site_id, COALESCE(ps.site_name, '')::TEXT,
    t.quote_id, t.invoice_id, t.visit_id, t.tags, t.source, t.is_archived,
    t.created_at, t.updated_at, t.created_by, COALESCE(au.full_name, '')::TEXT
  FROM internal.tasks t
  LEFT JOIN projects.projects pp ON pp.id = t.project_id
  LEFT JOIN projects.project_sites ps ON ps.id = t.site_id
  LEFT JOIN internal.authorized_users au ON au.id = t.created_by
  WHERE t.id = p_task_id;
END; $$;
ALTER FUNCTION "public"."tasks_get"("p_task_id" "uuid") OWNER TO "postgres";
--
-- Name: tasks_get_activity("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."tasks_get_activity"("p_task_id" "uuid") RETURNS TABLE("id" "uuid", "created_at" timestamp with time zone, "created_by" "uuid", "created_by_name" "text", "type" "text", "message" "text", "meta" "jsonb")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT a.id, a.created_at, a.created_by, COALESCE(au.full_name, '')::TEXT, a.type, a.message, a.meta
  FROM internal.task_activity a
  LEFT JOIN internal.authorized_users au ON au.id = a.created_by
  WHERE a.task_id = p_task_id ORDER BY a.created_at DESC;
END; $$;
ALTER FUNCTION "public"."tasks_get_activity"("p_task_id" "uuid") OWNER TO "postgres";
--
-- Name: tasks_get_assignees("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."tasks_get_assignees"("p_task_id" "uuid") RETURNS TABLE("user_id" "uuid", "user_name" "text", "role_in_task" "text", "assigned_at" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT ta.user_id, COALESCE(au.full_name, '')::TEXT, ta.role_in_task, ta.assigned_at
  FROM internal.task_assignees ta
  LEFT JOIN internal.authorized_users au ON au.id = ta.user_id
  WHERE ta.task_id = p_task_id ORDER BY ta.role_in_task, ta.assigned_at;
END; $$;
ALTER FUNCTION "public"."tasks_get_assignees"("p_task_id" "uuid") OWNER TO "postgres";
--
-- Name: tasks_list_for_user("uuid", "text", "text", boolean, "uuid", "uuid", boolean, integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."tasks_list_for_user"("p_user_id" "uuid" DEFAULT NULL::"uuid", "p_status" "text" DEFAULT NULL::"text", "p_priority" "text" DEFAULT NULL::"text", "p_due_today" boolean DEFAULT false, "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_site_id" "uuid" DEFAULT NULL::"uuid", "p_include_archived" boolean DEFAULT false, "p_limit" integer DEFAULT 50, "p_offset" integer DEFAULT 0) RETURNS TABLE("id" "uuid", "title" "text", "description" "text", "status" "text", "priority" "text", "due_date" "date", "start_date" "date", "completed_at" timestamp with time zone, "project_id" "uuid", "project_name" "text", "site_id" "uuid", "site_name" "text", "quote_id" "uuid", "invoice_id" "uuid", "visit_id" "uuid", "tags" "text"[], "source" "text", "is_archived" boolean, "created_at" timestamp with time zone, "updated_at" timestamp with time zone, "created_by" "uuid", "created_by_name" "text", "assignee_count" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_user_id UUID;
BEGIN
  v_user_id := COALESCE(p_user_id, internal.get_authorized_user_id(auth.uid()));
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'Not authorized'; END IF;
  RETURN QUERY
  SELECT DISTINCT t.id, t.title, t.description, t.status::TEXT, t.priority::TEXT,
    t.due_date, t.start_date, t.completed_at,
    t.project_id, COALESCE(pp.project_name, '')::TEXT, t.site_id, COALESCE(ps.site_name, '')::TEXT,
    t.quote_id, t.invoice_id, t.visit_id, t.tags, t.source, t.is_archived,
    t.created_at, t.updated_at, t.created_by, COALESCE(au.full_name, '')::TEXT,
    (SELECT count(*)::INT FROM internal.task_assignees ta2 WHERE ta2.task_id = t.id)
  FROM internal.tasks t
  LEFT JOIN internal.task_assignees ta ON ta.task_id = t.id
  LEFT JOIN projects.projects pp ON pp.id = t.project_id
  LEFT JOIN projects.project_sites ps ON ps.id = t.site_id
  LEFT JOIN internal.authorized_users au ON au.id = t.created_by
  WHERE (ta.user_id = v_user_id OR t.created_by = v_user_id OR internal.is_admin() OR internal.is_manager())
    AND (p_status IS NULL OR t.status = p_status)
    AND (p_priority IS NULL OR t.priority = p_priority)
    AND (NOT p_due_today OR t.due_date = CURRENT_DATE)
    AND (p_project_id IS NULL OR t.project_id = p_project_id)
    AND (p_site_id IS NULL OR t.site_id = p_site_id)
    AND (p_include_archived OR NOT t.is_archived)
    AND t.status <> 'CANCELLED'
  ORDER BY t.updated_at DESC, t.id
  LIMIT p_limit OFFSET p_offset;
END; $$;
ALTER FUNCTION "public"."tasks_list_for_user"("p_user_id" "uuid", "p_status" "text", "p_priority" "text", "p_due_today" boolean, "p_project_id" "uuid", "p_site_id" "uuid", "p_include_archived" boolean, "p_limit" integer, "p_offset" integer) OWNER TO "postgres";
--
-- Name: tasks_set_status("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."tasks_set_status"("p_task_id" "uuid", "p_status" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_user_id UUID; v_old TEXT;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'Not authorized'; END IF;
  SELECT status INTO v_old FROM internal.tasks WHERE id = p_task_id;
  UPDATE internal.tasks SET status = p_status WHERE id = p_task_id;
  INSERT INTO internal.task_activity (task_id, created_by, type, message, meta)
  VALUES (p_task_id, v_user_id, 'STATUS_CHANGE', 'Estado: ' || v_old || ' ÔåÆ ' || p_status,
    jsonb_build_object('old_status', v_old, 'new_status', p_status));
  RETURN true;
END; $$;
ALTER FUNCTION "public"."tasks_set_status"("p_task_id" "uuid", "p_status" "text") OWNER TO "postgres";
--
-- Name: tasks_unassign("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."tasks_unassign"("p_task_id" "uuid", "p_user_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_caller UUID; v_name TEXT;
BEGIN
  v_caller := internal.get_authorized_user_id(auth.uid());
  IF v_caller IS NULL THEN RAISE EXCEPTION 'Not authorized'; END IF;
  DELETE FROM internal.task_assignees WHERE task_id = p_task_id AND user_id = p_user_id;
  SELECT full_name INTO v_name FROM internal.authorized_users WHERE id = p_user_id;
  INSERT INTO internal.task_activity (task_id, created_by, type, message) VALUES (p_task_id, v_caller, 'ASSIGNMENT', 'Desasignado: ' || COALESCE(v_name, ''));
  RETURN true;
END; $$;
ALTER FUNCTION "public"."tasks_unassign"("p_task_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";
--
-- Name: tasks_update("uuid", "text", "text", "text", "date", "date", "text"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."tasks_update"("p_task_id" "uuid", "p_title" "text" DEFAULT NULL::"text", "p_description" "text" DEFAULT NULL::"text", "p_priority" "text" DEFAULT NULL::"text", "p_due_date" "date" DEFAULT NULL::"date", "p_start_date" "date" DEFAULT NULL::"date", "p_tags" "text"[] DEFAULT NULL::"text"[]) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_user_id UUID;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN RAISE EXCEPTION 'Not authorized'; END IF;
  UPDATE internal.tasks SET title = COALESCE(p_title, title), description = COALESCE(p_description, description),
    priority = COALESCE(p_priority, priority), due_date = COALESCE(p_due_date, due_date),
    start_date = COALESCE(p_start_date, start_date), tags = COALESCE(p_tags, tags)
  WHERE id = p_task_id;
  INSERT INTO internal.task_activity (task_id, created_by, type, message) VALUES (p_task_id, v_user_id, 'FIELD_CHANGE', 'Tarea actualizada');
  RETURN true;
END; $$;
ALTER FUNCTION "public"."tasks_update"("p_task_id" "uuid", "p_title" "text", "p_description" "text", "p_priority" "text", "p_due_date" "date", "p_start_date" "date", "p_tags" "text"[]) OWNER TO "postgres";
