-- Name: toggle_user_status("uuid", boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."toggle_user_status"("p_user_id" "uuid", "p_is_active" boolean) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal'
    AS $$
BEGIN
  UPDATE internal.authorized_users
  SET is_active = p_is_active, updated_at = now()
  WHERE id = p_user_id;
  
  RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."toggle_user_status"("p_user_id" "uuid", "p_is_active" boolean) OWNER TO "postgres";
