-- Name: update_authorized_user("uuid", "text", "text", "text", "text", boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_authorized_user"("p_user_id" "uuid", "p_full_name" "text", "p_phone" "text", "p_department" "text", "p_job_position" "text", "p_is_active" boolean) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal'
    AS $$
BEGIN
  UPDATE internal.authorized_users
  SET 
    full_name = p_full_name,
    phone = p_phone,
    department = p_department::department_type,
    job_position = p_job_position,
    is_active = p_is_active,
    updated_at = now()
  WHERE id = p_user_id;
  
  RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."update_authorized_user"("p_user_id" "uuid", "p_full_name" "text", "p_phone" "text", "p_department" "text", "p_job_position" "text", "p_is_active" boolean) OWNER TO "postgres";
--
-- Name: update_canvassing_location("uuid", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_canvassing_location"("p_location_id" "uuid", "p_data" "jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$

DECLARE

  v_user_id UUID;

  v_update_data JSONB;

BEGIN

  v_user_id := internal.get_authorized_user_id(auth.uid());

  

  -- Verificar permisos: solo el creador puede actualizar

  IF NOT EXISTS (

    SELECT 1 FROM crm.location 

    WHERE id = p_location_id AND created_by = v_user_id

  ) THEN

    RAISE EXCEPTION 'No tienes permiso para actualizar este punto de Canvassing';

  END IF;

  

  -- Construir objeto de actualizaci├│n excluyendo campos que no se deben actualizar

  v_update_data := p_data - 'id' - 'created_by' - 'created_at';

  v_update_data := v_update_data || jsonb_build_object('modified_by', v_user_id);

  

  -- Actualizar la tabla (solo campos que existen en v_update_data)

  UPDATE crm.location

  SET 

    -- A. Ubicaci├│n

    address = COALESCE(v_update_data->>'address', address),

    city = COALESCE(v_update_data->>'city', city),

    province = COALESCE((v_update_data->>'province')::TEXT, province),

    postal_code = COALESCE((v_update_data->>'postal_code')::TEXT, postal_code),

    country = COALESCE((v_update_data->>'country')::TEXT, country),

    location_references = COALESCE((v_update_data->>'location_references')::TEXT, location_references),

    -- B. Negocio

    company_name = COALESCE((v_update_data->>'company_name')::TEXT, company_name),

    business_type = COALESCE((v_update_data->>'business_type')::crm.business_type, business_type),

    business_size_sqm = COALESCE((v_update_data->>'business_size_sqm')::NUMERIC, business_size_sqm),

    business_floors = COALESCE((v_update_data->>'business_floors')::INTEGER, business_floors),

    business_hours = COALESCE((v_update_data->>'business_hours')::TEXT, business_hours),

    years_in_operation = COALESCE((v_update_data->>'years_in_operation')::INTEGER, years_in_operation),

    -- C. Contacto

    contact_first_name = COALESCE((v_update_data->>'contact_first_name')::TEXT, contact_first_name),

    contact_last_name = COALESCE((v_update_data->>'contact_last_name')::TEXT, contact_last_name),

    contact_position = COALESCE((v_update_data->>'contact_position')::TEXT, contact_position),

    contact_phone_primary = COALESCE((v_update_data->>'contact_phone_primary')::TEXT, contact_phone_primary),

    contact_phone_secondary = COALESCE((v_update_data->>'contact_phone_secondary')::TEXT, contact_phone_secondary),

    contact_email_primary = COALESCE((v_update_data->>'contact_email_primary')::TEXT, contact_email_primary),

    preferred_contact_method = COALESCE((v_update_data->>'preferred_contact_method')::crm.contact_method, preferred_contact_method),

    best_contact_time = COALESCE((v_update_data->>'best_contact_time')::crm.contact_time, best_contact_time),

    is_decision_maker = COALESCE((v_update_data->>'is_decision_maker')::BOOLEAN, is_decision_maker),

    secondary_contact_name = COALESCE((v_update_data->>'secondary_contact_name')::TEXT, secondary_contact_name),

    secondary_contact_phone = COALESCE((v_update_data->>'secondary_contact_phone')::TEXT, secondary_contact_phone),

    -- D. Estado

    status = COALESCE((v_update_data->>'status')::crm.canvassing_status, status),

    priority = COALESCE((v_update_data->>'priority')::crm.canvassing_priority, priority),

    lead_score = COALESCE((v_update_data->>'lead_score')::INTEGER, lead_score),

    lead_source = COALESCE((v_update_data->>'lead_source')::TEXT, lead_source),

    assigned_to = COALESCE((v_update_data->>'assigned_to')::UUID, assigned_to),

    team_id = COALESCE((v_update_data->>'team_id')::UUID, team_id),

    -- E. Soluciones AV

    av_solutions_required = COALESCE((v_update_data->>'av_solutions_required')::crm.av_solution_type[], av_solutions_required),

    solution_details = COALESCE((v_update_data->>'solution_details')::TEXT, solution_details),

    number_of_screens = COALESCE((v_update_data->>'number_of_screens')::INTEGER, number_of_screens),

    equipment_locations = COALESCE((v_update_data->>'equipment_locations')::TEXT, equipment_locations),

    estimated_budget_range = COALESCE((v_update_data->>'estimated_budget_range')::TEXT, estimated_budget_range),

    project_urgency = COALESCE((v_update_data->>'project_urgency')::TEXT, project_urgency),

    -- F. Situaci├│n Actual

    has_current_av_installation = COALESCE((v_update_data->>'has_current_av_installation')::BOOLEAN, has_current_av_installation),

    current_provider = COALESCE((v_update_data->>'current_provider')::TEXT, current_provider),

    installation_age_years = COALESCE((v_update_data->>'installation_age_years')::INTEGER, installation_age_years),

    current_installation_problems = COALESCE((v_update_data->>'current_installation_problems')::TEXT, current_installation_problems),

    has_maintenance_contract = COALESCE((v_update_data->>'has_maintenance_contract')::BOOLEAN, has_maintenance_contract),

    maintenance_contract_provider = COALESCE((v_update_data->>'maintenance_contract_provider')::TEXT, maintenance_contract_provider),

    maintenance_contract_end_date = COALESCE((v_update_data->>'maintenance_contract_end_date')::DATE, maintenance_contract_end_date),

    has_requested_competitor_quotes = COALESCE((v_update_data->>'has_requested_competitor_quotes')::BOOLEAN, has_requested_competitor_quotes),

    competitors_contacted = COALESCE((v_update_data->>'competitors_contacted')::TEXT, competitors_contacted),

    -- G. Comercial

    interest_level = COALESCE((v_update_data->>'interest_level')::INTEGER, interest_level),

    purchase_phase = COALESCE((v_update_data->>'purchase_phase')::crm.purchase_phase, purchase_phase),

    main_objections = COALESCE((v_update_data->>'main_objections')::TEXT[], main_objections),

    objections_other = COALESCE((v_update_data->>'objections_other')::TEXT, objections_other),

    economic_decision_maker_identified = COALESCE((v_update_data->>'economic_decision_maker_identified')::BOOLEAN, economic_decision_maker_identified),

    approval_process = COALESCE((v_update_data->>'approval_process')::TEXT, approval_process),

    -- H. Citas

    appointment_date = COALESCE((v_update_data->>'appointment_date')::DATE, appointment_date),

    appointment_time = COALESCE((v_update_data->>'appointment_time')::TIME, appointment_time),

    appointment_type = COALESCE((v_update_data->>'appointment_type')::crm.appointment_type, appointment_type),

    appointment_location = COALESCE((v_update_data->>'appointment_location')::TEXT, appointment_location),

    callback_date = COALESCE((v_update_data->>'callback_date')::DATE, callback_date),

    callback_time = COALESCE((v_update_data->>'callback_time')::TIME, callback_time),

    reminder_enabled = COALESCE((v_update_data->>'reminder_enabled')::BOOLEAN, reminder_enabled),

    reminder_time_before = COALESCE((v_update_data->>'reminder_time_before')::TEXT, reminder_time_before),

    -- I. Archivos

    photos = COALESCE((v_update_data->>'photos')::TEXT[], photos),

    videos = COALESCE((v_update_data->>'videos')::TEXT[], videos),

    documents = COALESCE((v_update_data->>'documents')::TEXT[], documents),

    -- J. T├®cnico

    technical_service_type = COALESCE((v_update_data->>'technical_service_type')::crm.technical_service_type, technical_service_type),

    maintenance_frequency = COALESCE((v_update_data->>'maintenance_frequency')::crm.maintenance_frequency, maintenance_frequency),

    proposed_maintenance_contract = COALESCE((v_update_data->>'proposed_maintenance_contract')::BOOLEAN, proposed_maintenance_contract),

    maintenance_contract_value = COALESCE((v_update_data->>'maintenance_contract_value')::NUMERIC, maintenance_contract_value),

    existing_equipment = COALESCE((v_update_data->>'existing_equipment')::TEXT, existing_equipment),

    has_active_warranties = COALESCE((v_update_data->>'has_active_warranties')::BOOLEAN, has_active_warranties),

    warranty_end_date = COALESCE((v_update_data->>'warranty_end_date')::DATE, warranty_end_date),

    local_access_info = COALESCE((v_update_data->>'local_access_info')::TEXT, local_access_info),

    -- K. Tags

    tags = COALESCE((v_update_data->>'tags')::TEXT[], tags)

  WHERE id = p_location_id;

  

  RETURN p_location_id;

END;

$$;
ALTER FUNCTION "public"."update_canvassing_location"("p_location_id" "uuid", "p_data" "jsonb") OWNER TO "postgres";
--
-- Name: update_catalog_category("uuid", "text", "text", "text", "uuid", integer, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_catalog_category"("p_id" "uuid", "p_name" "text" DEFAULT NULL::"text", "p_slug" "text" DEFAULT NULL::"text", "p_description" "text" DEFAULT NULL::"text", "p_parent_id" "uuid" DEFAULT NULL::"uuid", "p_sort_order" integer DEFAULT NULL::integer, "p_is_active" boolean DEFAULT NULL::boolean) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$ BEGIN IF NOT internal.is_admin() THEN RAISE EXCEPTION 'Only admins can update categories'; END IF; UPDATE catalog.categories SET name = COALESCE(p_name, name), slug = COALESCE(lower(regexp_replace(trim(p_slug), '\s+', '-', 'g')), slug), description = COALESCE(p_description, description), parent_id = COALESCE(p_parent_id, parent_id), sort_order = COALESCE(p_sort_order, sort_order), is_active = COALESCE(p_is_active, is_active), updated_at = now() WHERE id = p_id; RETURN FOUND; END; $$;
ALTER FUNCTION "public"."update_catalog_category"("p_id" "uuid", "p_name" "text", "p_slug" "text", "p_description" "text", "p_parent_id" "uuid", "p_sort_order" integer, "p_is_active" boolean) OWNER TO "postgres";
--
-- Name: update_catalog_product("uuid", "text", "text", "text", "uuid", "catalog"."unit_type", numeric, numeric, numeric, "uuid", boolean, numeric, "uuid", boolean, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_catalog_product"("p_id" "uuid", "p_name" "text" DEFAULT NULL::"text", "p_sku" "text" DEFAULT NULL::"text", "p_description" "text" DEFAULT NULL::"text", "p_category_id" "uuid" DEFAULT NULL::"uuid", "p_unit" "catalog"."unit_type" DEFAULT NULL::"catalog"."unit_type", "p_cost_price" numeric DEFAULT NULL::numeric, "p_sale_price" numeric DEFAULT NULL::numeric, "p_discount_percent" numeric DEFAULT NULL::numeric, "p_tax_rate_id" "uuid" DEFAULT NULL::"uuid", "p_track_stock" boolean DEFAULT NULL::boolean, "p_min_stock_alert" numeric DEFAULT NULL::numeric, "p_supplier_id" "uuid" DEFAULT NULL::"uuid", "p_clear_supplier" boolean DEFAULT false, "p_is_active" boolean DEFAULT NULL::boolean) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NOT internal.is_admin() THEN RAISE EXCEPTION 'Only admins can update products'; END IF;
  UPDATE catalog.products
  SET name = COALESCE(p_name, name),
      sku = COALESCE(p_sku, sku),
      description = COALESCE(p_description, description),
      category_id = COALESCE(p_category_id, category_id),
      unit = COALESCE(p_unit, unit),
      cost_price = COALESCE(p_cost_price, cost_price),
      sale_price = COALESCE(p_sale_price, sale_price),
      discount_percent = COALESCE(p_discount_percent, discount_percent),
      tax_rate_id = COALESCE(p_tax_rate_id, tax_rate_id),
      track_stock = COALESCE(p_track_stock, track_stock),
      min_stock_alert = COALESCE(p_min_stock_alert, min_stock_alert),
      supplier_id = CASE WHEN p_clear_supplier THEN NULL WHEN p_supplier_id IS NOT NULL THEN p_supplier_id ELSE supplier_id END,
      is_active = COALESCE(p_is_active, is_active),
      updated_at = now()
  WHERE id = p_id;
  RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."update_catalog_product"("p_id" "uuid", "p_name" "text", "p_sku" "text", "p_description" "text", "p_category_id" "uuid", "p_unit" "catalog"."unit_type", "p_cost_price" numeric, "p_sale_price" numeric, "p_discount_percent" numeric, "p_tax_rate_id" "uuid", "p_track_stock" boolean, "p_min_stock_alert" numeric, "p_supplier_id" "uuid", "p_clear_supplier" boolean, "p_is_active" boolean) OWNER TO "postgres";
--
-- Name: update_client("uuid", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "uuid", "date", timestamp with time zone, "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_client"("p_client_id" "uuid", "p_company_name" "text" DEFAULT NULL::"text", "p_contact_phone" "text" DEFAULT NULL::"text", "p_contact_email" "text" DEFAULT NULL::"text", "p_lead_stage" "text" DEFAULT NULL::"text", "p_lead_source" "text" DEFAULT NULL::"text", "p_industry_sector" "text" DEFAULT NULL::"text", "p_urgency" "text" DEFAULT NULL::"text", "p_tax_id" "text" DEFAULT NULL::"text", "p_legal_name" "text" DEFAULT NULL::"text", "p_billing_address" "text" DEFAULT NULL::"text", "p_billing_city" "text" DEFAULT NULL::"text", "p_billing_province" "text" DEFAULT NULL::"text", "p_billing_postal_code" "text" DEFAULT NULL::"text", "p_billing_country" "text" DEFAULT NULL::"text", "p_website" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text", "p_assigned_to" "uuid" DEFAULT NULL::"uuid", "p_next_follow_up_date" "date" DEFAULT NULL::"date", "p_created_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_instagram_handle" "text" DEFAULT NULL::"text", "p_tiktok_handle" "text" DEFAULT NULL::"text", "p_linkedin_url" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$

DECLARE

  v_is_admin boolean;

BEGIN

  -- Check if user is admin

  v_is_admin := internal.is_admin();

  

  UPDATE crm.clients

  SET 

    company_name = COALESCE(p_company_name, company_name),

    contact_phone = COALESCE(p_contact_phone, contact_phone),

    contact_email = COALESCE(p_contact_email, contact_email),

    lead_stage = COALESCE(p_lead_stage::crm.lead_stage, lead_stage),

    lead_source = COALESCE(p_lead_source::crm.lead_source, lead_source),

    industry_sector = COALESCE(p_industry_sector::crm.industry_sector, industry_sector),

    urgency = COALESCE(p_urgency::crm.urgency_level, urgency),

    tax_id = COALESCE(p_tax_id, tax_id),

    legal_name = COALESCE(p_legal_name, legal_name),

    billing_address = COALESCE(p_billing_address, billing_address),

    billing_city = COALESCE(p_billing_city, billing_city),

    billing_province = COALESCE(p_billing_province, billing_province),

    billing_postal_code = COALESCE(p_billing_postal_code, billing_postal_code),

    billing_country = COALESCE(p_billing_country, billing_country),

    website = COALESCE(p_website, website),

    notes = COALESCE(p_notes, notes),

    assigned_to = COALESCE(p_assigned_to, assigned_to),

    next_follow_up_date = COALESCE(p_next_follow_up_date, next_follow_up_date),

    instagram_handle = COALESCE(p_instagram_handle, instagram_handle),

    tiktok_handle = COALESCE(p_tiktok_handle, tiktok_handle),

    linkedin_url = COALESCE(p_linkedin_url, linkedin_url),

    -- Only admins can change created_at

    created_at = CASE WHEN v_is_admin AND p_created_at IS NOT NULL THEN p_created_at ELSE created_at END,

    updated_at = now()

  WHERE id = p_client_id AND deleted_at IS NULL;

  

  RETURN FOUND;

END;

$$;
ALTER FUNCTION "public"."update_client"("p_client_id" "uuid", "p_company_name" "text", "p_contact_phone" "text", "p_contact_email" "text", "p_lead_stage" "text", "p_lead_source" "text", "p_industry_sector" "text", "p_urgency" "text", "p_tax_id" "text", "p_legal_name" "text", "p_billing_address" "text", "p_billing_city" "text", "p_billing_province" "text", "p_billing_postal_code" "text", "p_billing_country" "text", "p_website" "text", "p_notes" "text", "p_assigned_to" "uuid", "p_next_follow_up_date" "date", "p_created_at" timestamp with time zone, "p_instagram_handle" "text", "p_tiktok_handle" "text", "p_linkedin_url" "text") OWNER TO "postgres";
--
-- Name: update_client_coordinates("uuid", numeric, numeric, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_client_coordinates"("p_client_id" "uuid", "p_latitude" numeric, "p_longitude" numeric, "p_full_address" "text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
    UPDATE crm.clients
    SET 
        latitude = p_latitude,
        longitude = p_longitude,
        full_address = p_full_address,
        updated_at = now()
    WHERE id = p_client_id AND deleted_at IS NULL;
    
    RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."update_client_coordinates"("p_client_id" "uuid", "p_latitude" numeric, "p_longitude" numeric, "p_full_address" "text") OWNER TO "postgres";
--
-- Name: update_client_status("uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_client_status"("p_client_id" "uuid", "p_new_status" "text", "p_note" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_user_id UUID;
    v_user_name TEXT;
    v_previous_status TEXT;
    v_note_content TEXT;
BEGIN
    -- Obtener informaci├│n del usuario actual
    SELECT au.id, au.full_name 
    INTO v_user_id, v_user_name
    FROM internal.authorized_users au
    WHERE au.auth_user_id = auth.uid();
    
    IF v_user_id IS NULL THEN
        RAISE EXCEPTION 'Usuario no autorizado';
    END IF;
    
    -- Obtener estado anterior
    SELECT lead_stage::TEXT INTO v_previous_status
    FROM crm.clients WHERE id = p_client_id AND deleted_at IS NULL;
    
    IF v_previous_status IS NULL THEN
        RAISE EXCEPTION 'Cliente no encontrado';
    END IF;
    
    -- No hacer nada si el estado es el mismo
    IF v_previous_status = p_new_status THEN
        RETURN TRUE;
    END IF;
    
    -- Actualizar estado
    UPDATE crm.clients
    SET lead_stage = p_new_status::crm.lead_stage, updated_at = now()
    WHERE id = p_client_id;
    
    -- Crear nota de cambio de estado
    v_note_content := 'Estado cambiado de "' || v_previous_status || '" a "' || p_new_status || '"';
    IF p_note IS NOT NULL AND p_note != '' THEN
        v_note_content := v_note_content || '. ' || p_note;
    END IF;
    
    INSERT INTO crm.client_notes (
        client_id,
        note_type,
        content,
        previous_status,
        new_status,
        user_id,
        user_name
    ) VALUES (
        p_client_id,
        'status_change',
        v_note_content,
        v_previous_status,
        p_new_status,
        v_user_id,
        v_user_name
    );
    
    RETURN TRUE;
END;
$$;
ALTER FUNCTION "public"."update_client_status"("p_client_id" "uuid", "p_new_status" "text", "p_note" "text") OWNER TO "postgres";
