CREATE FUNCTION "public"."update_external_credit_provider"("p_id" "uuid", "p_name" "text" DEFAULT NULL::"text", "p_creditor_account_code" "text" DEFAULT NULL::"text", "p_expense_account_code" "text" DEFAULT NULL::"text", "p_is_active" boolean DEFAULT NULL::boolean) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
