--

CREATE FUNCTION "public"."update_invoice"("p_invoice_id" "uuid", "p_client_id" "uuid" DEFAULT NULL::"uuid", "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_project_name" "text" DEFAULT NULL::"text", "p_issue_date" "date" DEFAULT NULL::"date", "p_due_date" "date" DEFAULT NULL::"date", "p_notes" "text" DEFAULT NULL::"text", "p_internal_notes" "text" DEFAULT NULL::"text", "p_payment_terms" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT NULL::"text", "p_site_id" "uuid" DEFAULT NULL::"uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'Usuario no autorizado';
  END IF;

  UPDATE sales.invoices
  SET
    client_id = COALESCE(p_client_id, client_id),
    project_id = COALESCE(p_project_id, project_id),
    project_name = COALESCE(p_project_name, project_name),
    issue_date = COALESCE(p_issue_date, issue_date),
    due_date = COALESCE(p_due_date, due_date),
    notes = COALESCE(p_notes, notes),
    internal_notes = COALESCE(p_internal_notes, internal_notes),
    payment_terms = COALESCE(p_payment_terms, payment_terms),
    status = COALESCE(p_status, status),
    site_id = COALESCE(p_site_id, site_id),
    updated_at = now()
  WHERE id = p_invoice_id;

  RETURN FOUND;
END;
$$;
