-- Name: update_invoice_line("uuid", "text", "text", numeric, numeric, numeric, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_invoice_line"("p_line_id" "uuid", "p_concept" "text" DEFAULT NULL::"text", "p_description" "text" DEFAULT NULL::"text", "p_quantity" numeric DEFAULT NULL::numeric, "p_unit_price" numeric DEFAULT NULL::numeric, "p_discount_percent" numeric DEFAULT NULL::numeric, "p_tax_rate" numeric DEFAULT NULL::numeric) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$

DECLARE

  v_invoice_id UUID;

  v_is_locked BOOLEAN;

BEGIN

  SELECT invoice_id INTO v_invoice_id FROM sales.invoice_lines WHERE id = p_line_id;

  SELECT is_locked INTO v_is_locked FROM sales.invoices WHERE id = v_invoice_id;

  

  IF COALESCE(v_is_locked, false) THEN

    RAISE EXCEPTION 'No se pueden editar l├¡neas de una factura bloqueada';

  END IF;



  UPDATE sales.invoice_lines

  SET

    concept = COALESCE(p_concept, concept),

    description = COALESCE(p_description, description),

    quantity = COALESCE(p_quantity, quantity),

    unit_price = COALESCE(p_unit_price, unit_price),

    discount_percent = COALESCE(p_discount_percent, discount_percent),

    tax_rate = COALESCE(p_tax_rate, tax_rate),

    updated_at = now()

  WHERE id = p_line_id;



  RETURN FOUND;

END;

$$;
ALTER FUNCTION "public"."update_invoice_line"("p_line_id" "uuid", "p_concept" "text", "p_description" "text", "p_quantity" numeric, "p_unit_price" numeric, "p_discount_percent" numeric, "p_tax_rate" numeric) OWNER TO "postgres";
--
-- Name: update_own_user_info("uuid", "text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_own_user_info"("p_user_id" "uuid", "p_full_name" "text" DEFAULT NULL::"text", "p_phone" "text" DEFAULT NULL::"text", "p_job_position" "text" DEFAULT NULL::"text", "p_theme_preference" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal'
    AS $$

DECLARE

  v_updated boolean := false;

BEGIN

  -- Verificar que el usuario existe y est├í activo

  IF NOT EXISTS (SELECT 1 FROM internal.authorized_users WHERE id = p_user_id AND is_active = true) THEN

    RAISE EXCEPTION 'User not found or inactive';

  END IF;



  -- Actualizar campos solo si se proporcionan (no NULL)

  UPDATE internal.authorized_users

  SET 

    full_name = CASE 

      WHEN p_full_name IS NOT NULL THEN p_full_name 

      ELSE full_name 

    END,

    phone = CASE 

      WHEN p_phone IS NOT NULL THEN p_phone 

      ELSE phone 

    END,

    job_position = CASE 

      WHEN p_job_position IS NOT NULL THEN p_job_position 

      ELSE job_position 

    END,

    theme_preference = CASE 

      WHEN p_theme_preference IS NOT NULL THEN p_theme_preference 

      ELSE theme_preference 

    END,

    updated_at = now()

  WHERE id = p_user_id;

  

  -- FOUND is a special PL/pgSQL variable, use it directly

  v_updated := FOUND;

  

  RETURN v_updated;

END;

$$;
ALTER FUNCTION "public"."update_own_user_info"("p_user_id" "uuid", "p_full_name" "text", "p_phone" "text", "p_job_position" "text", "p_theme_preference" "text") OWNER TO "postgres";
