-- Name: update_pack_item("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_pack_item"("p_item_id" "uuid", "p_quantity" integer) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_pack_id UUID;
BEGIN
  SELECT pack_id INTO v_pack_id FROM internal.product_pack_items WHERE id = p_item_id;
  
  UPDATE internal.product_pack_items
  SET quantity = p_quantity
  WHERE id = p_item_id;
  
  -- Recalculate pack prices
  IF v_pack_id IS NOT NULL THEN
    PERFORM public.update_product_pack(v_pack_id);
  END IF;
  
  RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."update_pack_item"("p_item_id" "uuid", "p_quantity" integer) OWNER TO "postgres";
--
-- Name: update_partner_compensation_run("uuid", numeric, numeric, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_partner_compensation_run"("p_compensation_run_id" "uuid", "p_gross_amount" numeric DEFAULT NULL::numeric, "p_irpf_rate" numeric DEFAULT NULL::numeric, "p_notes" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_status TEXT;
  v_irpf_amount NUMERIC(12,2);
  v_net_amount NUMERIC(12,2);
  v_gross NUMERIC(12,2);
  v_irpf NUMERIC(5,2);
BEGIN
  SELECT status, gross_amount, irpf_rate INTO v_status, v_gross, v_irpf
  FROM accounting.partner_compensation_runs
  WHERE id = p_compensation_run_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Retribuci├│n no encontrada: %', p_compensation_run_id;
  END IF;
  
  IF v_status != 'DRAFT' THEN
    RAISE EXCEPTION 'Solo se pueden editar retribuciones en estado DRAFT. Estado actual: %', v_status;
  END IF;
  
  v_gross := COALESCE(p_gross_amount, v_gross);
  v_irpf := COALESCE(p_irpf_rate, v_irpf);
  v_irpf_amount := v_gross * (v_irpf / 100);
  v_net_amount := v_gross - v_irpf_amount;
  
  UPDATE accounting.partner_compensation_runs
  SET gross_amount = v_gross, irpf_rate = v_irpf, irpf_amount = v_irpf_amount,
      net_amount = v_net_amount, notes = COALESCE(p_notes, notes), updated_at = now()
  WHERE id = p_compensation_run_id;
  
  RETURN TRUE;
END;
$$;
ALTER FUNCTION "public"."update_partner_compensation_run"("p_compensation_run_id" "uuid", "p_gross_amount" numeric, "p_irpf_rate" numeric, "p_notes" "text") OWNER TO "postgres";
--
-- Name: update_product("uuid", "text", "text", "public"."product_type", numeric, numeric, numeric, integer, boolean, "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_product"("p_product_id" "uuid", "p_name" "text" DEFAULT NULL::"text", "p_description" "text" DEFAULT NULL::"text", "p_type" "public"."product_type" DEFAULT NULL::"public"."product_type", "p_base_price" numeric DEFAULT NULL::numeric, "p_cost_price" numeric DEFAULT NULL::numeric, "p_tax_rate" numeric DEFAULT NULL::numeric, "p_stock" integer DEFAULT NULL::integer, "p_is_active" boolean DEFAULT NULL::boolean, "p_default_tax_id" "uuid" DEFAULT NULL::"uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_actual_tax_rate numeric;
BEGIN
  -- If default_tax_id is provided, get its rate
  IF p_default_tax_id IS NOT NULL THEN
    SELECT rate INTO v_actual_tax_rate
    FROM internal.taxes
    WHERE id = p_default_tax_id AND is_active = true;
  ELSE
    v_actual_tax_rate := p_tax_rate;
  END IF;

  UPDATE internal.products
  SET
    name = COALESCE(p_name, name),
    description = COALESCE(p_description, description),
    type = COALESCE(p_type, type),
    base_price = COALESCE(p_base_price, base_price),
    cost_price = COALESCE(p_cost_price, cost_price),
    tax_rate = COALESCE(v_actual_tax_rate, tax_rate),
    stock = CASE 
      WHEN COALESCE(p_type, type) = 'service' THEN NULL 
      ELSE COALESCE(p_stock, stock) 
    END,
    is_active = COALESCE(p_is_active, is_active),
    default_tax_id = COALESCE(p_default_tax_id, default_tax_id),
    updated_at = now()
  WHERE id = p_product_id;
  
  RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."update_product"("p_product_id" "uuid", "p_name" "text", "p_description" "text", "p_type" "public"."product_type", "p_base_price" numeric, "p_cost_price" numeric, "p_tax_rate" numeric, "p_stock" integer, "p_is_active" boolean, "p_default_tax_id" "uuid") OWNER TO "postgres";
