CREATE FUNCTION "public"."update_product_category"("p_category_id" "uuid", "p_name" "text" DEFAULT NULL::"text", "p_code" "text" DEFAULT NULL::"text", "p_description" "text" DEFAULT NULL::"text", "p_display_order" integer DEFAULT NULL::integer, "p_is_active" boolean DEFAULT NULL::boolean, "p_type" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF auth.uid() IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  IF NOT internal.is_admin() THEN
    RAISE EXCEPTION 'Only admins can update categories';
  END IF;

  UPDATE internal.product_categories
  SET
    name = COALESCE(UPPER(p_name), name),
    code = COALESCE(UPPER(p_code), code),
    description = COALESCE(p_description, description),
    display_order = COALESCE(p_display_order, display_order),
    is_active = COALESCE(p_is_active, is_active),
    type = COALESCE(p_type, type),
    updated_at = now()
  WHERE id = p_category_id;

  RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."update_product_category"("p_category_id" "uuid", "p_name" "text", "p_code" "text", "p_description" "text", "p_display_order" integer, "p_is_active" boolean, "p_type" "text") OWNER TO "postgres";
--
-- Name: update_product_pack("uuid", "text", "text", numeric, numeric, boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_product_pack"("p_pack_id" "uuid", "p_name" "text" DEFAULT NULL::"text", "p_description" "text" DEFAULT NULL::"text", "p_discount_percent" numeric DEFAULT NULL::numeric, "p_tax_rate" numeric DEFAULT NULL::numeric, "p_is_active" boolean DEFAULT NULL::boolean) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_base_price NUMERIC;
  v_final_price NUMERIC;
  v_discount NUMERIC;
BEGIN
  -- Calculate base price from products
  SELECT COALESCE(SUM(p.base_price * ppi.quantity), 0)
  INTO v_base_price
  FROM internal.product_pack_items ppi
  JOIN internal.products p ON ppi.product_id = p.id
  WHERE ppi.pack_id = p_pack_id;
  
  -- Get discount to use
  SELECT COALESCE(p_discount_percent, pp.discount_percent)
  INTO v_discount
  FROM internal.product_packs pp
  WHERE pp.id = p_pack_id;
  
  v_final_price := ROUND(v_base_price * (1 - v_discount / 100), 2);
  
  UPDATE internal.product_packs
  SET
    name = COALESCE(UPPER(p_name), name),
    description = COALESCE(p_description, description),
    discount_percent = COALESCE(p_discount_percent, discount_percent),
    tax_rate = COALESCE(p_tax_rate, tax_rate),
    is_active = COALESCE(p_is_active, is_active),
    base_price = v_base_price,
    final_price = v_final_price,
    updated_at = now()
  WHERE id = p_pack_id;
  
  RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."update_product_pack"("p_pack_id" "uuid", "p_name" "text", "p_description" "text", "p_discount_percent" numeric, "p_tax_rate" numeric, "p_is_active" boolean) OWNER TO "postgres";
