-- Name: update_purchase_invoice("uuid", "text", "date", "date", "text", "text", "text", "text", "uuid", "uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_purchase_invoice"("p_invoice_id" "uuid", "p_supplier_invoice_number" "text" DEFAULT NULL::"text", "p_issue_date" "date" DEFAULT NULL::"date", "p_due_date" "date" DEFAULT NULL::"date", "p_status" "text" DEFAULT NULL::"text", "p_expense_category" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text", "p_internal_notes" "text" DEFAULT NULL::"text", "p_supplier_id" "uuid" DEFAULT NULL::"uuid", "p_technician_id" "uuid" DEFAULT NULL::"uuid", "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_manual_beneficiary_name" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE sales.purchase_invoices
  SET
    supplier_invoice_number = COALESCE(p_supplier_invoice_number, supplier_invoice_number),
    issue_date = COALESCE(p_issue_date, issue_date),
    due_date = COALESCE(p_due_date, due_date),
    status = COALESCE(p_status, status),
    expense_category = COALESCE(p_expense_category, expense_category),
    notes = COALESCE(p_notes, notes),
    internal_notes = COALESCE(p_internal_notes, internal_notes),
    supplier_id = p_supplier_id,
    technician_id = p_technician_id,
    project_id = p_project_id,
    manual_beneficiary_name = CASE
      WHEN p_supplier_id IS NOT NULL OR p_technician_id IS NOT NULL THEN NULL
      ELSE COALESCE(p_manual_beneficiary_name, manual_beneficiary_name)
    END,
    updated_at = now()
  WHERE id = p_invoice_id;
END;
$$;
ALTER FUNCTION "public"."update_purchase_invoice"("p_invoice_id" "uuid", "p_supplier_invoice_number" "text", "p_issue_date" "date", "p_due_date" "date", "p_status" "text", "p_expense_category" "text", "p_notes" "text", "p_internal_notes" "text", "p_supplier_id" "uuid", "p_technician_id" "uuid", "p_project_id" "uuid", "p_manual_beneficiary_name" "text") OWNER TO "postgres";
--
-- Name: update_purchase_invoice("uuid", "text", "date", "date", "text", "text", "text", "text", "uuid", "uuid", "uuid", "text", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_purchase_invoice"("p_invoice_id" "uuid", "p_supplier_invoice_number" "text" DEFAULT NULL::"text", "p_issue_date" "date" DEFAULT NULL::"date", "p_due_date" "date" DEFAULT NULL::"date", "p_status" "text" DEFAULT NULL::"text", "p_expense_category" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text", "p_internal_notes" "text" DEFAULT NULL::"text", "p_supplier_id" "uuid" DEFAULT NULL::"uuid", "p_technician_id" "uuid" DEFAULT NULL::"uuid", "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_manual_beneficiary_name" "text" DEFAULT NULL::"text", "p_site_id" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
  v_site_mode text;
  v_default_site_id uuid;
  v_final_site_id uuid;
BEGIN
  v_final_site_id := p_site_id;

  IF p_project_id IS NOT NULL THEN
    SELECT pp.site_mode, pp.default_site_id
    INTO v_site_mode, v_default_site_id
    FROM projects.projects pp
    WHERE pp.id = p_project_id;

    IF v_site_mode = 'MULTI_SITE' AND v_final_site_id IS NULL THEN
      RAISE EXCEPTION 'site_id is required for MULTI_SITE projects';
    END IF;

    IF v_site_mode = 'SINGLE_SITE' AND v_final_site_id IS NULL THEN
      v_final_site_id := v_default_site_id;
    END IF;

    IF v_final_site_id IS NOT NULL AND NOT EXISTS (
      SELECT 1
      FROM projects.project_sites ps
      WHERE ps.id = v_final_site_id
        AND ps.project_id = p_project_id
        AND ps.is_active = true
    ) THEN
      RAISE EXCEPTION 'site_id does not belong to this project or is inactive';
    END IF;
  ELSE
    v_final_site_id := NULL;
  END IF;

  UPDATE sales.purchase_invoices
  SET
    supplier_invoice_number = COALESCE(p_supplier_invoice_number, supplier_invoice_number),
    issue_date = COALESCE(p_issue_date, issue_date),
    due_date = COALESCE(p_due_date, due_date),
    status = COALESCE(p_status, status),
    expense_category = COALESCE(p_expense_category, expense_category),
    notes = COALESCE(p_notes, notes),
    internal_notes = COALESCE(p_internal_notes, internal_notes),
    supplier_id = p_supplier_id,
    technician_id = p_technician_id,
    project_id = p_project_id,
    site_id = v_final_site_id,
    manual_beneficiary_name = CASE
      WHEN p_supplier_id IS NOT NULL OR p_technician_id IS NOT NULL THEN NULL
      ELSE COALESCE(p_manual_beneficiary_name, manual_beneficiary_name)
    END,
    updated_at = now()
  WHERE id = p_invoice_id;
END;
$$;
ALTER FUNCTION "public"."update_purchase_invoice"("p_invoice_id" "uuid", "p_supplier_invoice_number" "text", "p_issue_date" "date", "p_due_date" "date", "p_status" "text", "p_expense_category" "text", "p_notes" "text", "p_internal_notes" "text", "p_supplier_id" "uuid", "p_technician_id" "uuid", "p_project_id" "uuid", "p_manual_beneficiary_name" "text", "p_site_id" "uuid") OWNER TO "postgres";
--
-- Name: update_purchase_invoice("uuid", "text", "uuid", "uuid", "date", "date", "uuid", "text", "text", "text", "text", "uuid", numeric, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_purchase_invoice"("p_invoice_id" "uuid", "p_invoice_number" "text" DEFAULT NULL::"text", "p_supplier_id" "uuid" DEFAULT NULL::"uuid", "p_technician_id" "uuid" DEFAULT NULL::"uuid", "p_issue_date" "date" DEFAULT NULL::"date", "p_due_date" "date" DEFAULT NULL::"date", "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_expense_category" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text", "p_internal_notes" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT NULL::"text", "p_client_id" "uuid" DEFAULT NULL::"uuid", "p_withholding_amount" numeric DEFAULT NULL::numeric, "p_supplier_invoice_number" "text" DEFAULT NULL::"text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_invoice RECORD;
    v_internal_number TEXT;
BEGIN
    -- Obtener factura actual
    SELECT * INTO v_invoice
    FROM sales.purchase_invoices
    WHERE id = p_invoice_id;
    
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Factura no encontrada';
    END IF;
    
    -- Si est├í bloqueada y no es solo actualizaci├│n de notas, rechazar
    IF v_invoice.is_locked = true AND (p_notes IS NULL OR p_notes != v_invoice.notes) THEN
        -- Permitir actualizar notas incluso si est├í bloqueada
        IF p_notes IS NOT NULL AND p_notes != v_invoice.notes THEN
            UPDATE sales.purchase_invoices
            SET notes = p_notes,
                updated_at = NOW()
            WHERE id = p_invoice_id;
            RETURN;
        ELSE
            RAISE EXCEPTION 'No se puede editar una factura bloqueada';
        END IF;
    END IF;
    
    -- Si el estado cambia a CONFIRMED, generar n├║mero interno y bloquear
    IF p_status = 'CONFIRMED' AND v_invoice.status != 'CONFIRMED' THEN
        -- Generar n├║mero interno si no existe
        IF v_invoice.internal_purchase_number IS NULL THEN
            -- Usar los IDs actualizados o los existentes
            v_internal_number := public.generate_internal_purchase_number(
                p_supplier_id := COALESCE(p_supplier_id, v_invoice.supplier_id),
                p_technician_id := COALESCE(p_technician_id, v_invoice.technician_id),
                p_document_type := COALESCE(v_invoice.document_type, 'INVOICE')
            );
            
            -- Verificar que no exista
            WHILE EXISTS (SELECT 1 FROM sales.purchase_invoices WHERE internal_purchase_number = v_internal_number) LOOP
                v_internal_number := public.generate_internal_purchase_number(
                    p_supplier_id := COALESCE(p_supplier_id, v_invoice.supplier_id),
                    p_technician_id := COALESCE(p_technician_id, v_invoice.technician_id),
                    p_document_type := COALESCE(v_invoice.document_type, 'INVOICE')
                );
            END LOOP;
        ELSE
            v_internal_number := v_invoice.internal_purchase_number;
        END IF;
        
        -- Actualizar con bloqueo
        UPDATE sales.purchase_invoices
        SET
            supplier_invoice_number = COALESCE(p_supplier_invoice_number, supplier_invoice_number),
            internal_purchase_number = v_internal_number,
            status = 'CONFIRMED',
            is_locked = true,
            locked_at = NOW(),
            supplier_id = COALESCE(p_supplier_id, supplier_id),
            technician_id = COALESCE(p_technician_id, technician_id),
            issue_date = COALESCE(p_issue_date, issue_date),
            due_date = COALESCE(p_due_date, due_date),
            project_id = COALESCE(p_project_id, project_id),
            expense_category = COALESCE(p_expense_category, expense_category),
            notes = COALESCE(p_notes, notes),
            internal_notes = COALESCE(p_internal_notes, internal_notes),
            client_id = COALESCE(p_client_id, client_id),
            withholding_amount = COALESCE(p_withholding_amount, withholding_amount),
            updated_at = NOW()
        WHERE id = p_invoice_id;
    ELSE
        -- Actualizaci├│n normal (sin cambio a CONFIRMED)
        UPDATE sales.purchase_invoices
        SET
            supplier_invoice_number = COALESCE(p_supplier_invoice_number, supplier_invoice_number),
            supplier_id = COALESCE(p_supplier_id, supplier_id),
            technician_id = COALESCE(p_technician_id, technician_id),
            issue_date = COALESCE(p_issue_date, issue_date),
            due_date = COALESCE(p_due_date, due_date),
            project_id = COALESCE(p_project_id, project_id),
            expense_category = COALESCE(p_expense_category, expense_category),
            notes = COALESCE(p_notes, notes),
            internal_notes = COALESCE(p_internal_notes, internal_notes),
            status = COALESCE(p_status, status),
            client_id = COALESCE(p_client_id, client_id),
            withholding_amount = COALESCE(p_withholding_amount, withholding_amount),
            updated_at = NOW()
        WHERE id = p_invoice_id;
    END IF;
END;
$$;
ALTER FUNCTION "public"."update_purchase_invoice"("p_invoice_id" "uuid", "p_invoice_number" "text", "p_supplier_id" "uuid", "p_technician_id" "uuid", "p_issue_date" "date", "p_due_date" "date", "p_project_id" "uuid", "p_expense_category" "text", "p_notes" "text", "p_internal_notes" "text", "p_status" "text", "p_client_id" "uuid", "p_withholding_amount" numeric, "p_supplier_invoice_number" "text") OWNER TO "postgres";
--
-- Name: update_purchase_invoice_line("uuid", "text", "text", numeric, numeric, numeric, numeric, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_purchase_invoice_line"("p_line_id" "uuid", "p_concept" "text" DEFAULT NULL::"text", "p_description" "text" DEFAULT NULL::"text", "p_quantity" numeric DEFAULT NULL::numeric, "p_unit_price" numeric DEFAULT NULL::numeric, "p_tax_rate" numeric DEFAULT NULL::numeric, "p_withholding_tax_rate" numeric DEFAULT NULL::numeric, "p_discount_percent" numeric DEFAULT NULL::numeric) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_invoice_id UUID;
BEGIN
    -- Obtener invoice_id
    SELECT purchase_invoice_id
    INTO v_invoice_id
    FROM sales.purchase_invoice_lines
    WHERE id = p_line_id;

    IF NOT FOUND THEN
        RAISE EXCEPTION 'L├¡nea no encontrada';
    END IF;

    -- Actualizar l├¡nea
    UPDATE sales.purchase_invoice_lines
    SET
        concept = COALESCE(p_concept, concept),
        description = COALESCE(p_description, description),
        quantity = COALESCE(p_quantity, quantity),
        unit_price = COALESCE(p_unit_price, unit_price),
        tax_rate = COALESCE(p_tax_rate, tax_rate),
        withholding_tax_rate = COALESCE(p_withholding_tax_rate, withholding_tax_rate),
        discount_percent = COALESCE(p_discount_percent, discount_percent),
        updated_at = NOW()
    WHERE id = p_line_id;

    -- Recalcular totales de la factura
    PERFORM public.recalculate_purchase_invoice(v_invoice_id);
END;
$$;
ALTER FUNCTION "public"."update_purchase_invoice_line"("p_line_id" "uuid", "p_concept" "text", "p_description" "text", "p_quantity" numeric, "p_unit_price" numeric, "p_tax_rate" numeric, "p_withholding_tax_rate" numeric, "p_discount_percent" numeric) OWNER TO "postgres";
--
-- Name: update_purchase_order("uuid", "uuid", "uuid", "uuid", "text", "date", "date", "date", "date", "date", "text", "text", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_purchase_order"("p_order_id" "uuid", "p_supplier_id" "uuid" DEFAULT NULL::"uuid", "p_technician_id" "uuid" DEFAULT NULL::"uuid", "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_status" "text" DEFAULT NULL::"text", "p_issue_date" "date" DEFAULT NULL::"date", "p_expected_start_date" "date" DEFAULT NULL::"date", "p_expected_end_date" "date" DEFAULT NULL::"date", "p_actual_start_date" "date" DEFAULT NULL::"date", "p_actual_end_date" "date" DEFAULT NULL::"date", "p_notes" "text" DEFAULT NULL::"text", "p_internal_notes" "text" DEFAULT NULL::"text", "p_linked_purchase_invoice_id" "uuid" DEFAULT NULL::"uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
    v_supplier_name TEXT;
    v_supplier_tax_id TEXT;
    v_approved_by UUID;
BEGIN
    -- Si cambia el proveedor, actualizar datos desnormalizados
    IF p_supplier_id IS NOT NULL THEN
        SELECT company_name, tax_id
        INTO v_supplier_name, v_supplier_tax_id
        FROM internal.suppliers
        WHERE id = p_supplier_id;
    END IF;
    
    -- Si el estado cambia a APPROVED, registrar qui├®n aprob├│
    IF p_status = 'APPROVED' THEN
        SELECT id INTO v_approved_by
        FROM internal.authorized_users
        WHERE auth_user_id = auth.uid();
    END IF;
    
    UPDATE sales.purchase_orders
    SET 
        supplier_id = COALESCE(p_supplier_id, supplier_id),
        technician_id = COALESCE(p_technician_id, technician_id),
        project_id = COALESCE(p_project_id, project_id),
        supplier_name = COALESCE(v_supplier_name, supplier_name),
        supplier_tax_id = COALESCE(v_supplier_tax_id, supplier_tax_id),
        status = COALESCE(p_status::sales.purchase_order_status, status),
        issue_date = COALESCE(p_issue_date, issue_date),
        expected_start_date = COALESCE(p_expected_start_date, expected_start_date),
        expected_end_date = COALESCE(p_expected_end_date, expected_end_date),
        actual_start_date = COALESCE(p_actual_start_date, actual_start_date),
        actual_end_date = COALESCE(p_actual_end_date, actual_end_date),
        notes = COALESCE(p_notes, notes),
        internal_notes = COALESCE(p_internal_notes, internal_notes),
        linked_purchase_invoice_id = COALESCE(p_linked_purchase_invoice_id, linked_purchase_invoice_id),
        approved_by = COALESCE(v_approved_by, approved_by),
        approved_at = CASE WHEN p_status = 'APPROVED' AND approved_at IS NULL THEN NOW() ELSE approved_at END
    WHERE id = p_order_id;
    
    RETURN FOUND;
END;
$$;
ALTER FUNCTION "public"."update_purchase_order"("p_order_id" "uuid", "p_supplier_id" "uuid", "p_technician_id" "uuid", "p_project_id" "uuid", "p_status" "text", "p_issue_date" "date", "p_expected_start_date" "date", "p_expected_end_date" "date", "p_actual_start_date" "date", "p_actual_end_date" "date", "p_notes" "text", "p_internal_notes" "text", "p_linked_purchase_invoice_id" "uuid") OWNER TO "postgres";
