ALTER FUNCTION "public"."update_purchase_order_line"("p_line_id" "uuid", "p_concept" "text", "p_description" "text", "p_quantity" numeric, "p_unit" "text", "p_unit_price" numeric, "p_tax_rate" numeric, "p_withholding_rate" numeric, "p_discount_percent" numeric, "p_group_name" "text") OWNER TO "postgres";
--
-- Name: update_quote("uuid", "uuid", "text", "date", "text", "uuid", "text", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_quote"("p_quote_id" "uuid", "p_client_id" "uuid" DEFAULT NULL::"uuid", "p_project_name" "text" DEFAULT NULL::"text", "p_valid_until" "date" DEFAULT NULL::"date", "p_status" "text" DEFAULT NULL::"text", "p_project_id" "uuid" DEFAULT NULL::"uuid", "p_notes" "text" DEFAULT NULL::"text", "p_site_id" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_old_status TEXT;
  v_current_number TEXT;
  v_new_number TEXT;
BEGIN
  SELECT status::TEXT, quote_number
  INTO v_old_status, v_current_number
  FROM quotes.quotes
  WHERE id = p_quote_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Quote not found: %', p_quote_id;
  END IF;

  IF v_old_status = 'DRAFT' AND p_status = 'SENT' AND v_current_number LIKE 'BORR-%' THEN
    v_new_number := quotes.get_next_quote_number();

    UPDATE quotes.quotes SET
      preliminary_number = v_current_number,
      quote_number = v_new_number,
      status = 'SENT'::quotes.quote_status,
      issue_date = CURRENT_DATE,
      client_id = COALESCE(p_client_id, client_id),
      project_name = COALESCE(p_project_name, project_name),
      valid_until = COALESCE(p_valid_until, valid_until),
      notes = COALESCE(p_notes, notes),
      project_id = COALESCE(p_project_id, project_id),
      site_id = COALESCE(p_site_id, site_id),
      updated_at = now()
    WHERE id = p_quote_id;
  ELSIF v_old_status = 'DRAFT' AND p_status = 'SENT' THEN
    UPDATE quotes.quotes SET
      status = 'SENT'::quotes.quote_status,
      issue_date = CURRENT_DATE,
      client_id = COALESCE(p_client_id, client_id),
      project_name = COALESCE(p_project_name, project_name),
      valid_until = COALESCE(p_valid_until, valid_until),
      notes = COALESCE(p_notes, notes),
      project_id = COALESCE(p_project_id, project_id),
      site_id = COALESCE(p_site_id, site_id),
      updated_at = now()
    WHERE id = p_quote_id;
  ELSE
    UPDATE quotes.quotes SET
      client_id = COALESCE(p_client_id, client_id),
      project_name = COALESCE(p_project_name, project_name),
      valid_until = COALESCE(p_valid_until, valid_until),
      status = COALESCE(p_status::quotes.quote_status, status),
      project_id = COALESCE(p_project_id, project_id),
      notes = COALESCE(p_notes, notes),
      site_id = COALESCE(p_site_id, site_id),
      updated_at = now()
    WHERE id = p_quote_id;
  END IF;

  PERFORM public.recalculate_quote_totals(p_quote_id);
END;
$$;
ALTER FUNCTION "public"."update_quote"("p_quote_id" "uuid", "p_client_id" "uuid", "p_project_name" "text", "p_valid_until" "date", "p_status" "text", "p_project_id" "uuid", "p_notes" "text", "p_site_id" "uuid") OWNER TO "postgres";
--
-- Name: update_quote_line("uuid", "text", "text", numeric, numeric, numeric, numeric); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_quote_line"("p_line_id" "uuid", "p_concept" "text" DEFAULT NULL::"text", "p_description" "text" DEFAULT NULL::"text", "p_quantity" numeric DEFAULT NULL::numeric, "p_unit_price" numeric DEFAULT NULL::numeric, "p_tax_rate" numeric DEFAULT NULL::numeric, "p_discount_percent" numeric DEFAULT NULL::numeric) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_quote_id UUID;
BEGIN
  -- Check user authorization
  IF internal.get_authorized_user_id(auth.uid()) IS NULL THEN
    RAISE EXCEPTION 'User not authorized';
  END IF;
  
  -- Get quote_id for the line
  SELECT quote_id INTO v_quote_id FROM quotes.quote_lines WHERE id = p_line_id;
  
  IF v_quote_id IS NULL THEN
    RETURN FALSE;
  END IF;
  
  -- Update the line
  UPDATE quotes.quote_lines
  SET
    concept = COALESCE(p_concept, concept),
    description = COALESCE(p_description, description),
    quantity = COALESCE(p_quantity, quantity),
    unit_price = COALESCE(p_unit_price, unit_price),
    tax_rate = COALESCE(p_tax_rate, tax_rate),
    discount_percent = COALESCE(p_discount_percent, discount_percent),
    updated_at = NOW()
  WHERE id = p_line_id;
  
  -- Update quote totals
  PERFORM quotes.update_quote_totals(v_quote_id);
  
  RETURN TRUE;
END;
$$;
ALTER FUNCTION "public"."update_quote_line"("p_line_id" "uuid", "p_concept" "text", "p_description" "text", "p_quantity" numeric, "p_unit_price" numeric, "p_tax_rate" numeric, "p_discount_percent" numeric) OWNER TO "postgres";
--
-- Name: update_quote_lines_order("uuid", "uuid"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_quote_lines_order"("p_quote_id" "uuid", "p_line_ids" "uuid"[]) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_line_id UUID;
  v_order INTEGER;
BEGIN
  -- Check user authorization
  IF internal.get_authorized_user_id(auth.uid()) IS NULL THEN
    RAISE EXCEPTION 'User not authorized';
  END IF;
  
  -- Update line_order for each line based on its position in the array
  FOR v_order IN 1..array_length(p_line_ids, 1) LOOP
    v_line_id := p_line_ids[v_order];
    
    UPDATE quotes.quote_lines
    SET line_order = v_order,
        updated_at = NOW()
    WHERE id = v_line_id
      AND quote_id = p_quote_id;
  END LOOP;
  
  RETURN TRUE;
END;
$$;
ALTER FUNCTION "public"."update_quote_lines_order"("p_quote_id" "uuid", "p_line_ids" "uuid"[]) OWNER TO "postgres";
--
-- Name: update_site_planning("uuid", "date", integer, "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_site_planning"("p_site_id" "uuid", "p_planned_start_date" "date" DEFAULT NULL::"date", "p_planned_days" integer DEFAULT NULL::integer, "p_planned_end_date" "date" DEFAULT NULL::"date") RETURNS json
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_calc_end DATE;
  v_current_status TEXT;
  v_new_status TEXT;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());

  SELECT ps.site_status INTO v_current_status
  FROM projects.project_sites ps WHERE ps.id = p_site_id;

  IF v_current_status IS NULL THEN
    RAISE EXCEPTION 'Site not found';
  END IF;

  -- Calculate end date from start + days
  IF p_planned_start_date IS NOT NULL AND p_planned_days IS NOT NULL AND p_planned_end_date IS NULL THEN
    v_calc_end := p_planned_start_date + (p_planned_days - 1);
  ELSE
    v_calc_end := p_planned_end_date;
  END IF;

  -- Determine status transition
  v_new_status := v_current_status;
  IF v_current_status = 'PLANNED' AND p_planned_start_date IS NOT NULL THEN
    v_new_status := 'SCHEDULED';
  END IF;

  UPDATE projects.project_sites
  SET
    planned_start_date = COALESCE(p_planned_start_date, planned_start_date),
    planned_days = COALESCE(p_planned_days, planned_days),
    planned_end_date = COALESCE(v_calc_end, planned_end_date),
    site_status = v_new_status,
    updated_at = now()
  WHERE id = p_site_id;

  RETURN json_build_object('status', v_new_status, 'planned_end_date', v_calc_end);
END;
$$;
ALTER FUNCTION "public"."update_site_planning"("p_site_id" "uuid", "p_planned_start_date" "date", "p_planned_days" integer, "p_planned_end_date" "date") OWNER TO "postgres";
