-- Name: update_tax("uuid", "text", "text", numeric, "text", boolean, boolean, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."update_tax"("p_tax_id" "uuid", "p_name" "text" DEFAULT NULL::"text", "p_code" "text" DEFAULT NULL::"text", "p_rate" numeric DEFAULT NULL::numeric, "p_description" "text" DEFAULT NULL::"text", "p_is_default" boolean DEFAULT NULL::boolean, "p_is_active" boolean DEFAULT NULL::boolean, "p_display_order" integer DEFAULT NULL::integer) RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_tax_type text;
BEGIN
  -- Obtener el tipo de impuesto actual
  SELECT tax_type INTO v_tax_type FROM internal.taxes WHERE id = p_tax_id;

  -- Si se establece como default, quitar el default actual del mismo tipo
  IF p_is_default = true THEN
    UPDATE internal.taxes SET is_default = false WHERE tax_type = v_tax_type AND is_default = true AND id != p_tax_id;
  END IF;

  UPDATE internal.taxes
  SET
    name = COALESCE(p_name, name),
    code = COALESCE(p_code, code),
    rate = COALESCE(p_rate, rate),
    description = COALESCE(p_description, description),
    is_default = COALESCE(p_is_default, is_default),
    is_active = COALESCE(p_is_active, is_active),
    display_order = COALESCE(p_display_order, display_order)
  WHERE id = p_tax_id;

  RETURN FOUND;
END;
$$;
