CREATE FUNCTION "public"."update_worker"("p_user_id" "uuid", "p_department" "text" DEFAULT NULL::"text", "p_job_position" "text" DEFAULT NULL::"text", "p_phone" "text" DEFAULT NULL::"text", "p_tax_id" "text" DEFAULT NULL::"text", "p_iban" "text" DEFAULT NULL::"text", "p_irpf_rate" numeric DEFAULT NULL::numeric, "p_address" "text" DEFAULT NULL::"text", "p_city" "text" DEFAULT NULL::"text", "p_postal_code" "text" DEFAULT NULL::"text", "p_province" "text" DEFAULT NULL::"text", "p_ss_regime" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE internal.authorized_users
  SET
    -- Cast text to department_type enum only if p_department is provided
    department = CASE 
      WHEN p_department IS NOT NULL THEN p_department::internal.department_type 
      ELSE department 
    END,
    job_position = COALESCE(p_job_position, job_position),
    phone = COALESCE(p_phone, phone),
    tax_id = COALESCE(p_tax_id, tax_id),
    iban = COALESCE(p_iban, iban),
    irpf_rate = COALESCE(p_irpf_rate, irpf_rate),
    address = COALESCE(p_address, address),
    city = COALESCE(p_city, city),
    postal_code = COALESCE(p_postal_code, postal_code),
    province = COALESCE(p_province, province),
    ss_regime = COALESCE(p_ss_regime, ss_regime),
    updated_at = now()
  WHERE id = p_user_id;

  RETURN FOUND;
END;
$$;
