--
-- Name: upsert_company_contacts("text", "text", "text", "text", "jsonb", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."upsert_company_contacts"("p_contact_email" "text" DEFAULT NULL::"text", "p_contact_phone" "text" DEFAULT NULL::"text", "p_contact_phone_secondary" "text" DEFAULT NULL::"text", "p_whatsapp_number" "text" DEFAULT NULL::"text", "p_social_networks" "jsonb" DEFAULT '[]'::"jsonb", "p_business_hours" "text" DEFAULT NULL::"text", "p_google_maps_url" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_id UUID;
BEGIN
  -- Verificar que es admin
  IF NOT internal.is_admin() THEN
    RAISE EXCEPTION 'Solo los administradores pueden modificar los contactos';
  END IF;

  -- Intentar obtener el registro existente
  SELECT cc.id INTO v_id FROM internal.company_contacts cc LIMIT 1;

  IF v_id IS NOT NULL THEN
    -- Actualizar
    UPDATE internal.company_contacts SET
      contact_email = p_contact_email,
      contact_phone = p_contact_phone,
      contact_phone_secondary = p_contact_phone_secondary,
      whatsapp_number = p_whatsapp_number,
      social_networks = p_social_networks,
      business_hours = p_business_hours,
      google_maps_url = p_google_maps_url,
      updated_at = now()
    WHERE id = v_id;
  ELSE
    -- Insertar
    INSERT INTO internal.company_contacts (
      contact_email, contact_phone, contact_phone_secondary, whatsapp_number,
      social_networks, business_hours, google_maps_url
    ) VALUES (
      p_contact_email, p_contact_phone, p_contact_phone_secondary, p_whatsapp_number,
      p_social_networks, p_business_hours, p_google_maps_url
    )
    RETURNING id INTO v_id;
  END IF;

  RETURN v_id;
END;
$$;
ALTER FUNCTION "public"."upsert_company_contacts"("p_contact_email" "text", "p_contact_phone" "text", "p_contact_phone_secondary" "text", "p_whatsapp_number" "text", "p_social_networks" "jsonb", "p_business_hours" "text", "p_google_maps_url" "text") OWNER TO "postgres";
