-- Name: upsert_company_preferences(integer, integer, "text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."upsert_company_preferences"("p_quote_validity_days" integer DEFAULT NULL::integer, "p_invoice_payment_days" integer DEFAULT NULL::integer, "p_default_currency" "text" DEFAULT NULL::"text", "p_bank_accounts" "jsonb" DEFAULT NULL::"jsonb") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_id UUID;
BEGIN
  -- Verificar que es admin
  IF NOT internal.is_admin() THEN
    RAISE EXCEPTION 'Solo los administradores pueden modificar las preferencias';
  END IF;

  -- Verificar si ya existe un registro
  SELECT id INTO v_id FROM internal.company_preferences LIMIT 1;
  
  IF v_id IS NULL THEN
    -- Insertar nuevo registro
    INSERT INTO internal.company_preferences (
      quote_validity_days,
      invoice_payment_days,
      default_currency,
      bank_accounts
    ) VALUES (
      COALESCE(p_quote_validity_days, 15),
      COALESCE(p_invoice_payment_days, 30),
      COALESCE(p_default_currency, 'EUR'),
      COALESCE(p_bank_accounts, '[]'::jsonb)
    )
    RETURNING id INTO v_id;
  ELSE
    -- Actualizar registro existente
    UPDATE internal.company_preferences
    SET
      quote_validity_days = COALESCE(p_quote_validity_days, quote_validity_days),
      invoice_payment_days = COALESCE(p_invoice_payment_days, invoice_payment_days),
      default_currency = COALESCE(p_default_currency, default_currency),
      bank_accounts = COALESCE(p_bank_accounts, bank_accounts),
      updated_at = NOW()
    WHERE id = v_id;
  END IF;
  
  RETURN v_id;
END;
$$;
ALTER FUNCTION "public"."upsert_company_preferences"("p_quote_validity_days" integer, "p_invoice_payment_days" integer, "p_default_currency" "text", "p_bank_accounts" "jsonb") OWNER TO "postgres";
