-- Name: upsert_company_settings("text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."upsert_company_settings"("p_legal_name" "text", "p_tax_id" "text", "p_vat_number" "text" DEFAULT NULL::"text", "p_commercial_name" "text" DEFAULT NULL::"text", "p_company_type" "text" DEFAULT 'company'::"text", "p_country" "text" DEFAULT 'Espa├▒a'::"text", "p_fiscal_address" "text" DEFAULT NULL::"text", "p_fiscal_postal_code" "text" DEFAULT NULL::"text", "p_fiscal_city" "text" DEFAULT NULL::"text", "p_fiscal_province" "text" DEFAULT NULL::"text", "p_billing_email" "text" DEFAULT NULL::"text", "p_billing_phone" "text" DEFAULT NULL::"text", "p_website" "text" DEFAULT NULL::"text", "p_logo_url" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_settings_id UUID;
BEGIN
  -- Check if user is admin
  IF NOT public.has_role(auth.uid(), 'admin') THEN
    RAISE EXCEPTION 'Access denied: admin role required';
  END IF;
  
  -- Check if settings exist in internal schema
  SELECT id INTO v_settings_id FROM internal.company_settings LIMIT 1;
  
  IF v_settings_id IS NULL THEN
    -- Insert new settings
    INSERT INTO internal.company_settings (
      legal_name, tax_id, vat_number, commercial_name, company_type, country,
      fiscal_address, fiscal_postal_code, fiscal_city, fiscal_province,
      billing_email, billing_phone, website, logo_url
    ) VALUES (
      p_legal_name, p_tax_id, p_vat_number, p_commercial_name, p_company_type, p_country,
      p_fiscal_address, p_fiscal_postal_code, p_fiscal_city, p_fiscal_province,
      p_billing_email, p_billing_phone, p_website, p_logo_url
    )
    RETURNING id INTO v_settings_id;
  ELSE
    -- Update existing settings
    UPDATE internal.company_settings
    SET 
      legal_name = COALESCE(p_legal_name, legal_name),
      tax_id = COALESCE(p_tax_id, tax_id),
      vat_number = COALESCE(p_vat_number, vat_number),
      commercial_name = COALESCE(p_commercial_name, commercial_name),
      company_type = COALESCE(p_company_type, company_type),
      country = COALESCE(p_country, country),
      fiscal_address = COALESCE(p_fiscal_address, fiscal_address),
      fiscal_postal_code = COALESCE(p_fiscal_postal_code, fiscal_postal_code),
      fiscal_city = COALESCE(p_fiscal_city, fiscal_city),
      fiscal_province = COALESCE(p_fiscal_province, fiscal_province),
      billing_email = COALESCE(p_billing_email, billing_email),
      billing_phone = COALESCE(p_billing_phone, billing_phone),
      website = COALESCE(p_website, website),
      logo_url = COALESCE(p_logo_url, logo_url),
      updated_at = now()
    WHERE id = v_settings_id;
  END IF;
  
  RETURN v_settings_id;
END;
$$;
ALTER FUNCTION "public"."upsert_company_settings"("p_legal_name" "text", "p_tax_id" "text", "p_vat_number" "text", "p_commercial_name" "text", "p_company_type" "text", "p_country" "text", "p_fiscal_address" "text", "p_fiscal_postal_code" "text", "p_fiscal_city" "text", "p_fiscal_province" "text", "p_billing_email" "text", "p_billing_phone" "text", "p_website" "text", "p_logo_url" "text") OWNER TO "postgres";
