-- Name: upsert_site_assignment("uuid", "uuid", "text", "date", "date", "text", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."upsert_site_assignment"("p_site_id" "uuid", "p_technician_id" "uuid", "p_role" "text" DEFAULT 'INSTALLER'::"text", "p_date_from" "date" DEFAULT NULL::"date", "p_date_to" "date" DEFAULT NULL::"date", "p_notes" "text" DEFAULT NULL::"text", "p_assignment_id" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
  v_id UUID;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());

  IF p_assignment_id IS NOT NULL THEN
    UPDATE projects.site_technician_assignments
    SET technician_id = p_technician_id,
        role = COALESCE(p_role, role),
        date_from = p_date_from,
        date_to = p_date_to,
        notes = p_notes,
        updated_at = now()
    WHERE id = p_assignment_id
    RETURNING id INTO v_id;
  ELSE
    INSERT INTO projects.site_technician_assignments (site_id, technician_id, role, date_from, date_to, notes, created_by)
    VALUES (p_site_id, p_technician_id, COALESCE(p_role, 'INSTALLER'), p_date_from, p_date_to, p_notes, v_user_id)
    RETURNING id INTO v_id;
  END IF;

  RETURN v_id;
END;
$$;
ALTER FUNCTION "public"."upsert_site_assignment"("p_site_id" "uuid", "p_technician_id" "uuid", "p_role" "text", "p_date_from" "date", "p_date_to" "date", "p_notes" "text", "p_assignment_id" "uuid") OWNER TO "postgres";
--
-- Name: v4_get_group_settings("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."v4_get_group_settings"("p_conversation_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal', 'ai', 'public'
    AS $$
DECLARE
  v_auth_uid uuid;
  v_is_admin boolean;
  v_is_manager boolean;
  v_settings RECORD;
BEGIN
  v_auth_uid := auth.uid();
  v_is_admin := internal.user_has_role(v_auth_uid, 'admin');
  v_is_manager := internal.user_has_role(v_auth_uid, 'manager');

  IF NOT v_is_admin AND NOT v_is_manager THEN
    RETURN jsonb_build_object('error', 'Access denied');
  END IF;

  SELECT * INTO v_settings
  FROM ai.group_agent_settings
  WHERE conversation_id = p_conversation_id;

  IF v_settings.conversation_id IS NULL THEN
    RETURN jsonb_build_object(
      'exists', false,
      'auto_mode', false,
      'agent_name', 'NEXO AI',
      'model', 'qwen2.5:3b',
      'intervention_level', 'medium',
      'cooldown_minutes', 10,
      'last_intervention_at', null
    );
  END IF;

  RETURN jsonb_build_object(
    'exists', true,
    'conversation_id', v_settings.conversation_id,
    'department', v_settings.department,
    'agent_name', v_settings.agent_name,
    'model', v_settings.model,
    'auto_mode', v_settings.auto_mode,
    'intervention_level', v_settings.intervention_level,
    'cooldown_minutes', v_settings.cooldown_minutes,
    'last_intervention_at', v_settings.last_intervention_at,
    'created_at', v_settings.created_at,
    'updated_at', v_settings.updated_at
  );
END;
$$;
ALTER FUNCTION "public"."v4_get_group_settings"("p_conversation_id" "uuid") OWNER TO "postgres";
--
-- Name: v4_join_department_conversation("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."v4_join_department_conversation"("p_conversation_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql"
    SET "search_path" TO 'ai', 'internal', 'public'
    AS $$
DECLARE
  v_user_id uuid;
  v_dept ai.department_scope;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());
  IF v_user_id IS NULL THEN
    RAISE EXCEPTION 'User not authorized';
  END IF;

  SELECT c.department INTO v_dept
  FROM ai.conversations c
  WHERE c.id = p_conversation_id AND c.scope = 'department';

  IF v_dept IS NULL THEN
    RAISE EXCEPTION 'Conversation not found or not a department group';
  END IF;

  IF NOT ai.user_can_access_department(v_dept) THEN
    RAISE EXCEPTION 'No tienes acceso al grupo de %', v_dept;
  END IF;

  INSERT INTO ai.conversation_members (conversation_id, user_id, role)
  VALUES (p_conversation_id, v_user_id, 'member')
  ON CONFLICT DO NOTHING;

  RETURN true;
END;
$$;
ALTER FUNCTION "public"."v4_join_department_conversation"("p_conversation_id" "uuid") OWNER TO "postgres";
--
-- Name: v4_set_group_settings("uuid", "text", "text", boolean, "text", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."v4_set_group_settings"("p_conversation_id" "uuid", "p_agent_name" "text" DEFAULT NULL::"text", "p_model" "text" DEFAULT NULL::"text", "p_auto_mode" boolean DEFAULT NULL::boolean, "p_intervention_level" "text" DEFAULT NULL::"text", "p_cooldown_minutes" integer DEFAULT NULL::integer) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'internal', 'ai', 'public'
    AS $$
DECLARE
  v_auth_uid uuid;
  v_conv RECORD;
  v_result RECORD;
BEGIN
  v_auth_uid := auth.uid();

  IF NOT internal.user_has_role(v_auth_uid, 'admin') THEN
    RAISE EXCEPTION 'Only admin can modify group agent settings';
  END IF;

  SELECT id, scope, department INTO v_conv
  FROM ai.conversations
  WHERE id = p_conversation_id;

  IF v_conv.id IS NULL THEN
    RAISE EXCEPTION 'Conversation not found';
  END IF;

  IF v_conv.scope != 'department' THEN
    RAISE EXCEPTION 'Agent settings only apply to department conversations';
  END IF;

  IF p_intervention_level IS NOT NULL AND p_intervention_level NOT IN ('low', 'medium', 'high') THEN
    RAISE EXCEPTION 'intervention_level must be low, medium, or high';
  END IF;

  INSERT INTO ai.group_agent_settings (conversation_id, department)
  VALUES (p_conversation_id, v_conv.department)
  ON CONFLICT (conversation_id) DO NOTHING;

  UPDATE ai.group_agent_settings
  SET
    agent_name = COALESCE(p_agent_name, agent_name),
    model = COALESCE(p_model, model),
    auto_mode = COALESCE(p_auto_mode, auto_mode),
    intervention_level = COALESCE(p_intervention_level, intervention_level),
    cooldown_minutes = COALESCE(p_cooldown_minutes, cooldown_minutes)
  WHERE conversation_id = p_conversation_id
  RETURNING * INTO v_result;

  RETURN jsonb_build_object(
    'success', true,
    'conversation_id', v_result.conversation_id,
    'auto_mode', v_result.auto_mode,
    'intervention_level', v_result.intervention_level,
    'model', v_result.model,
    'cooldown_minutes', v_result.cooldown_minutes
  );
END;
$$;
ALTER FUNCTION "public"."v4_set_group_settings"("p_conversation_id" "uuid", "p_agent_name" "text", "p_model" "text", "p_auto_mode" boolean, "p_intervention_level" "text", "p_cooldown_minutes" integer) OWNER TO "postgres";
--
-- Name: validate_invitation_token("text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION "public"."validate_invitation_token"("p_token" "text", "p_email" "text") RETURNS TABLE("is_valid" boolean, "user_id" "uuid", "error_message" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_token_record internal.invitation_tokens%ROWTYPE;
  v_user internal.authorized_users%ROWTYPE;
BEGIN
  -- Find the token
  SELECT * INTO v_token_record
  FROM internal.invitation_tokens
  WHERE token = p_token;
  
  IF NOT FOUND THEN
    RETURN QUERY SELECT false::boolean, NULL::uuid, 'Token no encontrado'::text;
    RETURN;
  END IF;
  
  -- Check if already used
  IF v_token_record.used_at IS NOT NULL THEN
    RETURN QUERY SELECT false::boolean, NULL::uuid, 'Este enlace ya ha sido utilizado'::text;
    RETURN;
  END IF;
  
  -- Check expiration
  IF v_token_record.expires_at < now() THEN
    RETURN QUERY SELECT false::boolean, NULL::uuid, 'El enlace de invitaci├│n ha expirado'::text;
    RETURN;
  END IF;
  
  -- Verify email matches user
  SELECT * INTO v_user
  FROM internal.authorized_users
  WHERE id = v_token_record.user_id;
  
  IF NOT FOUND OR v_user.email != p_email THEN
    RETURN QUERY SELECT false::boolean, NULL::uuid, 'El email no coincide con la invitaci├│n'::text;
    RETURN;
  END IF;
  
  -- Valid token
  RETURN QUERY SELECT true::boolean, v_token_record.user_id, NULL::text;
END;
$$;
ALTER FUNCTION "public"."validate_invitation_token"("p_token" "text", "p_email" "text") OWNER TO "postgres";
