--

CREATE FUNCTION "quotes"."delete_stale_drafts"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'quotes', 'public'
    AS $$
DECLARE
  v_count integer;
BEGIN
  DELETE FROM quotes.quotes
  WHERE status = 'DRAFT'::quotes.quote_status
    AND created_at < (NOW() - INTERVAL '30 days');

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;
