--
-- Name: duplicate_quote("uuid"); Type: FUNCTION; Schema: quotes; Owner: postgres
--

CREATE FUNCTION "quotes"."duplicate_quote"("p_quote_id" "uuid") RETURNS TABLE("new_quote_id" "uuid", "new_quote_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'quotes', 'public'
    AS $$
DECLARE
  v_source_quote quotes.quotes%ROWTYPE;
  v_new_quote_id uuid;
  v_new_number text;
  v_current_user_id uuid;
BEGIN
  -- Get current user
  v_current_user_id := auth.uid();
  
  -- Get source quote
  SELECT * INTO v_source_quote FROM quotes.quotes WHERE id = p_quote_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Quote not found';
  END IF;
  
  -- Get next draft number
  v_new_number := quotes.get_next_draft_number();
  
  -- Create new quote with same data
  INSERT INTO quotes.quotes (
    quote_number,
    client_id,
    project_id,
    project_name,
    order_number,
    status,
    valid_until,
    notes,
    created_by
  )
  VALUES (
    v_new_number,
    v_source_quote.client_id,
    v_source_quote.project_id,
    v_source_quote.project_name,
    NULL,
    'DRAFT'::quotes.quote_status,
    NULL, -- User can set a new validity date
    v_source_quote.notes,
    v_current_user_id
  )
  RETURNING id INTO v_new_quote_id;
  
  -- Copy all quote lines
  INSERT INTO quotes.quote_lines (
    quote_id,
    concept,
    description,
    quantity,
    unit_price,
    tax_rate,
    discount_percent,
    subtotal,
    tax_amount,
    total,
    line_order
  )
  SELECT
    v_new_quote_id,
    concept,
    description,
    quantity,
    unit_price,
    tax_rate,
    discount_percent,
    subtotal,
    tax_amount,
    total,
    line_order
  FROM quotes.quote_lines
  WHERE quote_id = p_quote_id
  ORDER BY line_order;
  
  -- Update totals in the new quote
  UPDATE quotes.quotes q SET
    subtotal = COALESCE(
      (SELECT SUM(ql.subtotal) FROM quotes.quote_lines ql WHERE ql.quote_id = v_new_quote_id),
      0
    ),
    tax_amount = COALESCE(
      (SELECT SUM(ql.tax_amount) FROM quotes.quote_lines ql WHERE ql.quote_id = v_new_quote_id),
      0
    ),
    total = COALESCE(
      (SELECT SUM(ql.total) FROM quotes.quote_lines ql WHERE ql.quote_id = v_new_quote_id),
      0
    )
  WHERE q.id = v_new_quote_id;
  
  -- If source quote is DRAFT, change it to SENT and assign a real number
  IF v_source_quote.status = 'DRAFT' THEN
    -- Get next real quote number
    PERFORM quotes.update_quote(
      p_quote_id := p_quote_id,
      p_status := 'SENT'
    );
  END IF;
  
  RETURN QUERY SELECT v_new_quote_id, v_new_number;
END;
$$;
ALTER FUNCTION "quotes"."duplicate_quote"("p_quote_id" "uuid") OWNER TO "postgres";
--
-- Name: expire_overdue_quotes(); Type: FUNCTION; Schema: quotes; Owner: postgres
--

CREATE FUNCTION "quotes"."expire_overdue_quotes"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'quotes', 'public'
    AS $$
DECLARE
  v_count integer;
BEGIN
  UPDATE quotes.quotes
  SET status = 'EXPIRED'::quotes.quote_status,
      updated_at = now()
  WHERE status = 'SENT'::quotes.quote_status
    AND valid_until IS NOT NULL
    AND valid_until < CURRENT_DATE;

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;
ALTER FUNCTION "quotes"."expire_overdue_quotes"() OWNER TO "postgres";
--
-- Name: generate_quote_number(); Type: FUNCTION; Schema: quotes; Owner: postgres
--

CREATE FUNCTION "quotes"."generate_quote_number"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'quotes', 'public'
    AS $$
DECLARE
  v_year TEXT;
  v_seq INTEGER;
BEGIN
  v_year := TO_CHAR(now(), 'YY');
  v_seq := nextval('quotes.quote_number_seq');
  NEW.quote_number := 'P-' || v_year || '-' || LPAD(v_seq::TEXT, 6, '0');
  RETURN NEW;
END;
$$;
ALTER FUNCTION "quotes"."generate_quote_number"() OWNER TO "postgres";
--
-- Name: get_next_draft_number(); Type: FUNCTION; Schema: quotes; Owner: postgres
--

CREATE FUNCTION "quotes"."get_next_draft_number"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'quotes', 'public'
    AS $_$

DECLARE

  v_year TEXT;

  v_max_seq INTEGER;

  v_new_number TEXT;

BEGIN

  -- Get current year (2 digits)

  v_year := TO_CHAR(NOW(), 'YY');

  

  -- Lock the quotes table

  LOCK TABLE quotes.quotes IN SHARE ROW EXCLUSIVE MODE;

  

  -- Get the max sequence number for draft quotes for the current year

  SELECT COALESCE(MAX(

    CASE 

      WHEN quote_number ~ ('^BORR-P-' || v_year || '-[0-9]{6}$')

      THEN CAST(SUBSTRING(quote_number FROM 11 FOR 6) AS INTEGER)

      ELSE 0

    END

  ), 0)

  INTO v_max_seq

  FROM quotes.quotes

  WHERE quote_number LIKE 'BORR-P-' || v_year || '-%';

  

  -- Generate the new draft quote number

  v_new_number := 'BORR-P-' || v_year || '-' || LPAD((v_max_seq + 1)::TEXT, 6, '0');

  

  RETURN v_new_number;

END;

$_$;
ALTER FUNCTION "quotes"."get_next_draft_number"() OWNER TO "postgres";
--
-- Name: FUNCTION "get_next_draft_number"(); Type: COMMENT; Schema: quotes; Owner: postgres
--

COMMENT ON FUNCTION "quotes"."get_next_draft_number"() IS 'Genera un n├║mero provisional ├║nico para borradores usando una secuencia. 
El n├║mero definitivo (P-YY-XXXXXX) se asigna cuando pasa a estado SENT.';
--
-- Name: get_next_quote_number(); Type: FUNCTION; Schema: quotes; Owner: postgres
--

CREATE FUNCTION "quotes"."get_next_quote_number"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'quotes', 'public'
    AS $_$
DECLARE
  v_year TEXT;
  v_max_seq INTEGER;
  v_new_number TEXT;
BEGIN
  -- Get current year (2 digits)
  v_year := TO_CHAR(NOW(), 'YY');
  
  -- Lock the quotes table to prevent concurrent inserts from getting the same number
  LOCK TABLE quotes.quotes IN SHARE ROW EXCLUSIVE MODE;
  
  -- Get the max sequence number for the current year
  SELECT COALESCE(MAX(
    CASE 
      WHEN quote_number ~ ('^P-' || v_year || '-[0-9]{6}$')
      THEN CAST(SUBSTRING(quote_number FROM 6 FOR 6) AS INTEGER)
      ELSE 0
    END
  ), 0)
  INTO v_max_seq
  FROM quotes.quotes
  WHERE quote_number LIKE 'P-' || v_year || '-%';
  
  -- Generate the new quote number
  v_new_number := 'P-' || v_year || '-' || LPAD((v_max_seq + 1)::TEXT, 6, '0');
  
  RETURN v_new_number;
END;
$_$;
ALTER FUNCTION "quotes"."get_next_quote_number"() OWNER TO "postgres";
--
-- Name: log_quote_change(); Type: FUNCTION; Schema: quotes; Owner: postgres
--

CREATE FUNCTION "quotes"."log_quote_change"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'sales', 'accounting', 'internal', 'crm', 'quotes'
    AS $$

BEGIN

  -- Log status changes

  IF OLD.status IS DISTINCT FROM NEW.status THEN

    INSERT INTO quotes.quote_history (quote_id, field_name, old_value, new_value, changed_by)

    VALUES (NEW.id, 'status', OLD.status::text, NEW.status::text, NEW.created_by);

  END IF;

  

  -- Log notes changes

  IF OLD.notes IS DISTINCT FROM NEW.notes THEN

    INSERT INTO quotes.quote_history (quote_id, field_name, old_value, new_value, changed_by)

    VALUES (NEW.id, 'notes', OLD.notes, NEW.notes, NEW.created_by);

  END IF;

  

  -- Log client changes

  IF OLD.client_id IS DISTINCT FROM NEW.client_id THEN

    INSERT INTO quotes.quote_history (quote_id, field_name, old_value, new_value, changed_by)

    VALUES (NEW.id, 'client_id', OLD.client_id::text, NEW.client_id::text, NEW.created_by);

  END IF;

  

  RETURN NEW;

END;

$$;
ALTER FUNCTION "quotes"."log_quote_change"() OWNER TO "postgres";
--
-- Name: log_quote_status_to_project(); Type: FUNCTION; Schema: quotes; Owner: postgres
--

CREATE FUNCTION "quotes"."log_quote_status_to_project"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'quotes', 'public'
    AS $$
DECLARE
  v_user_name TEXT;
  v_old_status TEXT;
  v_new_status TEXT;
  v_msg TEXT;
BEGIN
  IF NEW.project_id IS NULL THEN
    RETURN NEW;
  END IF;

  v_old_status := OLD.status::TEXT;
  v_new_status := NEW.status::TEXT;

  IF v_old_status IS DISTINCT FROM v_new_status THEN
    SELECT full_name INTO v_user_name
    FROM internal.authorized_users WHERE id = auth.uid();

    v_msg := 'Presupuesto ' || COALESCE(NEW.quote_number, '') || ': estado cambiado de ' || 
             COALESCE(v_old_status, 'N/A') || ' a ' || v_new_status;

    INSERT INTO projects.project_activity (
      project_id, activity_type, content, metadata, created_by, created_by_name
    ) VALUES (
      NEW.project_id, 'QUOTE_STATUS', v_msg,
      jsonb_build_object('quote_id', NEW.id, 'quote_number', NEW.quote_number,
                         'old_status', v_old_status, 'new_status', v_new_status),
      auth.uid(), COALESCE(v_user_name, 'Sistema')
    );

    INSERT INTO quotes.quote_activity (
      quote_id, activity_type, content, metadata, created_by, created_by_name
    ) VALUES (
      NEW.id, 'STATUS_CHANGE', v_msg,
      jsonb_build_object('old_status', v_old_status, 'new_status', v_new_status),
      auth.uid(), COALESCE(v_user_name, 'Sistema')
    );
  END IF;

  RETURN NEW;
END;
$$;
ALTER FUNCTION "quotes"."log_quote_status_to_project"() OWNER TO "postgres";
--
-- Name: set_quote_issue_date(); Type: FUNCTION; Schema: quotes; Owner: postgres
--

CREATE FUNCTION "quotes"."set_quote_issue_date"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'quotes', 'public'
    AS $$
BEGIN
  -- Si el estado cambia de DRAFT a SENT y no tiene issue_date
  IF OLD.status = 'DRAFT' AND NEW.status = 'SENT' AND NEW.issue_date IS NULL THEN
    NEW.issue_date := CURRENT_DATE;
    
    -- Si valid_until est├í definido, recalcular bas├índose en issue_date
    -- Asumimos que valid_until representa los d├¡as de validez desde la emisi├│n
    IF OLD.valid_until IS NOT NULL THEN
      -- Calcular los d├¡as de validez originales (desde created_at)
      NEW.valid_until := NEW.issue_date + (OLD.valid_until - OLD.created_at::date);
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$;
ALTER FUNCTION "quotes"."set_quote_issue_date"() OWNER TO "postgres";
--
-- Name: update_quote("uuid", "uuid", "text", "date", "text", "text"); Type: FUNCTION; Schema: quotes; Owner: postgres
--

CREATE FUNCTION "quotes"."update_quote"("p_quote_id" "uuid", "p_client_id" "uuid" DEFAULT NULL::"uuid", "p_project_name" "text" DEFAULT NULL::"text", "p_valid_until" "date" DEFAULT NULL::"date", "p_status" "text" DEFAULT NULL::"text", "p_notes" "text" DEFAULT NULL::"text") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'quotes', 'public'
    AS $$
DECLARE
  v_current_status text;
  v_current_number text;
  v_new_number text;
  v_is_draft_number boolean;
BEGIN
  SELECT status::text, quote_number INTO v_current_status, v_current_number
  FROM quotes.quotes WHERE id = p_quote_id;
  
  IF NOT FOUND THEN
    RETURN false;
  END IF;
  
  v_is_draft_number := v_current_number LIKE 'BORR-%';
  
  IF p_status = 'SENT' AND v_is_draft_number THEN
    v_new_number := quotes.get_next_quote_number();
  ELSE
    v_new_number := NULL;
  END IF;
  
  IF v_current_status = 'REJECTED' AND p_status IS NOT NULL AND p_status != 'REJECTED' THEN
    RAISE EXCEPTION 'Cannot change status from REJECTED';
  END IF;
  
  UPDATE quotes.quotes SET
    client_id = COALESCE(p_client_id, client_id),
    project_name = COALESCE(p_project_name, project_name),
    valid_until = COALESCE(p_valid_until, valid_until),
    status = COALESCE(p_status::quotes.quote_status, status),
    notes = COALESCE(p_notes, notes),
    quote_number = COALESCE(v_new_number, quote_number),
    provisional_number = CASE 
      WHEN v_new_number IS NOT NULL THEN v_current_number 
      ELSE provisional_number 
    END,
    issue_date = CASE
      WHEN v_current_status = 'DRAFT' AND p_status = 'SENT' THEN CURRENT_DATE
      ELSE issue_date
    END,
    updated_at = now()
  WHERE id = p_quote_id;
  
  RETURN true;
END;
$$;
ALTER FUNCTION "quotes"."update_quote"("p_quote_id" "uuid", "p_client_id" "uuid", "p_project_name" "text", "p_valid_until" "date", "p_status" "text", "p_notes" "text") OWNER TO "postgres";
--
-- Name: update_quote_totals("uuid"); Type: FUNCTION; Schema: quotes; Owner: postgres
--

CREATE FUNCTION "quotes"."update_quote_totals"("p_quote_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'quotes', 'public'
    AS $$
DECLARE
  v_subtotal NUMERIC;
  v_tax_amount NUMERIC;
  v_total NUMERIC;
BEGIN
  SELECT 
    COALESCE(SUM(subtotal), 0),
    COALESCE(SUM(tax_amount), 0),
    COALESCE(SUM(total), 0)
  INTO v_subtotal, v_tax_amount, v_total
  FROM quotes.quote_lines
  WHERE quote_id = p_quote_id;
  
  UPDATE quotes.quotes
  SET 
    subtotal = v_subtotal,
    tax_amount = v_tax_amount,
    total = v_total,
    updated_at = NOW()
  WHERE id = p_quote_id;
END;
$$;
ALTER FUNCTION "quotes"."update_quote_totals"("p_quote_id" "uuid") OWNER TO "postgres";
--
-- Name: can_access_invoice_archive("uuid"); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."can_access_invoice_archive"("p_invoice_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'sales', 'internal', 'projects'
    AS $$
DECLARE
  v_user_id UUID;
  v_invoice_project_id UUID;
  v_invoice_created_by UUID;
BEGIN
  v_user_id := internal.get_authorized_user_id(auth.uid());

  IF auth.uid() IS NULL OR v_user_id IS NULL THEN
    RETURN FALSE;
  END IF;

  IF internal.is_admin() OR internal.is_manager() OR internal.is_readonly() THEN
    RETURN TRUE;
  END IF;

  SELECT i.project_id, i.created_by
  INTO v_invoice_project_id, v_invoice_created_by
  FROM sales.invoices i
  WHERE i.id = p_invoice_id;

  IF NOT FOUND THEN
    RETURN FALSE;
  END IF;

  IF internal.is_sales() AND v_invoice_created_by = v_user_id THEN
    RETURN TRUE;
  END IF;

  IF v_invoice_project_id IS NOT NULL AND projects.can_access_project(v_invoice_project_id) THEN
    RETURN TRUE;
  END IF;

  RETURN FALSE;
END;
$$;
ALTER FUNCTION "sales"."can_access_invoice_archive"("p_invoice_id" "uuid") OWNER TO "postgres";
--
-- Name: create_invoice_from_quote("uuid"); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."create_invoice_from_quote"("p_quote_id" "uuid") RETURNS TABLE("invoice_id" "uuid", "invoice_number" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
    v_quote RECORD;
    v_invoice_id uuid;
    v_invoice_number text;
    v_user_id UUID;
BEGIN
    -- Validar usuario y obtener el id correcto de authorized_users
    v_user_id := internal.get_authorized_user_id(auth.uid());
    IF v_user_id IS NULL THEN
        RAISE EXCEPTION 'Usuario no autorizado';
    END IF;
    
    SELECT q.id, q.client_id, q.project_id, q.project_name, q.status, q.notes
    INTO v_quote
    FROM quotes.quotes q
    WHERE q.id = p_quote_id;
    
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Quote not found';
    END IF;
    
    IF v_quote.status != 'APPROVED' THEN
        RAISE EXCEPTION 'Only approved quotes can be invoiced';
    END IF;
    
    v_invoice_number := public.get_next_invoice_number();
    
    INSERT INTO sales.invoices (
        invoice_number, source_quote_id, client_id, project_id, project_name,
        status, issue_date, due_date, notes, created_by
    ) VALUES (
        v_invoice_number, p_quote_id, v_quote.client_id, v_quote.project_id, 
        v_quote.project_name, 'DRAFT', CURRENT_DATE, CURRENT_DATE + INTERVAL '30 days',
        v_quote.notes, v_user_id  -- Usar v_user_id en lugar de auth.uid()
    )
    RETURNING id INTO v_invoice_id;
    
    INSERT INTO sales.invoice_lines (
        invoice_id, concept, description, quantity, unit_price, tax_rate, discount_percent, line_order
    )
    SELECT v_invoice_id, concept, description, quantity, unit_price, tax_rate, discount_percent, line_order
    FROM quotes.quote_lines
    WHERE quote_id = p_quote_id
    ORDER BY line_order;
    
    UPDATE quotes.quotes SET status = 'INVOICED', updated_at = now() WHERE id = p_quote_id;
    
    RETURN QUERY SELECT v_invoice_id, v_invoice_number;
END;
$$;
ALTER FUNCTION "sales"."create_invoice_from_quote"("p_quote_id" "uuid") OWNER TO "postgres";
--
-- Name: generate_po_number(); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."generate_po_number"() RETURNS "text"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
    v_year INTEGER;
    v_next_number INTEGER;
    v_po_number TEXT;
BEGIN
    v_year := EXTRACT(YEAR FROM CURRENT_DATE);
    
    -- Insertar o actualizar secuencia del a├▒o
    INSERT INTO sales.purchase_order_sequences (year, last_number)
    VALUES (v_year, 1)
    ON CONFLICT (year) DO UPDATE
    SET last_number = sales.purchase_order_sequences.last_number + 1
    RETURNING last_number INTO v_next_number;
    
    -- Formato: PO-YY-XXXXXX
    v_po_number := 'PO-' || LPAD((v_year % 100)::TEXT, 2, '0') || '-' || LPAD(v_next_number::TEXT, 6, '0');
    
    RETURN v_po_number;
END;
$$;
ALTER FUNCTION "sales"."generate_po_number"() OWNER TO "postgres";
--
-- Name: generate_purchase_invoice_number("date"); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."generate_purchase_invoice_number"("p_issue_date" "date" DEFAULT CURRENT_DATE) RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
  v_year int;
  v_year_short text;
  v_next_number int;
  v_invoice_number text;
BEGIN
  v_year := EXTRACT(YEAR FROM p_issue_date)::int;
  v_year_short := RIGHT(v_year::text, 2);
  
  -- Get next number from sequence counter
  INSERT INTO audit.sequence_counters (prefix, year, current_number, last_generated_at)
  VALUES ('PINV', v_year, 1, now())
  ON CONFLICT (prefix, year) DO UPDATE
  SET current_number = audit.sequence_counters.current_number + 1,
      last_generated_at = now()
  RETURNING current_number INTO v_next_number;
  
  -- Format: C-YY-XXXXXX
  v_invoice_number := 'C-' || v_year_short || '-' || LPAD(v_next_number::text, 6, '0');
  
  RETURN v_invoice_number;
END;
$$;
ALTER FUNCTION "sales"."generate_purchase_invoice_number"("p_issue_date" "date") OWNER TO "postgres";
--
-- Name: get_next_draft_invoice_number(); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."get_next_draft_invoice_number"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'sales', 'public'
    AS $_$
DECLARE
  v_max_seq INTEGER;
  v_next_number TEXT;
BEGIN
  -- Lock the invoices table to prevent concurrent inserts from getting the same number
  LOCK TABLE sales.invoices IN SHARE ROW EXCLUSIVE MODE;
  
  -- Get the max sequence number for F-BORR
  SELECT COALESCE(MAX(
    CASE 
      WHEN preliminary_number ~ '^F-BORR-[0-9]+$'
      THEN CAST(SUBSTRING(preliminary_number FROM 8) AS INTEGER)
      ELSE 0
    END
  ), 0)
  INTO v_max_seq
  FROM sales.invoices
  WHERE preliminary_number LIKE 'F-BORR-%';
  
  -- Generate the new draft invoice number
  v_next_number := 'F-BORR-' || LPAD((v_max_seq + 1)::TEXT, 4, '0');
  
  RETURN v_next_number;
END;
$_$;
ALTER FUNCTION "sales"."get_next_draft_invoice_number"() OWNER TO "postgres";
--
-- Name: get_next_draft_number(); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."get_next_draft_number"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_next_num INTEGER;
BEGIN
  v_next_num := nextval('sales.draft_invoice_seq');
  RETURN 'F-BORR-' || LPAD(v_next_num::TEXT, 4, '0');
END;
$$;
ALTER FUNCTION "sales"."get_next_draft_number"() OWNER TO "postgres";
--
-- Name: get_next_invoice_number(); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."get_next_invoice_number"() RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'sales'
    AS $$
DECLARE
  v_year TEXT;
  v_seq INTEGER;
  v_invoice_number TEXT;
BEGIN
  v_year := TO_CHAR(CURRENT_DATE, 'YY');
  
  INSERT INTO sales.invoice_sequences (year, last_number)
  VALUES (EXTRACT(YEAR FROM CURRENT_DATE)::INTEGER, 0)
  ON CONFLICT (year) DO NOTHING;
  
  UPDATE sales.invoice_sequences 
  SET last_number = last_number + 1
  WHERE year = EXTRACT(YEAR FROM CURRENT_DATE)::INTEGER
  RETURNING last_number INTO v_seq;
  
  v_invoice_number := 'F-' || v_year || '-' || LPAD(v_seq::TEXT, 6, '0');
  
  RETURN v_invoice_number;
END;
$$;
ALTER FUNCTION "sales"."get_next_invoice_number"() OWNER TO "postgres";
--
-- Name: lock_invoice_on_issue(); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."lock_invoice_on_issue"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'sales', 'public'
    AS $$
BEGIN
  IF NEW.status = 'ISSUED' AND (OLD.status IS NULL OR OLD.status != 'ISSUED') THEN
    NEW.is_locked := true;
    NEW.locked_at := now();
    IF NEW.issue_date IS NULL THEN
      NEW.issue_date := CURRENT_DATE;
    END IF;
  END IF;
  RETURN NEW;
END;
$$;
ALTER FUNCTION "sales"."lock_invoice_on_issue"() OWNER TO "postgres";
--
-- Name: log_invoice_status_to_project(); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."log_invoice_status_to_project"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
  v_user_name TEXT;
  v_old_status TEXT;
  v_new_status TEXT;
  v_msg TEXT;
  v_inv_number TEXT;
BEGIN
  IF NEW.project_id IS NULL THEN
    RETURN NEW;
  END IF;

  v_old_status := OLD.status::TEXT;
  v_new_status := NEW.status::TEXT;

  IF v_old_status IS DISTINCT FROM v_new_status THEN
    SELECT full_name INTO v_user_name
    FROM internal.authorized_users WHERE id = auth.uid();

    v_inv_number := COALESCE(NEW.invoice_number, NEW.preliminary_number, '');
    v_msg := 'Factura ' || v_inv_number || ': estado cambiado de ' || 
             COALESCE(v_old_status, 'N/A') || ' a ' || v_new_status;

    INSERT INTO projects.project_activity (
      project_id, activity_type, content, metadata, created_by, created_by_name
    ) VALUES (
      NEW.project_id, 'INVOICE_STATUS', v_msg,
      jsonb_build_object('invoice_id', NEW.id, 'invoice_number', v_inv_number,
                         'old_status', v_old_status, 'new_status', v_new_status),
      auth.uid(), COALESCE(v_user_name, 'Sistema')
    );
  END IF;

  RETURN NEW;
END;
$$;
ALTER FUNCTION "sales"."log_invoice_status_to_project"() OWNER TO "postgres";
