--
-- Name: prevent_locked_purchase_invoice_modification(); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."prevent_locked_purchase_invoice_modification"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'sales', 'public'
    AS $$
BEGIN
  -- If document is locked OR status is PAID, prevent ALL financial modifications
  IF OLD.is_locked = true OR OLD.status = 'PAID' THEN
    IF NEW.subtotal IS DISTINCT FROM OLD.subtotal 
       OR NEW.tax_amount IS DISTINCT FROM OLD.tax_amount 
       OR NEW.total IS DISTINCT FROM OLD.total
       OR NEW.withholding_amount IS DISTINCT FROM OLD.withholding_amount THEN
      RAISE EXCEPTION 'Cannot modify financial values of a locked/paid purchase invoice. Invoice % is immutable.', OLD.internal_purchase_number;
    END IF;
  END IF;
  
  -- Auto-lock when status changes to PAID
  IF NEW.status = 'PAID' AND OLD.status != 'PAID' THEN
    NEW.is_locked := true;
  END IF;
  
  RETURN NEW;
END;
$$;
ALTER FUNCTION "sales"."prevent_locked_purchase_invoice_modification"() OWNER TO "postgres";
--
-- Name: prevent_locked_purchase_line_modification(); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."prevent_locked_purchase_line_modification"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
  v_invoice_locked BOOLEAN;
  v_invoice_status TEXT;
  v_invoice_number TEXT;
BEGIN
  SELECT is_locked, status, internal_purchase_number
  INTO v_invoice_locked, v_invoice_status, v_invoice_number
  FROM sales.purchase_invoices
  WHERE id = COALESCE(OLD.purchase_invoice_id, NEW.purchase_invoice_id);
  
  IF v_invoice_locked = true OR v_invoice_status = 'PAID' THEN
    RAISE EXCEPTION 'Cannot modify lines of locked/paid purchase invoice %. Document is immutable.', v_invoice_number;
  END IF;
  
  RETURN COALESCE(NEW, OLD);
END;
$$;
ALTER FUNCTION "sales"."prevent_locked_purchase_line_modification"() OWNER TO "postgres";
--
-- Name: recalculate_invoice_paid_amount("uuid"); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."recalculate_invoice_paid_amount"("p_invoice_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
  v_total_paid NUMERIC(12,2);
BEGIN
  SELECT COALESCE(SUM(amount), 0)
  INTO v_total_paid
  FROM sales.invoice_payments
  WHERE invoice_id = p_invoice_id
    AND is_confirmed = true;
  
  UPDATE sales.invoices
  SET paid_amount = v_total_paid,
      updated_at = now()
  WHERE id = p_invoice_id;
END;
$$;
ALTER FUNCTION "sales"."recalculate_invoice_paid_amount"("p_invoice_id" "uuid") OWNER TO "postgres";
--
-- Name: recalculate_purchase_invoice_paid_amount(); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."recalculate_purchase_invoice_paid_amount"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
  v_invoice_id UUID;
  v_total_paid NUMERIC;
  v_invoice_total NUMERIC;
  v_current_status TEXT;
  v_internal_number TEXT;
  v_issue_date DATE;
BEGIN
  IF TG_OP = 'DELETE' THEN
    v_invoice_id := OLD.purchase_invoice_id;
  ELSE
    v_invoice_id := NEW.purchase_invoice_id;
  END IF;

  -- Calculate total paid
  SELECT COALESCE(SUM(amount), 0)
  INTO v_total_paid
  FROM sales.purchase_invoice_payments
  WHERE purchase_invoice_id = v_invoice_id;

  -- Get invoice total, current status, internal_number and issue_date
  SELECT total, status, internal_purchase_number, issue_date 
  INTO v_invoice_total, v_current_status, v_internal_number, v_issue_date
  FROM sales.purchase_invoices
  WHERE id = v_invoice_id;

  -- Determinar nuevo estado
  -- Para facturas negativas, comparar valores absolutos
  IF v_invoice_total < 0 THEN
    -- Factura negativa (nota de cr├®dito)
    IF v_total_paid <= v_invoice_total THEN -- -191.30 <= -191.30
      -- Si va a cambiar a PAID y no tiene n├║mero interno, generarlo
      IF v_current_status <> 'PAID' AND v_internal_number IS NULL THEN
        v_internal_number := sales.generate_purchase_invoice_number(COALESCE(v_issue_date, CURRENT_DATE));
      END IF;
      
      UPDATE sales.purchase_invoices
      SET
        paid_amount = v_total_paid,
        internal_purchase_number = COALESCE(internal_purchase_number, v_internal_number),
        status = 'PAID',
        updated_at = now()
      WHERE id = v_invoice_id;
    ELSIF v_total_paid < 0 THEN
      UPDATE sales.purchase_invoices
      SET
        paid_amount = v_total_paid,
        status = 'PARTIAL',
        updated_at = now()
      WHERE id = v_invoice_id;
    ELSE
      UPDATE sales.purchase_invoices
      SET
        paid_amount = v_total_paid,
        updated_at = now()
      WHERE id = v_invoice_id;
    END IF;
  ELSE
    -- Factura positiva (normal)
    IF v_total_paid >= COALESCE(v_invoice_total, 0) THEN
      -- Si va a cambiar a PAID y no tiene n├║mero interno, generarlo
      IF v_current_status <> 'PAID' AND v_internal_number IS NULL THEN
        v_internal_number := sales.generate_purchase_invoice_number(COALESCE(v_issue_date, CURRENT_DATE));
      END IF;
      
      UPDATE sales.purchase_invoices
      SET
        paid_amount = v_total_paid,
        internal_purchase_number = COALESCE(internal_purchase_number, v_internal_number),
        status = 'PAID',
        updated_at = now()
      WHERE id = v_invoice_id;
    ELSIF v_total_paid > 0 THEN
      UPDATE sales.purchase_invoices
      SET
        paid_amount = v_total_paid,
        status = 'PARTIAL',
        updated_at = now()
      WHERE id = v_invoice_id;
    ELSE
      UPDATE sales.purchase_invoices
      SET
        paid_amount = v_total_paid,
        updated_at = now()
      WHERE id = v_invoice_id;
    END IF;
  END IF;

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;
  RETURN NEW;
END;
$$;
ALTER FUNCTION "sales"."recalculate_purchase_invoice_paid_amount"() OWNER TO "postgres";
--
-- Name: recalculate_purchase_invoice_totals(); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."recalculate_purchase_invoice_totals"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
  v_subtotal NUMERIC;
  v_tax_amount NUMERIC;
  v_withholding_amount NUMERIC;
  v_total NUMERIC;
BEGIN
  SELECT 
    COALESCE(SUM(subtotal), 0),
    COALESCE(SUM(tax_amount), 0),
    COALESCE(SUM(withholding_amount), 0),
    COALESCE(SUM(total), 0)
  INTO v_subtotal, v_tax_amount, v_withholding_amount, v_total
  FROM sales.purchase_invoice_lines
  WHERE purchase_invoice_id = COALESCE(NEW.purchase_invoice_id, OLD.purchase_invoice_id);
  
  UPDATE sales.purchase_invoices
  SET 
    subtotal = v_subtotal,
    tax_amount = v_tax_amount,
    withholding_amount = v_withholding_amount,
    -- El total debe ser: subtotal + tax_amount - withholding_amount
    total = v_subtotal + v_tax_amount - v_withholding_amount,
    updated_at = now()
  WHERE id = COALESCE(NEW.purchase_invoice_id, OLD.purchase_invoice_id);
  
  RETURN COALESCE(NEW, OLD);
END;
$$;
ALTER FUNCTION "sales"."recalculate_purchase_invoice_totals"() OWNER TO "postgres";
--
-- Name: recalculate_purchase_order_totals(); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."recalculate_purchase_order_totals"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
    v_order_id UUID;
    v_subtotal NUMERIC(12,2);
    v_tax_amount NUMERIC(12,2);
    v_withholding_amount NUMERIC(12,2);
    v_total NUMERIC(12,2);
BEGIN
    -- Determinar el ID del pedido
    IF TG_OP = 'DELETE' THEN
        v_order_id := OLD.purchase_order_id;
    ELSE
        v_order_id := NEW.purchase_order_id;
    END IF;
    
    -- Calcular totales desde las l├¡neas
    SELECT 
        COALESCE(SUM(subtotal), 0),
        COALESCE(SUM(tax_amount), 0),
        COALESCE(SUM(withholding_amount), 0),
        COALESCE(SUM(total), 0)
    INTO v_subtotal, v_tax_amount, v_withholding_amount, v_total
    FROM sales.purchase_order_lines
    WHERE purchase_order_id = v_order_id;
    
    -- Actualizar el pedido
    UPDATE sales.purchase_orders
    SET 
        subtotal = v_subtotal,
        tax_amount = v_tax_amount,
        withholding_amount = v_withholding_amount,
        total = v_total
    WHERE id = v_order_id;
    
    RETURN COALESCE(NEW, OLD);
END;
$$;
ALTER FUNCTION "sales"."recalculate_purchase_order_totals"() OWNER TO "postgres";
--
-- Name: recalculate_purchase_paid_amount(); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."recalculate_purchase_paid_amount"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
  v_paid NUMERIC;
  v_total NUMERIC;
  v_new_status TEXT;
BEGIN
  SELECT COALESCE(SUM(amount), 0)
  INTO v_paid
  FROM sales.purchase_invoice_payments
  WHERE purchase_invoice_id = COALESCE(NEW.purchase_invoice_id, OLD.purchase_invoice_id)
    AND is_confirmed = true;
  
  SELECT total INTO v_total
  FROM sales.purchase_invoices
  WHERE id = COALESCE(NEW.purchase_invoice_id, OLD.purchase_invoice_id);
  
  -- Determinar nuevo estado
  IF v_paid >= v_total THEN
    v_new_status := 'PAID';
  ELSIF v_paid > 0 THEN
    v_new_status := 'PARTIAL';
  ELSE
    v_new_status := NULL; -- No cambiar estado si no hay pagos
  END IF;
  
  UPDATE sales.purchase_invoices
  SET 
    paid_amount = v_paid,
    -- pending_amount es GENERATED, no se actualiza manualmente
    status = COALESCE(v_new_status, status),
    updated_at = now()
  WHERE id = COALESCE(NEW.purchase_invoice_id, OLD.purchase_invoice_id);
  
  RETURN COALESCE(NEW, OLD);
END;
$$;
ALTER FUNCTION "sales"."recalculate_purchase_paid_amount"() OWNER TO "postgres";
--
-- Name: trigger_recalculate_invoice_totals(); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."trigger_recalculate_invoice_totals"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
  v_invoice_id UUID;
BEGIN
  -- Determinar invoice_id seg├║n la operaci├│n
  IF TG_OP = 'DELETE' THEN
    v_invoice_id := OLD.invoice_id;
  ELSE
    v_invoice_id := NEW.invoice_id;
  END IF;
  
  -- Recalcular totales
  PERFORM sales.update_invoice_totals(v_invoice_id);
  
  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  ELSE
    RETURN NEW;
  END IF;
END;
$$;
ALTER FUNCTION "sales"."trigger_recalculate_invoice_totals"() OWNER TO "postgres";
--
-- Name: trigger_recalculate_paid_amount(); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."trigger_recalculate_paid_amount"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
  v_invoice_id UUID;
BEGIN
  IF TG_OP = 'DELETE' THEN
    v_invoice_id := OLD.invoice_id;
  ELSE
    v_invoice_id := NEW.invoice_id;
  END IF;
  PERFORM sales.recalculate_invoice_paid_amount(v_invoice_id);
  PERFORM sales.update_invoice_status_from_payments(v_invoice_id);
  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  ELSE
    RETURN NEW;
  END IF;
END;
$$;
ALTER FUNCTION "sales"."trigger_recalculate_paid_amount"() OWNER TO "postgres";
