--
-- Name: update_invoice_status_from_payments("uuid"); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."update_invoice_status_from_payments"("p_invoice_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
  v_invoice RECORD;
BEGIN
  SELECT id, total, paid_amount, status, due_date
  INTO v_invoice
  FROM sales.invoices
  WHERE id = p_invoice_id;
  
  IF v_invoice.id IS NULL THEN
    RETURN;
  END IF;
  
  IF v_invoice.paid_amount >= COALESCE(v_invoice.total, 0) THEN
    UPDATE sales.invoices
    SET status = 'PAID',
        updated_at = now()
    WHERE id = p_invoice_id
      AND status NOT IN ('PAID', 'CANCELLED');
      
  ELSIF v_invoice.paid_amount > 0 AND v_invoice.paid_amount < COALESCE(v_invoice.total, 0) THEN
    UPDATE sales.invoices
    SET status = 'PARTIAL',
        updated_at = now()
    WHERE id = p_invoice_id
      AND status NOT IN ('PAID', 'CANCELLED');
      
  ELSIF v_invoice.status = 'ISSUED' 
    AND v_invoice.due_date IS NOT NULL 
    AND v_invoice.due_date < CURRENT_DATE 
    AND v_invoice.paid_amount < COALESCE(v_invoice.total, 0) THEN
    UPDATE sales.invoices
    SET status = 'OVERDUE',
        updated_at = now()
    WHERE id = p_invoice_id
      AND status NOT IN ('PAID', 'CANCELLED');
  END IF;
END;
$$;
ALTER FUNCTION "sales"."update_invoice_status_from_payments"("p_invoice_id" "uuid") OWNER TO "postgres";
--
-- Name: update_invoice_totals("uuid"); Type: FUNCTION; Schema: sales; Owner: postgres
--

CREATE FUNCTION "sales"."update_invoice_totals"("p_invoice_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'sales', 'public'
    AS $$
DECLARE
  v_subtotal NUMERIC(12,2) := 0;
  v_tax_amount NUMERIC(12,2) := 0;
  v_total NUMERIC(12,2) := 0;
BEGIN
  -- Calcular totales desde las l├¡neas
  -- subtotal = sum(quantity * unit_price * (1 - discount_percent / 100))
  -- tax_amount = sum(subtotal_line * tax_rate / 100)
  -- total = subtotal + tax_amount
  SELECT 
    COALESCE(SUM(
      quantity * unit_price * (1 - COALESCE(discount_percent, 0) / 100)
    ), 0),
    COALESCE(SUM(
      quantity * unit_price * (1 - COALESCE(discount_percent, 0) / 100) * (COALESCE(tax_rate, 0) / 100)
    ), 0),
    COALESCE(SUM(
      quantity * unit_price * (1 - COALESCE(discount_percent, 0) / 100) * (1 + COALESCE(tax_rate, 0) / 100)
    ), 0)
  INTO v_subtotal, v_tax_amount, v_total
  FROM sales.invoice_lines
  WHERE invoice_id = p_invoice_id;
  
  -- Actualizar factura
  UPDATE sales.invoices
  SET 
    subtotal = v_subtotal,
    tax_amount = v_tax_amount,
    total = v_total,
    updated_at = NOW()
  WHERE id = p_invoice_id;
END;
$$;
ALTER FUNCTION "sales"."update_invoice_totals"("p_invoice_id" "uuid") OWNER TO "postgres";
