--
-- Name: check_rate_limit("text", "text", integer, integer); Type: FUNCTION; Schema: security; Owner: postgres
--

CREATE FUNCTION "security"."check_rate_limit"("p_identifier" "text", "p_identifier_type" "text" DEFAULT 'email'::"text", "p_max_attempts" integer DEFAULT 5, "p_window_minutes" integer DEFAULT 15) RETURNS TABLE("allowed" boolean, "remaining_attempts" integer, "retry_after_seconds" integer, "total_attempts" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'security', 'public'
    AS $$
DECLARE
  v_window_start TIMESTAMPTZ;
  v_attempt_count INTEGER;
  v_oldest_attempt TIMESTAMPTZ;
BEGIN
  v_window_start := now() - (p_window_minutes || ' minutes')::INTERVAL;
  
  -- Contar intentos fallidos en la ventana de tiempo
  SELECT COUNT(*), MIN(attempted_at)
  INTO v_attempt_count, v_oldest_attempt
  FROM security.login_attempts
  WHERE identifier = p_identifier
    AND identifier_type = p_identifier_type
    AND attempted_at >= v_window_start
    AND success = false;
  
  -- Calcular resultado
  IF v_attempt_count >= p_max_attempts THEN
    RETURN QUERY SELECT 
      false::BOOLEAN,
      0::INTEGER,
      GREATEST(0, EXTRACT(EPOCH FROM (v_oldest_attempt + (p_window_minutes || ' minutes')::INTERVAL - now()))::INTEGER),
      v_attempt_count::INTEGER;
  ELSE
    RETURN QUERY SELECT 
      true::BOOLEAN,
      (p_max_attempts - v_attempt_count)::INTEGER,
      0::INTEGER,
      v_attempt_count::INTEGER;
  END IF;
END;
$$;
ALTER FUNCTION "security"."check_rate_limit"("p_identifier" "text", "p_identifier_type" "text", "p_max_attempts" integer, "p_window_minutes" integer) OWNER TO "postgres";
--
-- Name: cleanup_expired_otps(); Type: FUNCTION; Schema: security; Owner: postgres
--

CREATE FUNCTION "security"."cleanup_expired_otps"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'security'
    AS $$
DECLARE
  v_deleted INTEGER;
BEGIN
  DELETE FROM security.otp_codes
  WHERE expires_at < NOW()
  RETURNING 1 INTO v_deleted;
  
  RETURN COALESCE(v_deleted, 0);
END;
$$;
ALTER FUNCTION "security"."cleanup_expired_otps"() OWNER TO "postgres";
--
-- Name: cleanup_old_attempts(integer); Type: FUNCTION; Schema: security; Owner: postgres
--

CREATE FUNCTION "security"."cleanup_old_attempts"("p_older_than_hours" integer DEFAULT 24) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'security', 'public'
    AS $$
DECLARE
  v_deleted_count INTEGER;
BEGIN
  DELETE FROM security.login_attempts
  WHERE attempted_at < now() - (p_older_than_hours || ' hours')::INTERVAL;
  
  GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
  
  RETURN v_deleted_count;
END;
$$;
ALTER FUNCTION "security"."cleanup_old_attempts"("p_older_than_hours" integer) OWNER TO "postgres";
--
-- Name: generate_otp("text", "inet", "text"); Type: FUNCTION; Schema: security; Owner: postgres
--

CREATE FUNCTION "security"."generate_otp"("p_email" "text", "p_ip_address" "inet" DEFAULT NULL::"inet", "p_user_agent" "text" DEFAULT NULL::"text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'security'
    AS $$
DECLARE
  v_code TEXT;
BEGIN
  -- Generate 6-digit code
  v_code := LPAD(FLOOR(RANDOM() * 1000000)::TEXT, 6, '0');
  
  -- Invalidate any existing codes for this email
  DELETE FROM security.otp_codes 
  WHERE user_email = LOWER(p_email);
  
  -- Insert new code (expires in 10 minutes)
  INSERT INTO security.otp_codes (user_email, code, expires_at, ip_address, user_agent)
  VALUES (LOWER(p_email), v_code, NOW() + INTERVAL '10 minutes', p_ip_address, p_user_agent);
  
  RETURN v_code;
END;
$$;
ALTER FUNCTION "security"."generate_otp"("p_email" "text", "p_ip_address" "inet", "p_user_agent" "text") OWNER TO "postgres";
--
-- Name: record_login_attempt("text", "text", boolean, "inet", "text"); Type: FUNCTION; Schema: security; Owner: postgres
--

CREATE FUNCTION "security"."record_login_attempt"("p_identifier" "text", "p_identifier_type" "text" DEFAULT 'email'::"text", "p_success" boolean DEFAULT false, "p_ip_address" "inet" DEFAULT NULL::"inet", "p_user_agent" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'security', 'public'
    AS $$
DECLARE
  v_attempt_id UUID;
BEGIN
  INSERT INTO security.login_attempts (
    identifier,
    identifier_type,
    success,
    ip_address,
    user_agent
  ) VALUES (
    p_identifier,
    p_identifier_type,
    p_success,
    p_ip_address,
    p_user_agent
  )
  RETURNING id INTO v_attempt_id;
  
  RETURN v_attempt_id;
END;
$$;
ALTER FUNCTION "security"."record_login_attempt"("p_identifier" "text", "p_identifier_type" "text", "p_success" boolean, "p_ip_address" "inet", "p_user_agent" "text") OWNER TO "postgres";
