--
-- Name: verify_otp("text", "text"); Type: FUNCTION; Schema: security; Owner: postgres
--

CREATE FUNCTION "security"."verify_otp"("p_email" "text", "p_code" "text") RETURNS TABLE("valid" boolean, "message" "text", "remaining_attempts" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'security'
    AS $$
DECLARE
  v_otp RECORD;
BEGIN
  -- Get the OTP record
  SELECT * INTO v_otp
  FROM security.otp_codes
  WHERE user_email = LOWER(p_email)
    AND NOT verified
    AND expires_at > NOW()
  ORDER BY created_at DESC
  LIMIT 1;
  
  -- No valid OTP found
  IF NOT FOUND THEN
    RETURN QUERY SELECT FALSE, 'C├│digo expirado o no encontrado. Solicita uno nuevo.'::TEXT, 0;
    RETURN;
  END IF;
  
  -- Check max attempts
  IF v_otp.attempts >= v_otp.max_attempts THEN
    -- Delete the OTP
    DELETE FROM security.otp_codes WHERE id = v_otp.id;
    RETURN QUERY SELECT FALSE, 'M├íximo de intentos alcanzado. Solicita un nuevo c├│digo.'::TEXT, 0;
    RETURN;
  END IF;
  
  -- Increment attempts
  UPDATE security.otp_codes 
  SET attempts = attempts + 1 
  WHERE id = v_otp.id;
  
  -- Verify code
  IF v_otp.code = p_code THEN
    -- Mark as verified and delete
    DELETE FROM security.otp_codes WHERE id = v_otp.id;
    RETURN QUERY SELECT TRUE, 'C├│digo verificado correctamente.'::TEXT, 0;
  ELSE
    RETURN QUERY SELECT FALSE, 'C├│digo incorrecto.'::TEXT, (v_otp.max_attempts - v_otp.attempts - 1)::INTEGER;
  END IF;
END;
$$;
ALTER FUNCTION "security"."verify_otp"("p_email" "text", "p_code" "text") OWNER TO "postgres";
