    "tax_rate" numeric(5,2) DEFAULT 21.00 NOT NULL,
    "discount_percent" numeric(5,2) DEFAULT 0,
    "subtotal" numeric(12,2) GENERATED ALWAYS AS ((("quantity" * "unit_price") * ((1)::numeric - (COALESCE("discount_percent", (0)::numeric) / (100)::numeric)))) STORED,
    "tax_amount" numeric(12,2) GENERATED ALWAYS AS ((((("quantity" * "unit_price") * ((1)::numeric - (COALESCE("discount_percent", (0)::numeric) / (100)::numeric))) * "tax_rate") / (100)::numeric)) STORED,
    "total" numeric(12,2) GENERATED ALWAYS AS (((("quantity" * "unit_price") * ((1)::numeric - (COALESCE("discount_percent", (0)::numeric) / (100)::numeric))) * ((1)::numeric + ("tax_rate" / (100)::numeric)))) STORED,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "group_name" "text"
);
