--
-- Name: client_payment_summary; Type: VIEW; Schema: sales; Owner: postgres
--

CREATE VIEW "sales"."client_payment_summary" AS
 SELECT "i"."client_id",
    "c"."company_name" AS "client_name",
    "count"(DISTINCT "i"."id") AS "invoice_count",
    "count"("ip"."id") AS "payment_count",
    "sum"("ip"."amount") AS "total_paid",
    "sum"("i"."total") AS "total_invoiced",
    "sum"(COALESCE("i"."pending_amount", (0)::numeric)) AS "total_pending"
   FROM (("sales"."invoices" "i"
     LEFT JOIN "sales"."invoice_payments" "ip" ON ((("ip"."invoice_id" = "i"."id") AND ("ip"."is_confirmed" = true))))
     LEFT JOIN "crm"."clients" "c" ON (("c"."id" = "i"."client_id")))
  WHERE ("i"."status" <> 'CANCELLED'::"text")
  GROUP BY "i"."client_id", "c"."company_name";
ALTER VIEW "sales"."client_payment_summary" OWNER TO "postgres";
