--
-- Name: COLUMN "purchase_invoices"."status"; Type: COMMENT; Schema: sales; Owner: postgres
--

COMMENT ON COLUMN "sales"."purchase_invoices"."status" IS 'Estados posibles:
- DRAFT: Borrador
- PENDING: Pendiente de procesar
- PENDING_VALIDATION: Desde esc├íner, pendiente de validaci├│n del usuario
- CONFIRMED: Validada/confirmada
- REGISTERED: Registrada contablemente
- APPROVED: Aprobada
- PARTIAL: Parcialmente pagada
- PAID: Pagada completamente
- CANCELLED: Cancelada
- OVERDUE: Vencida';
