--
-- Name: financial_movements; Type: VIEW; Schema: sales; Owner: postgres
--

CREATE VIEW "sales"."financial_movements" AS
 SELECT 'INCOME'::"text" AS "movement_type",
    "i"."id",
    "i"."invoice_number",
    "i"."issue_date",
    "i"."total" AS "amount",
    "c"."company_name" AS "counterparty",
    'CLIENT'::"text" AS "counterparty_type",
    "i"."project_id"
   FROM ("sales"."invoices" "i"
     JOIN "crm"."clients" "c" ON (("i"."client_id" = "c"."id")))
  WHERE ("i"."status" = ANY (ARRAY['ISSUED'::"text", 'PAID'::"text", 'PARTIAL'::"text"]))
UNION ALL
 SELECT 'EXPENSE'::"text" AS "movement_type",
    "pi"."id",
    "pi"."invoice_number",
    "pi"."issue_date",
    (- "pi"."total") AS "amount",
    COALESCE("s"."company_name", "t"."company_name", 'Gasto General'::"text") AS "counterparty",
        CASE
            WHEN ("pi"."supplier_id" IS NOT NULL) THEN 'SUPPLIER'::"text"
            WHEN ("pi"."technician_id" IS NOT NULL) THEN 'TECHNICIAN'::"text"
            ELSE 'EXPENSE'::"text"
        END AS "counterparty_type",
    "pi"."project_id"
   FROM (("sales"."purchase_invoices" "pi"
     LEFT JOIN "internal"."suppliers" "s" ON (("pi"."supplier_id" = "s"."id")))
     LEFT JOIN "internal"."technicians" "t" ON (("pi"."technician_id" = "t"."id")))
  WHERE ("pi"."status" = ANY (ARRAY['ISSUED'::"text", 'REGISTERED'::"text", 'PARTIAL'::"text", 'PAID'::"text"]));
ALTER VIEW "sales"."financial_movements" OWNER TO "postgres";
--
-- Name: financial_summary; Type: VIEW; Schema: sales; Owner: postgres
--

CREATE VIEW "sales"."financial_summary" AS
 SELECT 'SALES'::"text" AS "transaction_type",
    "sum"(COALESCE("i"."total", (0)::numeric)) AS "total_amount",
    "sum"(COALESCE("i"."paid_amount", (0)::numeric)) AS "total_paid",
    "sum"(COALESCE("i"."pending_amount", (0)::numeric)) AS "total_pending",
    "count"(*) AS "transaction_count"
   FROM "sales"."invoices" "i"
  WHERE ("i"."status" <> 'CANCELLED'::"text")
UNION ALL
 SELECT 'PURCHASES'::"text" AS "transaction_type",
    (- "sum"(COALESCE("pi"."total", (0)::numeric))) AS "total_amount",
    (- "sum"(COALESCE("pi"."paid_amount", (0)::numeric))) AS "total_paid",
    (- "sum"(COALESCE("pi"."pending_amount", (0)::numeric))) AS "total_pending",
    "count"(*) AS "transaction_count"
   FROM "sales"."purchase_invoices" "pi"
  WHERE ("pi"."status" <> 'CANCELLED'::"text");
ALTER VIEW "sales"."financial_summary" OWNER TO "postgres";
