-- Name: invoice_payments_with_details; Type: VIEW; Schema: sales; Owner: postgres
--

CREATE VIEW "sales"."invoice_payments_with_details" AS
 SELECT "ip"."id",
    "ip"."invoice_id",
    "i"."invoice_number",
    "ip"."amount",
    "ip"."payment_date",
    "ip"."payment_method",
    "ip"."bank_reference",
    "ip"."notes",
    "ip"."is_confirmed",
    "ip"."registered_by",
    "au"."full_name" AS "registered_by_name",
    "ip"."created_at",
    "i"."client_id",
    "c"."company_name" AS "client_name",
    "i"."project_id",
    "p"."project_number",
    "i"."project_name"
   FROM (((("sales"."invoice_payments" "ip"
     JOIN "sales"."invoices" "i" ON (("i"."id" = "ip"."invoice_id")))
     LEFT JOIN "crm"."clients" "c" ON (("c"."id" = "i"."client_id")))
     LEFT JOIN "projects"."projects" "p" ON (("p"."id" = "i"."project_id")))
     LEFT JOIN "internal"."authorized_users" "au" ON (("au"."id" = "ip"."registered_by")));
ALTER VIEW "sales"."invoice_payments_with_details" OWNER TO "postgres";
