--
-- Name: project_payment_summary; Type: VIEW; Schema: sales; Owner: postgres
--

CREATE VIEW "sales"."project_payment_summary" AS
 SELECT "i"."project_id",
    "p"."project_number",
    "i"."project_name",
    "count"(DISTINCT "i"."id") AS "invoice_count",
    "count"("ip"."id") AS "payment_count",
    "sum"("ip"."amount") AS "total_paid",
    "sum"("i"."total") AS "total_invoiced",
    "sum"(COALESCE("i"."pending_amount", (0)::numeric)) AS "total_pending"
   FROM (("sales"."invoices" "i"
     LEFT JOIN "sales"."invoice_payments" "ip" ON ((("ip"."invoice_id" = "i"."id") AND ("ip"."is_confirmed" = true))))
     LEFT JOIN "projects"."projects" "p" ON (("p"."id" = "i"."project_id")))
  WHERE (("i"."status" <> 'CANCELLED'::"text") AND ("i"."project_id" IS NOT NULL))
  GROUP BY "i"."project_id", "p"."project_number", "i"."project_name";
ALTER VIEW "sales"."project_payment_summary" OWNER TO "postgres";
