    "subtotal" numeric(12,2) GENERATED ALWAYS AS ("round"((("quantity" * "unit_price") * ((1)::numeric - (COALESCE("discount_percent", (0)::numeric) / (100)::numeric))), 2)) STORED,
    "tax_amount" numeric(12,2) GENERATED ALWAYS AS ("round"((((("quantity" * "unit_price") * ((1)::numeric - (COALESCE("discount_percent", (0)::numeric) / (100)::numeric))) * "tax_rate") / (100)::numeric), 2)) STORED,
    "withholding_amount" numeric(12,2) GENERATED ALWAYS AS ("round"((((("quantity" * "unit_price") * ((1)::numeric - (COALESCE("discount_percent", (0)::numeric) / (100)::numeric))) * COALESCE("withholding_rate", (0)::numeric)) / (100)::numeric), 2)) STORED,
    "total" numeric(12,2) GENERATED ALWAYS AS ("round"((((("quantity" * "unit_price") * ((1)::numeric - (COALESCE("discount_percent", (0)::numeric) / (100)::numeric))) * ((1)::numeric + ("tax_rate" / (100)::numeric))) - (((("quantity" * "unit_price") * ((1)::numeric - (COALESCE("discount_percent", (0)::numeric) / (100)::numeric))) * COALESCE("withholding_rate", (0)::numeric)) / (100)::numeric)), 2)) STORED,
    "group_name" "text",
    "created_at" timestamp with time zone DEFAULT "now"(),
    "updated_at" timestamp with time zone DEFAULT "now"()
);
